INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(1, '01-01', '1 stycznia', 'Czujność', NULL, '„Zachowujemy to, co mamy tylko dzięki czujności...”  \r\n\r\n~Tekst Podstawowy \r\n\r\nW jaki sposób zachowujemy czujność w zdrowieniu? W pierwszej kolejności, poprzez uświadomienie sobie, że jesteśmy chorzy na chorobę, która pozostanie z nami do końca życia. Bez względu na to, jak długo jesteśmy czyści, jak bardzo nasze życie zmieniło się na lepsze lub jak wielka jest nasza przemiana duchowa, nadal jesteśmy uzależnieni. Nasza choroba nieustannie czyha i jest gotowa uruchomić zastawioną pułapkę, jeśli tylko damy jej ku temu sposobność. Zachowywanie czujności jest więc naszym codziennym głównym zadaniem. Staramy się być stale czujni i gotowi uporać się z oznakami nadchodzących kłopotów. Nie oznacza to jednak, że ciągle powinniśmy żyć w irracjonalnym strachu przed tym, że jeśli przestaniemy choć na chwilę mieć się na baczności, to spotka nas coś strasznego. Powinniśmy po prostu ciągle zachowywać podstawowe środki ostrożności. Codzienna modlitwa, regularne uczestnictwo w mityngach i świadome nie narażanie na szwank naszych duchowych zasad w celu ułatwienia sobie życia - to podstawowe akty czujności. Dokonujemy obrachunku moralnego, gdy jest to konieczne, dzielimy się z innymi, gdy jesteśmy o to proszeni i z troską dbamy o nasze zdrowienie. Jednak, przede wszystkim, powinniśmy być uważni! Wytchnienie od naszego uzależnienia dostajemy tylko na jeden dzień i trwa to tak długo, jak długo pozostajemy czujni. Każdego dnia wprowadzamy zasady zdrowienia we wszystko, co robimy i codziennie wieczorem dziękujemy naszej Sile Wyższej za kolejny czysty dzień.', 'Będę czujny, robiąc wszystko co konieczne, aby chronić moje zdrowienie.'),
(2, '01-02', '2 stycznia', 'Weź głęboki oddech i porozmawiaj z Bogiem', NULL, '„Czasem, gdy się modlimy, zdarza się rzecz nadzwyczajna: znajdujemy sposób i energię, aby robić rzeczy daleko wykraczające poza nasze możliwości.\"\r\n\r\n~Tekst Podstawowy  \r\n\r\nRadzenie sobie z drobnymi irytacjami i frustracjami, które niesie z sobą życie, jest często najtrudniejszą umiejętnością, jakiej musimy się nauczyć w trakcie zdrowienia. Codziennie stajemy twarzą w twarz z małymi kłopotami. Począwszy od rozwiązywania supełków na sznurówkach naszych dzieci do stania w kolejce w sklepie nasze dni są wypełnione małymi trudnościami, którym musimy jakoś sprostać. Jeśli nie będziemy ostrożni, może okazać się, że radzimy sobie z tymi trudnościami poprzez stosowanie siłowych rozwiązań lub branie wszystkiego „na klatę” z zaciśniętymi zębami, jednocześnie udzielając sobie surowego pouczenia na temat tego, jak powinniśmy sobie w danej sytuacji poradzić. Są to skrajne przykłady naszej nieumiejętności radzenia sobie z problemami, ale nawet jeśli nie jest aż tak źle, to na pewno można to ulepszyć. Za każdym razem, gdy wbrew naszym planom życie stawia nas w obliczu jakiegoś drobnego niepowodzenia, możemy po prostu wziąć głęboki oddech i porozmawiać z Bogiem, jakkolwiek Go pojmujemy. Wiedząc, że możemy czerpać od tej Siły cierpliwość, wytrwałość, tolerancję lub cokolwiek, czego potrzebujemy, jesteśmy w stanie lepiej radzić sobie z problemami i częściej się uśmiechać.', 'Kiedy tylko poczuję się sfrustrowany, zaczerpnę głębokiego oddechu i porozmawiam z moim Bogiem.'),
(3, '01-03', '3 stycznia', 'Nasza największa potrzeba', NULL, '„Ostatecznie, zmieniamy swoje przekonania oraz sposób myślenia i zaczynamy rozumieć, że naszą największą potrzebą jest poznanie woli Boga oraz siła do jej spełnienia.\"\r\n\r\n~Tekst Podstawowy\r\n\r\nKiedy po raz pierwszy pojawiliśmy się w NA, mieliśmy wiele różnych wyobrażeń o tym, jakie są nasze potrzeby. Niektórzy z nas stawiali sobie za cel gromadzenie osobistego dobytku. Myśleliśmy, że w parze ze zdrowieniem powinien iść sukces zewnętrzny. Zdrowienie jednak nie jest równe powodzeniu. Dzisiaj jesteśmy przekonani, że naszą największą potrzebą jest duchowe przewodnictwo i siła. Największą szkodą, jaką wyrządziło nam uzależnienie jest uszczerbek na naszej duchowości. Nasza podstawowa motywacja była kierowana przez naszą chorobę: zdobyć, wziąć i znaleźć sposoby oraz środki na to, aby zdobyć więcej. Nasze życie, zniewolone obezwładniającym pragnieniem narkotyku, było pozbawione celu i spójności. Staliśmy się duchowymi bankrutami. Prędzej czy później uświadamiamy sobie, że tym, czego nam najbardziej potrzeba w zdrowieniu jest „poznanie woli Boga wobec nas oraz siła do jej spełnienia\". Dzięki temu poznaniu odnajdziemy kierunek i poczucie sensu, które uzależnienie ukryło przed nami. Pełnienie woli Boga uwolni nas od samowoli. Nie kierując się już jedynie własnymi potrzebami, potrafimy żyć na równi z innymi. Nie ma nic złego w zewnętrznym sukcesie. Lecz bez duchowego aspektu, który oferuje nam program NA, nasza największa potrzeba w zdrowieniu nie spełni się, bez względu na to jak dobrze by się nam w życiu wiodło.', 'Będę dążył do zaspokojenia mojej największej potrzeby: żywego i opartego na przewodnictwie związku z Bogiem, jakkolwiek go pojmuję.'),
(4, '01-04', '4 stycznia', 'Miłość wspólnoty', NULL, '„Dzisiaj, wzmocnieni miłością wspólnoty, możemy wreszcie spojrzeć w oczy drugiemu człowiekowi i być wdzięczni za to, kim jesteśmy.”\r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy braliśmy, niewielu z nas było w stanie patrzeć komuś prosto w oczy - wstydziliśmy się tego, kim byliśmy. Wiedzieliśmy, że nasz umysł nie był zajęty niczym porządnym ani zdrowym. Nasz czas, pieniądze i energia nie służyły tworzeniu związków przepełnionych miłością, nie służyły też dzieleniu się z innymi ani robieniu czegoś dobrego dla społeczeństwa. Byliśmy w sidłach obsesji i kompulsji, które prowadziły nas tylko w jednym kierunku – w dół. Zdrowiejąc, przestajemy staczać się po równi pochyłej. Co jednak sprawiło, że powstrzymaliśmy ten proces staczanie się i skierowaliśmy się w górę ku otwartym przestrzeniom szerokiego i wolnego świata? Uczyniła to miłość wspólnoty. Wiedzieliśmy, że przebywając w towarzystwie innych uzależnionych nie zostaniemy odrzuceni. Dzięki ich przykładowi dowiedzieliśmy się jak zacząć w pozytywny sposób brać udział w otaczającym nas życiu. Gdy nie byliśmy pewni, jaką drogę wybrać, gdy potykaliśmy się, gdy musieliśmy naprawiać zło, które wyrządziliśmy, wiedzieliśmy, że inni członkowie wspólnoty dodadzą nam otuchy. Stopniowo nabraliśmy poczucia wolności. Już nie jesteśmy skuci naszą chorobą; teraz możemy budować, wzrastać i dzielić się tym z innymi. A gdy potrzebujemy wsparcia w robieniu następnego kroku, jest ono tutaj. Bezpieczeństwo, które zapewnia nam miłość wspólnoty, czyni nasze nowe życie znośnym.', 'Mogę spojrzeć każdemu człowiekowi w oczy bez uczucia wstydu. Jestem wdzięczny za pełne miłości wsparcie, które sprawia, że jest to możliwe.'),
(5, '01-05', '5 stycznia', 'Zdrowienie w domu', NULL, '\"Możemy na nowo cieszyć się naszymi rodzinami i zamiast być dla nich kłopotem lub ciężarem możemy stać się ich chlubą i wsparciem.”\r\n\r\n~Tekst Podstawowy  \r\n\r\nCzyż zdrowiejąc nie robimy rzeczy wspaniałych? Codziennie chodzimy na mityngi, wieczory spędzamy z przyjaciółmi ze wspólnoty a w weekend pędzimy na kolejne warsztaty. Lecz jeśli nasze życie domowe rozpada się, to znaczy, że chyba jednak nie jesteśmy tacy wspaniali. Spodziewamy się od naszych bliskich zrozumienia. Przecież nie zażywamy już narkotyków! Czy oni nie dostrzegają naszego postępu? Czy nie rozumieją jak ważne są nasze mityngi, nasza służba i nasze zaangażowanie we wspólnotę? Nasi bliscy nie docenią i nie zrozumieją zmiany, jaką NA wprowadza w nasze życie, dopóki im tego nie pokażemy. Jeśli pędzimy na mityng w taki sam sposób, w jaki wybiegaliśmy z domu po narkotyki, to co się w takim razie zmieniło? Jeśli nadal ignorujemy pragnienia oraz potrzeby naszych partnerów i dzieci, jeśli nie podejmujemy się obowiązków domowych, oznacza to, że nie „stosujemy tych zasad we wszystkich sferach naszego życia”. Powinniśmy żyć programem gdziekolwiek jesteśmy i cokolwiek robimy. Jeżeli chcemy, aby nasze życie duchowe było czymś więcej niż tylko teorią, musimy żyć nim w domu. Gdy będziemy to robić, ludzie, z którymi dzielimy nasze życie, z pewnością zauważą zmiany i będą wdzięczni, że znaleźliśmy NA.', 'Zabiorę moje zdrowienie ze sobą do domu.'),
(6, '01-06', '6 stycznia', 'Jak to działa?', NULL, '„Zwykłem myśleć, że znam odpowiedzi na wszystkie pytania, ale dzisiaj cieszę się, że tak nie jest.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJakie są dwa ulubione słowa większości uzależnionych? „Ja wiem!”. Niestety, wielu z nas zjawia się w NA z przekonaniem, że zna odpowiedzi na wszystkie pytania. Wiemy dużo na temat tego, co z nami jest nie w porządku. Ale wiedza ta, sama w sobie, nigdy nie pomogła nam utrzymać się w czystości nawet przez jakiś krótki okres czasu. Członkowie wspólnoty, którzy mają dłuższy staż w zdrowieniu, pierwsi przyznają, że im dłużej są tutaj, tym więcej muszą się uczyć. Ale wiedzą jedno: stosując się do tego prostego programu Dwunastu Kroków, byli w stanie pozostać czystymi. Nie pytają już: „dlaczego?\"; pytają: „jak?”. Wartość niekończących się spekulacji blednie w porównaniu z doświadczeniem uzależnionych, którzy znaleźli sposób na to, aby stać się czystymi i żyć w czystości. Nie oznacza to, że nie możemy pytać: „dlaczego?\", gdy jest to stosowne. Nie po to przecież przybyliśmy do NA, aby przestać myśleć! Jednak na samym początku warto przeformułować nasze pytania. Zamiast pytać „dlaczego?\", pytajmy „jak?\". Jak mam pracować nad tym krokiem? Jak często powinienem uczestniczyć w mityngach? Jak mam postępować, aby pozostać czystym?', 'Nie znam wszystkich odpowiedzi, ale wiem gdzie znaleźć tę, która jest dla mnie istotna. Spytam dziś drugiego uzależnionego: „Jak to działa?”'),
(7, '01-07', '7 stycznia', 'Zdrowienie', NULL, '„Anonimowi Narkomani oferują uzależnionym program zdrowienia, który jest czymś więcej, niż tylko życiem bez narkotyków. Nie jest też wyłącznie drogą lepszego życia w starym piekle, w którym żyliśmy, ale jest czymś lepszym niż wszystko, czego do tej pory zaznaliśmy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nMało kto spośród nas byłby zainteresowany „zdrowieniem”, które oznaczałoby powrót do tego, co mieliśmy zanim zaczęliśmy brać. Wielu z nas dotkliwie cierpiało z powodu fizycznego, seksualnego lub emocjonalnego wykorzystywania. Wydawało się, że branie i bycie na haju jest jedynym możliwym sposobem na to, aby jakoś sobie z tym poradzić. Cierpienie niektórych z nas, jeszcze sprzed czasu zanim się uzależniliśmy, było mniej widoczne, lecz równie bolesne. Brakowało nam ukierunkowania i celu. Ogarniała nas duchowa pustka. Czuliśmy się odizolowani i niezdolni do empatii. Nie mieliśmy żadnej z tych rzeczy, które nadają życiu sens i wartość. Braliśmy narkotyki, na próżno próbując zapełnić nimi tę wewnętrzną pustkę. Większość z nas nie chciałaby „odzyskać” tego, co mieliśmy przedtem. Zdrowienie, które znajdujemy w NA jest czymś innym: jest szansą na nowe życie. Dostajemy narzędzia, za pomocą których możemy usunąć zgliszcza naszego życia. Dostajemy też wsparcie, jakiego potrzebujemy, żeby z odwagą wyruszyć w nową drogę. Dostajemy również dar świadomego kontaktu z Siłą większą od nas samych, która daje nam wewnętrzną siłę i wskazówki, których tak bardzo brakowało nam w przeszłości. Zdrowienie? Tak, w każdym calu. Dostajemy zupełnie nowe życie, lepsze niż kiedykolwiek moglibyśmy to sobie wyobrazić. Jesteśmy wdzięczni. ', 'Dostałem coś, czego nigdy nie miałem, coś, co wydawało mi się niemożliwe: życie zdrowiejącego uzależnionego. Jestem dziś wdzięczny Sile Wyższej bardziej, niż mogę to wyrazić słowami.'),
(8, '01-08', '8 stycznia', 'Dorastanie', NULL, '„Stan naszego ducha stanowi podstawę uwieńczonego sukcesem zdrowienia, które oferuje nam nieograniczony rozwój”.\r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy nasi znajomi obchodzą rocznice czystości, mówią często, że w NA „wydorośleli\". Słuchając ich, myślimy: „Dobra, ale co to znaczy?\". Zaczynamy się zastanawiać czy my też staliśmy się już dorośli. Przyglądamy się swojemu życiu i widzimy, że faktycznie posiadamy wszystkie zewnętrzne oznaki dorosłości: książeczka czekowa, dzieci, praca, obowiązki. Jednak w środku często czujemy się jak dzieci. Życie wciąż jeszcze zbija nas z tropu. Często nie wiemy jak się zachować. Czasem zastanawiamy się czy jesteśmy naprawdę dorośli, czy jesteśmy tylko dziećmi, którym dano dorosłe ciała i takież obowiązki. Nie powinno się oceniać rozwoju na podstawie wieku lub stopnia odpowiedzialności. Najlepszą miarą rozwoju jest stan naszego ducha, który stanowi podstawę naszego zdrowienia. Jeśli ciągle jesteśmy zależni od ludzi, miejsc i rzeczy, zapewniając sobie w ten sposób wewnętrzną satysfakcję jak dziecko, które we wszystkim jest zależne od rodziców, to faktycznie musimy jeszcze trochę wydorośleć. Jeśli jednak stoimy pewnie na fundamencie naszego duchowego stanu, biorąc jego utrzymanie za nasz najważniejszy obowiązek, możemy uważać siebie za dojrzałych. Na tym fundamencie nasze możliwości rozwoju są nieograniczone.', 'Miarą mojej dojrzałości jest poziom odpowiedzialności, którą biorę za utrzymanie stanu swojego ducha. Dziś będzie to moim najwyższym priorytetem.'),
(9, '01-09', '9 stycznia', 'Odwzajemnić dobroć naszego sponsora', NULL, '„Nasze pierwsze próby zaangażowania się w relacje z innymi ludźmi zaczynają się zwykle od kontaktu z naszym sponsorem.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNasi sponsorzy mogą być obfitym źródłem mądrości, czułych słów wsparcia oraz informacji na temat zdrowienia. Tak wiele dla nas zrobili. Począwszy od późnych nocnych telefonów, do godzin spędzonych na wysłuchiwaniu naszej pisemnej pracy nad krokami; uwierzyli w nas i poświęcali dla nas swój czas, aby tego dowieść. Stanowczo a zarazem w pełen miłości sposób pokazali nam jak być uczciwym. W trudnych chwilach, gdy wszystko wokół nas wrzało, ich bezgraniczne współczucie dodawało nam sił do dalszej wędrówki. Sposób, w jaki nam pomagali, nakłonił nas, abyśmy zaczęli szukać odpowiedzi wewnątrz siebie, w wyniku czego staliśmy się dojrzałymi, odpowiedzialnymi i pewnymi siebie osobami. Pomimo, że nasz sponsor dał nam tak wiele i nigdy nie zażądał w zamian żadnej zapłaty, możemy robić pewne rzeczy, poprzez które okażemy mu naszą wdzięczność. Traktujmy naszego sponsora z szacunkiem. Sponsor nie jest koszem na śmieci, który został zaprojektowany specjalnie dla nas, abyśmy mogli wrzucać tam wszystkie swoje brudy. Podobnie jak my, nasi sponsorzy też mają swoje ciężkie chwile i utrapienia i czasami potrzebują naszego wsparcia. Są ludźmi, mają uczucia i są wdzięczni za naszą troskę. Być może chcieliby otrzymać od nas kartkę lub telefon, jako wyrazy naszej miłości. Cokolwiek robimy, aby zrewanżować się za dobroć naszego sponsora, wzmacniamy nasze zdrowienie, nie wspominając już o radości, jaką sprawimy naszemu sponsorowi. ', 'Mój sponsor zatroszczył się o mnie, gdy ja nie mogłem zatroszczyć się sam o siebie. Dziś zrobię coś miłego dla mojego sponsora.'),
(10, '01-10', '10 stycznia', 'Wdzięczność', NULL, '„Jestem bardzo wdzięczny za to, że uwierzyłem.”  \r\n\r\n~IP nr 21\r\n\r\nSamotnik a utrzymywanie czystości  Gdy spotyka nas jakaś trudna sytuacja, wiara w Siłę Wyższą może wszystko odmienić. Gdy sprawy w zdrowieniu nie układają się po naszej myśli, nasz sponsor może polecić nam napisanie „listy wdzięczności”. Pisząc ją, uwzględnijmy naszą wiarę w Siłę większą od nas samych. Jednym z największych darów, jakie otrzymujemy dzięki programowi Dwunastu Kroków, jest wiara w Boga, jakkolwiek Go pojmujemy. Program Dwunastu Kroków prowadzi nas łagodnie w kierunku duchowego przebudzenia. Podobnie jak rozwijało się nasze uzależnienie, w trakcie pracy nad programem Anonimowych Narkomanów rozwija się nasze życie duchowe. Kroki są naszą drogą do związku z Bogiem, jakkolwiek Go pojmujemy. Ta Siła Wyższa daje nam wsparcie, gdy ścieżka, którą kroczymy, staje się wyboista. Czy jesteśmy wdzięczni za nasz pogłębiający się związek z Siłą Wyższą? Czy pamiętamy, aby dziękować Bogu za każdy dzień czystości, bez względu na to, co by się tego dnia nie wydarzyło? Czy pamiętamy, że bez względu na to jak głęboka byłaby nasza rozpacz lub jak ogromna byłaby nasza radość, Bóg, jakkolwiek Go pojmujemy, zawsze jest z nami? Nasze zdrowienie jest darem, darem, który czasami uważamy za oczywisty. Każdego dnia, w którym pozostajemy czyści, możemy cieszyć się opieką naszej Siły Wyższej.', 'Jestem wdzięczny za moją relację z Siłą Wyższą, która się mną opiekuje.'),
(11, '01-11', '11 stycznia', 'Wiara', NULL, '„W miarę tego, jak w naszym codziennym życiu rozwijamy w sobie wiarę, spostrzegamy, że nasza Siła Wyższa daje potrzebną nam siłę i przewodnictwo.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNiektórzy spośród nas, rozpoczynając zdrowienie, są bardzo wystraszeni i niepewni siebie. Czujemy się słabi i samotni. Nie jesteśmy pewni, w jakim kierunku podążać i nie wiemy gdzie możemy znaleźć odpowiedzi na nasze pytania. Słyszymy, że jeśli odnajdziemy w sobie choć trochę wiary w Siłę większą od nas samych, to odnajdziemy również poczucie bezpieczeństwa i przewodnictwo. Wiara jednak nie przychodzi z dnia na dzień. Potrzeba czasu i wysiłku, aby mogła ona wzrastać. Ziarno zostaje zasiane w chwili, gdy prosimy naszą Silę Wyższą o pomoc. Potem zaś, gdy ta pomoc przychodzi, uznajemy jej źródło. Żywimy maleńkie ziarenko wiary światłem naszych codziennych modlitw. Nasza wiara wzrasta jako nagroda za to, że przeżywamy życie na warunkach, jakie ono dyktuje. Pewnego dnia uświadamiamy sobie, że nasza wiara stała się podobna do ogromnego rozłożystego drzewa - nie powstrzyma ono sztormów życia, lecz wiemy, że jesteśmy bezpieczni w jego schronieniu.', 'Wiem, że wiara w moją Siłę Wyższą nie uciszy sztormów życia, ale uciszy moje serce. Gdy nadejdą trudne czasy, użyję mojej wiary jako schronienia.'),
(12, '01-12', '12 stycznia', 'Duchowe przebudzenia', NULL, '„Przebudzeni duchowo w rezultacie tych Kroków...”  \r\n\r\n~Krok Dwunasty  \r\n\r\n„Po czym poznam, że doznałem duchowego przebudzenia?” Wielu z nas osiąga duchowe przebudzenie stopniowo. Naszą pierwszą duchową świadomością może być po prostu to, że na nowo zaczynamy doceniać życie. Być może pewnego dnia niespodziewanie odkryjemy śpiew ptaków o poranku. Proste piękno kwiatu może przypomnieć nam, że wszystko wokół nas jest dziełem Siły większej od nas samych. Nasze duchowe przebudzenie często staje się silniejsze wraz z upływem czasu. Możemy dążyć do głębszej duchowej świadomości, po prostu żyjąc codziennym życiem. Możemy nie ustawać w wysiłku, udoskonalając naszą duchowość poprzez codzienną modlitwę i medytację. Możemy, wsłuchując się w samych siebie, odnaleźć potrzebne nam wskazówki. Możemy zapytać innych uzależnionych o ich doświadczenia w sferze duchowości. Możemy znaleźć chwilę, aby docenić piękno otaczającego nas świata.', 'Będę rozmyślać o tych przebudzeniach duchowych, których już doświadczyłem. Będę dążył do świadomości Boga. Poświęcę codziennie chwilę czasu na to, aby docenić dzieła, jakich dokonuje moja Siła Wyższa.'),
(13, '01-13', '13 stycznia', 'Poddać się, aby zwyciężyć', NULL, '„Pomoc uzależnionemu zaczyna się dopiero wtedy, gdy jest on w stanie przyznać się do całkowitej porażki.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCałkowita porażka - cóż to za pomysł! To przecież oznacza kapitulację. Kapitulacja, to całkowite poddanie się. Bez żadnych opcji rezerwowych. Opuścić ręce i zrezygnować z walki. Można ewentualnie podnieść rękę do góry na naszym pierwszym mityngu i przyznać się, że jesteśmy uzależnieni. Skąd możemy wiedzieć, że zrobiliśmy już Krok Pierwszy, który pozwoli nam żyć bez narkotyków? Wiemy to, ponieważ raz dokonawszy tego gigantycznego kroku nie musimy już nigdy wracać do brania – właśnie dzisiaj. Tylko tyle. Nie jest to łatwe, ale jest to bardzo proste. Pracujemy nad Pierwszym Krokiem. Akceptujemy to, że jesteśmy uzależnieni. „Jedna działka to za dużo, a tysiąc nigdy dość\". Przekonaliśmy się o tym już wystarczająco wiele razy. Przyznajemy, że nie jesteśmy w stanie kontrolować żadnych narkotyków. Uznajemy to i jeśli jest to konieczne, wypowiadamy na głos. Robimy Krok Pierwszy, rozpoczynając nasz dzień. Tylko na jeden dzień. Takie przyznanie się uwalnia nas na jeden dzień, właśnie dzisiaj, od konieczności ciągłych powrotów do naszego uzależnienia. Kapitulujemy w obliczu tej choroby. Poddajemy się. Opuszczamy ring. Lecz poddając się, zwyciężamy. To jest właśnie paradoks Pierwszego Kroku: poddajemy się, aby zwyciężyć i, poddając się, zyskujemy potężną siłę, jakiej nigdy nawet nie mogliśmy sobie wyobrazić.', 'Przyznam się, że jestem bezsilny wobec mojego uzależnienia. Poddam się, aby zwyciężyć.'),
(14, '01-14', '14 stycznia', 'Kochający Bóg\r\n', NULL, '„To, jak pojmujemy Siłę Wyższą, zależy wyłącznie od nas... Sugeruje się tylko, aby Siła ta była kochająca, troskliwa i większa od nas samych.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPowiedziano nam, że możemy wierzyć w taką Siłę Wyższą, jaką chcemy, dopóki będzie ona kochająca i oczywiście większa od nas samych. Jednak niektórzy spośród nas mają problem z tymi wymaganiami. Albo nie wierzymy w nic poza sobą, albo wierzymy, że to, co można by nazwać „Bogiem\" musi być pozbawione serca i rozsądku, zsyłając nam pecha według własnych kaprysów. Uwierzenie w kochającą Siłę dla niektórych z nas jest z różnych powodów przeskoczeniem na zupełnie inne tory. Myśl o powierzeniu naszej woli i życia opiece czegoś, co mogłoby nas skrzywdzić, z pewnością napełni nas niechęcią. Jeśli rozpoczynamy pracę nad programem z przekonaniem, że Bóg potrafi tylko osądzać i jest bezlitosny, to, chcąc naprawdę poczuć ulgę, jaką przynosi Krok Trzeci, musimy takie myślenie przezwyciężyć. Nasze pozytywne doświadczenia w zdrowieniu mogą pomóc nam uwierzyć w kochającego Boga, jakkolwiek Go pojmujemy. Doznaliśmy ulgi w chorobie, która od dłuższego czasu przynosiła nam same nieszczęścia. Znaleźliśmy wskazówki i wsparcie, jakiego potrzebujemy, żeby rozwijać nasz nowy styl życia. Zaczęliśmy doświadczać pełni ducha tam, gdzie do tej pory była tylko pustka. Te aspekty naszego zdrowienia mają swoje źródło w Bogu kochającym, a nie w Bogu surowym i pełnym nienawiści. I im więcej zdobywamy doświadczenia w zdrowieniu, tym więcej będziemy mieli zaufania do tej kochającej Siły Wyższej.', 'Otworzę mój umysł i moje serce na wiarę w to, że Bóg jest Bogiem kochającym i że moja kochająca Siła Wyższa robi dla mnie to, czego ja sam nie mogę zrobić dla siebie.'),
(15, '01-15', '15 stycznia', 'Lęk', NULL, '„Dojrzewamy do tego, aby czuć się dobrze z naszą Siłą Wyższą, jako źródłem siły. W miarą wzrostu naszego zaufania do tej Siły, zaczynamy przezwyciężać lęk przed życiem.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy, będąc bezsilni, kierujemy się samowolą, życie staje się przerażającym i wymykającym się spod kontroli doświadczeniem. Zdrowiejąc, powierzamy naszą wolę i życie bezpiecznej opiece Boga, jakkolwiek Go pojmujemy. Gdy jednak przestajemy pracować nad programem i tracimy świadomy kontakt z naszą Siłą Wyższą, ponownie zaczynamy przejmować kontrolę nad swoim życiem, odrzucając tym samym opiekę Boga. Jeśli codziennie nie podejmiemy decyzji o poddaniu swojego życia opiece naszej Sile Wyższej, może nas przytłoczyć lęk przed życiem. Dzięki pracy nad Dwunastoma Krokami odkryliśmy, że wiara w Siłę większą od nas samych pomaga uciszyć ten lęk. Im bardziej zbliżamy się do kochającego Boga, tym bardziej stajemy się świadomi naszej Siły Wyższej. A im bardziej świadomi jesteśmy opieki, jaką Bóg roztacza nad nami, tym mniejszy staje się nasz lęk. Gdy czujemy się wystraszeni, zadajemy sobie pytanie: „Czy ten lęk oznacza brak wiary w moim życiu? Czy znowu zacząłem kontrolować swoje życie tylko po to, aby kolejny raz przekonać się, że sam nie jestem w stanie nad nim zapanować?\" Jeśli odpowiedź na te pytania jest twierdząca, to, ponownie powierzając naszą wolę i życie opiece Boga, jakkolwiek Go pojmujemy, możemy pozbyć się tego lęku.', 'Zdam się na opiekę mojej Siły Wyższej, aby uwolnić się od lęku przed życiem'),
(16, '01-16', '16 stycznia', 'Zadzwoń!', NULL, '„Baliśmy się tego, że jeśli kiedykolwiek ujawnilibyśmy się tacy jacy naprawdę jesteśmy, to na pewno zostalibyśmy odrzuceni...(Lecz) nasi przyjaciele ze wspólnoty okazują nam zrozumienie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPotrzebujemy naszych przyjaciół ze wspólnoty NA, ich doświadczenia, przyjaźni, śmiechu, ich przewodnictwa i wielu, wielu innych rzeczy. A jednak znaczna cześć spośród nas waha się zadzwonić do swojego sponsora lub odwiedzić przyjaciela z NA. Nie chcemy się im narzucać. Chcemy do kogoś zadzwonić, ale nie czujemy się warci czyjegoś czasu. Boimy się, że gdy tylko nas poznają takimi, jakimi naprawdę jesteśmy, to z pewnością nas odrzucą. Zapominamy, że nasi przyjaciele ze wspólnoty NA są po prostu tacy sami jak my. Nie ma rzeczy, której byśmy nie zrobili, miejsca, w którym byśmy nie byli, uczucia, którego byśmy nie doświadczyli, z którym inni zdrowiejący uzależnieni nie mogliby się zidentyfikować. Im bardziej pozwalamy innym, aby nas poznali, tym częściej słyszymy: „Jesteś we właściwym miejscu. Jesteś wśród przyjaciół. Tu jest twoje miejsce. Witaj!\" Zapominamy także o tym, że inni potrzebują nas tak samo jak my ich. Nie jesteśmy jedynymi, którzy chcą gdzieś przynależeć, którzy pragną doświadczać ciepła przyjaźni i chcą mieć z kim się dzielić. Jeśli izolujemy się od naszych przyjaciół ze wspólnoty, pozbawiamy ich czegoś, czego oni potrzebują, czegoś, co tylko my możemy im dać: naszego czasu, naszego towarzystwa i nas samych, takich, jakimi naprawdę jesteśmy. We wspólnocie Anonimowych Narkomanów zdrowiejący uzależnieni troszczą się o siebie nawzajem. A po drugiej stronie linii telefonicznej nie czeka nas odrzucenie, lecz miłość, ciepło i identyfikacja Wspólnoty NA. Zadzwoń!', 'W NA jestem wśród przyjaciół. Wyciągnę rękę do innych, dając i przyjmując to, co może dać wspólnota.'),
(17, '01-17', '17 stycznia', 'Przebaczenie', NULL, '„W miarę uświadamiania sobie faktu, że potrzebujemy wybaczenia, sami zaczynamy bardziej wybaczać. Wiemy przynajmniej, że zdrowiejąc, nie zamierzamy już dłużej niszczyć ludziom życia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy braliśmy, często traktowaliśmy innych ludzi źle, czasami umyślnie szukając sposobów, aby ich unieszczęśliwić. Być może, zdrowiejąc, nadal mamy tendencję do oceniania innych, ponieważ wydaje nam się, że wiemy jak ta lub inna osoba powinna się zachować. Lecz w miarę naszego zdrowienia okazuje się, że aby zaakceptować siebie, musimy zaakceptować otaczających nas ludzi. Czasem trudno jest patrzeć jak uwidacznia się czyjeś szaleństwo. Jeśli jednak przestaniemy skupiać się tylko i wyłącznie na problemie, będziemy mogli zająć się jego rozwiązaniem. Jeśli zaś czujemy się dotknięci uczynkami innych ludzi, możemy zastosować zasadę wybaczania. ', 'Będę dążyć do tego, aby raczej wybaczać niż szukać wybaczenia. Postaram się postępować w taki sposób, abym czuł się godny własnej miłości.'),
(18, '01-18', '18 stycznia', 'Prosty obrachunek', NULL, '„Kontynuując obrachunek osobisty, wyrabiamy w sobie nawyk przyglądania się w sposób usystematyzowany swoim działaniom, postawom oraz związkom z ludźmi.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCodzienny obrachunek jest narzędziem, przy pomocy którego możemy uprościć swoje życie. Najtrudniejszą sprawą w prowadzeniu regularnego obrachunku może okazać się decyzja o tym, jak go rozpocząć. Czy powinniśmy go robić pisemnie? Co powinniśmy poddać analizie? Jak bardzo szczegółowo? Jak się mamy zorientować, czy zrobiliśmy już wszystko, co trzeba? Niepostrzeżenie proste ćwiczenie zamienia się w poważny projekt. Oto jeden prosty przykład codziennego obrachunku. Przeznaczmy kilka minut pod koniec każdego dnia, aby usiąść spokojnie i podsumować nasze uczucia. Czy czujemy jakiś ucisk w żołądku? Czy jesteśmy niezadowoleni z dnia, który właśnie się kończy? Co się wydarzyło? Jaki był nasz udział w tej sprawie? Czy powinniśmy w związku z tym coś naprawić? Co zmienilibyśmy w swoim postępowaniu, gdybyśmy mogli cofnąć czas? W codziennym obrachunku chcemy również uwzględnić pozytywne aspekty naszego życia. Co dzisiaj sprawiło mi satysfakcję? Czy zrobiłem coś pożytecznego? Czy byłem odpowiedzialny? Uprzejmy? Kochający? Czy w pełni doświadczyłem miłości i dobroci w tym, co przyniósł mi dzień? Co dzisiaj zrobiłem takiego, co chciałbym zrobić ponownie? Aby nasz codzienny obrachunek był skuteczny, nie musi być wcale skomplikowany. Jest to bardzo proste narzędzie, które możemy wykorzystać do tego, aby pozostawać w codziennym kontakcie z samym sobą.', 'Chcę być świadomym tego, co czuję, żyjąc życiem, które zostało mi dane. Pod koniec dzisiejszego dnia zrobię zwięzły i prosty obrachunek.'),
(19, '01-19', '19 stycznia', 'Wyolbrzymianie', NULL, '„Gdy przestajemy żyć tu i teraz, nasze problemy zaczynają się bezzasadnie rozrastać.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNiektórzy spośród nas mają tendencję do wyolbrzymiania swoich problemów. Nawet tym, którzy w jakimś stopniu odnaleźli już pogodę ducha, zdarzyło się kiedyś w okresie zdrowienia rozdmuchać jakiś problem niewspółmiernie do rzeczywistej sytuacji - a jeśli jeszcze tak nie postąpiliśmy, z pewnością niedługo to nastąpi! Gdy przyłapiemy się na obsesyjnym przejmowaniu się jakąś trudnością życiową, dobrze zrobi nam, jeśli przypomnimy sobie dokładnie o wszystkim, co nam się układa dobrze. Być może obawiamy się, że nie zdołamy zapłacić rachunków w tym miesiącu. Zamiast więc siedzieć nad kalkulatorem, przeliczając w kółko te same sumy, możemy zastanowić się jak obniżyć nasze wydatki. Przestrzegając tego mini-podsumowania, zaczynamy realizować bieżące zadania, pamiętając o tym, że dopóki nie stoimy w miejscu, nasza kochająca Siła Wyższa będzie opiekować się naszym życiem. Poważne problemy zdarzają się raz na jakiś czas, ale nie musimy ich sobie stwarzać. Zaufanie do kochającego Boga, jakkolwiek Go pojmujemy, pozwoli nam zobaczyć nasze problemy w ich prawdziwym wymiarze. Nie musimy już dłużej stwarzać wokół siebie chaosu, aby poczuć, że nasze życie jest ekscytujące. Zdrowienie przyniesie nam niezliczoną ilość prawdziwie życiowych powodów do podnieceń i głębokich przeżyć. ', 'Spojrzę realnie na moje problemy i zobaczę, że w większości są one nieznaczne. Przestanę się nimi przejmować i będę cieszył się zdrowieniem.'),
(20, '01-20', '20 stycznia', 'Jedna obietnica, wiele darów', NULL, 'Wspólnota Anonimowych Narkomanów daje tylko jedną obietnicę - wolność od czynnego uzależnienia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWyobraźmy sobie jakby to było, gdybyśmy przyszli na swój pierwszy mityng NA zdesperowani, z chęcią zaprzestania brania, a zaserwowano by nam następującą reklamę: „Jeżeli tylko będziesz przerabiać kroki i nie będziesz zażywać narkotyków, to ożenisz się, będziesz miał domek na przedmieściu, dwójkę lub szóstkę dzieci i zaczniesz nosić porządne ubrania. Staniesz się odpowiedzialnym, pożytecznym członkiem społeczeństwa i będziesz obracał się w wyższych sferach. Będziesz bogaty i zrobisz błyskotliwą karierę”. Większość z nas powitana taką bajerą szybko zawróciłaby w stronę drzwi i uciekła. Zamiast tego typu wierutnych bzdur i odstraszających wizji przyszłości otrzymujemy na powitanie obietnicę nadziei - nadziei na wolność od czynnego uzależnienia. Gdy słyszymy, że już nigdy więcej nie musimy brać, czujemy jak spływa na nas upragniona ulga. Nikt nas nie zmusza, abyśmy się do czegokolwiek dostosowali. A po pewnym czasie zdrowienia zaczynają nam się przydarzać dobre rzeczy. Dostajemy różne dary – dary duchowe, dary materialne, dary, o których zawsze marzyliśmy, ale nigdy nie ośmieliliśmy się mieć nadziei, że kiedykolwiek je otrzymamy. Są to jednak prawdziwe dary i nie obiecano ich nam tylko dlatego, że zostaliśmy członkami NA. Jedyne, co nam obiecano, to wolność od uzależnienia - i jest to bardziej niż wystarczające!', 'Obiecano mi wolność od czynnego uzależnienia. Dary, które otrzymuje są owocami mojego zdrowienia.'),
(21, '01-21', '21 stycznia', 'Jedność a jednolitość', NULL, '„Jedność jest czymś, co musi istnieć w NA.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJedność, to nie to samo co jednolitość. Jedność wynika z faktu, że łączy nas jeden wspólny cel - zdrowienie i pomoc innym w utrzymywaniu czystości. Jednak często widzimy, że chociaż dążymy do tego samego celu, to środki i metody, którymi próbujemy go osiągnąć, mogą być zdecydowanie różne. Nie możemy narzucać innym naszego poglądu na temat jedności ani mylić jedności z ujednoliceniem. W rzeczywistości, dużą zaletą programu NA jest brak jednolitości. Jedność wynika z naszego wspólnego celu, a nie z norm narzuconych grupie przez kilku, mających dobre intencje, członków grupy. Grupa, której jedność pochodzi z miłości wypełniającej serca jej członków, pozwala każdemu uzależnionemu nieść posłanie na jego lub jej własny niepowtarzalny sposób. W naszych wzajemnych relacjach w NA często dochodzi do głośnych sporów. Musimy pamiętać, że dopóki koncentrujemy się na głównym celu grupy szczegóły tego, jak załatwiamy daną sprawę nie są aż tak ważne. Widzimy, że ci sami ludzie, którzy kłócili się zawzięcie z powodu jakiejś błahostki, jednoczą się, gdy nowoprzybyły potrzebuje pomocy. Gdy po raz pierwszy zjawiliśmy się na mityngu, ktoś na nas czekał. Teraz nadchodzi nasza kolej, aby zająć ich miejsce i służyć innym. Potrzebujemy jedności, ponieważ pomaga ona nam pokazać nowoprzybyłemu, że ten sposób życia działa.', 'Będę dążyć do tego, aby być częścią jedności. Wiem, że jedność to nie to samo co jednolitość.'),
(22, '01-22', '22 stycznia', 'Szkoła zdrowienia', NULL, '„Jest to program uczenia się.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNauka zdrowienia jest ciężką pracą. Często najtrudniej jest nauczyć się rzeczy, których najbardziej potrzebujemy. Uczymy się zdrowienia, aby przygotować się do przyjęcia doświadczeń, które szykuje nam życie. Słuchając na mityngach dzielenia się innych, odnotowujmy w myślach to, do czego będziemy mogli się odnieść w przyszłości. Aby być gotowi, studiujemy pomiędzy „lekcjami” swoje notatki i literaturę. Tak jak studenci mają okazję sprawdzić swoją wiedzę podczas testu, tak samo i my możemy przekonać się o stanie naszego zdrowienia w chwili kryzysu. Jak zwykle, mamy możliwość wyboru sposobu, w jaki odpowiemy na życiowe wyzwania. Możemy się ich bać i unikać jako potencjalnego zagrożenia dla naszego spokoju, ale możemy też z wdzięcznością uznać je za okazje do rozwoju. Życiowe wyzwania dodają nam coraz więcej siły, potwierdzając zasady, które poznaliśmy dzięki zdrowieniu. Pozbawieni tych wyzwań moglibyśmy zapomnieć, czego się nauczyliśmy i popaść w stagnację. Są to okazje, które mobilizują nas do duchowego przebudzenia. Zauważymy, że po każdym kryzysie następują okresy odpoczynku, dzięki którym mamy czas, aby oswoić się z naszymi nowymi umiejętnościami. Po przeanalizowaniu naszych doświadczeń powinniśmy podzielić się swoją wiedzą z kimś, kto jeszcze uczy się tego, czego myśmy się już nauczyli. W szkole zdrowienia wszyscy jesteśmy zarówno nauczycielami, jak i uczniami.', 'Będę uczył się zdrowienia. Wyjdę naprzeciw życiowym wyzwaniom, będąc pewnym tego, czego się nauczyłem i gotów do podzielenia się tym z innymi.'),
(23, '01-23', '23 stycznia', 'Zachowanie pogody ducha', NULL, '„Brak codziennego oparcia może objawiać się na wiele różnych sposobów.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy zdarzyło się wam kiedykolwiek skwitować czyjś zachwyt nad ładną pogodą po prostu krótkim stwierdzeniem: „Jest paskudnie\"? Gdy tak się zachowujemy, prawdopodobnie cierpimy na brak codziennego oparcia w naszym programie. W zdrowieniu życie może stać się bardzo gorączkowe. Być może dodatkowe obowiązki w pracy doprowadzają was do wściekłości. Może przez jakiś czas nie byliście na mityngu. Może byliście zbyt zajęci, aby znaleźć czas na medytację, a może zaniedbaliście regularny posiłek lub nie wyspaliście się dobrze. Jakikolwiek byłby to powód, wasza pogoda ducha została osłabiona. Gdy tak się dzieje, to powinniśmy jak najszybciej zacząć działać. Nie możemy pozwolić, aby jeden „zły dzień” zakończony złą postawą rozciągnął się na dwa lub trzy kolejne dni, lub na cały tydzień. Od tego, czy codziennie opieramy się na programie zależy nasze zdrowienie. Bez względu na to, co spotyka nas w życiu, nie możemy pozwolić sobie na lekceważenie zasad, które uratowały nam życie. Istnieje wiele sposobów na to, aby odzyskać pokój ducha. Możemy pójść na mityng, zatelefonować do sponsora, spotkać się przy kawie z innym zdrowiejącym uzależnionym lub spróbować nieść posłanie nowoprzybyłemu. Możemy się modlić. Możemy znaleźć chwilę, aby zadać sobie pytanie, jakich prostych rzeczy jeszcze nie zrobiliśmy. Gdy nasza postawa prowadzi nas do upadku, możemy zapobiec tragedii, używając bardzo prostych rozwiązań.', 'Przyjrzę się temu, na czym opieram swój codzienny program zdrowienia..'),
(24, '01-24', '24 stycznia', 'Od izolacji do więzi', NULL, '„Nasza choroba wpędziła nas w izolację.... Wrogo usposobieni, urażeni, egocentryczni i samolubni odcięliśmy się od świata zewnętrznego.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nUzależnienie jest chorobą, która izoluje nas od społeczeństwa, rodziny i samych siebie. Ukrywaliśmy się. Kłamaliśmy. Gardziliśmy tym, jak żyją inni ludzie, ponieważ dla nas było to nieosiągalne. A co najgorsze, wmawialiśmy sobie, że wszystko jest w porządku, mimo świadomości tego, że jesteśmy poważnie chorzy. Nasz kontakt ze światem i rzeczywistością był zerwany. Życie straciło dla nas sens i coraz bardziej oddalaliśmy się od rzeczywistości. Program NA jest przeznaczony właśnie dla takich ludzi, jak my. Wyrywając nas z izolacji, pomaga nam odzyskać kontakt z życiem, jakie dane jest nam przeżyć. Przestajemy oszukiwać samych siebie co do stanu, w jakim się znajdujemy, uznajemy swoją bezsilność i nieumiejętność kierowania własnym życiem. Rozwijamy w sobie wiarę w to, że nasze życie może się zmienić na lepsze, że zdrowienie jest możliwe, i że szczęście jest osiągalne. Stajemy się uczciwi, przestajemy ukrywać się, „demaskujemy się i mówimy prawdę”, jaka by ona nie była. Robiąc to, umacniamy więzi, które łączą nasze osobiste życie z otaczającym nas światem. My, uzależnieni, nie powinniśmy żyć w izolacji. Dwanaście Kroków może odbudować naszą więź z życiem i ze światem - jeśli będziemy nad nimi pracować.', 'Jestem częścią otaczającego mnie świata. Będę praktykował mój program, by wzmocnić swoją więź ze światem.'),
(25, '01-25', '25 stycznia', 'Dodatkowy dar', NULL, '„Widzimy jak to się dzieje wokół nas codziennie. Ta zadziwiająca zmiana jest dowodem duchowego przebudzenia.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nObserwujemy ich, jak przychodzą pokonani na swój pierwszy mityng ze zniszczoną sferą duchową. Ich cierpienie jest oczywiste, a pragnienie otrzymania pomocy jeszcze bardziej widoczne. Odbierają swój powitalny breloczek i wstrząśnięci tym wysiłkiem wracają na miejsce. Potem widzimy ich znowu i wydają się być nieco bardziej zrelaksowani. Znaleźli sponsora i codziennie uczęszczają na mityngi. Nadal unikają naszego spojrzenia, ale potakują głowami, rozpoznając w tym, co mówimy swoją historię. W ich oczach widać przebłysk nadziei, a gdy zachęcamy ich, aby przychodzili tu znowu, uśmiechają się niepewnie. Kilka miesięcy później stoją już na pewniejszym gruncie. Nauczyli się patrzeć prosto w oczy. Pracują nad krokami ze swoim sponsorem i dzięki temu zdrowieją. Słuchamy ich, jak dzielą się na mityngach, a po mityngu razem ustawiamy krzesła. Kilka lat później są spikerami w czasie warsztatów na zlotach. Zyskali wspaniałą, pogodną i wesołą osobowość. Uśmiechają się na nasz widok, obejmują nas i mówią, że nigdy by tego nie osiągnęli bez nas. Rozumieją też, gdy odpowiadamy im: „jak również i my bez ciebie”.', 'Odnajdę radość w byciu świadkiem zdrowienia innych.'),
(26, '01-26', '26 stycznia', 'Egocentryzm', NULL, '„Duchową częścią naszej choroby jest całkowity egocentryzm.\"   \r\n\r\n~Tekst Podstawowy \r\n\r\nCzym jest egocentryzm? Jest wiarą w to, że świat kręci się wokół nas. Naszej uwagi warte są wyłącznie nasze życzenia i nasze potrzeby. Nasz egocentryczny umysł wierzy, że jeśli tylko pozwoli się mu na realizację jego własnych pomysłów, będzie w stanie osiągnąć wszystko, czego zapragnie. Egocentryzm zakłada całkowitą samowystarczalność. Mówimy, że egocentryzm jest duchową częścią naszej choroby, ponieważ egocentryczny umysł nie może wyobrazić sobie niczego większego lub ważniejszego od siebie samego. Istnieje jednak duchowy środek mogący zaradzić naszej duchowej chorobie: Dwanaście Kroków Anonimowych Narkomanów. Kroki te uwalniają nas od egocentryzmu i pomagają skupić się na Bogu. Poprzez uznanie własnej bezsilności i poszukiwanie wsparcia u Siły większej, niż nasza własna, pozbywamy się złudzeń dotyczących naszej samowystarczalności. Przyznając się do błędów, naprawiając szkody i szukając wiedzy o tym, co dobrego pochodzi od Boga, jakkolwiek Go pojmujemy, uznajemy, że nasze zadufanie w sobie jest bezzasadne. Służąc innym, a nie tylko sobie samemu, jakby spuszczamy powietrze z przytłaczającego nas poczucia zarozumiałości. Dręczący naszą duszę egocentryzm może zostać wyleczony przy pomocy duchowego środka, którym jest Dwanaście Kroków. ', 'Moje przewodnictwo i moja siła pochodzą od Siły Wyższej, a nie ode mnie samego. Będę praktykować Dwanaście Kroków, aby stać się bardziej skoncentrowanym na Bogu, niż na samym sobie'),
(27, '01-27', '27 stycznia', 'Uczyć się żyć od nowa', NULL, ',,Uczymy się nowych sposobów życia. Nasze stare poglądy już nas nie ograniczają.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nByć może w dzieciństwie uczono nas, lub nie uczono, odróżniać dobro od zła, jak też innych podstawowych zasad życia. Bez względu na to, większość z nas do czasu rozpoczęcia zdrowienia miała bardzo niejasne pojęcie o tym, jak żyć. Izolacja od reszty społeczeństwa przyczyniła się do tego, że ignorowaliśmy podstawowe ludzkie obowiązki i rozwinęliśmy w sobie dziwaczne zdolności mające ułatwić nam radzenie sobie z otaczającym nas światem. Niektórzy spośród nas nie umieli mówić prawdy, inni byli tak szczerzy, że ranili każdego, z kim rozmawiali. Jedni nie potrafili dać sobie rady z najprostszymi komplikacjami w życiu osobistym, drudzy zaś starali się rozwiązać problemy całego świata. Niektórzy nigdy się nie złościli, nawet będąc nieuczciwie traktowani, inni nie ustawali w obwinianiu wszystkiego i wszystkich poza sobą samym. Bez względu na to, jak wielkie byłyby nasze problemy, we wspólnocie Anonimowych Narkomanów wszyscy mamy szansę nauczyć się żyć od nowa. Może musimy nauczyć się uprzejmości i tego, jak troszczyć się o innych. Może musimy zaakceptować własną odpowiedzialność. A może musimy przezwyciężyć strach i podjąć jakieś ryzyko. Jednego możemy być pewni: każdego dnia, po prostu żyjąc swoim życiem, uczymy się czegoś nowego.', 'Teraz wiem więcej o tym jak żyć, niż wiedziałem wczoraj, ale nie tak dużo jak będę wiedział jutro. Dzisiaj nauczę się czegoś nowego.'),
(28, '01-28', '28 stycznia', 'Uzależniony na zawsze', NULL, ',,Nigdy w pełni nie wyzdrowiejemy, niezależnie od tego, jak długo jesteśmy czyści.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPo pewnym czasie pracy nad programem niektórym z nas zaczyna się wydawać, że jesteśmy już wyleczeni. Nauczyliśmy się wszystkiego, czego NA mogło nas nauczyć; znudziliśmy się mityngami, a nasz sponsor w kółko powtarza to samo: „kroki - kroki - KROKI!\" Uznajemy, że nadszedł czas, aby zabrać się za swoje życie, ograniczyć chodzenie mityngi i spróbować nadrobić stracone na czynnym uzależnieniu lata. Postępując tak, narażamy swoje zdrowienie. Ci spośród nas, którzy po takich próbach zaliczyli wpadkę, często starają się uczęszczać na tyle mityngów, na ile tylko mogą - niektórzy nie opuszczają żadnego mityngu przez kilka lat. Zrozumienie tego, że zawsze będziemy uzależnieni może zająć nam wiele czasu. Jednego dnia możemy czuć się świetnie, a innego bardzo źle, lecz codziennie jesteśmy uzależnieni. Wciąż ulegamy złudzeniom, zaprzeczeniom, racjonalizacjom, wymówkom, szaleństwu - wszystkim tym typowym dla osoby uzależnionej sposobom myślenia. Jeśli chcemy żyć i cieszyć się życiem bez zażywania narkotyków, musimy codziennie aktywnie pracować nad programem zdrowienia.', 'Jestem uzależniony każdego dnia, lecz dzisiaj mam możliwość bycia zdrowiejącym uzależnionym. Dokonuję takiego wyboru, pracując nad programem.'),
(29, '01-29', '29 stycznia', 'Pierwszy krok - krok działania', NULL, ',,Czy rozumiemy, że nie mamy i mieć nie możemy żadnej kontroli nad narkotykami?\"\r\n\r\n~Tekst Podstawowy  \r\n\r\nPoczątkowo wielu z nas myślało, że Pierwszy Krok nie wymaga działania - po prostu poddajemy się i przechodzimy do Kroku Drugiego. Jednakże Krok Pierwszy wymaga działania!  Działania, które podejmiemy w związku z Krokiem Pierwszym, będą widoczne w sposobie naszego życia, począwszy od naszego pierwszego dnia czystości. Jeśli naprawdę wierzymy, że jesteśmy bezsilni wobec naszego uzależnienia, będziemy unikać przebywania w pobliżu narkotyków. Jeśli nadal dzielimy życie lub zadajemy się z czynnie uzależnionymi ludźmi, wskazuje to na to, że w naszym programie jest jakaś luka. Absolutna przekonanie, że Krok Pierwszy nas dotyczy, wyraża się w tym, że usuwamy z domu wszelkie narkotyki i akcesoria z nimi związane.  Z upływem czasu nie tylko kontynuujemy wykonywanie podstawowych czynności związanych z Krokiem Pierwszym, ale także dodajemy nowe rzeczy do jego repertuaru. Zamiast próbować kontrolować swoje uczucia nauczymy się je przeżywać. Zaniechamy prób zostania swoimi własnymi przewodnikami i jedynymi autorytetami w zdrowieniu; przestaniemy być sami sobie sponsorami. Aby zaznać duchowego spełnienia, zaczniemy coraz intensywniej szukać Siły większej, niż nasza własna, zamiast próbować wypełnić tę pustkę czymkolwiek innym.  Poddanie się jest dopiero początkiem. Gdy już poddaliśmy się, musimy teraz nauczyć się żyć w spokoju, który odkryliśmy.', 'Podejmę wszelkie niezbędne działania związane z Krokiem Pierwszym. Naprawdę wierzę w to, że muszę to zrobić.'),
(30, '01-30', '30 stycznia', 'Oddawanie', NULL, '„Powinniśmy dobrowolnie i z wdzięczności dawać to, co dobrowolnie i z wdzięcznością dano nam.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW zdrowieniu otrzymujemy wiele darów. Być może jednym z największych darów jest duchowe przebudzenie, które zaczyna się wtedy, gdy przestajemy brać, i które z każdym dniem umacnia się poprzez stosowanie w naszym życiu kroków. Nowa iskierka życia wewnętrznego jest bezpośrednim rezultatem naszej nowej relacji z Siłą Wyższą, relacji zainicjowanej i rozwijającej się dzięki życiu według Dwunastu Kroków. Powoli, w miarę realizacji naszego programu, blask zdrowienia rozwiewa mroki naszej choroby. Jednym ze sposobów okazywania wdzięczności za dary zdrowienia jest pomoc innym w odnalezieniu tego, co sami znaleźliśmy. Możemy robić to na wiele sposobów: dzieląc się doświadczeniem na mityngach, wykonując „dwunastokrokowe” telefony, podejmując się sponsorowania, będąc wolontariuszem w H&I lub pełniąc dyżury w telefonie zaufania. Życie duchowe, dane nam w zdrowieniu, potrzebuje uzewnętrznienia się, ponieważ „możemy zachować to, co mamy, jedynie poprzez dzielenie się tym z innymi.”', 'Dar zdrowienia wzrasta, gdy się nim dzielę. Znajdę kogoś, z kim się nim podzielę.'),
(31, '01-31', '31 stycznia', 'Zaufanie', NULL, '„Właśnie dzisiaj zaufam komuś z NA, komuś, kto we mnie wierzy i chce mi pomóc w moim zdrowieniu.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNauka zaufania, to ryzykowna sprawa. Nasze dotychczasowe doświadczenia, jako czynnie uzależnionych osób, nauczyły nas, że naszym kumplom nie należy ufać. Nie mogliśmy zaufać nawet samym sobie. Teraz, gdy zdrowiejemy, zaufanie jest wręcz niezbędne. Potrzebujemy czegoś, na czym możemy polegać, w co możemy wierzyć i co da nam nadzieję w naszym zdrowieniu. Dla niektórych z nas pierwszą rzeczą, której jesteśmy w stanie zaufać, są słowa innych uzależnionych, dzielących się na mityngach; wyczuwamy w ich słowach prawdę. Znalezienie kogoś, komu możemy zaufać, ułatwia nam proszenie o pomoc. I w miarę wzrostu naszego zaufania do ich zdrowienia, uczymy się ufać samym sobie.', 'Podejmę decyzję, aby komuś zaufać. Będę działać zgodnie z tym zaufaniem.'),
(32, '02-01', '1 lutego', 'Trudności', NULL, '„Czuliśmy się inni.... Dopiero po tym, jak poddamy się, jesteśmy w stanie przezwyciężyć alienację uzależnienia.” \r\n\r\n~Tekst Podstawowy  „\r\n\r\nTy tego nie rozumiesz!” – parskaliśmy, próbując się w ten sposób ukryć. „Ja jestem inny! Mnie naprawdę jest ciężko!”. Kiedy braliśmy, wciąż używaliśmy tych zwrotów, chcąc uniknąć konsekwencji swojego uzależnienia lub obejść powszechnie obowiązujące zasady. Być może wykrzyczeliśmy to na naszym pierwszym mityngu. A może całkiem niedawno przyłapaliśmy się na używaniu tych zwrotów. Jakżeż wielu z nas ma poczucie odmienności i wyjątkowości. Jako uzależnieni potrafimy użyć wszelkich sposobów, aby się odizolować. Nic jednak nie usprawiedliwia rezygnacji ze zdrowienia, nie ma niczego, co sprawiałoby, że nie nadajemy się do programu - ani śmiertelna choroba, ani bieda, ani nic innego. Tysiące uzależnionych odnalazło zdrowienie, pomimo prawdziwych problemów, którym musieli stawić czoła. Dzięki pracy nad programem wzrosła ich duchowa świadomość - pomimo trudności, a może właśnie w wyniku tych trudności. W kwestii zdrowienia nasze osobiste uwarunkowania i różnice nie mają znaczenia. Kiedy przestaniemy obstawać przy swojej wyjątkowości i poddamy się tej prostej drodze życia, na pewno odkryjemy, że czujemy się częścią czegoś większego. I to poczucie przynależności daje nam siłę, aby iść przez życie, pokonując napotykane trudności.', 'Przestanę uważać się za kogoś wyjątkowego i zaakceptuję wspólne dla wszystkich zasady zdrowienia. Moje problemy nie wykluczają mnie ze zdrowienia, a wręcz przeciwnie - wciągają mnie w nie.');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(33, '02-02', '2 lutego', 'Dobra wola', NULL, '„Dobra wola najlepiej wyraża się w służbie; dobra służba, to robienie właściwych rzeczy z właściwych powodów.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nDuchowym rdzeniem naszej choroby jest egocentryzm. Jedynym motywem postępowania w kontaktach z ludźmi, jakiego nauczyło nas uzależnienie, był egoizm - chcieliśmy mieć to, czego właśnie chcieliśmy i wtedy, kiedy tego chcieliśmy. Obsesja na własnym punkcie była głęboko zakorzeniona w naszym życiu. Jak więc w zdrowieniu możemy wykorzenić tę auto-obsesję? Przeciwstawiamy się przejawom naszej choroby, stosując kilka bardzo prostych zasad duchowych. Aby przeciwdziałać egocentryzmowi naszego uzależnienia, uczymy się stosować zasadę dobrej woli. Zamiast służyć tylko sobie samemu, zaczynamy służyć innym. Zamiast myśleć o tym, co możemy zdobyć w danej sytuacji, myślimy najpierw o tym, co jest dobre dla innych. Gdy stajemy przed moralnym wyborem, uczymy się tego, by przed podjęciem odpowiednich działań zrobić pauzę na odwołanie się do zasad duchowych. Kiedy zaczynamy „robić właściwe rzeczy z właściwych powodów”, możemy odkryć zachodzące w nas zmiany. Tam, gdzie wcześniej kierowała nami samowola, teraz kieruje nami dobra wola ukierunkowana na innych. Chroniczny egocentryzm uzależnienia traci swą władzę nad nami. Uczymy się „stosować te zasady we wszystkich naszych poczynaniach”; żyjemy naszym zdrowieniem, a nie naszą chorobą. ', 'Gdziekolwiek jestem, cokolwiek robię, będę starał się służyć innym, a nie tylko samemu sobie. Kiedy zetknę się z jakimś dylematem, spróbuję robić właściwe rzeczy z właściwych powodów.'),
(34, '02-03', '3 lutego', ' Potrzebujemy siebie nawzajem', NULL, '„Dołączyć do nas może każdy, bez względu na wiek, rasę, orientację seksualną, przynależność religijną lub jej brak.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nUzależnienie sprawiało, że byliśmy zamknięci na wszystko, co było nowe lub inne. Myśleliśmy, że nie potrzebujemy nikogo ani niczego. Nie odnajdywaliśmy niczego wartościowego w ludziach z innego środowiska, innej rasy, innego pochodzenia etnicznego, z innej klasy społecznej lub ekonomicznej. Być może uważaliśmy, że jeżeli coś jest inne, to znaczy, że jest gorsze. Zdrowiejąc, nie możemy sobie pozwolić na takie postawy. Przyszliśmy do NA, ponieważ nasze pomysły zaprowadziły nas donikąd. Jeżeli chcemy wzrastać w zdrowieniu, musimy otworzyć nasz umysły na te doświadczenia, które działają, nie patrząc na ich źródła. Bez względu na nasze osobiste życiowe okoliczności, wszystkich nas łączą w NA dwie rzeczy, których nie dzielimy z nikim innym: nasza choroba i nasze zdrowienie. Jesteśmy zależni od siebie nawzajem ze względu na doświadczenie, którym się dzielimy - im bardziej różnorodne są te doświadczenia, tym lepiej. Abyśmy mogli stawić czoła wyzwaniom, jakie niesie ze sobą życie w czystości, potrzebna jest nam każda cząstka doświadczenia, wiele różnych spojrzeń na nasz program. Zdrowienie, często, nie jest łatwe. Siłę potrzebną nam do zdrowienia często czerpiemy od innych członków NA. Dzisiaj, jesteśmy wdzięczni za różnorodność członków naszej grupy, ponieważ z tej różnorodności czerpiemy siłę.', 'Wiem, że im bardziej różnorodne są doświadczenia mojej grupy, tym więcej wsparcia będzie ona potrafiła zaoferować mi w różnych życiowych sytuacjach, którym będę musiał stawić czoła. Dzisiaj, na mojej grupie domowej wszyscy uzależnieni, bez względu na ich pochodzenie, będą przeze mnie mile widziani.'),
(35, '02-04', '4 lutego', 'Dobre samopoczucie nie jest najważniejsze', NULL, '„Dla nas zdrowienie jest czymś więcej, niż tylko przyjemnością.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy braliśmy, większość z nas dokładnie wiedziała, jak się będzie czuć z dnia na dzień. Wystarczyło przeczytać etykietkę na butelce lub wiedzieć co było w torebce. Planowaliśmy nasze uczucia i naszym codziennym celem było osiągnięcie dobrego samopoczucia. Zdrowiejąc, możemy z dnia na dzień, a nawet z minuty na minutę, odczuwać całą gamę różnorodnych uczuć. Rano możemy czuć się energiczni i szczęśliwi, a po południu niespodziewanie ogarnia nas przygnębienie i smutek. Ponieważ nie planujemy już codziennie rano naszych uczuć na cały dzień, mogą ogarniać nas dość uciążliwe odczucia, takie jak poranne zmęczenie lub bezsenność. Oczywiście, zawsze istnieje jakiś sposób na to, aby poczuć się dobrze, ale nie o to przecież chodzi. Dzisiaj, naszym głównym zadaniem nie jest osiągnięcie dobrego samopoczucia, lecz nauczenie się rozumienia swoich uczuć i radzenia sobie z nimi, bez względu na to, jakie by one nie były. Robimy to, pracując nad krokami i dzieląc się naszymi uczuciami z innymi.', 'Zaakceptuję moje uczucia, bez względu na to, jakie by one nie były, po prostu zaakceptuję je takimi, jakie są. Będę pracować nad programem i uczyć się żyć z moimi uczuciami.'),
(36, '02-05', '5 lutego', 'Wracaj dalej!', NULL, '„Jesteśmy wdzięczni, że zostaliśmy tak miło przyjęci na spotkaniach, że czuliśmy się komfortowo”. \r\n\r\n~Tekst podstawowy \r\n\r\nPamiętacie, jak bardzo się baliśmy, kiedy weszliśmy na nasze pierwsze spotkanie NA? Nawet jeśli szliśmy z przyjacielem, większość z nas pamięta, jak trudno było przyjść na to pierwsze spotkanie. Co nas skłoniło do powrotu? Większość z nas ma wdzięczne wspomnienia z powitania, jakie nas spotkało i tego, jak dobrze się dzięki temu czuliśmy. Kiedy podnieśliśmy rękę jako nowicjusz, otworzyliśmy drzwi innym członkom, aby podeszli do nas i powitali nas. Czasami różnica pomiędzy uzależnionymi, którzy wychodzą z pierwszego spotkania i nigdy nie wrócą do NA, a uzależnionymi, którzy zostają, aby szukać wyzdrowienia, polega na prostym uścisku członka NA. Kiedy przez jakiś czas jesteśmy czyści, łatwo jest wycofać się z procesji przybyszów — w końcu widzieliśmy tak wielu ludzi przychodzących i odchodzących. Ale członkowie, którzy mają trochę wolnego czasu, mogą sprawić różnicę między uzależnionym, który nie wraca, a uzależnionym, który wciąż wraca. Oferując nasze numery telefonów, uściski lub po prostu ciepłe powitanie, wyciągamy rękę Anonimowych Narkomanów do uzależnionego, który wciąż cierpi.', 'Pamiętam powitanie, jakie mnie spotkało, kiedy po raz pierwszy przyjechałem do NA. Dzisiaj wyrazę swoją wdzięczność, przytulając nową osobę.'),
(37, '02-06', '6 lutego', 'Ja nie mogę, ale my możemy', NULL, '„Wmówiliśmy sobie, że poradzimy sobie sami i prowadziliśmy nasze życie zgodnie z tym przekonaniem. Efekty tego były katastrofalne i w końcu każdy z nas musiał przyznać, że samowystarczalność jest kłamstwem.” \r\n\r\n~Tekst Podstawowy  \r\n\r\n„Ja nie mogę, ale my możemy.” Ta prosta, lecz głęboka prawda dotyczy naszej, jako członków NA, podstawowej potrzeby: razem, możemy pozostać czyści, lecz, izolując się, pozostajemy w złym towarzystwie. Aby zdrowieć, potrzebujemy wsparcia innych uzależnionych. Samowystarczalność hamuje nie tylko naszą zdolność do utrzymywania czystości. Z narkotykami czy bez nich, życie według samowoli nieuchronnie prowadzi do katastrofy. Jesteśmy zależni od innych ludzi pod każdym względem, począwszy od dóbr materialnych i różnych usług, aż po miłość i przyjaźń, a jednak nasza samowola wpędza nas w permanentny konflikt właśnie z tymi ludźmi. Aby prowadzić spełnione życie, musimy żyć z innymi ludźmi w zgodzie. Jesteśmy jednak zależni nie tylko od innych uzależnionych i innych ludzi z naszego otoczenia. Siła nie jest typowym atrybutem człowieka, a jednak potrzebujemy siły, aby żyć. Znajdujemy ją w Sile większej od nas samych, która wyposażana nas w brakujące nam przewodnictwo i siłę. Gdy stwarzamy pozory, że jesteśmy samowystarczalni, izolujemy się od źródła siły potrzebnej do efektywnego prowadzenia nas przez życie: naszej Siły Wyższej. Samowystarczalność nie działa. Potrzebujemy innych uzależnionych, potrzebujemy innych ludzi, i aby żyć pełnią życia, potrzebujemy Siły Większej od nas samych. ', 'Będę szukać wsparcia innych zdrowiejących uzależnionych, zgody z otaczającymi mnie ludźmi i opieki mojej Siły Wyższej. Ja nie mogę, ale my możemy.'),
(38, '02-07', '7 lutego', 'To nie jest test', NULL, '„... znaleźliśmy kochającego, osobowego Boga, do którego możemy się zwrócić”. ~Tekst Podstawowy  Niektórzy z nas, zaczynając swoje zdrowienie, mieli wrażenie, że życiowe trudności są serią testów stworzonych po to, aby nas czegoś nauczyć. Taki sposób myślenia ujawnia się, gdy przytrafia się nam coś bardzo przykrego, a my mówimy: „Moja Siła Wyższa mnie testuje!”. Jesteśmy przekonani, że gdy ktoś proponuje nam narkotyki, jest to testem naszego zdrowienia, a sytuacja, w której moglibyśmy zrobić coś wbrew zasadom, bez ryzyka zostania przyłapanym, jest testem naszego charakteru. Możemy nawet myśleć, że testem naszej wiary jest cierpienie z powodu jakiejś życiowej tragedii.  Lecz kochająca Siła Wyższa nie testuje naszego zdrowienia, charakteru lub wiary. To jest po prostu życie i czasem jest ono bolesne. Wielu z nas utraciło nie z własnej winy osoby, z którym łączyła nas miłość. Niektórzy spośród nas stracili całe bogactwo materialne. Niektórzy nawet stracili własne dzieci. Życie może być czasem ogromnie bolesne, lecz ból ten nie jest zsyłany nam przez naszą Siłę Wyższą. Ta siła jest raczej wciąż obok nas, gotowa nas nieść, gdy nie będziemy mogli iść o własnych siłach. Nie ma takiej krzywdy, którą może wyrządzić nam życie, a której Bóg, jakkolwiek go pojmujemy, nie mógłby uzdrowić.', 'Będę wierzył, że wola mojej Siły Wyższej jest dla mnie dobra i że jestem kochany. Będę szukał pomocy mojej Siły Wyższej w razie potrzeby.'),
(39, '02-08', '8 lutego', 'Kto to jest sponsor?', NULL, ' „… sponsor NA jest członkiem NA, który żyje programem zdrowienia, i który jest chętny do zbudowania z nami wyjątkowej, wspierającej, obustronnej relacji.” \r\n\r\n~IP 11\r\n\r\nKim jest sponsor? Wiemy: to ta miła osoba, z którą piliśmy kawę po naszym pierwszym mityngu. To ta szczodra dusza, która dzieli się zdrowieniem za darmo. Ten, który nas zadziwia niesamowitym wglądem w nasze wady charakteru. Ten, który nam przypomina o dokończeniu Czwartego Kroku, który słucha naszego Piątego Kroku, i który nie opowiada nikomu, jak bardzo jesteśmy dziwni. Bardzo łatwo jest zacząć przyjmować to wszystko jako coś, co nam się należy, ponieważ przyzwyczailiśmy się, że jest tu ktoś, kto jest do naszej dyspozycji. Może się zdarzyć, że przez jakiś czas będziemy zabiegani i będziemy sobie tłumaczyć: „zadzwonię do mojego sponsora później, teraz posprzątam dom, pójdę na zakupy, zagadnę tę atrakcyjną osobę…”. W końcu wpadamy w kłopoty i zdziwieni zastanawiamy się, w którym miejscu popełniliśmy błąd. Nasz sponsor nie czyta w myślach. To od nas zależy, czy wyciągniemy rękę po pomoc. Gdy potrzebujemy pomocy w pracy nad krokami lub realnego spojrzenia pomagającego nam w wyprostowaniu naszego pokrętnego sposobu myślenia, lub po prostu przyjaciela, do nas należy zwrócenie się z prośbą o to. Sponsorzy są pełnymi ciepła, mądrymi, cudownymi ludźmi i możemy bez ograniczeń czerpać z ich doświadczenia - jedyne, co musimy zrobić, to poprosić o to.', 'Jestem wdzięczny za czas, miłość i doświadczenie, którymi dzieli się ze mną mój sponsor. Dziś zadzwonię do mojego sponsora.'),
(40, '02-09', '9 lutego', ' Samoakceptacja', NULL, '„Gdy zaakceptujemy siebie, będziemy mogli również zaakceptować innych, bezwarunkowo, prawdopodobnie po raz pierwszy w życiu.\" \r\n\r\n~IP nr 19 \r\n\r\nSamoakceptacja  Wielu z nas, jak tylko sięgnie pamięcią, czuło się jakby nigdy do niczego nie przynależeli. Bez względu na to, jak wielka byłaby grupa otaczających nas osób, nigdy nie czuliśmy się jej częścią. Mieliśmy trudności z \"dopasowaniem się\". Byliśmy głęboko przekonani, że gdyby inni dowiedzieli się, jacy jesteśmy naprawdę, to odrzuciliby nas. Być może nasze uzależnienie zaczęło kiełkować właśnie w tej atmosferze egocentryzmu. Wielu z nas ukrywało ból alienacji pod postawą przekory. W efekcie mówiliśmy światu: „Nie potrzebujecie mnie? Cóż, ja was też nie potrzebuję. Mam swoje narkotyki i sam o siebie mogę zadbać!\" Im bardziej postępowało nasze uzależnienie, tym wyższe mury budowaliśmy wokół siebie. Te mury zaczęły opadać, kiedy odnaleźliśmy akceptację innych zdrowiejących uzależnionych. Wraz z akceptacją innych zaczynamy uczyć się ważnej zasady samoakceptacji. A gdy zaczynamy akceptować samych siebie, możemy zaprosić innych do swojego życia bez lęku przed odrzuceniem.', 'W NA jestem akceptowany; pasuję tutaj. Dzisiaj mogę bezpiecznie wpuścić innych do mojego życia.'),
(41, '02-10', '10 lutego', 'Przyjemność', NULL, '„W zdrowieniu zmienia się nasz stosunek do zabawy.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas, patrząc w przeszłość, uświadamia sobie, że w czasie czynnego uzależnienia nasze pojmowanie zabawy było dosyć dziwne. Niektórzy z nas stroili się i chodzili na dyskoteki. Tańczyliśmy, piliśmy alkohol i braliśmy inne narkotyki, aż do wschodu słońca. Przy byle okazji dochodziło do bójek. To, co wtedy nazywaliśmy zabawą, dziś nazywamy chorobą. Dzisiaj nasze wyobrażenie o zabawie zmieniło się. Obecnie przyjemność sprawia nam spacer nad morzem, rzeką lub jeziorem, w czasie którego obserwujemy łabędzie na tle zachodzącego słońca. Przyjemnością jest dla nas piknik NA lub prezentacja talentów w czasie konferencji NA. Przyjemność sprawia nam ubranie się elegancko, spożycie uroczystego posiłku i nie interesowanie się wybuchającymi bójkami i konfliktami. Dzięki łasce Siły Wyższej nasze wyobrażenie o tym, czym jest zabawa, zmieniło się zasadniczo. Jeśli dziś oglądamy wschód słońca, to przede wszystkim dlatego, że poprzedniego wieczoru poszliśmy dość wcześnie spać, a nie dlatego, że rano ze spuchniętymi oczami opuściliśmy dyskotekę po narkotycznej nocy. I nawet, gdyby było to jedyną rzeczą, którą otrzymaliśmy od NA, byłoby to wystarczające.', 'Odnajdę zabawę i radość w zdrowieniu!'),
(42, '02-11', '11 lutego', 'Z przekleństwa do błogosławieństwa\r\n', NULL, '„W trakcie naszego zdrowienia staliśmy się bardzo wdzięczni... Jesteśmy chorzy, ale zdrowiejemy.” \r\n\r\n~Tekst Podstawowy   \r\n\r\nCzynne uzależnienie nie było błahostką; wielu z nas ledwo uszło z życiem. Lecz wygłaszanie tyrad przeciwko chorobie, lamentowanie nad tym, co nam wyrządziła i użalanie się na stan, w jakim nas zostawiła – wszystko to może tylko pogrążyć nas w rozgoryczeniu i żalu. Droga do wolności i duchowego rozwoju rozpoczyna się tam, gdzie zgorzknienie się kończy a zaczyna akceptacja. Nie przeczy to temu, że uzależnienie przynosi cierpienie. Ale to właśnie ta choroba przywiodła nas do Anonimowych Narkomanów; bez niej nie zaczęlibyśmy szukać zdrowienia i nie doznalibyśmy błogosławieństw, które ono przynosi. Pogrążając nas w izolacji, choroba zmusiła nas do szukania wspólnoty. Przynosząc nam cierpienie, wyposażyła nas w doświadczenie niezbędne do niesienia pomocy innym, pomocy, której nikt poza nami tak dobrze nie potrafi udzielić. Rzucając nas na kolana, uzależnienie umożliwiło nam poddanie się opiece kochającej Siły Wyższej. Nikomu nie życzymy choroby uzależnienia. Faktem jednak jest, że my uzależnieni mamy już tę chorobę - i ponadto, bez tej choroby, być może nigdy nie wyruszylibyśmy w naszą duchową podróż. Tysiące ludzi przez całe swoje życie poszukuje tego, co myśmy znaleźli w NA - wspólnoty, poczucia sensu i celu oraz świadomego kontaktu z Siłą Wyższą. Dziś jesteśmy wdzięczni za wszystko, co sprowadziło na nas to błogosławieństwo.', 'Zaakceptuję fakt mojej choroby i będę starał się dostrzegać błogosławieństwa mojego zdrowienia.'),
(43, '02-12', '12 lutego', 'Życie chwilą', NULL, '„Żałowaliśmy przeszłości, baliśmy się przyszłości, a teraźniejszość nie była ekscytująca.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nZanim doświadczymy zdrowienia, które dzieje się podczas pracy nad Dwunastoma Krokami, bez wątpienia nie znajdziemy stwierdzenia bardziej dla nas prawdziwego niż cytat powyżej. Większość z nas przyszła do NA ze zwieszonymi ze wstydu głowami. Myśląc o przeszłości chcielibyśmy cofnąć czas i zmienić ją. Nasze fantazje i oczekiwania odnośnie przyszłości mogą być tak ekstremalne, że już na pierwszej randce, myślimy, kto będzie naszym prawnikiem w sprawie rozwodowej. Prawie każde doświadczenie powoduje u nas wspomnienia z przeszłości lub projekcje dotyczące przyszłości. Na początku trudno jest żyć teraźniejszością. Wydaje się, że nasze myśli nigdy się nie zatrzymają. Mamy trudności z tym, aby po prostu się cieszyć. Za każdym razem, kiedy uświadamiamy sobie, że nasze myśli nie są skupione na tym, co się dzieje w chwili obecnej, możemy poprosić kochającego Boga, aby nam pomógł, oderwać się od samych siebie. Jeżeli żałujemy przeszłości, możemy dokonać zadośćuczynienia wybierając teraz inny sposób życia; jeżeli boimy się przyszłości, pracujemy nad tym, aby dzisiaj żyć odpowiedzialnie. Kiedy pracujemy nad krokami i modlimy się za każdym razem, kiedy odkrywamy, że nie żyjemy teraźniejszością, stwierdzamy, że nie zdarza się to już tak często, jak kiedyś. Nasza wiara pomoże nam żyć tylko na dzisiaj. Będziemy przeżywać godziny, a nawet całe dni, kiedy nasza uwaga będzie zupełnie skupiona na chwili obecnej, a nie na godnej pożałowania przeszłości, albo przerażającej przyszłości.', 'Kiedy w pełni żyję chwilą obecną, otwieram się na radości, które w przeciwnym razie mogą mnie ominąć. Jeżeli będę mieć z tym problemy, poproszę o pomoc kochającego Boga.'),
(44, '02-13', '13 lutego', 'Więzi, które nas łączą', NULL, '„Tak długo, jak długo więzi, które nas łączą są silniejsze od sił, które nas rozbijają, wszystko będzie dobrze.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas ma poczucie, że bez NA nasza choroba doprowadziłaby nas do śmierci. Dzięki NA jest dla nas ratunek. Brak jedności jest jednak zjawiskiem powszechnym, występującym również w NA. Reagując na pojawiające się czasami w naszej wspólnocie destrukcyjne siły, musimy nauczyć się szukać rozwiązań. Jeżeli decydujemy się, aby być częścią rozwiązania, a nie częścią problemu, to zmierzamy w dobrym kierunku. Nasze osobiste zdrowienie i rozwój NA zależy od tego, czy na naszych mityngach panuje atmosfera zdrowienia. Czy jesteśmy gotowi, aby pomagać naszej grupie w poszukiwaniu rozwiązań konfliktów? Czy jako członkowie grupy dążymy do tego, aby otwarcie i szczerze mówić o trudnościach? Czy próbujemy przyczyniać się do wspólnego dobra wszystkich naszych członków bardziej, niż forsować nasze własne interesy? Czy jako osoby godne zaufania w służbie bierzemy pod uwagę to, jak nasze działania wpływają na nowoprzybyłych? Służba może pokazać zarówno najlepsze, jak i najgorsze nasze strony. Często, dzięki służbie mamy kontakt z niektórymi ze swoich bardziej uciążliwych wad charakteru. Czy uciekamy w strachu przed obowiązkami, które niesie ze sobą służba, zamiast stawić czoła temu, czego moglibyśmy się o sobie dowiedzieć? Jeśli pamiętamy o tym, co jest siłą więzi, które nas łączą, czyli o naszym zdrowieniu z uzależnienia, wszystko będzie dobrze.', 'Będę dążyć do tego, aby służyć naszej wspólnocie. Nie będę obawiać się tego, że odkryję, kim jestem.'),
(45, '02-14', '14 lutego', 'Uczciwość i duchowość', NULL, '„Wszyscy mają pełne i nie ograniczone prawo do własnego pojmowania Boga. I dlatego, mając to prawo i chcąc wzrastać duchowo, musimy być uczciwi wobec naszej wiary.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nNa mityngach, w czasie przerw, w rozmowach ze sponsorem słyszymy jak nasi przyjaciele z NA mówią o swoim pojmowaniu Siły Wyższej. Byłoby łatwo „płynąć z prądem”, przyswajając czyjąś wiarę. Lecz tak, jak nikt inny nie może zdrowieć za nas, tak samo niczyja duchowość nie zastąpi naszej własnej. Musimy uczciwie poszukać takiego pojmowania Boga, które naprawdę będzie dla nas skuteczne. Wielu z nas zaczyna to poszukiwanie poprzez modlitwę i medytację, a kontynuuje poprzez doświadczenia w zdrowieniu. Czy mamy przykłady na to, że dana nam była siła większa niż nasza własna do tego, abyśmy mogli sprostać życiowym wyzwaniom? Czy w trudnych chwilach udało nam się znaleźć wyjście z sytuacji, jeśli tylko spokojnie go szukaliśmy? Jaka to, naszym zdaniem, Siła prowadziła nas i wzmacniała? Jakiej Siły szukamy? Odpowiadając sobie na te pytania, znajdziemy takie pojmowanie naszej Siły Wyższej, które w zupełności wystarczy do tego, aby w poczuciu bezpieczeństwa i ufności prosić Ją o opiekę nad naszą wolą i naszym życiem. Zapożyczone pojmowanie Boga może działać przez krótki czas. Jednak na dłuższą metę musimy dojść do własnego rozumienia Siły Wyższej, ponieważ jest to Siła, która będzie nas niosła przez całe nasze zdrowienie. ', 'Szukam Siły większej ode mnie, która może pomóc mi w duchowym wzroście. Dzisiaj uczciwie przyjrzę się swoim przekonaniom i dojdę do własnego pojmowania Boga.'),
(46, '02-15', '15 lutego', 'Duchowe przebudzenie', NULL, '„Ostatnim, czego oczekiwaliśmy to duchowe przebudzenie.“ \r\n\r\n~Tekst Podstawowy  \r\n\r\nNiewielu z nas przyszło na swój pierwszy mityng z palącym pragnieniem robienia osobistej inwentury czy z przekonaniem, że w ich duszy istnieje duchowa pustka. Nie przeczuwaliśmy, że właśnie rozpoczynamy podróż, która obudzi naszą śpiącą duszę. Jak głośny budzik, Krok Pierwszy przenosi nas w stan półświadomości, chociaż w momencie, kiedy dzwoni, nie jesteśmy pewni, czy podniesiemy się z łóżka, czy też raczej pośpimy jeszcze pięć minut dłużej. Delikatna dłoń poklepująca nas po ramieniu, kiedy pracujemy nad Krokiem Drugim i Trzecim powoduje, że wstajemy, przeciągamy się i ziewamy. Musimy otrzeć sen z naszych oczu, aby napisać Czwarty Krok i podzielić się Piątym. Kiedy pracujemy nad Szóstym, siódmym, Ósmym i Dziewiątym Krokiem zauważamy skok w naszym kroczeniu i początek uśmiechu na naszych ustach. Nasza dusza śpiewa pod prysznicem, kiedy robimy Krok Dziesiąty i Jedenasty. A wtedy opuszczamy dom, szukając innych, aby ich obudzić.Nie musimy spędzić reszty naszego życia w duchowej śpiączce. Być może rano nie wstajemy chętnie, ale kiedy to już zrobimy, prawie zawsze jesteśmy szczęśliwi z tego powodu. ', 'Aby obudzić moją śpiącą duszę będę używać Dwunastu Kroków.'),
(47, '02-16', '16 lutego', 'Poczucie wierności', NULL, '„Kiedy wzbraniamy się przed tym, aby zaakceptować rzeczywistość dnia dzisiejszego, zaprzeczamy naszej wierze w Siłę Wyższą, a to może nam przynieść jeszcze większe cierpienie.” \r\n\r\n~IP nr 8, \r\n\r\nWłaśnie dzisiaj  Niektóre dni nie są takie, jak byśmy chcieli żeby były. Nasze problemy mogą być tak proste jak pęknięta sznurówka albo długa kolejka w supermarkecie. Możemy doświadczać też poważniejszych rzeczy: utraty pracy, mieszkania, ukochanej osoby. Tak czy inaczej doświadczając trudności próbujemy unikać naszych uczuć, zamiast po prostu przyznać, że te uczucia są trudne. Nikt nie obiecywał nam, że wszystko będzie się toczyło zgodnie z naszą wolą, jeżeli przestaniemy brać. W rzeczywistości, pewne jest to, że życie będzie się toczyło dalej, bez względu na to, czy będziemy brać czy nie. Będziemy mieć lepsze i gorsze dni, przyjemne i nieprzyjemne uczucia. Jednak nie musimy już przed nimi uciekać. Możemy doświadczać bólu, żałoby, smutku, złości, frustracji – wszystkich tych uczuć, których kiedyś unikaliśmy z pomocą narkotyków. Stwierdzamy, że wszystkie te uczucia możemy przeżyć w czystości. Nie umrzemy i świat się nie skończy, tylko dlatego, że przeżywamy nieprzyjemne uczucia. Uczymy się ufać w to, że możemy przeżyć bez względu na to, co przyniesie nam dany dzień.', 'Zademonstruję moje zaufanie wobec Boga doświadczając tego dnia po prostu takim, jaki jest.'),
(48, '02-17', '17 lutego', 'Niesiemy posłanie, a nie uzależnionych', NULL, '„Można ich analizować, doradzać im, grozić, bić, izolować ich, apelować do ich rozsądku, ale nie przestaną brać, dopóki sami tego nie zechcą.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nByć może to jedna z najtrudniejszych prawd, jakim musimy spojrzeć w twarz w naszym zdrowieniu, że wobec uzależnienia innych jesteśmy tak samo bezsilni, jak wobec naszego własnego. Być może myślimy, że poprzez duchowe przebudzenie w naszym własnym życiu jesteśmy zdolni do tego, aby nakłonić innych uzależnionych, aby znaleźli zdrowienie. Istnieją jednak granice tego, co możemy zrobić, aby pomóc innym uzależnionym. Nie możemy ich zmusić do tego, aby przestali brać. Nie możemy dać im efektów pracy nad krokami, ani wzrastać za nich. Nie możemy zabrać im ich samotności ani bólu. Nie istnieje nic, co moglibyśmy powiedzieć, aby przekonać wystraszonego uzależnionego do zamiany dobrze znanej żałosności uzależnienia na przerażającą niepewność zdrowienia. Nie możemy wskoczyć w czyjąś skórę, zmienić jego cele i zadecydować za niego, co jest dla niego najlepsze. Jednak kiedy powstrzymujemy się od tego, aby ćwiczyć naszą siłę na uzależnieniu innych, być może im pomagamy. Inni mogą doświadczyć wzrostu, jeżeli pozwolimy im przeżywać rzeczywistość, jakkolwiek bolesna by ona nie była. Mogą stać się produktywni na swój własny sposób, jeżeli nie będziemy robić tego za nich. Jeżeli troszczymy się o to, abyśmy byli odpowiedzialni tylko za siebie, inni mogą wtedy wziąć odpowiedzialność za swoje własne życie. Jeżeli potrafimy to wszystko zaakceptować, czynimy to, do czego jesteśmy przeznaczeni – niesiemy posłanie, a nie uzależnionych. ', 'Zaakceptuję to, że jestem bezsilny nie tylko wobec własnego uzależnienia, ale również wobec uzależnienia innych. Będę nieść posłanie, a nie uzależnionych.'),
(49, '02-18', '18 lutego', 'Współpraca w zdrowieniu', NULL, '„Dopóki przyjmuję wszystko na spokojnie i zobowiązuję się wobec mojej Siły Wyższej, że będę postępował najlepiej jak tylko potrafię  wiem, że dzisiaj moja Siła Wyższa zaopiekuje się mną.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas czuje, że w zdrowieniu zobowiązać się powinniśmy przede wszystkim wobec naszej Siły Wyższej. Wiedząc, że o własnych siłach nie uda nam się pozostać czystymi i zdrowieć, współpracujemy z Siłą większą od nas samych. Zobowiązujemy się powierzyć życie opiece naszej Siły Wyższej, a w zamian nasza Siła Wyższa nas prowadzi. Współpraca ta jest niezbędna, abyśmy mogli pozostać czyści. W pierwszych dniach zdrowienia często wydaje się, że ta współpraca jest najcięższą rzeczą, jaką kiedykolwiek robiliśmy. Lecz siła płynąca z naszego zobowiązania się do zdrowienia i moc Bożej opieki wystarczą, aby pomóc nam pokonać trudności dnia dzisiejszego. W tej współpracy naszym zadaniem jest codzienne wykonywanie wszystkiego jak potrafimy najlepiej, uczestniczenie w otaczającym nas życiu oraz podejmowanie się stawianych przed nami zadań i stosowanie przy tym zasad zdrowienia najlepiej jak potrafimy. Obiecujemy,  że będziemy postępować najlepiej jak tyko możemy - bez udawania, bez pretendowania do miana „supermanów”, po prostu, robiąc postępy w zdrowieniu. Gdy w tej współpracy w zdrowieniu wywiązujemy się z tego, co do nas należy, doświadczamy opieki Siły Wyższej.', 'Wywiążę się z zobowiązania do współpracy wobec mojej Siły Wyższej.'),
(50, '02-19', '19 lutego', 'Zastrzeżenia', NULL, '„Nawrót nigdy nie jest przypadkiem. Jest on oznaką tego, że mamy wobec naszego programu jakieś zastrzeżenia.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nZastrzeżenia są czymś, co skrzętnie odkładamy na bok, by użyć tego w przyszłości. W naszym przypadku, zastrzeżenia takie są oczekiwaniem na to, że jeśli to i to się wydarzy, to na pewno zaliczymy wpadkę. Jakie wydarzenia mogłyby być na tyle bolesne, że nie bylibyśmy w stanie ich znieść? Być może wydaje nam się, że będziemy musieli wziąć, jeżeli zostaniemy opuszczeni przez małżonka lub partnera. Jeśli stracimy pracę, to też, oczywiście, będziemy musieli wziąć. Może sądzimy, że śmierć ukochanej osoby okaże się nie do zniesienia. W każdym razie, skrywane przez nas zastrzeżenia dają nam przyzwolenie, aby wziąć, jeżeli staną się one rzeczywistością - a to zdarza się dość często. Poprzez analizę naszych oczekiwań i ich zmianę, tam gdzie jest to możliwe, możemy przygotować się na sukces, zamiast na nawrót. Wielu z nas ma w głowie listę oczekiwanych nieszczęść, które są ściśle związane z naszymi lękami. Możemy się uczyć jak wytrzymać ból, obserwując innych członków NA, którzy przechodzą podobne cierpienia. Możemy odnieść ich doświadczenia do naszych własnych oczekiwań. Zamiast wmawiać sobie, że będziemy musieli przyćpać, gdy dana rzecz nam się przydarzy, możemy umacniać się w przekonaniu, że możemy pozostać czyści, bez względu na to, co dzisiaj przyniesie życie.', 'Sprawdzę jakie mam zastrzeżenia, które mogłyby zagrozić mojej czystości i podzielę się nimi z drugim uzależnionym.'),
(51, '02-20', '20 lutego', 'Bezsilność i odpowiedzialność osobista', NULL, '„Przez naszą nieumiejętność brania osobistej odpowiedzialności, sami stwarzaliśmy sobie problemy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy wzbraniamy się przed wzięciem odpowiedzialności za swoje życie, rezygnujemy z naszej własnej siły. Musimy pamiętać o tym, że co prawda jesteśmy bezsilni wobec naszego uzależnienia, ale nie wobec naszych zachowań. Wielu z nas nadużywało koncepcji bezsilności do tego, aby unikać podejmowania decyzji lub trzymać się czegoś, z czego już dawno wyrośliśmy. Twierdziliśmy, że jesteśmy bezsilni wobec naszych własnych działań. Obwinialiśmy innych ludzi za nasze różne niepowodzenia, zamiast zrobić coś pozytywnego, co pomogłoby nam wybrnąć z tych kłopotów. Jeżeli w dalszym ciągu unikamy odpowiedzialności, twierdząc, że jesteśmy „bezsilni,” wpędzamy się znowu w zwątpienie i nieszczęście, jakiego doświadczaliśmy w czynnym uzależnieniu. Perspektywa spędzenia wielu lat swojego zdrowienia w poczuciu bycia ofiarą jest bardzo realna. Zamiast pozwalać naszemu życiu przemijać nam koło nosa, możemy nauczyć się dokonywania słusznych wyborów i podejmowania ryzyka. Być może robimy błędy, ale możemy się na nich uczyć. Głębsza świadomość samego siebie i wzmożona gotowość do akceptowania odpowiedzialności osobistej daje nam możliwość do zmieniania się, dokonywania wyborów i wzrastania.', 'Są to moje uczucia, moje działania i moje decyzje. Zaakceptuję moją odpowiedzialność za nie.'),
(52, '02-21', '21 lutego', 'Użalanie się nad sobą czy zdrowienie – wybór należy do nas', NULL, '„Użalanie się nad sobą jest jedną z najbardziej destrukcyjnych wad; będzie wysysać z nas całą pozytywną energię.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas w trakcie aktywnego uzależnienia używało użalania się nad sobą, jako mechanizmu przetrwania. Nie wierzyliśmy, że istnieje jakaś alternatywa w odniesieniu do naszej choroby - albo może nie chcieliśmy wierzyć. Dopóki mogliśmy użalać się nad sobą i winić innych za nasze kłopoty, dopóty nie musieliśmy odpowiadać za konsekwencje naszych działań. Uważając, że nie jesteśmy w stanie nic zmienić, nie musieliśmy uznawać potrzeby takiej zmiany. Ten ”mechanizm przetrwania” przeszkadzał nam w podjęciu zdrowienia i dzień po dniu prowadził nas w stronę autodestrukcji. Użalanie się nad sobą jest narzędziem naszej choroby. Musimy więc przestać go używać i w zamian uczyć się korzystania z nowych narzędzi, które daje nam program NA. Utwierdzamy się w tym, że skuteczna pomoc jest dla nas dostępna; gdy jej szukamy, znajdujemy ją w programie NA, zastępując użalanie się wdzięcznością. Mamy do dyspozycji wiele narzędzi: Dwanaście Kroków, pomoc naszego sponsora, przyjaźń innych zdrowiejących uzależnionych oraz opiekę naszej Siły Wyższej. Dostępność tych wszystkich narzędzi jest bardziej niż wystarczającym powodem, aby być wdzięcznym. Nie żyjemy już dłużej w izolacji, pozbawieni nadziei. W każdej sytuacji, która może nas spotkać mamy w zasięgu ręki niezawodną pomoc. Najpewniejszym sposobem, aby stać się wdzięcznym jest wykorzystanie  z pomocy, którą oferuje nam program NA i doświadczenie zmian, jakie program wnosi w nasze życie. ', 'Będę wdzięczny za nadzieję, którą dało mi NA. Będę rozwijać moje zdrowienie i przestanę użalać się nad sobą.'),
(53, '02-22', '22 lutego', 'Czy to wola Boża czy moja?', NULL, '„Prowadziliśmy nadal obrachunek moralny z miejsca przyznając się do popełnianych błędów.” \r\n\r\n~Krok Dziesiąty  \r\n\r\nW NA odkrywamy, że harmonia w naszym życiu jest tym większa, im bardziej żyjemy według woli naszej Siły Wyższej. Używamy Kroku Dziesiątego jako pomocy do utrzymania tej harmonii. Każdego dnia dajemy sobie czas na to, aby obserwować nasze zachowanie. Niektórzy z nas mierzą każde działanie prostym pytaniem: „Czy to wola Boga, czy moja?” W wielu przypadkach stwierdzamy, że nasze działania były zgodne z wolą Siły Wyższej wobec nas i w zgodzie z otaczającym nas światem. W niektórych przypadkach jednak odkryjemy sprzeczności między naszym zachowaniem a naszymi wartościami. Działaliśmy według naszej własnej woli a nie według woli Bożej i wynikiem tego stał się rozdźwięk w naszym życiu. Kiedy odkrywamy takie sprzeczności, przyznajemy, że popełniliśmy błąd i staramy się go naprawić. Kiedy staje się dla nas bardziej świadome to, co w danej sytuacji jest wolą Boga, tym mniej prawdopodobne jest to, że znowu postąpimy tak samo. A wtedy bardziej jesteśmy w stanie żyć w zgodzie z wolą naszej Siły Wyższej i w zgodzie z otaczającym nas światem.', 'Chciałbym żyć w harmonii z moim światem. Dzisiaj sprawdzę moje działania pytając: „Czy to wola Boga, czy moja?”'),
(54, '02-23', '23 lutego', 'Posłanie i posłańcy', NULL, '„Anonimowość jest duchową podstawą wszystkich naszych tradycji, przypominając nam zawsze o pierwszeństwie zasad przed osobistymi pragnieniami.” \r\n\r\n~Tradycja Dwunasta  \r\n\r\nTradycja Dwunasta przypomina nam o tym, jak ważne jest „stawianie zasad przed osobistymi pragnieniami”. Na mityngach zdrowienia może to być parafrazowane następująco: „Nie strzela się do kogoś, kto przynosi posłanie!“ Często jednak mylimy posłanie z posłańcem i odrzucamy to, czym ktoś się dzieli na mityngu ze względu na osobisty konflikt z tą osobą. Jeśli mamy problemy ze słuchaniem pewnych osób dzielących się na mityngach, to być może powinniśmy omówić to z naszym sponsorem. Sponsor może pomóc nam skoncentrować bardziej na treści wypowiedzi niż na wypowiadającej się osobie. Sponsor może pomóc nam również w rozpoznaniu naszych uraz, które przeszkadzają nam w uznania wartości doświadczenia ze zdrowienia danej osoby. Zadziwiającym jest to, jak dużo możemy skorzystać z mityngów, jeżeli pozwolimy sobie postępować według sugestii Dwunastej Tradycji, koncentrując się na zasadach zdrowienia, a nie na osobach.', 'Dziś na mityngu będę praktykować zasadę anonimowości. Skoncentruję się na posłaniu zdrowienia, a nie na osobowości człowieka, który niesie to posłanie.'),
(55, '02-24', '24 lutego', 'Nowy wpływ', NULL, '„To czego naprawdę potrzebowaliśmy, to przemiany osobowości. Odwrócenie się od autodestrukcyjnych wzorców życiowych stało się koniecznością.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas we wczesnym okresie swojego życia potrafiło się cieszyć, zachwycać oraz dawać i otrzymywać bezwarunkową miłość. Gdy zaczęliśmy zażywać narkotyki, ulegliśmy oddziaływaniu, które powoli zaczęło pozbawiać nas tych umiejętności. W miarę kroczenia drogą uzależnienia coraz bardziej oddalaliśmy się od radości, zachwytu i miłości. Tej drogi jednak nie przebyliśmy w ciągu jednego dnia. Lecz bez względu na to ile czasu nam ona zajęła, przyszliśmy do NA z czymś więcej niż tylko z problemem narkotykowym. Pod wpływem uzależnienia nasze życiowe wzorce zostały wypaczone nie do poznania. To prawda, że Dwanaście Kroków czyni cuda, ale niewiele z nich zaczyna działać natychmiast. Nasza choroba powoli wpływała destrukcyjnie na nasz rozwój duchowy. Zdrowienie wywiera na nasze życie zupełnie nowy wpływ, a źródło wspólnoty i duchowej siły powoli prowadzi nas do nowego, zdrowego stylu życia. Ta zmiana oczywiście nie zachodzi się „ot tak, po prostu”. Gdy jednak pozwalamy, by NA wywarło swój wpływ na nasze życie, doświadczamy z czasem osobistej przemiany, którą nazywamy zdrowieniem. Dwanaście Kroków oferuje nam program swego rodzaju współpracy, potrzebnej do odbudowania w naszym życiu radości, zachwytu i miłości.', 'Będę współpracować z nowym wpływem wspólnoty i duchowej siły, który NA wprowadziło w moje życie. Będę pracować nad kolejnym krokiem mojego programu.'),
(56, '02-25', '25 lutego', 'Chorzy współmiernie do naszych tajemnic\r\n', NULL, '„Napisanie obrachunku tylko po to, by wrzucić go do szuflady byłoby sprawą fatalną. Nasze wady rosną w ciemności, a umierają, gdy zostają wyciągnięte na światło dzienne.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nIleż to razy słyszeliśmy, że poziom naszej choroby jest współmierny do naszych nieujawnionych tajemnic? Chociaż wiele osób nie decyduje się wykorzystać mityngów do tego, aby dzielić się intymnymi szczegółami swojego życia, ważne jest, by każdy z nas sam odkrył, co najlepiej działa w jego przypadku. Co jednak zrobimy z tymi sprawami, których odkrycie mogłoby sprawić, że spalilibyśmy się ze wstydu? Ile i komu jesteśmy w stanie bez skrępowania ujawnić? A jeżeli nie jesteśmy w stanie dzielić się niektórymi fragmentami naszego życia na mityngach, to do kogo możemy się zwrócić? Sponsoring jest odpowiedzią na te wszystkie pytania. Chociaż budowanie związku ze sponsorem wymaga czasu, powinniśmy mu zaufać na tyle, abyśmy mogli z nim być całkowicie uczciwi. Nasze wady mają nad nami przewagę jedynie do czasu pozostawania w ukryciu. Jeżeli chcemy uwolnić się od tych wad, musimy je ujawnić. Sekrety pozostają sekretami, dopóki nie podzielimy się nimi z innym człowiekiem.', 'Ujawnię moje sekrety. Będę ćwiczył uczciwość wobec mojego sponsora.'),
(57, '02-26', '26 lutego', 'Wyrzuty sumienia', NULL, '„Krok Ósmy oferuje nam wielką zmianę życia zdominowanego poczuciem winy i wyrzutami sumienia.” \r\n\r\n~Tekst Podstawowy   \r\n\r\nWyrzuty sumienia były jednymi z tych uczuć, które utrzymywały nas w braniu narkotyków. Czynne uzależnienie powodowało, że błądziliśmy, zostawiając za sobą ślady goryczy i spustoszenia, które były zbyt bolesne, aby o nich myśleć. Nasze wyrzuty sumienia często były spotęgowane naszymi wyobrażeniami o tym, że nie możemy już nic zrobić z krzywdami, które wyrządziliśmy. Nie było możliwości, aby to wszystko naprawić. Odbieramy wyrzutom sumienia część ich mocy poprzez rzetelne skonfrontowanie się z nimi. Zaczynamy Krok Ósmy, sporządzając dokładną listę wszystkich osób, które skrzywdziliśmy. Uznajemy swój udział w naszej bolesnej przeszłości. Jednak Krok Ósmy nie wymaga od nas naprawienia wszystkich naszych błędów, a jedynie tylko tego, abyśmy się stali gotowi do zadośćuczynienia wszystkim skrzywdzonym przez nas ludziom. Kiedy stajemy się gotowi do zadośćuczynienia krzywd, które wyrządziliśmy, potwierdzamy naszą gotowość do zmiany. Umacniamy w ten sposób proces zdrowienia. Wyrzuty sumienia przestają być instrumentem, którego używamy do torturowania siebie. Stają się one narzędziem, którego możemy używać do osiągnięcia przebaczenia dla samego siebie.', 'Wykorzystam wszelkie przejawy wyrzutów sumienia jako kolejną odskocznię w zdrowieniu według Dwunastu Kroków.'),
(58, '02-27', '27 lutego', ' Z czystych pobudek', NULL, '„Badamy nasze działania, reakcje i motywy postępowania. Często zauważamy, że są one lepsze, niż się nam wydaje”. \r\n\r\n~Tekst Podstawowy   \r\n\r\nWyobraź sobie książeczkę z codziennymi medytacjami, w której byłoby następujące przesłanie: „Gdy obudzisz się rano, przed opuszczeniem łóżka daj sobie chwilę na refleksję. Połóż się z powrotem, zbierz myśli i zastanów się nad swoimi dzisiejszymi planami. Jeden po drugim przeanalizuj motywy, które kryją się za twoimi planami. Jeżeli twoje motywy nie są idealnie czyste, obróć się na drugi bok i śpij dalej”. Czyż nie byłoby to nonsensem? Bez względu na okres naszej czystości, prawie za wszystkimi naszymi działaniami kryją się niejednoznaczne motywy. Jednakże nie może być to powodem, by zatrzymać nasze życie. Nie musimy czekać, aż nasze motywy staną się zupełnie czyste, aby zacząć żyć zdrowieniem. Gdy program zaczyna działać w naszym życiu, zaczynami coraz rzadziej kierować się naszymi wątpliwymi motywami. Regularnie analizujemy siebie i rozmawiamy z naszym sponsorem o tym, co odkryliśmy. Modlimy się, prosząc o poznanie woli naszej Siły Wyższej względem nas i szukamy siły do tego, by działać zgodnie z tym, czego się dowiedzieliśmy. Jaki jest tego efekt? Nie stajemy się doskonali, ale stajemy się lepsi. Zaczęliśmy pracować nad duchowym programem. Nigdy nie będziemy duchowymi gigantami. Gdy jednak realnie przyjrzymy się sobie, zauważymy być może, że postępujemy lepiej niż nam się wydaje.', 'Dokonam realistycznej analizy siebie. Poszukam siły, aby postępować zgodnie z moimi najlepszymi, a nie najgorszymi motywami.'),
(59, '02-28', '28 lutego', 'Największy Dar', NULL, '„W przyszłości, nasza nowo odkryta wiara będzie fundamentem naszej odwagi”. \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy zaczynamy chodzić na mityngi, słyszymy jak inni uzależnieni mówią o darach otrzymanych w rezultacie pracy nad tym programem, o rzeczach, o których nigdy byśmy nie pomyśleli jako o darach. Jedną z nich jest odnowiona zdolność przeżywania uczuć, które przez długi czas tłumiliśmy narkotykami. Nie jest trudno myśleć o miłości, radości i szczęściu jako o darach, nawet jeśli upłynęło wiele czasu od chwili, gdy je przeżywaliśmy. Lecz co ze „złymi” uczuciami, takimi jak złość, smutek, lęk i samotność? Uważamy, że takie emocje nie mogą być pojmowane jako dary. Poza tym, jak możemy być wdzięczni za rzeczy, od których chcemy uciec?! Możemy odczuwać wdzięczność za te uczucia pojawiające się w naszym życiu, jeśli spojrzymy na nie z właściwej perspektywy. Musimy pamiętać o tym, że uwierzyliśmy w kochającą Siłę Wyższą i poprosiliśmy tę Siłę o opiekowanie się nami – a nasza Siła Wyższa nie popełnia błędów. Uczucia, które mamy, „dobre” czy „złe”, są nam dane w jakimś celu. Mając to na uwadze, zdajemy sobie sprawę, że nie ma „złych” uczuć, są tylko lekcje, które mają nas czegoś nauczyć. Nasza wiara i opieka Siły Wyższej dają nam odwagę potrzebną do tego, aby sprostać uczuciom, które mogą pojawiać się każdego dnia. We wczesnym okresie zdrowienia słyszeliśmy, że „twoja Siła Wyższa nie da ci więcej, niż zdołasz unieść jednego dnia”. Zdolność zaś do odczuwania własnych emocji jest jednym z największych darów zdrowienia.', 'Spróbuję wyjść naprzeciw swoim uczuciom, mocno wierząc w to, iż wystarczy mi odwagi, aby sprostać wszelkim uczuciom, które mogą pojawić się w moim życiu.'),
(60, '02-29', '29 lutego', 'Wszystko!', NULL, '„Nasza choroba została zatrzymana i teraz wszystko jest możliwe. Stajemy się coraz bardziej otwarci i otwarci na nowe pomysły we wszystkich obszarach naszego życia”. \r\n\r\n~Tekst podstawowy \r\n\r\nDla wielu z nas pierwsze kilka miesięcy lub lat w NA to wspaniały czas. Jesteśmy gotowi spróbować wszystkiego, a nasze oczy są ciągle otwarte na nowe radości i nowe horyzonty. Nareszcie uwolnieni od aktywnego uzależnienia, odzyskując młodość i świeżość, wszystko wydaje się możliwe. Mając jednak trochę czystego czasu za sobą, nasz program może być mniej pilny. Być może nie jesteśmy już tak chętni, jak kiedyś, do wykorzystania doświadczeń innych. Możemy napotkać kilka pozornie nieuleczalnych wad naszego charakteru, które pomniejszają bezgraniczny optymizm wynikający z naszego wczesnego powrotu do zdrowia. Wiemy za dużo, żeby wierzyć, że wszystko jest możliwe. Jak przywrócić entuzjazm do zdrowienia? Modlimy się o to; dzielimy się tym; i szukamy entuzjazmu, którego nam brakuje. Są członkowie – niektórzy z większą ilością wolnego czasu od nas, inni z mniejszym – którzy mają entuzjazm, którego szukamy i którzy chętnie się nim z nami podzielą, jeśli ich o to poprosimy. Aby jednak skorzystać z ich doświadczenia, musimy ćwiczyć otwartość umysłu i ponownie stać się skłonnymi do nauczania. Kiedy stajemy się otwarci na nowe pomysły i gotowi je wypróbować, odkryjemy, że po raz kolejny wszystko wydaje się możliwe.', 'Zawsze jest jeszcze więcej do nauczenia się i od kogo mogę się uczyć podczas mojego powrotu do zdrowia. Dziś będę otwarta na nowe pomysły i chętna do ich wypróbowania. Póki jestem, wiem, że wszystko jest możliwe.'),
(61, '03-01', '1 marca', 'Atak lęku?', NULL, '„Siła, która nas przyprowadziła do tego programu wciąż jest z nami i jest gotowa nadal nam przewodzić, jeśli jej na to pozwolimy.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy miewamy ataki paniki? Gdziekolwiek byśmy się nie obrócili, przytłaczają nas rzeczy, których wymaga od nas życie. Jesteśmy sparaliżowani i nie wiemy, co z tym zrobić. Jak możemy pokonać taki atak lęku? Po pierwsze, zatrzymujemy się. Nie jesteśmy w stanie uporać się ze wszystkim naraz, więc zatrzymujemy się na chwilę, aby rzeczy uporządkować. Robimy „szybkie podsumowanie” spraw, które nas dręczą. Analizujemy każdy punkt, zadając sobie pytanie: „Jak bardzo, tak naprawdę, jest to ważne?”. Zobaczymy, że w większości przypadków znaczna część tych obaw i zmartwień nie wymaga naszej niezwłocznej uwagi. Możemy je odłożyć na bok i skoncentrować się na tych sprawach, które rzeczywiście muszą być rozwiązane natychmiast. Wtedy znów zatrzymujemy się i zadajemy sobie pytanie: „Kto, tak w ogóle, ma nad tym wszystkim kontrolę?” To pytanie pomoże nam przypomnieć sobie, że kontrolę nad wszystkim ma nasza Siła Wyższa. Poszukujemy w danej sytuacji woli naszej Siły Wyższej, jaka by ona nie była. Możemy to zrobić na wiele sposobów: poprzez modlitwę, poprzez rozmowę ze sponsorem lub z przyjaciółmi z NA, poprzez udział w mityngu i poproszenie innych, aby podzielili się swoim doświadczeniem. Gdy wola naszej Siły Wyższej staje się dla nas jasna, modlimy się o zdolność do jej wykonania. I dopiero wtedy podejmujemy działania. Atak lęku nie musi nas paraliżować. Możemy wykorzystać zasoby programu NA do uporania się ze wszystkim, co spotka nas na naszej drodze. ', 'Moja Siła Wyższa nie przyprowadziła mnie tą drogą do zdrowienia tylko po to, aby mnie teraz opuścić! Gdy dopadnie mnie lęk, wykonam określone kroki w poszukiwaniu nieustającej opieki i przewodnictwa Boga.'),
(62, '03-02', '2 marca', 'Sukces', NULL, '„Każda forma sukcesu była przerażająca i obca.“ \r\n\r\n~Tekst Podstawowy  \r\n\r\nZanim przyszliśmy do NA, niewielu z nas wiedziało, czym jest sukces. Każda próba zaprzestania zażywania na własną rękę kończyła się porażką. Zaczęliśmy tracić nadzieję, że kiedykolwiek uwolnimy się od czynnego uzależnienia. Przyzwyczailiśmy się do porażki, spodziewaliśmy się jej, akceptowaliśmy ją i myśleliśmy, że tak już po prostu musi być. Gdy zachowujemy czystość, zaczynamy odnosić sukcesy. Jesteśmy dumni z tego, co osiągnęliśmy. Zaczynamy podejmować zdrowe ryzyko. Być może czasem obrywamy po głowie, ale nawet takie sytuacje mogą być postrzegane jako sukces, jeżeli wyciągamy z nich wnioski. Czasami, gdy osiągamy jakiś cel, wahamy się czy się tym pochwalić, ponieważ boimy się, że będziemy posądzeni o arogancję. Nasza Siła Wyższa chce jednak, abyśmy odnosili sukcesy i chce, byśmy dzielili się dumą z naszych osiągnięć z tymi, których kochamy. Kiedy dzielimy się naszymi sukcesami z innymi członkami NA, często zaczynają oni wierzyć, że też mogą osiągnąć swoje cele. Odnosząc sukcesy, pomagamy w budowaniu fundamentów tym, którzy podążają naszymi śladami.', 'Poświęcę czas na to, by delektować się swoimi sukcesami. Będę z „postawą wdzięczności” dzielić się moimi zwycięstwami.'),
(63, '03-03', '3 marca', 'Nawrót-wpadka', NULL, '„Jeszcze niejeden raz ogarnie nas chęć zażycia. Będziemy chcieli uciec i poczujemy się paskudnie. Powinniśmy sobie wtedy przypomnieć skąd przyszliśmy, i że tym razem będzie jeszcze gorzej. Są to chwile, w których najbardziej potrzebujemy programu.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nJeśli zaczynamy rozmyślać o ewentualnej wpadce, powinniśmy przypomnieć sobie nasze branie razem z jego gorzkim końcem. Dla wielu z nas ten koniec oznaczałby poważne problemy zdrowotne, więzienie lub nawet śmierć. Ilu z nas znało ludzi, którzy po wielu latach czystości mieli wpadkę, która zakończyła się śmiercią. Istnieje jednak śmierć, która towarzyszy naszemu powrotowi do czynnego uzależnienia, i która może być gorsza od śmierci fizycznej. Jest nią śmierć duchowa, której doświadczamy, gdy izolujemy się od naszej Siły Wyższej. Jeśli zażyjemy narkotyk, duchowa więź, którą budowaliśmy przez lata osłabnie i być może zupełnie zniknie. Poczujemy się naprawdę samotni. W naszym zdrowieniu oczywiście zdarzają się nam okresy ciemności. Tylko w jeden sposób możemy przejść przez te trudne chwile: z wiarą. Jeśli wierzymy, że nasza Siła Większa jest z nami, wówczas wiemy, że wszystko będzie dobrze. Bez względu na to, jak bardzo źle możemy się poczuć w naszym zdrowieniu, wpadka nigdy nie jest rozwiązaniem. Wspólnie znajdujemy zdrowienie. Jeśli pozostajemy czyści, ciemność odejdzie, a my odnajdziemy głębszą więź z naszą Siłą Wyższą. ', 'Dziękuję mojej Sile Wyższej za prezent, którym jest NA. Wiem, że wpadka nie jest żadnym wyjściem. Bez względu na to jakie wyzwania czekają na mnie, stawię im czoła z pomocą Boga, jakkolwiek go rozumiem.');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(64, '03-04', '4 marca', 'Proces', NULL, '„Ten program stał się częścią mnie... Dzisiaj lepiej rozumiem wydarzenia zachodzące w moim życiu. Już nie walczę z tym procesem.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy trwaliśmy w czynnym uzależnieniu, wydarzenia w naszym życiu wydawały się być pozbawione sensu. Po prostu „załatwialiśmy sprawy”, często nie wiedząc dlaczego to robimy i jakie mogą być tego konsekwencje. Życie nie miało dla nas większej wartości ani znaczenia. Dwunastokrokowy proces nadał naszemu życiu sens; pracując nad krokami, dojrzewamy do tego, aby zaakceptować zarówno ciemną, jak i jasną stronę swojej osobowości. Odrzuciliśmy zaprzeczanie, które przeszkadzało nam zrozumieć, jaki wpływ wywierało na nas uzależnienie. Uczciwie analizujemy samych siebie, zaczynamy rozpoznawać schematy naszego myślenia, uczuć i zachowań. Dzięki całkowitemu otwarciu się przed drugim człowiekiem zyskaliśmy pokorę i nowy punkt widzenia. Dążąc do tego, aby nasze wady zostały usunięte, rozwijamy w sobie zrozumienie wartości własnej bezsilności oraz mocy, którą nam zapewnia Siła większa od naszej własnej. Wraz z wzrastającym zrozumieniem siebie, osiągamy większy wgląd w innych oraz zwiększa się nasza akceptacja w stosunku do nich. Dwanaście Kroków stanowi klucz do procesu, który nazywamy „życiem”. Gdy pracujemy nad krokami, stają się one częścią nas, a my stajemy się częścią otaczającego nas życia. Nasz świat już nie jest pozbawiony sensu; teraz lepiej rozumiemy to, co dzieje się w naszym życiu. Nie walczymy dłużej z tym procesem. Dzisiaj, pracując nad krokami, żyjemy nim.', 'Życie jest procesem; Dwanaście Kroków jest kluczem. Dziś użyję kroków, aby wziąć udział w tym procesie, rozumiejąc siebie i ciesząc się sobą oraz swoim zdrowieniem.'),
(65, '03-05', '5 marca', 'Od ocknięcia się do przebudzenia duchowego', NULL, '„Kiedy wyłania się konieczność uznania swojej bezsilności, prawdopodobnie najpierw będziemy szukać sposobów, aby tego uniknąć. Gdy już je wyczerpiemy, zaczynamy dzielić się tym z innymi i znajdujemy nadzieję.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzasami słyszymy na mityngu, że „ocknięcie się prowadzi do przebudzenia duchowego”. Jakiego rodzaju ocknięcia się doświadczamy w zdrowieniu? Takie ocknięcie się może się zdarzyć, kiedy jakaś niepożądana część naszego zachowania, o której myśleliśmy, że jest głęboko ukryta, staje się nagle jawna i widoczna dla całego świata. Nasz sponsor może również sprowokować takie ocknięcie się, mówiąc: „Jeżeli chcesz pozostać czysty i zdrowieć, musisz pracować nad krokami, tak jak wszyscy inni”. Większość z nas nie znosi, gdy zdziera się z nich maski. Nie lubimy być nadzy. Takie doświadczenie dostarcza dużą porcję pokory. Naszą pierwszą reakcją na takie obnażenie jest zazwyczaj szok i wściekłość, a jednak pomimo to rozpoznajemy prawdę, gdy ją słyszymy. I tak właśnie następuje ocknięcie się. Takie ocknięcie się często ujawnia nasze ograniczenia, które przeszkadzają nam w robieniu duchowych postępów w zdrowieniu. A kiedy ograniczenia te staną się widoczne, możemy, pracując nad krokami, zacząć usuwać je z naszego życia. Możemy zacząć doświadczać zdrowienia i pogody ducha, które są wstępem do ponownego przebudzenia ducha.', 'Będę postrzegać ocknięcie się jako okazję do wzrostu w kierunku duchowego przebudzenia.'),
(66, '03-06', '6 marca', 'Racjonalizowanie niweczy nasze zdrowienie', NULL, '„W wyniku pracy nad Dwunastoma Krokami nie jestem już w stanie oszukiwać siebie tak, jak kiedyś.”  \r\n\r\n~Tekst Podstawowy (Historie Osobiste)\r\n\r\nWszyscy ulegamy racjonalizacjom. Czasami wiemy, że to robimy, przyznajemy się do tego, ale pomimo to, nadal racjonalizujemy nasze zachowania. Zdrowienie może stać się bardzo bolesne, jeżeli uznamy, że z takich lub innych powodów proste zasady programu nas nie dotyczą. Z pomocą naszego sponsora lub innych osób z NA zaczynamy zauważać, jakich wymówek używamy na usprawiedliwienie swoich zachowań. Czy wydaje nam się, że niektóre zasady po prostu nas nie dotyczą? Czy uważamy, że wiemy więcej niż wszyscy inni członkowie NA, nawet ci z wieloletnim stażem czystości? Z jakich powodów sądzimy, że jesteśmy tacy wyjątkowi? Oczywiście, możemy z powodzeniem przez jakiś okres naszego zdrowienia racjonalizować swoje zachowania. W końcu jednak musimy spojrzeć prawdzie w oczy i zacząć zachowywać się odpowiednio. Zasady Dwunastu Kroków prowadzą nas do nowego życia w zdrowieniu. A tam nie ma miejsca na racjonalizacje.', 'Nie mogę pracować nad Krokami, oszukując jednocześnie samego siebie. Przeanalizuję swoje myśli pod kątem racjonalizacji, ujawnię je przed moim sponsorem i pozbędę się ich.'),
(67, '03-07', '7 marca', 'Priorytety', NULL, '„Dobre czasy mogą również stać się pułapką; niebezpieczeństwo kryje się w tym, że możemy zapomnieć o naszym głównym priorytecie, którym jest pozostanie w czystość.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW naszym zdrowieniu wszystko może zacząć układać się bardzo dobrze. Może znaleźliśmy naszą ”bratnią duszę”, może odnieśliśmy sukces zawodowy lub założyliśmy rodzinę. Być może relacje z członkami naszej rodziny zostały uzdrowione. Sprawy układają się tak dobrze, że ledwie znajdujemy czas, aby chodzić na mityngi. Może zaczęliśmy ponownie integrować się ze społeczeństwem z tak wielkim powodzeniem, że zapomnieliśmy, iż w pewnych sytuacjach nie zawsze reagujemy tak, jak inni ludzie. Być może postawiliśmy pewne wartości ponad innymi. Czy uczęszczanie na mityngi nadal jest dla nas priorytetem? Czy wciąż sponsorujemy? Czy dzwonimy do swojego sponsora? Nad którym krokiem obecnie pracujemy? Czy wciąż jesteśmy gotowi zwlekać się z łóżka o jakiejś nieludzkiej porze, aby wykonać lub odebrać telefon w ramach Dwunastego Kroku? Czy pamiętamy o praktykowaniu zasad we wszystkich naszych poczynaniach? Czy jesteśmy dostępni, gdy inni członkowie NA nas potrzebują? Czy pamiętamy, skąd przyszliśmy, czy też „dobre czasy” pozwalają nam o tym zapomnieć? Aby zachować czystość, musimy pamiętać, że od przeszłości dzieli nas tylko jedna działka narkotyku. Jesteśmy wdzięczni za dobre czasy, lecz nie możemy dopuścić do tego, aby odciągnęły one nas od kontynuacji zdrowienia w NA.', 'Jestem wdzięczny za dobre czasy, lecz nie zapominam, skąd przyszedłem. Dzisiaj moim głównym priorytetem jest pozostanie czystym oraz wzrastanie w moim zdrowieniu.'),
(68, '03-08', '8 marca', 'Ucząc się kochać samego siebie', NULL, '„To, czego pragniemy najbardziej, to poczuć się dobrze z samym sobą.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\n„Będziemy cię kochać, aż nauczysz się kochać siebie samego”. Te słowa, słyszane tak często na mityngach, niosą obietnicę dnia, którego tak niecierpliwie oczekujemy - dnia, w którym dowiemy się jak pokochać siebie. Poczucie własnej wartości - wszyscy pragniemy tego nieuchwytnego poczucie, gdy tylko o nim usłyszymy. Niektórym z nas wydawało się, że w pewnych okolicznościach ocierali się o nie, podczas gdy inni podejmowali się konkretnych działań łącznie z afirmacjami przed lustrem. Lecz techniki samowzmocnienia oraz nowoczesne terapie psychologiczne mogą pomóc nam tylko w pewnym stopniu. Istnieją określone, praktyczne kroki, których możemy się podjąć, aby okazać sobie tę miłość, bez względu na to, czy ją „czujemy”, czy nie. Możemy zatroszczyć się o siebie. Możemy robić dla siebie miłe rzeczy, tak, jakbyśmy to robili dla ukochanej osoby lub przyjaciela. Możemy zacząć zwracać uwagę na nasze własne potrzeby. Możemy nawet zwrócić uwagę na zalety, które tak bardzo cenimy u naszych przyjaciół - takie jak inteligencja i poczucie humoru - i zobaczyć czy przypadkiem sami nie posiadamy podobnych zalet. Z pewnością odkryjemy, że faktycznie jesteśmy sympatycznymi i uroczymi osobami, i gdy raz to odkryjemy, poczujemy się na naszej drodze dobrze.', 'Zrobię dziś coś, co pomoże mi rozpoznać i poczuć miłość do siebie samego.'),
(69, '03-09', '9 marca', 'Drobne niepowodzenia', NULL, '„W przeszłości, często z prostych sytuacji robiliśmy problemy; z igły robiliśmy widły.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nRobienie z igieł wideł wydaje się być naszą specjalnością. Czy słyszałeś już o tym, że dla uzależnionego nawet przebita opona może urosnąć do rangi tragedii życiowej? A iluż z nas na widok złego kierowcy zapomina o wszelkich zasadach przyzwoitości. A co z otwieraczem do puszek, który nie działa? Wiesz, z tym, który wyrzuciłeś przez okno z drugiego piętra. Dobrze rozumiemy tych, którzy mówią: „Boże użycz mi teraz cierpliwości”. Nie, to nie wielkie niepowodzenia doprowadzają nas do szału. Takie wydarzenia jak rozwód, śmierć, poważna choroba lub utrata pracy wstrząsną nami, ale je przetrwamy. Z doświadczenia nauczyliśmy się, że aby przejść przez większość życiowych kryzysów powinniśmy się zwrócić o pomoc do naszej Siły Wyższej i do innych uzależnionych. Lecz to właśnie drobne sprawy, zwykłe codzienne problemy, które niesie ze sobą życie bez narkotyków, wydawać się mogą tym, co najbardziej dotyka większość uzależnionych w ich zdrowieniu. Gdy dręczą nas drobne niepowodzenia, Modlitwa o Pogodę Ducha może pomóc nam odzyskać właściwą perspektywę. Możemy sobie przypomnieć, że powierzenie tych drobnych niepowodzeń opiece naszej Siły Wyższej przyniesie nam wewnętrzny spokój i nowe spojrzenie na życie.', 'Będę pracować nad cierpliwością. Spróbuję nie rozdmuchiwać problemów i przejść przez ten dzień z moją Siłą Wyższą.'),
(70, '03-10', '10 marca', 'Nasze osobiste zdrowienie', NULL, '„Kroki są naszym rozwiązaniem. Są naszym kołem ratunkowym. Są naszą obroną przeciwko uzależnieniu, które jest śmiertelną chorobą. Nasze kroki są zasadami, które umożliwiają nam zdrowienie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nIstnieje dużo rzeczy w NA, które można lubić. Na przykład mityngi są wspaniałe. Chodzimy na nie, aby zobaczyć naszych przyjaciół, usłyszeć inspirujące historie, podzielić się praktycznym doświadczeniem lub porozmawiać ze swoim sponsorem. Wspólne biwaki, zloty, imprezy - wszystko to jest cudowną, czystą zabawą w towarzystwie innych zdrowiejących uzależnionych. Lecz sercem naszego programu zdrowienia jest Dwanaście Kroków - w rzeczywistości to one są programem! Słyszeliśmy, że nie możemy pozostać czyści, licząc na to, że zdrowienie po prostu samo w nas wsiąknie. Inaczej mówiąc, nie możemy oczekiwać, że poprzez samo chodzenie na mityngi, bez względu na ich ilość, zaczniemy wdychać zdrowienie porami naszej skóry. Zdrowienie, jak mówi inne powiedzenie, jest pracą wewnętrzną. Narzędziem, którego używamy do wykonania tej „wewnętrznej pracy” jest Dwanaście Kroków. Nieustanne słuchanie innych, mówiących o akceptacji jest jedną rzeczą, a osobista praca nad Pierwszym Krokiem jest zgoła czymś innym. Historie o dokonanych zadośćuczynieniach mogą być inspirujące, jednak nic nas nie uwolni tak skutecznie od wyrzutów sumienia, jak osobista praca nad Krokiem Dziewiątym. To samo dotyczy wszystkich innych Kroków. W NA jest wiele rzeczy, które można cenić, aby jednak w pełni czerpać ze zdrowienia, musimy indywidualnie pracować nad Dwunastoma Krokami.', 'Pragnę wszystkiego, co ma do zaoferowania mój osobisty program zdrowienia. Będę pracować nad krokami.'),
(71, '03-11', '11 marca', 'Zmniejszenie ciężaru', NULL, '„Ocenianie błędów innych nie uczyni z nas lepszych ludzi. Uporządkowanie własnego życia sprawi, że poczujemy się lepiej.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzasami potrzebujemy czegoś namacalnego, co pomogłoby nam zrozumieć jaki wpływ mają na nas urazy, które nosimy w sobie. Możemy nie zdawać sobie sprawy z tego, jak bardzo niszczące działanie mają urazy. Myślimy sobie: „Co z tego, mam prawo być zły” lub „mogę żywić do kogoś urazę, ale nie widzę w tym nic złego”. Aby dokładniej zobaczyć jaki wpływ mają urazy na nasze życie, wyobraźmy sobie, że każda uraza to kamień, który musimy nosić. Niewielka uraza, jak na przykład złość na kogoś, kto źle prowadzi samochód, to kamyk. Żywienie urazy do całej grupy ludzi jest niczym ogromny głaz. Gdybyśmy naprawdę musieli nosić kamienie za każdą urazę, na pewno bylibyśmy bardzo zmęczeni takim ciężarem. Tak naprawdę, to im bardziej dokuczliwy stanie się dla nas ten ciężar, tym bardziej szczere będą nasze wysiłki, by się go pozbyć. Ciężar naszych uraz utrudnia nam rozwój duchowy. Jeżeli naprawdę zapragniemy wolności, będziemy szukać sposobności, aby uwolnić się od tego dodatkowego ciężaru na tyle, na ile jest to możliwe. A w miarę pozbywania tego balastu zaczniemy dostrzegać w sobie wzrastającą zdolność do wybaczania błędów naszym bliźnim i sobie samym. Będziemy karmić naszego ducha dobrymi myślami, miłymi słowami i służbą na rzecz innych.', 'Będę dążył do tego, aby usunąć ciężar uraz z mojej duszy.'),
(72, '03-12', '12 marca', 'Wyrwać się z rutyny', NULL, '„Podczas naszego zdrowienia często prześladować nas będą dawne zmory. Życie znowu może się stać bezsensowne, monotonne i nudne.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nCzasami wydaje się, że nic się nie zmienia. Wstajemy i chodzimy codziennie do tej samej pracy. Co wieczór jemy o tej samej porze. Co tydzień chodzimy na te same mityngi. Poranne rytuały były takie same dzisiaj, wczoraj, przedwczoraj i przed przedwczoraj. Po całym piekle naszego uzależnienia i karuzeli wczesnego zdrowienia spokojna codzienność może być przyjemna - ale tylko przez chwilę. Przychodzi jednak taki moment, gdy uświadamiamy sobie, że chcemy czegoś więcej. Wcześniej czy później zaczynamy uciekać od wlekącej się w naszym życiu jednostajności i nudy. Z pewnością przyjdą takie chwile, gdy bez konkretnego powodu poczujemy się niezadowoleni z naszego zdrowienia. Czujemy się tak, jakby brakowało nam czegoś, ale nie wiemy czego i dlaczego. Sporządzamy listę wdzięczności i znajdujemy dosłownie setki rzeczy, za które możemy być wdzięczni. Wszystkie nasze potrzeby są zaspokajane a nasze życie jest pełniejsze niż kiedykolwiek mieliśmy na to nadzieję. Co się w takim razie dzieje? Być może nadszedł czas, aby wykorzystać w pełni nasz potencjał. Nasze możliwości ograniczone są jedynie naszymi marzeniami. Możemy nauczyć się czegoś nowego, wyznaczyć sobie nowy cel, pomóc innemu nowoprzybyłemu lub nawiązać nową przyjaźń. Jeśli poszukamy dokładnie, z pewnością znajdziemy jakieś wyzwanie, a nasze życie znów stanie się sensowne, urozmaicone i spełnione.', 'Zrobię sobie przerwę od rutyny i wykorzystam w pełni mój potencjał.'),
(73, '03-13', '13 marca', 'Ta jedna, wyjątkowa osoba', NULL, '„Sponsor nie musi być naszym przyjacielem, ale powinien być kimś, komu możemy zaufać. Z nim możemy dzielić się sprawami, które są dla nas zbyt krępujące, by dzielić się nimi na mityngu.”  \r\n\r\n~IP nr 11 \r\n\r\nPoprosiliśmy kogoś, aby nam sponsorował, a powodów tego, że poprosiliśmy właśnie tę, a nie inną osobę może być tak wiele, jak wiele jest ziarenek piasku na plaży. Być może słyszeliśmy jego wypowiedzi na mityngu i uznaliśmy je za zabawne lub inspirujące. Może pomyśleliśmy o tym, że ta osoba ma super samochód i jeśli my będziemy pracować nad programem tak jak ona, to też taki będziemy mieli. Być może mieszkamy w małym mieście i ta osoba była jedyną, która miała czas, aby nam pomóc. Bez względu na to, czym kierowaliśmy się przy wyborze naszego sponsora, z pewnością zauważymy, że przyczyny, dla których będziemy chcieli nadal utrzymywać tę relację, są zupełnie inne. Nagle zadziwia nas zaskakującym wglądem i zastanawiamy się czy przypadkiem nie czytał potajemnie naszego Czwartego Kroku. Być może tkwimy właśnie w jakimś życiowym kryzysie, a jego doświadczenia w podobnych problemach pomagają nam w sposób, o jakim nigdy nie myśleliśmy, że jest możliwy. Gdy cierpimy, dzwonimy do niego, a on znajduje właściwe słowa, aby nas rzeczywiście pocieszyć. I żadne z tych ważnych dla nas rzeczy, które reprezentuje sobą i robi nasz sponsor nie są kwestią przypadku. On po prostu szedł przed nami tą samą ścieżką. Siła Wyższa postawiła tę wyjątkową osobę na naszej drodze i jesteśmy wdzięczni za jej obecność.', 'Docenię tę jedną wyjątkową osobę w moim życiu - mojego sponsora.'),
(74, '03-14', '14 marca', 'Relacje', NULL, '„Nasze obrachunki moralne zawierają również materiał dotyczący relacji z innymi ludźmi.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCóż za niedopowiedzenie! Zwłaszcza w późniejszym okresie zdrowienia cały obrachunek może skupić się właśnie na naszych relacjach z innymi ludźmi. Nasze życie wypełnione było relacjami z kochankami, przyjaciółmi, rodzicami, współpracownikami, dziećmi i innymi ludźmi, z którymi mieliśmy kontakt. Przyjrzenie się tym związkom może powiedzieć nam bardzo dużo o istocie naszego charakteru. Często w naszych obrachunkach pojawiają się urazy, które powstają w wyniku naszych codziennych wzajemnych relacjach z innymi. Staramy się dostrzec jaki jest nasz udział w tych konfliktach. Być może mamy nierealne oczekiwania wobec innych ludzi? Może narzucamy innym nasz sposób myślenia? Może jesteśmy czasem całkowicie nietolerancyjni? Często samo pisanie obrachunku uwalnia nas od napięcia spowodowanego trudnymi relacjami. Musimy jednak również podzielić się naszym obrachunkiem z innym człowiekiem. W ten sposób możemy zobaczyć jaki jest nasz udział w danym problemie i jak możemy znaleźć rozwiązanie. Obrachunek moralny jest narzędziem, które pozwala nam rozpocząć uzdrawianie naszych relacji. Uczymy się, że dziś z pomocą tego narzędzia możemy zacząć czerpać z tych relacji radość.', 'Zrobię obrachunek mojego udziału w relacjach z innymi. Spróbuję w sposób bogatszy i bardziej odpowiedzialny brać udział w tych relacjach.'),
(75, '03-15', '15 marca', 'Czuć się „częścią czegoś”', NULL, '„Spotkania po naszych mityngach są dobrą okazją do dzielenia się sprawami, o których nie dało się podyskutować w czasie mityngu.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzynne uzależnienie stawiało nas poza nawias społeczeństwa, izolowało nas. Źródłem naszego wyobcowania był strach. Uważaliśmy, że jeśli pozwolimy innym poznać nas bliżej, to na pewno zobaczą jacy jesteśmy okropni. Odrzucenie byłoby już tylko kwestią czasu. Gdy przychodzimy na nasz pierwszy mityng NA, jesteśmy zazwyczaj pod wrażeniem rodzinnej i przyjacielskiej atmosfery panującej pomiędzy innymi zdrowiejącymi uzależnionymi. My również możemy stać się częścią tej wspólnoty, jeżeli sobie na to pozwolimy. Jednym ze sposobów rozpoczęcia tego, może być przyłączenie się do wypadu do kawiarni po mityngu. Na takich spotkaniach możemy pozwolić runąć murom odgradzającym nas od innych i dowiedzieć się wielu nowych rzeczy o sobie i o innych członkach NA. Być może w cztery oczy będzie nam czasem łatwiej ujawnić sprawy, którymi niechętnie byśmy się dzielili przy całej grupie. Na wielu spośród takich wieczornych spotkań możemy zarówno uczyć się luźnych pogawędek, jak i nawiązywać głębokie, niezawodne przyjaźnie. Dzięki naszym nowopoznanym przyjaciołom z NA już nie musimy dłużej żyć w izolacji. Możemy stać się częścią wielkiej całości - Wspólnoty Anonimowych Narkomanów.', 'Wyrwę się z izolacji. Będę dążyć do tego, by poczuć się częścią Wspólnoty NA.'),
(76, '03-16', '16 marca', 'Obrachunek moralny', NULL, '„Celem szczegółowego i odważnego obrachunku moralnego jest uporządkowanie chaosu i sprzeczności panujących w naszym życiu, w wyniku czego będziemy mogli dowiedzieć się, kim naprawdę jesteśmy.”   \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzynnie uzależnieni żyją w chaosie i powodują chaos w swoim otoczeniu. Trudno jest przewidzieć co zrobią lub jacy będą w następnej chwili. Zazwyczaj sami uzależnieni są tak samo zaskoczeni tym, co robią, jak wszyscy inni. Kiedy braliśmy, nasze zachowanie było uwarunkowane potrzebami czynnego uzależnienia. Wielu z nas wciąż jeszcze uważa, że ich zachowanie w czasie czynnego uzależnienia było wyrazem ich osobowości i czują z tego powodu zwątpienie i wstyd. Dzisiaj nie musimy już być takimi ludźmi, jakimi byliśmy kiedyś, czyli kształtowanymi przez nasze uzależnienie; zdrowienie pozwala nam zmieniać się. Obrachunku Kroku Czwartego możemy użyć do tego, by spojrzeć poza potrzeby związane z dawnym uzależnionym życiem i dowiedzieć się, kim chcielibyśmy być dzisiaj. Opisywanie naszych zachowań i towarzyszących tym zachowaniom uczuć pomaga nam zrozumieć, kim chcielibyśmy być. Nasz obrachunek pomaga nam spojrzeć poza to, co wiąże się z potrzebami czynnego uzależnienia i poza nasze pragnienie bycia kochanym i akceptowanym – odkrywamy, kim naprawdę jesteśmy. Zaczynamy rozumieć co jest dla nas właściwe i jakie chcielibyśmy by było nasze życie. Jest to początek stawania się tym, kim naprawdę jesteśmy.', 'Jeżeli chcę się dowiedzieć kim jestem, przyjrzę się temu kim byłem i kim chcę być.'),
(77, '03-17', '17 marca', 'Prawdziwa odwaga', NULL, '„Ci, którym udaje się przetrwać trudne chwile, demonstrują odwagę, ale nie własną.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPrzed przyjściem do NA wielu z nas uważało się za odważnych ludzi tylko dlatego, że nigdy nie doświadczyło strachu. Tłumiliśmy narkotykami wszystkie nasze uczucia, w tym również strach, tak długo, dopóki nie przekonaliśmy samych siebie, że jesteśmy odważnymi i twardymi ludźmi, którzy nic nie złamie. Lecz odwaga oparta na narkotykach nie ma nic wspólnego z naszym obecnym sposobem życia. Zachowując czystość i zdrowiejąc, będziemy z pewnością czasami odczuwać strach. Gdy po raz pierwszy zauważymy, że się boimy, możemy pomyśleć, że jesteśmy tchórzami. Obawiamy się podnieść słuchawkę telefonu, ponieważ osoba po drugiej stronie może nas nie zrozumieć. Boimy się poprosić kogoś o sponsorowanie, ponieważ może nam odmówić. Boimy się szukać pracy. Boimy się być szczerzy z naszymi przyjaciółmi. Wszystkie te lęki są jednak naturalne i zdrowe. Niezdrowym jest pozwalanie na to, by strach nas paraliżował. Gdy pozwolimy naszym lękom, by powstrzymały nasz wzrost, zostaniemy pokonani. Prawdziwą odwagą nie jest brak strachu, lecz gotowość do tego, aby go pokonać.', 'Dzisiaj będę odważny. Jeśli się czegoś przestraszę, zrobię wszystko, co jest niezbędne do tego, by wzrastać w zdrowieniu.'),
(78, '03-18', '18 marca', 'Pełnia posłania', NULL, '„Na uzależnionym szczególne wrażenie robi odkrycie, że są inni ludzie, którzy w przeszłości i dziś również zmagają się z trudnościami podobnymi do jego trudności.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nBogactwo naszego zdrowienia jest zbyt wielkie, by zatrzymać je wyłącznie dla siebie. Niektórzy z nas uważają, że dzieląc się na mityngach, powinniśmy „pamiętać o nowoprzybyłym” i zawsze starać się nieść pozytywne posłanie. Czasem jednak najbardziej pozytywnym posłaniem, jakie możemy zanieść, jest podzielnie się tym, że właśnie teraz przechodzimy przez trudne chwile w naszym zdrowieniu i pomimo to pozostajemy czyści! Tak, przekazywanie naszym nowoprzybyłym pozytywnego przesłania nadziei daje nam dużo satysfakcji. Wiadomo jest, że nikt nie przepada za marudami. Zdarzają się jednak rzeczy bolesne, a życie, takie jakie jest, może zszokować nawet długo zdrowiejących członków NA. Jeśli jesteśmy wyposażeni w narzędzia programu, będziemy mogli przejść, zachowując czystość, przez każdą nawałnicę i będziemy mogli opowiedzieć o tym innym. Zdrowienie nie następuje od razu. Jest ono nieustającym procesem, a czasem również zmaganiem. Gdy rozcieńczamy pełnię naszego posłania tym, że pomijamy dzielenie się naszymi trudnymi chwilami, przez które przechodzimy w naszej wędrówce, pozbawiamy nowoprzybyłych szansy zobaczenia tego, że oni także mogą pozostać czystymi bez względu na to, co by się nie działo. Jeżeli nasze dzielnie się posłaniem ze zdrowienia będzie pełne, być może nie dowiemy się kto z tego skorzysta, ale możemy być pewni, że ktoś na pewno skorzysta. ', 'Będę uczciwie dzielił się zarówno dobrymi jak i trudnymi chwilami mojego zdrowienia. Będę pamiętał, że moje doświadczenie dotyczące zmagania się z przeciwnościami losu może być pomocne innym członkom wspólnoty.'),
(79, '03-19', '19 marca', 'Dzieląc się czymś wartościowym', NULL, '„Proste, uczciwe posłanie zdrowienia z uzależnienia brzmi wiarygodnie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJesteś na mityngu. Już od pewnego czasu trwa dzielenie się. Jeden lub dwóch uczestników mityngu opisało swoje duchowe doświadczenia w bardzo ujmujący sposób. Ktoś inny rozbawił nas swoimi wesołymi historiami. I wtedy prowadzący zaprasza do wypowiedzi ciebie. Ups! Nieśmiało przedstawiasz się, jąkając się, przepraszającym tonem wyciskasz z siebie kilka zdań, dziękujesz wszystkim za wysłuchanie i przez resztę mityngu siedzisz cicho w zakłopotaniu. Czy to brzmi znajomo? Nie tylko tobie tak się przytrafia. Wszyscy mieliśmy kiedyś uczucie, że to, czym się podzieliliśmy nie było wystarczająco duchowe, wystarczająco zabawne, czy wystarczająco jakieś tam. Jednak dzielenie się, to nie zawody. Wewnętrzną zawartością naszych mityngów jest identyfikacja i doświadczenie, to coś, czego my wszyscy mamy w nadmiarze. Gdy z głębi serca i uczciwie dzielimy się naszym doświadczeniem, inni uzależnieni czują, że mogą nam zaufać, ponieważ wiedzą, że jesteśmy tacy sami jak oni. Gdy w prosty sposób dzielimy się tym, co w naszym życiu zadziałało, możemy być pewni, że nasze posłanie pomoże innym. Nasze dzielenie się nie musi być ani szczególnie bystre, ani szczególnie wesołe, by brzmiało uczciwie. Wszyscy uzależnieni, którzy uczciwie pracują nad prowadzącym do zdrowienia programem, mogą podzielić się czymś o niezmiernej wartości, czymś, czym nie może się podzielić nikt inny: swoim własnym doświadczeniem.', 'Mam coś wartościowego, czym mogę się podzielić. Pójdę dziś na mityng i podzielę się moim doświadczeniem ze zdrowienia z choroby uzależnienia.'),
(80, '03-20', '20 marca', 'Siła Wyższa', NULL, '„Większość z nas nie ma problemu z tym by się przyznać do tego, że uzależnienie stało się w naszym życiu siłą destrukcyjną. Pomimo naszych wysiłków coraz bardziej wyniszczaliśmy się i wpadaliśmy w coraz większą rozpacz. W pewnym momencie zdaliśmy sobie sprawę z tego, że potrzebujemy pomocy jakiejś Siły większej od naszego uzależnienia.”\r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas nie ma wątpliwości co do tego, że nasze życie było przepełnione destrukcją. Wiedza o tym, że jesteśmy chorzy na chorobę zwaną uzależnieniem, pomaga nam zrozumieć źródło i przyczyny tej destrukcji. Widzimy, że uzależnienie jest siłą, która spowodowała spustoszenie w naszym życiu. W Pierwszym Kroku przyznajemy, że destrukcyjna siła uzależnienia jest większa od nas samych. Jesteśmy wobec niej bezsilni. W tej sytuacji naszą jedyną nadzieją jest znalezienie jakiejś Siły większej, niż moc naszego uzależnienia - Siły, której zależy na zachowaniu naszego życia, a nie na jego zakończeniu. Nie musimy jej rozumieć ani nazywać; musimy tylko wierzyć, że może istnieć taka Siła Wyższa. Wiara w możliwość istnienia jakiejś życzliwej Siły większej, niż nasze uzależnienie, daje nam wystarczająco dużo nadziei, abyśmy mogli zachować czystość przez jeden dzień. ', 'Wierzę w istnienie jakiejś Siły większej od mojego uzależnienia.'),
(81, '03-21', '21 marca', 'Choroba, którą można leczyć', NULL, '„Uzależnienie jest chorobą, która dotyczy nie tylko zażywania narkotyków.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nByć może na naszym pierwszym mityngu byliśmy zaskoczeni, słuchając członków NA, którzy mówili o tym, jak choroba uzależnienia wpłynęła na ich życie. Myśleliśmy sobie: „Choroba? Mamy tylko problem z narkotykami! O czym do licha oni mówią?” Po pewnym czasie pracy nad programem zaczęliśmy dostrzegać, że nasze uzależnienie sięga głębiej, niż nasze obsesyjne i kompulsywne zażywanie narkotyków. Zobaczyliśmy, że cierpieliśmy z powodu chronicznej choroby, która wpłynęła na wiele sfer naszego życia. Nie wiedzieliśmy, gdzie zaraziliśmy się tą chorobą, ale analizując siebie, zdaliśmy sobie sprawę, że była ona w nas obecna od wielu lat. Choroba uzależnienia wpływa na wszystkie sfery naszego życia i podobnie też działa program NA. Na swój pierwszy mityng przychodzimy ze wszystkimi objawami tej choroby: duchową pustką, emocjonalną agonią, bezsilnością i nieumiejętnością kierowania własnym życiem. Leczenie naszej choroby wymaga czegoś więcej, niż tylko abstynencji. Używamy do tego Dwunastu Kroków. Pomimo, iż nie są one lekarstwem, zaczynają nas uzdrawiać. Zdrowiejąc, doświadczamy daru życia.', 'Będę leczył moją chorobę, stosując Program Dwunastu Kroków.'),
(82, '03-22', '22 marca', 'Zasada samowystarczalności', NULL, '„Gdy braliśmy, byliśmy zależni od ludzi, miejsc i rzeczy. Szukaliśmy w nich wsparcia i oczekiwaliśmy, że dostarczę na to, czego brakowało nam w nas samych.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW królestwie zwierząt istnieje takie stworzenie, które żywi się innymi. Jest nim pasożyt. Przyczepia się on do ludzi i wyciąga z nich to, czego potrzebuje. Gdy jedna ofiara zdoła się go pozbyć, pasożyt przenosi się na inną. W naszym czynnym uzależnieniu zachowywaliśmy się podobnie. Osaczyliśmy nasze rodziny, przyjaciół i środowisko otaczających nas ludzi. Świadomie bądź też nieświadomie chcieliśmy praktycznie od każdego, kogo tylko spotkaliśmy, coś zdobyć, nie dając nic w zamian. Kiedy na naszym pierwszym mityngu zobaczyliśmy kapelusz, być może pomyśleliśmy: „Samowystarczalność! Cóż to za pomysł!?”. Przyglądając się na tym mityngu ludziom, zauważyliśmy jedną rzecz. Ci samowystarczalni uzależnieni byli wolni. Dzięki temu, że sami płacili, uzyskali przywilej podejmowania własnych decyzji. Jeśli w naszym życiu osobistym stosujemy zasadę samowystarczalności, sami zyskujemy ten rodzaj wolności. Już nikt nie ma prawa nam powiedzieć, gdzie mamy mieszkać, ponieważ sami opłacamy swój czynsz. Możemy jeść i nosić to co chcemy, jeździć tym czym chcemy, ponieważ sami się utrzymujemy. W przeciwieństwie do pasożyta, chcąc się pożywić, nie musimy być zależni od innych. Im więcej odpowiedzialności weźmiemy na siebie, tym więcej uzyskamy wolności.', 'Samowystarczalność może zapewnić mi bezgraniczną wolność. Dziś wezmę odpowiedzialność za siebie samego i będę opłacać własne rachunki na bieżąco.'),
(83, '03-23', '23 marca', 'Dary od Boga', NULL, '„Idziemy przez życie, przyjmując to, co przynosi nam codzienność.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNasz związek z Siłą Wyższą jest jak dwukierunkowa ulica. Modląc się, mówimy do Boga, a On słucha. Medytacja zaś jest najlepszym sposobem, żeby usłyszeć, jaka jest wola naszej Siły Wyższej. Wiemy, że jesteśmy odpowiedzialni za naszą postawę w tym związku. Jeżeli nie modlimy się i nie słuchamy, zamykamy się na wejście naszej Siły Wyższej w nasze życie. Gdy myślimy o związku z naszą Siłą Wyższą, musimy pamiętać o tym, że to my jesteśmy bezsilni. Możemy prosić o pokierowanie nami, możemy prosić o chęć do zmian i siłę, możemy prosić o poznanie woli naszej Siły Wyższej - jednak nie możemy stawiać żądań. Bóg, jakkolwiek Go pojmujemy - ten, który ma moc – zrealizuje swoją część tej relacji, dając nam dokładnie to, czego potrzebujemy, wtedy, gdy tego potrzebujemy. Musimy codziennie wykonywać czynności, które będą utrzymywać nasz związek z Siłą Wyższą przy życiu. Jednym ze sposobów na to jest stosowanie Jedenastego Kroku. Stosując go, pamiętamy o naszej bezsilności i uznajemy wolę Siły większej od nas samych.', 'To ja jestem bezsilny w moim związku z Siłą Wyższą. Dzisiaj, pamiętając kim jestem, będę pokornie przyjmował dary od Boga, jakkolwiek Go pojmuję.'),
(84, '03-24', '24 marca', 'Pozwolić odejść przeszłości', NULL, '„Nie liczy się to, skąd przyszliśmy, lecz dokąd podążamy.“  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy po raz pierwszy stykamy się ze zdrowieniem, niektórzy z nas odczuwają wstyd lub mają pewne wątpliwości, by przedstawiać się jako „uzależnieni”. W pierwszych dniach, walcząc o nowy sens swojego życia, jesteśmy przepełnieni zarówno strachem jak i nadzieją. Może się nam wydawać, że nie zdołamy uciec od naszej przeszłości, mamy wrażenie, że ona nas przytłacza. Myślenie o sobie inaczej niż przywykliśmy do tej pory może sprawiać nam trudność. Wspomnienia z przeszłości mogą służyć nam jako ostrzeżenie przed tym, co nas czeka, jeślibyśmy znów zaczęli brać, ale mogą one również uwięzić nas w koszmarze wstydu i strachu. I chociaż być trudno jest nam pozwolić odejść tym wspomnieniom, to każdy dzień zdrowienia coraz bardziej oddala nas od czynnego uzależnienia. Każdego dnia mamy więcej powodów do tego, aby patrzeć optymistycznie w przyszłość i mniej, żeby się karać. W zdrowieniu wszystkie drzwi stoją przed nami otworem. Mamy wiele możliwości wyboru. Nasze nowe życie jest bogate i pełne obietnic. I chociaż nie możemy zapomnieć naszej przeszłości, to nie musimy już w dłużej nią żyć. Możemy iść do przodu.', 'Spakuję swoje rzeczy i wyprowadzę się z przeszłości do przepełnionej nadzieją teraźniejszości.'),
(85, '03-25', '25 marca', 'Ja nie mogę, lecz my możemy', NULL, '„Wychodząc z izolacji naszego uzależnienia, znajdujemy wspólnotę ludzi, których łączą wspólne więzi... Nasza wiara, siła i nadzieja pochodzą od ludzi dzielących się swoim zdrowieniem...”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNie przyznawaj się do słabości, ukrywaj wszystkie niedoskonałości, zaprzeczaj każdemu błędowi, zrób to sam - to było kredo, którym kierowała się większość z nas. Zaprzeczaliśmy naszej bezsilności wobec uzależnienia i temu, że przestaliśmy kierować naszym życiem, wbrew wszystkim dowodom, które świadczyły, że jest przeciwnie. Wielu z nas nie poddawało się dopóki nie upewniliśmy się, że jest coś, czemu warto się poddać. Wielu z nas zrobiło Pierwszy Krok dopiero wtedy, gdy zobaczyliśmy dowody tego, że uzależnieni mogą zdrowieć w oparciu o program NA. W NA spotykamy ludzi, którzy będąc w podobnie trudnej sytuacji i potrzebie jak my, znaleźli narzędzia umożliwiające im zmienić tę sytuację. Ci uzależnieni są gotowi podzielić się z nami tymi narzędziami i dać nam emocjonalne wsparcie, które przyda się nam, gdy nauczymy się z nich korzystać. Zdrowiejący uzależnieni wiedzą, jak ważna może być pomoc innych, ponieważ swego czasu sami otrzymali taką pomoc. Gdy stajemy się częścią NA, przystępujemy do towarzystwa ludzi uzależnionych, takich jak my, do grupy ludzi, którzy wiedzą, że zdrowienie polega na wzajemnej pomocy.', 'Przyłączę się do wspólnoty zdrowienia. Potrzebne mi doświadczenie, siłę i nadzieję znajdę we Wspólnocie Anonimowych Narkomanów.'),
(86, '03-26', '26 marca', ' Zaufanie sponsorowi jest warte ryzyka\r\n', NULL, '„Szukając sponsora, większość członków NA rozgląda się za kimś, komu mogliby nauczyć się ufać, kogoś, kto wydaje się być osobą współczującą…” \r\n\r\n~IP nr 11\r\n\r\nIdea sponsorowania może być dla nas czymś zupełnie nowym. Wiele lat spędziliśmy, nie słuchając żadnych wskazówek, polegając wyłącznie na sobie, zachowując wobec wszystkich postawę podejrzliwości i braku zaufania. Teraz, gdy uczymy się żyć zdrowiejąc, stwierdzamy, że potrzebujemy pomocy. Nie ze wszystkim potrafimy poradzić sobie sami. Musimy podjąć ryzyko zaufania innemu człowiekowi. Często, pierwszą osobą, wobec której podejmujemy to ryzyko, jest nasz sponsor - osoba, którą szanujemy, z którą się identyfikujemy, osoba, której możemy zaufać. Kiedy otwieramy się przed naszym sponsorem, rozwija się między nami więź. Odkrywamy przed sponsorem nasze tajemnice i nabieramy zaufania co do jego dyskrecji. Dzielimy się z nim naszymi zmartwieniami i uczymy się korzystać z jego doświadczeń. Dzielimy się naszym bólem i spotykamy się z empatią. Poznajemy się nawzajem, zaczynamy się wzajemnie szanować i kochać. Im bardziej ufamy naszemu sponsorowi, tym bardziej uczymy się ufać sobie samym. Zaufanie pomaga nam wyjść z życia pełnego strachu, niepewności, podejrzliwości i dezorientacji. Na początku, zaufanie drugiemu uzależnionemu wydaje się nam ryzykowne. To zaufanie jest jednak tą samą zasadą, którą stosujemy w relacji z naszą Siłą Wyższą - ryzykowne czy nie, nasze doświadczenie pokazuje, że bez tego się nie da. Im bardziej podejmujemy ryzyko zaufania naszemu sponsorowi, tym bardziej otwarci będziemy wobec naszego życia. ', 'Chcę wzrastać i zmieniać się. Podejmę ryzyko zaufania mojemu sponsorowi i zostanę za to wynagrodzony.'),
(87, '03-27', '27 marca', 'Szukając zalet', NULL, '„Zgodnie z zasadami zdrowienia staramy się nie oceniać, nie szufladkować i nie moralizować się nawzajem.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nJakże często w naszym zdrowieniu mylnie ocenialiśmy czyjeś zachowanie, natychmiast formułując osąd, przyklejając etykietkę i szufladkując daną osobę? Być może inni rozwinęli w sobie odmienne od naszego wyobrażenie Siły Wyższej, które my uznaliśmy za pozbawione duchowości. Albo widzieliśmy jakąś parę, która miała sprzeczkę i przyjęliśmy, że ich związek jest chory, by potem dowiedzieć się, że od lat są udanym małżeństwem. Bezmyślne szufladkowanie naszych przyjaciół ze wspólnoty chroni nas przed włożeniem wysiłku w to, by dowiedzieć się o nich czegoś więcej. Za każdym razem, gdy osądzamy zachowanie innych, przestajemy postrzegać ich jako potencjalnych przyjaciół i partnerów na drodze zdrowienia. Gdybyśmy zapytali tych, których oceniamy, czy lubią być szufladkowani, usłyszelibyśmy w odpowiedzi głośne „nie!”. A czy nam nie przeszkadzałoby, gdybyśmy byli tak traktowani? Ależ oczywiście, że tak! Chcemy, aby inni dostrzegali nasze najlepsze cechy. Podobnie też nasi zdrowiejący uzależnieni przyjaciele ze wspólnoty chcą być dobrze postrzegani. Nasz program zdrowienia oczekuje od nas pozytywnego spojrzenia na życie. Im bardziej koncentrujemy się na pozytywnych cechach innych osób, tym więcej zauważamy ich u siebie. ', 'Odłożę na bok moje negatywne ocenianie innych i zamiast tego skoncentruję się na docenianiu ich pozytywnych cech.'),
(88, '03-28', '28 marca', 'Konfrontując się z uczuciami', NULL, '„Możemy obawiać się, że wchodząc w kontakt ze swoimi uczuciami wyzwolimy przytłaczający łańcuch reakcji bólu i paniki.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy braliśmy, wielu z nas nie było w stanie lub nie chciało odczuwać wielu emocji. Gdy byliśmy szczęśliwi, uszczęśliwialiśmy siebie jeszcze bardziej. Gdy byliśmy źli lub pogrążeni w depresji, zwykle maskowaliśmy te uczucia. Kontynuując ten wzorzec przez cały czas naszego aktywnego uzależnienia, zagmatwaliśmy się emocjonalnie do takiego stopnia, że nie wiedzieliśmy już czym są normalne uczucia. Po pewnym czasie, od chwili rozpoczęcie zdrowienia, widzimy, że emocje, które tłumiliśmy, nagle zaczynają wychodzić na powierzchnię. Może okazać się, że nie potrafimy zidentyfikować naszych uczuć. To, co wydaje się nam wściekłością, może być tylko frustracją, a to, co nazywamy depresją z myślami samobójczymi, może być po prostu smutkiem. Są to te sytuacje, w których potrzebujemy pomocy naszego sponsora lub innego członka NA. Pójście na mityng i powiedzenie o tym, co się dzieje w naszym życiu, może pomóc nam w tym, byśmy mogli konfrontować się ze swoimi uczuciami zamiast z lękiem przed nimi uciekać.', 'Nie będę uciekać przed nieprzyjemnymi uczuciami, których mogę doświadczyć. Będę korzystać ze wsparcia moich przyjaciół w zdrowieniu, aby pomóc sobie w konfrontacji ze swoimi uczuciami.'),
(89, '03-29', '29 marca', 'Nasza prawdziwa własna wola ', NULL, '„Wola Boga w stosunku do nas składa się z rzeczy, które są dla nas najcenniejsze. Wola Boga... staje się naszą prawdziwą własną wolą w stosunku do samych siebie.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nW ludzkiej naturze leży chęć otrzymania czegoś za darmo. Możemy być zachwyceni, gdy kasjer przez pomyłkę wyda nam resztę z 20 zł, chociaż zapłaciliśmy 10 zł. Mamy skłonność do tego, aby myśleć, że małe oszustwo nie ma większego znaczenia, jeżeli nikt o tym nie wie. Jest jednak ktoś, kto o tym wie - mianowicie my sami. A to zmienia postać rzeczy. Zasady, którymi kierowaliśmy się w czynnym uzależnieniu nie sprawdzają się zbyt długo w zdrowieniu. Gdy rozwijamy się duchowo, pracując nad Dwunastoma Krokami, zaczynamy rozwijać w sobie nowe wartości i standardy. Nieuczciwość zaczyna sprawiać nam dyskomfort, wykorzystanie jakiejś sytuacji z możliwością uniknięcia konsekwencji przestaje być powodem do dumy. Być może w przeszłości krzywdziliśmy i wykorzystywaliśmy innych. Gdy jednak zbliżamy się do naszej Siły Wyższej, nasze wartości zmieniają się. Wola Boga staje się ważniejsza od faktu, że coś mogłoby nam ujść na sucho. Kiedy zmieniają się nasze wartości, zmienia się również nasze życie. Prowadzeni wewnętrzną wiedzą daną nam przez Siłę Wyższą chcemy żyć według nowo odkrytych wartości. Przyjęliśmy wolę naszej Siły Wyższej, którą ma ona wobec nas i faktycznie, wola Boga stała się naszą prawdziwą własną wolą. ', 'Poprzez rozwijanie mojego świadomego kontaktu z Bogiem moje wartości zmieniły się. Dzisiaj będę praktykować wolę Boga, moją prawdziwą własną wolę.'),
(90, '03-30', '30 marca', 'Koncentracja na Bogu', NULL, '„Stopniowo, stajemy się bardziej skoncentrowani na Bogu niż na sobie i nasza rozpacz zamienia się w nadzieję.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nJak cudownie jest mieć nadzieję! Zanim przyszliśmy do NA wielu z nas żyło bez jakiejkolwiek nadziei. Byśmy przekonani, że naszym przeznaczeniem jest śmierć z powodu naszej choroby. Wielu członków naszej wspólnoty mówi, że w pierwszych miesiącach zdrowienia wszystko postrzegali w różowych kolorach. Przestaliśmy brać, zawarliśmy nowe przyjaźnie i życie wygląda obiecująco. Wszystko układa się wspaniale. I wtedy nadchodzi rzeczywistość. Życie jest ciągle życiem - wciąż się zdarza, że tracimy pracę, że zastawiają nas nasi partnerzy, że umierają przyjaciele lub przytrafiają się nam choroby. Abstynencja nie daje gwarancji, że życie będzie toczyć się po naszej myśli. Kiedy rzeczywistość życia jawi się nam w pełnej okazałości, zwracamy się do naszej Siły Wyższej i przypominamy sobie, że życie jest takie, jakie jest. Lecz bez względu na to, co by się nie działo w naszym zdrowieniu, nie musimy pogrążać się w rozpaczy, ponieważ zawsze jest nadzieja. Ta nadzieja leży w naszej relacji z Siłą Wyższą. Relacja ta rozwija się wraz z upływem czasu: „Stopniowo, stajemy się coraz bardziej skoncentrowani na Bogu”. Gdy coraz bardziej zdajemy się na moc naszej Siły Wyższej, przeciwności losu nie wpędzają już nas w rozpacz. Im bardziej koncentrujemy się na Bogu, tym mniej jesteśmy skoncentrowani na sobie', 'Zdam się na moją Siłę Wyższą. Zaakceptuję fakt, że bez względu na to, co się dzieje, moja Siła Wyższa zapewnia mi środki niezbędne do życia.'),
(91, '03-31', '31 marca', 'Wewnątrz i na zewnątrz', NULL, '„Naszą prawdziwą wartością jest bycie samym sobą.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nPodczas pracy nad krokami nieuniknionym jest odkrycie kilku podstawowych prawd o sobie. Proces odkrywania i ujawniania naszych tajemnic oraz badania naszego charakteru odsłoni naszą prawdziwą naturę. Gdy poznajemy samych siebie, musimy zdecydować się na to, aby być takimi, jakimi naprawdę jesteśmy. Może powinniśmy przyjrzeć się temu, co prezentujemy światu i zdrowiejącym z nami uzależnionym i zadać sobie pytanie, czy pasuje to do tego, co odkryliśmy w naszym wnętrzu. Czy udajemy, że nic nas nie obchodzi, podczas gdy w środku jesteśmy bardzo wrażliwi? Czy ukrywamy naszą niepewność siebie pod głupimi żartami, czy dzielimy się naszymi lękami z innymi? Czy ubieramy się jak nastolatki, chociaż dochodzimy do czterdziestki i tak na prawdę jesteśmy dość konserwatywni? Może powinniśmy inaczej spojrzeć na te rzeczy, które uznawaliśmy za „nie nasze”. Być może unikaliśmy NA-owskich imprez, ponieważ „nie lubimy tłumów”. A może mieliśmy ciche marzenie o zmianie zawodu, ale nie podjęliśmy w tym kierunku żadnych działań, ponieważ uznaliśmy, że nasze marzenia „są niepoprawne”? Gdy dojdziemy do nowego rozumienia siebie, będziemy również chcieli odpowiednio dopasować swoje zachowanie. Chcemy być tacy, jacy naprawdę jesteśmy.', 'Przyjrzę się swemu zewnętrznemu wizerunkowi, aby upewnić się, że pokrywa się on z moim wnętrzem. Spróbuję zachowywać się odpowiednio do poziomu wzrostu, którego doświadczyłem w zdrowieniu.'),
(92, '04-01', '1 kwietnia', 'Miłość i uzależnienie', NULL, '„Niektórzy z nas po raz pierwszy zauważyli konsekwencje swojego uzależnienia, przyglądając się swoim bliskim. Byliśmy bardzo zależni od ich wsparcia. Gdy znajdowali inne zainteresowania, przyjaciół lub okazywali komuś innemu miłość byliśmy źli, rozczarowani i czuliśmy się zranieni.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nUzależnienie miało wpływ na każdą sferę naszego życia. Tak jak szukaliśmy narkotyku, który załatwiłby nasze problemy, tak też szukaliśmy ludzi, którzy mogliby nas postawić na nogi. Żądaliśmy rzeczy niemożliwych, równocześnie odpychając tych, którzy mogli zaoferować nam coś wartościowego. Często pozostawali przy nas jedynie tacy ludzie, którzy sami byli zbyt słabi, aby przeciwstawić się naszym nierealnym oczekiwaniom. Nie ma w tym nic dziwnego, że biorąc, nie byliśmy w stanie zbudować i utrzymać zdrowych związków z innymi ludźmi. Dzisiaj, zdrowiejąc, przestaliśmy oczekiwać, że narkotyki załatwią nam cokolwiek. Jeżeli wciąż oczekujemy, że zrobią to jacyś ludzie, to być może nadszedł już czas na ogarnięcie programem zdrowienia naszych związków. Zaczynamy od przyznania się do tego, że mamy problem, ponieważ nie mamy zielonego pojęcia jak stworzyć zdrowy związek. Następnie, poszukujemy ludzi ze wspólnoty NA, którzy mieli podobne problemy i znaleźli rozwiązanie. Rozmawiamy z nimi i słuchamy ich doświadczenia dotyczącego tego aspektu ich zdrowienia. Stosujemy program we wszystkich naszych poczynaniach, poszukując w naszych związkach takiej samej wolności, jaką uzyskaliśmy w zdrowieniu.', 'Związki pełne miłości są w zasięgu ręki. Dziś przyjrzę się temu, jaki wpływ ma uzależnienie na moje związki i wtedy będę mógł rozpocząć ich uzdrawianie.'),
(93, '04-02', '2 kwietnia', 'Przyciąganie', NULL, '„Nasz wizerunek publiczny składa się z tego, co mamy do zaoferowania: z efektywnego i wypróbowanego sposobu na utrzymanie wolnego od narkotyków stylu życia.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nTak, przyciągamy nowe osoby. Coraz więcej uzależnionych trafia do NA. Lecz jak właściwie traktujemy nowych członków naszej wspólnoty, którzy przychodzą do nas wypaleni swoją walką z uzależnieniem? Czy wyciągamy rękę do nowoprzybyłych, którzy na naszych mityngach stoją z boku, zmieszani i niepewni? Czy jesteśmy gotowi podwieźć ich na mityng? Czy ciągle pracujemy z uzależnionymi, którzy wciąż jeszcze cierpią? Czy dajemy nowoprzybyłym swój numer telefonu? Czy godzimy się chętnie na telefon w ramach Dwunastego Kroku, nawet jeśli oznacza to, że musimy w środku nocy wstać z naszego ciepłego łóżka? Czy jesteśmy gotowi pracować z kimś, kto ma inną orientację seksualną lub pochodzi z innej kultury? Czy dobrze wykorzystujemy darowany nam czasy? Z pewnością zostaliśmy przyjęci do naszej wspólnoty z miłością i akceptacją. Tym, co przyciągnęło wielu z nas do NA było poczucie, że w końcu odnaleźliśmy miejsce, do którego przynależymy. Czy dajemy naszym nowoprzybyłym takie samo poczucie przynależności? Nie możemy reklamować NA. Gdy jednak zaczynamy stosować w naszym życiu zasady NA, przyciąga to do NA nowych członków, podobnie jak i nas to przyciągnęło do zdrowienia.', 'Będę pracować z nowoprzybyłymi. Przypomnę sobie, że ja też kiedyś byłem nowoprzybyłym. Spróbuję przyciągnąć innych takim samym poczuciem przynależności, jakie ja odnalazłem w NA.'),
(94, '04-03', '3 kwietnia', 'Tylko dla ciebie', NULL, '„Zauważyliśmy, że we wspólnocie idea duchowego przebudzenia przybiera bardzo różne formy, w zależności od osób ją prezentujących.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nChociaż wszyscy pracujemy nad tymi samymi krokami, każdy z nas na swój własny sposób przeżywa wynikające z tej pracy przebudzenie duchowe. Forma, w jakiej przejawia się duchowe przebudzenie w naszym życiu i życiu innych członków NA jest zróżnicowana i zależy od tego, kim jesteśmy. U niektórych z nas obiecywane w Kroku Dwunastym duchowe przebudzenie może przejawiać się poprzez odnowione zainteresowanie religią lub mistyką. U innych rodzi się zrozumienie dla życia otaczających ich ludzi i być może po raz pierwszy odczuwają empatię. A jeszcze inni zaczynają rozumieć, że kroki uświadomiły im ich własne moralne lub etyczne zasady. Większość z nas przeżywa swoje duchowe przebudzenie jako kombinację tego wszystkiego, a każda z tych kombinacji jest tak wyjątkowa, jak wyjątkowe są osoby, które doznały tego przebudzenia. Jeżeli istnieje tak wiele różnych rodzajów przebudzenia duchowego, to skąd wiemy, że faktycznie je przeżyliśmy? Dwunasty Krok daje nam dwa znaki: odnaleźliśmy zasady, które są w stanie poprowadzić nas w dobrym kierunku, takie zasady, które chcemy stosować we wszystkich naszych poczynaniach. Poza tym, inni uzależnieni stali się dla nas na tyle ważni, że bez ograniczeń dzielimy się z nimi doświadczeniem, które posiadamy. Nieistotne są szczegóły naszego przebudzenia, wszyscy otrzymujemy przewodnictwo i miłość, potrzebne nam do tego, abyśmy mogli prowadzić spełnione, zorientowane na duchowość życie. ', 'Bez względu na formę, jaką przybrało moje duchowe przebudzenie, pomogło mi ono znaleźć moje miejsce w świecie i wypełnić je miłością i życiem. Za to jestem wdzięczny.');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(95, '04-04', '4 kwietnia', 'Chroniąc nasze zdrowienie', NULL, '„Pamiętajmy, że to my… ostatecznie jesteśmy odpowiedzialni za nasze zdrowienie i za nasze decyzje.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas stanie w obliczu wyborów, które będą stanowić próbę sił dla naszego zdrowienia. Na przykład, gdy mamy bardzo mocne bóle fizyczne, musimy zdecydować, czy zażyć leki, czy nie. Musimy być bardzo uczciwi wobec siebie odnośnie powagi naszego bólu, uczciwi wobec lekarza w kwestii naszego uzależnienia i zdrowienia, uczciwi wobec naszego sponsora. Ostatecznie jednak decyzja należy do nas, ponieważ to my będziemy musieli żyć z jej konsekwencjami. Innym dość częstym wyzwaniem jest wybór, czy mamy iść, czy nie iść na zabawę, na której serwowany jest alkohol. Powinniśmy rozważyć w jakim stanie ducha jesteśmy. Jeżeli osoba, która wspiera nas w naszym zdrowieniu może pójść tam z nami, będzie nam łatwiej. Jeżeli jednak nie czujemy, że możemy podjąć się tego wyzwania, powinniśmy odrzucić zaproszenie. Dziś wiemy, że zachowanie naszego zdrowienia jest ważniejsze od zachowania twarzy. Wszystkie te decyzje są trudne, wymagają nie tylko starannego przemyślenia, ale też przewodnictwa naszego sponsora i pełnego poddania się Sile Wyższej. Korzystając z tych wszystkich środków, podejmujemy najlepszą decyzję jaką możemy. Ostatecznie jednak, decyzja jest nasza. Dzisiaj jesteśmy odpowiedzialni za nasze własne zdrowienie. ', 'Gdy stanę w obliczu decyzji, która może wystawić moje zdrowienie na próbę, przed jej podjęciem rozważę wszystkie środki, które mam do dyspozycji.'),
(96, '04-05', '5 kwietnia', 'Identyfikacja', NULL, '„Ktoś wreszcie dowiedział się o szalonych myślach, które miałem i szalonych rzeczach, które robiłem.” \r\n\r\n~Tekst Podstawowy (Historie Osobiste)  \r\n\r\nUzależnieni często mają poczucie, że są absolutnie wyjątkowi. Jesteśmy pewni, że nikt nie zażywał narkotyków tak jak my, ani nie robił tych rzeczy, które my robiliśmy, by je zdobyć. Uczucie, że nikt tak naprawdę nas nie rozumie może przez wiele lat powstrzymywać nas przed zdrowieniem. Kiedy jednak po raz pierwszy przychodzimy do NA, pozbywamy się tego poczucia bycia „najgorszymi” lub „najbardziej szalonymi”. Słuchamy jak inni członkowie dzielą się swoim doświadczeniem. Odkrywamy, że inni też szli taką samą pokrętną drogą, jaką myśmy szli, i że mimo to udało im się odnaleźć zdrowienie. Zaczynamy wierzyć, że zdrowienie jest dostępne również dla nas. W trakcie zdrowienia nasze myśli czasem są wciąż jeszcze szalone. Jednak odkrywamy, że jeśli dzielimy się naszymi problemami, to inni identyfikują się z nami i dzielą się tym, jak oni radzili sobie w podobnych sytuacjach. Bez względu na to, jakie by nie dręczyły nas zmartwienia, odnajdujemy nadzieję w dzieleniu się innych, gdy, odnosząc się do naszego doświadczenia, przekazują nam rozwiązania, które sami odnaleźli. Zaczynamy wierzyć w to, że jesteśmy w stanie przeżyć wszystko przez co przechodzimy i nadal rozwijać się w naszym zdrowieniu. Darem NA jest nauka o tym, że nie jesteśmy sami. Dzieląc się z innymi członkami naszym doświadczeniem, siłą, nadzieją i nawet naszymi szalonymi myślami, możemy stać się czyści i pozostać czystymi. Robiąc to, otwieramy się na rozwiązania, które inni znaleźli w obliczu podobnych do naszych życiowych wyzwań.', 'Jestem wdzięczny za to, że mogę zidentyfikować się z innymi. Dziś będę słuchać, jak dzielą się swoim doświadczeniem i podzielę się z nimi moim. '),
(97, '04-06', '6 kwietnia', 'Wzrastająca uczciwość', NULL, '„W praktyce, zmiany następują, ponieważ to, co jest właściwe dla jednego etapu zdrowienia, wcale nie musi być właściwe dla innego.\" \r\n\r\n~Tekst Podstawowy   \r\n\r\nGdy po raz pierwszy przyszliśmy do NA, wielu z nas nie miało legalnej pracy. Nie wszyscy z nas postanowili natychmiast po przyjściu do NA zostać uczciwymi, produktywnymi i przykładnymi obywatelami. Ale wkrótce odkrywamy, że nie czujemy się dobrze, robiąc niektóre rzeczy, które robiliśmy bez zastanowienia w okresie brania. Gdy wzrastamy w naszym zdrowieniu, zaczynamy być uczciwi w sprawach, którymi nie przejmowaliśmy się, gdy braliśmy. Zaczynamy oddawać pieniądze, których kasjer przez pomyłkę wydał nam za dużo, lub przyznajemy się, gdy potrącimy zaparkowany samochód. Odkrywamy, że bycie uczciwym w sprawach większych i poważniejszych staje się dla nas o wiele łatwiejsze, gdy zaczynamy być uczciwi w drobnych sprawach. Wielu z nas przybyło tutaj z bardzo małą zdolnością bycia uczciwym. Odkrywamy jednak, że gdy pracujemy nad krokami, nasze życie zaczyna się zmieniać. Nie czujemy się już komfortowo, czerpiąc korzyści kosztem innych. Możemy poczuć się dobrze z naszą nowoodkrytą uczciwością.', 'Sprawdzę poziom uczciwości w moim życiu i zobaczę, czy czuję się z tym dobrze.'),
(98, '04-07', '7 kwietnia', 'Wartość przeszłości', NULL, '„To pochodzące z pierwszej ręki doświadczenie ze wszystkich okresów choroby i zdrowienia ma niespotykaną wartość terapeutyczną. Jesteśmy tu po to, aby dobrowolnie dzielić się z każdym uzależnionym, który chce zdrowieć.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas przychodzi do NA z jakimś wielkim żalem. Nigdy nie skończyliśmy szkoły średniej lub nie poszliśmy na studia. Zniszczyliśmy przyjaźnie i małżeństwa. Straciliśmy pracę. I wiedzieliśmy, że nie możemy tego w żadne sposób zmienić. Być może myśleliśmy, że już zawsze będziemy pełni żalu, i że najprostszym rozwiązaniem będzie znaleźć jakiś sposób, by żyć z tym żalem. Z drugiej strony, gdy po raz pierwszy dzielimy się naszą przeszłością ze zmagającym się z trudnościami nowoprzybyłym, odrywamy, że jest ona niewykorzystaną kopalnią złota. Gdy ktoś dzieli się z nami swoim Piątym Krokiem, możemy mu dać wyjątkową formę wsparcia, którego nikt inny nie może mu dać - nasze własne doświadczenie. Robiliśmy te same rzeczy. Mieliśmy to samo uczycie wstydu i takie same wyrzuty sumienia. Cierpieliśmy w sposób, w jaki mogą cierpieć tylko uzależnieni. Możemy odnieść się do czyjegoś doświadczenia - i inni mogą zrobić to samo. Nasza przeszłość jest wartościowa, jest właściwie bezcenna, ponieważ możemy użyć jej do tego, aby pomóc uzależnionym, którzy wciąż jeszcze cierpią. Nasza Siła Wyższa może przez nas działać, gdy dzielimy się naszą przeszłością. Z tego powodu tu się znaleźliśmy i wykonanie tego jest najważniejszym celem, który musimy zrealizować. ', 'Nie będę dłużej ubolewał nad swoją przeszłością, ponieważ mogę się nią podzielić z innymi uzależnionymi, i być może dzięki temu unikną oni cierpienia, a może nawet śmierci.'),
(99, '04-08', '8 kwietnia', 'Szczęście', NULL, '„Dowiadujemy się czym jest szczęście, radość i wolność.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nJeśli ktoś zatrzymałby cię dzisiaj na ulicy i spytał, czy jesteś szczęśliwy, to co byś powiedział? „No tak, mam dach nad głową, jedzenie w lodówce, pracę, mój samochód jest sprawny... Tak, sądzę, że jestem szczęśliwy.” Taka byłaby być może Twoja odpowiedź. Są to sprawy i rzeczy, które wielu z nas z przyzwyczajenia kojarzy ze szczęściem. Często jednak zapominamy, że szczęście jest kwestią wyboru; nikt, poza nami samymi, nie może nas uszczęśliwić. Szczęście jest tym, co odnajdujemy, angażując się w NA. Szczęście, które czerpiemy z życia skoncentrowanego na służeniu ciągle jeszcze cierpiącym uzależnionym jest faktycznie wielkie. Gdy stawiamy służenie innym ponad nasze własne pragnienia, stwierdzamy, że już nie jesteśmy skoncentrowani wyłącznie na sobie. Dzięki temu nasze życie staje się bardziej satysfakcjonujące i harmonijne. Gdy służymy innym, nasze własne potrzeby są w pełni zaspokajane. Szczęście. Czym ono właściwie jest? Możemy myśleć o szczęściu jako o zadowoleniu i zaspokojeniu. Obydwa te stany umysłu wydają się przechodzić do nas wtedy, kiedy najmniej się o to staramy. Gdy żyjemy dniem dzisiejszym, niosąc posłanie tym, którzy wciąż jeszcze cierpią, znajdujemy zadowolenie, szczęście i życie wypełnione głębokim sensem.', 'Będę szczęśliwy. Znajdę swoje szczęście, pełniąc służbę na rzecz innych.'),
(100, '04-09', '9 kwietnia', 'Okazywanie negatywnych uczuć', NULL, '„Uczymy się doświadczać uczuć i uświadamiamy sobie, że nie mogą one wyrządzić nam krzywdy, jeśli im nie ulegamy.” \r\n\r\n~IP nr 16 \r\n\r\nWielu z nas przyszło do NA bez większej chęci zaprzestania zażywania. Oczywiście, narkotyki powodowały problemy, a my chcieliśmy pozbyć się tych problemów, lecz nie chcieliśmy zrezygnować z bycia na haju. W końcu jednak zrozumieliśmy, że nie możemy pozbyć się problemów, nie zaprzestając brania. Nawet jeśli chciało nam się brać, to nie robiliśmy tego, ponieważ nie chcieliśmy już ponosić konsekwencji brania. Im dłużej pozostawaliśmy czyści i pracowaliśmy nad programem, tym więcej doświadczaliśmy wolności. Prędzej czy później przymus brania narkotyków całkowicie nas opuścił i pozostawaliśmy czyści, ponieważ chcieliśmy żyć w czystości. Te same zasady dotyczą wszystkich innych negatywnych impulsów, które mogą nas dręczyć. Możemy mieć chęć zrobienia czegoś destrukcyjnego, tylko z tego powodu, że po prostu mamy taką chęć. Robiliśmy już wcześniej takie rzeczy i czasami uchodziło to nam na sucho, ale czasami też nie. Jeżeli nie mamy gotowości ponoszenia konsekwencji wynikających z ulegania takim uczuciom, nie musimy im ulegać. To może być trudne, może nawet tak trudne, jak utrzymywanie czystości na początku. Lecz inni czuli się podobnie i znaleźli sposób, by nie ulegać takim negatywnym impulsom. Dzieląc się tym i szukając pomocy innych uzależnionych oraz Siły, która jest większa od nas samych, możemy znaleźć przewodnictwo, wsparcie i siłę, które potrzebne nam są do tego, by powstrzymać się od wszystkich destrukcyjnych kompulsywnych zachowań. ', 'Przeżywanie swoich uczuć jest czymś zupełnie normalnym. Z pomocą mojego sponsora, moich przyjaciół z NA i mojej Siły Wyższej nie muszę już okazywać swoich negatywnych uczuć.'),
(101, '04-10', '10 kwietnia', 'Zbyt zajęci', NULL, '„Musimy stosować to, czego się nauczyliśmy, w przeciwnym razie stracimy to, niezależnie od okresu naszej czystości.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nOsiągnąwszy pewien okres czystości niektórzy z nas mają tendencję do zapominania, co jest naszym najwyższym priorytetem. Raz w tygodniu, lub rzadziej, mówimy: „Muszę dziś iść na mityng”. Nadchodzi pora mityngu i… Musimy właśnie nadrobić zaległości w jakichś sprawach, z pewnością ważnych, ale nie bardziej niż nasz regularny udział w NA. Dzieje się to stopniowo. Dostajemy pracę. Odnawiamy więzi rodzinne. Wychowujemy dzieci, pies jest chory lub chodzimy do szkoły wieczorowej. Trzeba posprzątać mieszkanie. Trzeba przyciąć trawnik. Musimy pracować do późnych godzin. Jesteśmy zmęczeni. Dzisiaj w teatrze jest dobre przedstawienie. I nagle, zauważamy, że od dawna nie dzwoniliśmy do naszego sponsora, nie byliśmy na mityngu, nie dzieliliśmy się z nowoprzybyłym, a nawet nie rozmawialiśmy z Bogiem. I co wtedy robimy? Albo odnawiamy nasze zobowiązanie wobec zdrowienia, albo w dalszym ciągu jesteśmy zbyt zajęci, aby zdrowieć, aż w końcu wydarzy się coś, co spowoduje, że przestaniemy kierować naszym własnym życiem. Cóż to za wybór! Najlepszej inwestycji dokonamy, wkładając więcej energii w umacnianie fundamentu zdrowienia, na którym zbudowane jest nasze życie. Ten fundament czyni wszystko inne możliwym, a z pewnością zawali się, jeśli będziemy zbyt zajęci wszystkim innym.', 'Nie mogę sobie pozwolić na to, abym nie miał czasu na zdrowienie. Zrobię dzisiaj coś, co podtrzyma moje zdrowienie. '),
(102, '04-11', '11 kwietnia', 'Zamknięty umysł', NULL, '„Nowa idea nie może być zaszczepiona w zamkniętym umyśle... Natomiast otwarty umysł pomaga nam dostrzec i wykorzystać to, co umykało nam przez całe życie.”\r\n\r\n~Tekst Podstawowy    \r\n\r\nPrzyszliśmy do NA, będąc w najniższym punkcie naszego życia. Skończyły się nam pomysły. Tym, czego najbardziej potrzebowaliśmy, znalazłszy się tutaj, były nowe idee i nowe sposoby na życie, płynące z doświadczenia ludzi, którzy zaznali skuteczności tych idei. Nasze zamknięte umysły przeszkadzały nam jednak w pełnym przyjęciu tych, tak bardzo potrzebnych nam do życia, idei. Zaprzeczanie przeszkadzało nam zobaczyć, jak bardzo naprawdę potrzebujemy nowych pomysłów i nowych kierunków Uznając naszą bezsilność i uświadamiając sobie, do jakiego stopnia straciliśmy kontrolę nad naszym życiem, pozwalamy sobie zobaczyć jak bardzo potrzebujemy tego, co NA ma do zaoferowania. Zdawanie się wyłącznie na siebie i na swoją własną wolę może przeszkodzić nam w tym, abyśmy przynajmniej uznali możliwość istnienia Siły większej od nas samych. Jeśli jednak uznajemy fakt, że nasza własna wola doprowadziła nas do opłakanego stanu, otwieramy nasze oczy i nasz umysł na nowe możliwości. Gdy inni opowiadają nam o Sile, która przywróciła w ich życiu równowagę wewnętrzną, zaczynamy wierzyć, że taka Siła może to zrobić również dla nas. Drzewo, któremu obetnie się gałęzie, umrze, jeżeli nie zostaną mu zaszczepione nowe. Podobnie też uzależnienie pozbawiło nas wszelkich drogowskazów. Aby wzrastać lub przynajmniej przeżyć, musimy otworzyć nasze umysły i pozwolić, aby nowe idee zostały zaszczepione w naszym życiu. ', 'Poproszę moją Siłę Wyższą, aby otworzyła mój umysł na nowe idee zdrowienia.'),
(103, '04-12', '12 kwietnia', 'Być częścią większej całości', NULL, '„Każde duchowe przebudzenie ma ze sobą coś wspólnego. Na te wspólne elementy między innymi składają się koniec samotności i poczucie ukierunkowania w naszym życiu.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nPewien rodzaj duchowego przebudzenia następuje, gdy napotykamy coś większego od nas samych. Podejrzewamy, że działają siły, które przekraczają nasze pojmowanie. Dostrzegamy jakiś ulotny fragment większej całości i w tym momencie doznajemy uczucia pokory. Podróż przez Dwanaście Kroków przyniesie nam duchowe doświadczenie tej samej natury, jednak będzie ono głębsze i trwalsze. Podlegamy postępującemu procesowi kurczącego się ego, równocześnie stając się bardziej świadomi szerszych perspektyw. Nasze postrzeganie świata poszerza się aż do punktu, w którym przestajemy już podlegać zadufaniu i zarozumiałości. Dzięki naszej nowej świadomości nie czujemy się już odizolowani od reszty ludzkości. Być może nie rozumiemy, dlaczego świat jest taki, jaki jest, ani dlaczego ludzie traktują się nawzajem z takim okrucieństwem. Rozumiemy jednak czym jest cierpienie i w zdrowieniu możemy zrobić co tylko potrafimy najlepszego, aby je złagodzić. Gdy nasz osobisty wkład łączy się z wkładem innych, stajemy się istotną częścią wielkiego planu. W końcu jesteśmy połączeni z całością. ', 'Jestem tylko jedną z osób w całym schemacie wszechrzeczy. Pokornie akceptuję moje miejsce w tej większej całości. '),
(104, '04-13', '13 kwietnia', 'Chęć przypodobania się innym', NULL, '„... szukanie aprobaty wpędza nas jeszcze głębiej w uzależnienie...” \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy inni aprobują to, co robimy lub mówimy, czujemy się dobrze; gdy nas dezaprobują, czujemy się źle. Ich opinie na nasz temat i to, jak one wpływają na nasze uczucia, mogą mieć swoje pozytywne strony. Gdy idziemy w dobrym kierunku, pozytywne opinie innych sprawiają, iż czujemy się dobrze i mogą być dla nas zachętą, byśmy kontynuowali to, co robimy. Chęć przypodobania się innym jest jednak czymś zupełnie innym. Gdy robimy coś, złego lub dobrego, po to tylko, aby zdobyć ich uznanie, jest to właśnie próba przypodobania się innym. Niskie poczucie własnej wartości może powodować potrzebę zdobycia czyjegoś uznania po to tylko, byśmy mogli się czuć dobrze sami ze sobą. Robimy wszystko, co naszym zdaniem może spowodować, że inni nas za to pochwalą. Przez chwilę czujemy się dobrze. Ale potem cierpimy. Próbując zadowalać innych, poniżamy siebie i swoje wartości. Uświadamiamy sobie, że aprobata innych ludzi nie zapełni naszej wewnętrznej pustki. Wewnętrzne zadowolenie, którego szukamy, możemy znaleźć, robiąc właściwe rzeczy z właściwych pobudek. Gdy zaprzestajemy działań mających na celu wyłącznie zdobycie czyjegoś uznania, przerywamy krąg naszej potrzeby przypodobanie się innym i zaczynamy wypełniać wolę naszej Siły Wyższej. Gdy zaczynamy tak postępować, możemy się poczuć miło zaskoczeni, zauważając, że ludzie, którzy naprawdę liczą się w naszym życiu, coraz bardziej będą aprobować nasze zachowanie. Najważniejszą sprawą jest jednak to, abyśmy aprobowali samych siebie.', 'Siło Wyższa, pomóż mi żyć w zgodzie z duchowymi zasadami. Tylko wtedy mogę sam siebie zaaprobować.'),
(105, '04-14', '14 kwietnia', 'Nowe spojrzenie', NULL, '„Czy rzeczywiście chcemy uwolnić się od naszych uraz, naszej złości i lęku? \r\n\r\n~Tekst Podstawowy  \r\n\r\nDlaczego nazywamy te cechy „niedoskonałościami”? Być może powinniśmy zacząć nazywać je „nad doskonałościami”, ponieważ w sposób doskonały umykają wszelkim próbom pozbycia się ich z naszego życia. Niektórzy z nas uważają, że wady charakteru są tym, co pozwoliło nam przeżyć, gdy braliśmy narkotyki. Jeżeli jest to prawdą, to nie ma w tym nic dziwnego, że czasem kurczowo się ich trzymamy, jak starych, dobrych przyjaciół. Jeżeli mamy problem z urazą, gniewem lub strachem, możemy zastanowić się, jak wyglądałoby nasze życie, gdybyśmy zostali uwolnieni od tych niezwykle kłopotliwych wad. Czasem, samo postawienie sobie pytania, dlaczego reagujemy w taki, a nie inny sposób, może wykorzenić lęk leżący u podstaw naszych zachowań. „Dlaczego obawiam się wyjść poza te aspekty swojej osobowości?” - pytamy siebie. „Czy boję się tego, kim się stanę bez tych cech?” Gdy demaskujemy nasz strach, zyskujemy zdolność wyjścia poza niego. Próbujemy wyobrazić sobie jakie byłoby nasze życie bez niektórych naszych najbardziej rażących wad. To pomaga nam poczuć, co leży poza naszym lękiem i daje nam motywację potrzebną do tego, by przejść ponad nim. Siła Wyższa oferuje nam nową wizję życia - życia wolnego od wad. Wizja ta jest kwintesencją naszych najlepszych i najjaśniejszych marzeń dotyczących nas samych. Nie powinniśmy się bać tej wizji.', 'Wyobrażę sobie, jak wyglądałoby moje życie bez wad charakteru. Poproszę o gotowość do tego, aby Bóg usunął moje niedoskonałości.'),
(106, '04-15', '15 kwietnia', 'Wracajcie', NULL, '„Zaczęliśmy czerpać radość z czystego życia i chcemy dostać jeszcze więcej spośród tych dobrych rzeczy, które w zanadrzu ma przygotowane dla nas wspólnota NA.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy pamiętasz jeszcze te czasy, kiedy widziałeś zdrowiejących uzależnionych w NA i dziwiłeś się: „Jeżeli nie biorą oni narkotyków, to z jakiego powodu, u licha, tak się cieszą?” Czy byłeś przekonany, że radość kończy się wraz z końcem brania narkotyków? Tak wielu z nas podobnie myślało. Byliśmy przekonani, że dobre życie zostawiamy za sobą. Dzisiaj, wielu z nas może się śmiać z tego fałszywego wyobrażenia, ponieważ wiemy jak pełne może być nasze życie w zdrowieniu. Wiele z tego, czym tak bardzo cieszymy się w zdrowieniu osiągnęliśmy przez aktywne uczestnictwo we wspólnocie NA. Zaczynamy znajdywać prawdziwych towarzyszy naszej drogi, przyjaciół, którzy nas rozumieją i troszczą się o nas po prostu dla nas samych. Znajdujemy miejsce, w którym możemy być pożyteczni dla innych. Mityngi zdrowienia, aktywność w służbach oraz wspólnotowe imprezy są po to, aby wypełnić nasz czas i nasze zainteresowania. Wspólnota może być lustrem, które daje nam dokładniejszy obraz nas samych. Znajdujemy tam nauczycieli, pomocników, przyjaciół, miłość, troskę i wsparcie. Wspólnota zawsze będzie miała nam coś do zaoferowania, tak długo, jak długo będziemy tutaj wracać.', 'Wiem gdzie jest dobre życie. Będę tutaj wracać.'),
(107, '04-16', '16 kwietnia', 'Działać jak gdyby…', NULL, '„Dzisiaj szukamy rozwiązań, a nie problemów. Próbujemy realizować to, czego nauczyliśmy się na podstawie doświadczenia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy po raz pierwszy usłyszeliśmy „działać jak gdyby” wielu z nas oburzyło się: „Ależ to jest nie uczciwe! Myślałem, że w NA powinniśmy być uczciwi wobec naszych uczuć“. Być może powinniśmy się zastanowić nad tym, jak to było, gdy po raz pierwszy przyszliśmy do NA. Może nie wierzyliśmy w Boga, lecz pomimo to modliliśmy się. Lub może nie byliśmy pewni czy program zadziała w naszym przypadku, lecz ciągle chodziliśmy na mityngi, nie zważając na to, co myśleliśmy. Tę samą zasadę możemy zastosować w naszym dalszym zdrowieniu. Być może boimy się tłumów, jeśli jednak będziemy działać z pełnym zaufaniem i wyciągniemy rękę do innych, to nie tylko poczujemy się lepiej sami ze sobą, lecz zauważymy również, że już nie boimy się wielkich zgromadzeń. Każde działanie, które podejmujemy w tym kierunku, przybliża nas do stania się ludźmi, którymi mamy zamiar się stać. Każda pozytywna zmiana, której dokonujemy, buduje nasz szacunek do samych siebie. Gdy zmieniamy nasze działania, uświadamiamy sobie, że również zaczyna zmieniać się nasze myślenie. Poprzez „działanie jak gdyby” rozwijamy w sobie właściwe myślenie.', 'Wykorzystam najbliższą okazję, by zadziałać tak, jakbym akceptował sytuację, przed którą wcześniej uciekałem.'),
(108, '04-17', '17 kwietnia', 'Mityngi są priorytetem', NULL, '„Początkowo miałem uczucie, że nie jest możliwym chodzenie na mityngi częściej niż raz lub dwa razy w tygodniu. Więcej po prostu nie pasowałoby do mojego napiętego planu pracy. Później nauczyłem się, że moje priorytety muszą zmienić się o 180 stopni. To właśnie wszystko inne musiało dopasować się do mojego harmonogramu mityngów.”  \r\n\r\n~Tekst Podstawowy (Historie Osobiste)  \r\n\r\nNiektórzy z nas, gdy po raz pierwszy przyszli do NA, nie uczęszczali regularnie na mityngi, a potem dziwili się, że nie udaje im się zachować czystości. Wkrótce uświadomiliśmy sobie, że jeżeli chcemy pozostać czyści, uczęszczanie na mityngi musimy sobie postawić za priorytet. Zaczęliśmy więc od początku. Postępując według sugestii naszego sponsora, zobowiązaliśmy się uczęszczać na dziewięćdziesiąt mityngów w dziewięćdziesiąt dni. Przez trzydzieści dni przedstawialiśmy się jako nowoprzybyli, tak, aby inni mogli nas poznać. Zgodnie z sugestiami naszego sponsora przestaliśmy mówić do czasu, aż nauczyliśmy się słuchać. Wkrótce zaczęliśmy wyczekiwać mityngów i zaczęliśmy zachowywać czystość. Dzisiaj chodzimy na mityngi z wielu różnych powodów. Czasami chodzimy na nie po to, by podzielić się z nowoprzybyłymi naszym doświadczeniem, siłą i nadzieją. Czasami idziemy po to, aby zobaczyć naszych przyjaciół. A czasami idziemy tylko z tego powodu, że potrzebujemy, żeby ktoś nas uścisnął. Czasami wychodząc z mityngu, stwierdzamy, że nic nie wzięliśmy z tego, co usłyszeliśmy, ale i tak czujemy się lepiej. Atmosfera miłości i radości, która wypełnia nasze mityngi, utrzymuje nas kolejny dzień w czystości. Bez względu na to, jak bardzo jesteśmy zajęci, uczęszczanie na mityngi czynimy naszym priorytetem.  ', 'W głębi serca wiem, że mityngi przynoszą mi korzyści różnego rodzaju. Dzisiaj chcę tego, co jest dla mnie dobre. Pójdę na mityng.'),
(109, '04-18', '18 kwietnia', 'Rozumiem', NULL, '„Pokornie prosiliśmy go, aby usunął nasze braki.“  \r\n\r\n~Tekst Podstawowy \r\n\r\nKiedy jesteśmy całkowicie gotowi, aby nasze wady charakteru zostały usunięte, wielu z nas jest całkowicie gotowych. Jak na ironię, dopiero wtedy jest to naprawdę trudne. Im bardziej staramy się pozbyć określonych wad charakteru, tym silniejsze wydają się one być. Pokory wymaga uświadomienie sobie, że jesteśmy bezsilni nie tylko wobec naszego uzależnienia, ale również wobec naszych wad charakteru. W końcu udaje się. Siódmy Krok nie mówi, abyśmy sami uwolnili się od naszych braków, lecz abyśmy prosili naszą Siłę Wyższą, żeby nam je zabrała. To, na czym skupiają się nasze codzienne modlitwy zaczyna się zmieniać. Przyznając naszą niezdolność do udoskonalenia samych siebie błagamy naszą Siłę Wyższą, aby zrobiła dla nas to, czego my sami nie możemy dla siebie zrobić. I czekamy. Nasz program może zatrzymać się na Kroku Siódmym na wiele dni. Być może nie doświadczymy nagłego i pełnego uwolnienia od braków – ale często jednak doświadczamy subtelnej zmiany postrzegania siebie i innych. Oczami Kroku Siódmego zaczynamy patrzeć mniej krytycznie na ludzi wokół nas. Wiemy, że wielu z nich tak, jak my, zmaga się ze swoimi brakami, których najchętniej pozbyliby się. Wiemy, że oni – tak samo, jak my – są bezsilni wobec własnych wad. Zastanawiamy się, czy oni również modlą się pokornie o usunięcie ich wad. Zaczynamy oceniać innych w ten sam sposób, w jaki nauczyliśmy się oceniać samych siebie: z empatią zrodzoną z pokory. Kiedy obserwujemy innych, nie przestając przy tym obserwować samych siebie, możemy w końcu powiedzieć: „Rozumiem.” ', 'Boże, pomóż mi, patrzeć oczami Kroku Siódmego. Pomóż mi zrozumieć.'),
(110, '04-19', '19 kwietnia', 'Ciężka praca ', NULL, '„Uzależnieni bardzo często chcieliby otrzymać wynagrodzenie należne za ciężką pracę, bez jej wykonania.”\r\n\r\nKiedy po raz pierwszy zjawiliśmy się w NA, niektórzy z nas chcieli dostać od razu wszystko. Chcieliśmy mieć pogodę ducha, samochód, szczęśliwy związek, przyjaciół, bliskość z naszym sponsorem - wszystko to, co inni otrzymali po miesiącach lub latach pracy nad krokami i życia takim życiem, jakie ono jest. Z trudem uczymy się, że pogodę ducha możemy osiągnąć tylko poprzez pracę nad krokami. Nowy samochód jest wynikiem codziennego stawiania się w pracy i próbowania „stosowania tych zasad we wszystkich sferach naszego życia“, również w naszym miejscu pracy. Zdrowe relacje są wynikiem ciężkiej pracy i gotowości do bycia otwartym wobec innych ludzi. Przyjaźń z naszym sponsorem jest wynikiem zwracania się do niego zarówno w dobrych jak i w złych chwilach. W NA znaleźliśmy drogę do lepszego życia. Aby jednak osiągnąć nasz cel, musimy włożyć w to sporo pracy.  ', 'Chcę mieć lepsze życie. Przeanalizuję swoje pragnienia, dowiem się jak mogę je zrealizować, porozmawiam o tym z moim sponsorem i wykonam niezbędną pracę'),
(111, '04-20', '20 kwietnia', 'Nie wtrącanie się', NULL, '„Uzależnienie jest chorobą dotyczącą całej rodziny, jednak zmienić możemy tylko siebie.“  \r\n\r\n~IP nr 13 \r\n\r\nMłodość i zdrowienie  Wielu z nas pochodzi z głęboko dysfunkcyjnych rodzin. Czasami, obłęd panujący w naszej rodzinie wydaje się nas przytłaczać. Od czasu do czasu mamy ochotę spakować torby i wyprowadzić się jak najdalej od rodziny. Modlimy się, aby nasza rodzina przyłączyła się do nas w zdrowieniu, lecz ku naszemu zmartwieniu nie zawsze tak się dzieje. Czasami, pomimo naszych usilnych starań niesienia posłania, stwierdzamy, że nie możemy pomóc tym, których najbardziej kochamy. Nasze grupowe doświadczenie uczy nas, że znajdujemy się zbyt blisko członków naszych rodzin, abyśmy mogli im pomóc. Uczymy się, że lepiej jest pozostawić ich opiece Siły Wyższej. Zauważyliśmy, że jeśli nie próbujemy rozwiązywać problemów naszych bliskich, dajemy im przestrzeń potrzebną do tego, aby sami mogli uporządkować swoje życie. Przypominając im, że nie możemy za nich rozwiązać ich problemów, uwalniamy się i możemy żyć swoim własnym życiem. Wierzymy, że Bóg pomoże naszym bliskim. Często, najlepsze, co możemy dać naszym ukochanym, to przykład własnego nieustannego zdrowienia. Dla duchowego zdrowienia naszych rodzin i nas samych musimy pozwolić naszym bliskim znaleźć swoją własną drogę zdrowienia.', 'Będę dążyć do tego, aby pracować nad własnym programem i pozostawić moją rodzinę pod opieką Siły Wyższej.'),
(112, '04-21', '21 kwietnia', 'Obawy', NULL, '„Odkryliśmy, że nie mamy wyboru - albo całkowicie zmienimy nasz stary sposób myślenia, albo wrócimy do brania.”\r\n\r\n~Tekst Podstawowy      \r\n\r\nWielu z nas odkryło, że nasz stary sposób myślenia zdominowany był przez strach. Baliśmy się, że nie będziemy w stanie zdobyć narkotyków lub nie będziemy mieli ich wystarczająco dużo. Baliśmy się zdemaskowania, aresztowania i uwięzienia. Paraliżował nas strach przed problemami finansowymi, przed bezdomnością, przedawkowaniem lub chorobą. Strach miał kontrolę nad wszystkim, co robiliśmy. Pierwsze dni naszego zdrowienia nie odróżniały się zbytnio od życia, jakim żyliśmy dotąd, toteż w naszych myślach dominował strach. Pytaliśmy siebie: „A jeżeli pozostanie czystym jest zbyt bolesne? A jeżeli mi się nie uda? A jeżeli ludzie z NA mnie nie polubią? A jeżeli NA nie zadziała?” Strach związany z tymi myślami nadal może kontrolować nasze zachowanie  i powstrzymywać nas przed podjęciem ryzyka, które jest niezbędne, byśmy mogli pozostać czyści i wzrastać. Skazanie siebie na pewną porażkę i poddanie się na samym początku może wydawać się nam łatwiejsze, niż zaryzykowanie wszystkiego dla nikłej nadziei. Tego rodzaju myślenie prowadzi prosto do nawrotu i wpadki.Aby pozostać w czystości, powinniśmy obudzić w sobie pragnienie zmiany swojego starego sposobu myślenia. To, co okazało się skuteczne dla innych uzależnionych, może okazać się skuteczne również dla nas - powinniśmy jednak wzbudzić w sobie chęć podjęcia takiej próby. Musimy zamienić nasze stare cyniczne wątpliwości na nowe, pełne nadziei podejście do życia. Gdy tak będziemy postępować, odkryjemy, że jest to warte ryzyka.', 'Modlę się o chęć do zmiany mojego starego sposobu działania i o to, abym mógł przeciwstawić się swoim obawom.'),
(113, '04-22', '22 kwietnia', 'Podróżując szeroką drogą', NULL, '„Jest to nasza droga do duchowego rozwoju.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nKiedy przyszliśmy na nasz pierwszy mityng NA, wydawało się, że dla wielu z nas jest to koniec drogi. Nie byliśmy w stanie już dłużej brać. Byliśmy duchowymi bankrutami. W większości byliśmy całkowicie odizolowani i nie wiedzieliśmy po co mamy żyć. Po pewnym czasie zrozumieliśmy, że rozpoczynając pracę nad programem, weszliśmy na drogę nieograniczonych możliwości. Na początku wystarczyło po prostu utrzymywać abstynencję. Jednak, obserwując innych uzależnionych, którzy pracowali nad krokami  i stosowali zasady programu w swoim życiu, zaczęliśmy zauważać, że zdrowienie jest czymś więcej, niż tylko abstynencją. Życie naszych przyjaciół z NA zmieniło się. Mieli oni kontakt z Bogiem, jakkolwiek Go pojmowali. Byli odpowiedzialnymi członkami wspólnoty i społeczeństwa. Mieli powód, aby żyć. Zaczęliśmy wierzyć, że w naszym przypadku jest to również możliwe.W trakcie naszej podróży zdrowienia możemy zostać sprowadzeni na manowce poprzez samozadowolenie, brak tolerancji lub nieuczciwość. W takiej sytuacji musimy szybko rozpoznać te objawy i powrócić na naszą ścieżkę, na otwartą drogę do wolności i wzrostu.', 'Kontynuuję rozwijanie swoich duchowych, społecznych oraz ogólnych życiowych umiejętności poprzez stosowanie zasad zawartych w moim programie. Mogę podążać szeroką drogą zdrowienia tak daleko, jak tylko będę chciał.'),
(114, '04-23', '23 kwietnia', 'Bóg, jakkolwiek Go pojmujemy', NULL, '„Wielu z nas pojmuje Boga po prostu jako siłę, która utrzymuje nas w czystości.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nNiektórzy z nas, wkraczając w zdrowienie, posiadają już jakieś swoje własne rozumienie Siły Wyższej. Jednakże dla wielu z nas słowo „Bóg” wciąż jest problemem. Być może mamy w ogóle wątpliwości odnośnie istnienia jakiejkolwiek formy Siły większej od naszej własnej. Możemy również mieć w pamięci nieprzyjemne doświadczenia związane z religią i unikać wszystkiego, co wiąże się z Bogiem. W zdrowieniu zaczynamy wszystko od nowa i oznacza to, że możemy również rozpocząć od nowa nasze życie duchowe. Jeżeli w okresie dorastania otrzymaliśmy jakąś wiedzę, z którą dziś nie czujemy się zbyt dobrze, to możemy spróbować zbliżyć się do duchowości w inny sposób. Nie musimy zrozumieć wszystkiego od razu i nie musimy znaleźć poprawnych odpowiedzi na wszystkie nasze pytania. Czasami, wystarczy sama świadomość tego, że inni członkowie NA wierzą i że ta wiara pomaga im w utrzymywaniu czystości. ', 'Teraz wystarcza mi, że wiem o mojej Sile Wyższej tylko tyle, że jest to Siła, która pomaga mi w utrzymywaniu czystości.'),
(115, '04-24', '24 kwietnia', 'Dwanaście Kroków życia', NULL, '„Dzięki abstynencji i pracy nad Dwunastoma Krokami NA nasze życie staje się pożyteczne.”   \r\n\r\n~Tekst Podstawowy  \r\n\r\nZanim przyszliśmy do NA, nasze życie kręciło się wokół brania. Zazwyczaj bardzo mało energii pozostawało nam na pracę, na relacje z ludźmi czy na inne formy aktywności. Służyliśmy tylko naszemu uzależnieniu. Dwanaście Kroków NA daje nam prosty sposób na zmianę naszego życia. Zaczynamy od tego, że utrzymujemy czystość tylko przez jeden dzień. Gdy przestajemy marnować naszą energię na uzależnienie, stwierdzamy, że wystarcza nam jej na rozwijanie innych zainteresowań. Wzrastając w zdrowieniu, stajemy się zdolni do utrzymania zdrowych relacji. Stajemy się godnymi zaufania pracownikami. Nasze hobby  i formy rozrywek wydają się być bardziej atrakcyjne. Uczestnicząc w NA, pomagamy innym. NA nie obiecuje nam, że znajdziemy dobrą pracę, partnera czy spełnione życie. Jeśli jednak pracujemy nad Dwunastoma Krokami tak solidnie, jak potrafimy, zauważamy, że stajemy się ludźmi, którzy potrafią znaleźć zatrudnienie, utrzymać związek z ukochaną osobą i pomagać innym. Przestajemy służyć naszej chorobie, a zaczynamy służyć Bogu  i innym ludziom. Dwanaście Kroków jest kluczem do przemiany naszego życia.', 'Odnajdę w sobie mądrość, aby zastosować Dwanaście Kroków w moim życiu i odwagę, aby wzrastać w moim zdrowieniu. Będę praktykować mój program, aby stać się odpowiedzialnym i produktywnym członkiem społeczeństwa. '),
(116, '04-25', '25 kwietnia', 'Akceptując rzeczywistość', NULL, '„Dziś, zdrowienie jest dla nas możliwe.“  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy braliśmy, nasze życie wypełnione było bólem i cierpieniem. Nie chcieliśmy zaakceptować naszej życiowej sytuacji, lecz nie mieliśmy również chęci do zmiany tego, co było nie do zaakceptowania w naszym życiu. Próbowaliśmy uciec przed bólem życia, biorąc narkotyki, lecz one tylko potęgowały nasze problemy. Nasze wypaczone postrzeganie rzeczywistości stało się naszym koszmarem. Żyjąc programem NA, uczymy się tego, że marzenia mogą zastąpić nasze koszmary. Wzrastamy i zmieniamy się. Osiągamy wolność wyboru. Jesteśmy zdolni do dawania i przyjmowania miłości. Możemy uczciwie dzielić się sobą, już nie wyolbrzymiając ani nie pomniejszając prawdy. Akceptujemy wyzwania, które przynosi nam życie i stawiamy im czoła  w dojrzały i odpowiedzialny sposób. Chociaż zdrowienie nie uodparnia nas na rzeczywistość, to we wspólnocie NA odnajdujemy wsparcie, troskę i zainteresowanie potrzebne nam do tego, by stawić jej czoła. Już nie musimy ukrywać się przed rzeczywistością, biorąc narkotyki, ponieważ poczucie jedności  z innymi uzależnionymi daje nam siłę. Dzisiaj, wsparcie, troska i empatia zdrowienia są naszym czystym przejrzystym oknem, przez które możemy oglądać, doświadczać i doceniać rzeczywistość taką, jaka jest.', 'Darem mojego zdrowienia jest życie takim życiem, jakie ono naprawdę jest i czerpanie z niego radości. Dzisiaj zaakceptuję otaczającą mnie rzeczywistość.'),
(117, '04-26', '26 kwietnia', 'Samoakceptacja', NULL, '„Najskuteczniejszym sposobem zaakceptowania siebie jest praktykowanie Dwunastu Kroków zdrowienia.”  \r\n\r\n~IP nr 19\r\n\r\nKiedy przyszliśmy do NA, większość z nas miała duże problemy  z samoakceptacją. Patrzyliśmy na spustoszenie, jakiego dokonaliśmy  w czasie aktywnego uzależnienia i gardziliśmy sobą. Mieliśmy problem z zaakceptowaniem własnej przeszłości i wynikającego z niej wizerunku siebie. Samoakceptacja przychodzi o wiele szybciej, jeśli najpierw pogodzimy się z faktem, że jesteśmy chorzy na chorobę zwaną uzależnieniem, ponieważ łatwiej jest nam zaakceptować siebie jako ludzi chorych, niż jako złych. Im łatwiej przychodzi nam akceptacja siebie, tym łatwiej jest nam zaakceptować odpowiedzialność za siebie. Samoakceptację osiągamy poprzez nieustający proces zdrowienia. Praca nad Dwunastoma Krokami Anonimowych Narkomanów uczy nas akceptacji siebie i swojego życia. Duchowe zasady, takie jak powierzanie, uczciwość, wiara i pokora, pomagają nam uwolnić się od ciężaru błędów przeszłości. Gdy stosujemy te zasady w codziennym życiu, nasza postawa zmienia się. Nasza samoakceptacja rośnie w miarę naszego wzrastania  w zdrowieniu.', 'Samoakceptacja jest procesem, który wprawiany jest w ruch programem Dwunastu Kroków. Dzisiaj zaufam temu procesowi, będę praktykować kroki i uczyć się większej akceptacji siebie samego.'),
(118, '04-27', '27 kwietnia', 'Rozpoznanie uraz i uwolnienie się od nich', NULL, '„Chcemy spojrzeć naszej przeszłości prosto w twarz, zobaczyć ją taką, jaka rzeczywiście była i uwolnić się od niej, by móc żyć dniem dzisiejszym.” \r\n\r\n~Tekst Podstawowy  \r\n\r\nNa początku zdrowienia wielu z nas miało problemy z rozpoznawaniem swoich uraz. Braliśmy się za Czwarty Krok, myśleliśmy, rozważaliśmy, aż  w końcu dochodziliśmy do wniosku, że po prostu nie mamy żadnych uraz. Być może nawet wmówiliśmy sobie, że w sumie nie jesteśmy aż tak bardzo chorzy. Takie bezwiedne wypieranie własnych uraz uwarunkowane jest naszym uzależnieniem. Większość naszych uczuć zostało ukrytych i to głęboko. Po pewnym czasie zdrowienia rozwija się w nas nowe postrzeganie rzeczywistości. Zaczynają wynurzać się nasze najgłębiej ukrywane uczucia i wyłaniają się urazy, o istnienie których nigdy byśmy siebie nie podejrzewali. Analizując te urazy, możemy odczuwać pokusę zatrzymania niektórych z nich, zwłaszcza wtedy, gdy sądzimy, że są one „uzasadnione”. Jednak musimy pamiętać, że „uzasadniona” uraza jest tak samo ciężka do uniesienia, jak każda inna. W miarę, jak stajemy się świadomi ciężarów, które w sobie nosimy, rośnie w nas pragnienie uwolnienia się od nich. Już nie musimy trzymać się kurczowo naszych uraz. Chcemy uwolnić się od tego, co niepożądane  i otworzyć się na zdrowienie.', 'Gdy odkryję jakąś urazę, zobaczę ją taką, jaka jest naprawdę i pozwolę jej odejść.'),
(119, '04-28', '28 kwietnia', 'Kto tak naprawdę zmienia się na lepsze?', NULL, '„Z kroków korzystać możemy również w celu doskonalenia swoich postaw. Nasze wspaniałe pomysły na życie wpędziły nas w kłopoty. Uznajemy potrzebę zmiany.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNa początku naszego zdrowienia większość z nas miała przynajmniej jedną osobę, której nie byliśmy w stanie znieść. Uważaliśmy ją za najbardziej gburowatą i okropną osobę spośród wszystkich uczestników programu. Wiedzieliśmy, że jest coś, co możemy zrobić, aby przezwyciężyć swoje negatywne uczucie do tej osoby, że możemy zastosować jakieś zasady zdrowienia. Ale jakie? Poprosiliśmy naszego sponsora o radę. Prawdopodobnie zapewnił nas z uśmiechem na twarzy, że jeśli tylko nadal będziemy przychodzić na mityngi, to zobaczymy jak ta osoba zmienia się na lepsze. To brzmiało rozsądnie. Wierzyliśmy, że kroki NA działają w życiu każdego z nas. Jeżeli zadziałały w naszym przypadku, to może również pomogą tej „okropnej” osobie.Czas mijał i w pewnej chwili zauważyliśmy, że ta osoba nie wydaje nam się już tak gburowata i okropna, jak przedtem. Stała się zupełnie znośna, a może nawet dająca się lubić. Przeżyliśmy miły szok, gdy uświadomiliśmy sobie, komu tak naprawdę się polepszyło. Dzięki temu, że wciąż chodziliśmy na mityngi i pracowaliśmy nad krokami zmieniło się nasze postrzeganie tej osoby. Osoba, która nas dotąd męczyła, stała się znośna, ponieważ rozwinęliśmy w sobie tolerancję, stała się miła, ponieważ rozwinęliśmy w sobie zdolność kochania.Więc kto tak naprawdę zmienia się na lepsze? My! Pracując nad programem, zaczynamy zupełnie inaczej postrzegać ludzi, którzy nas otaczają, ponieważ inaczej postrzegamy samych siebie.', 'Gdy ja zmieniam się na lepsze, dzieje się to również z innymi. Dzisiaj będę pracować nad tolerancją i postaram się okazać miłość tym, których spotykam.'),
(120, '04-29', '29 kwietnia', 'A co, jeśli...?', NULL, '„Żyjąc dniem dzisiejszym, uwalniamy się od ciężaru przeszłości i od lęku przed przyszłością. Nauczyliśmy się podejmować wszelkie konieczne działania, a ich rezultaty pozostawiać w rękach naszej Siły Wyższej.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy braliśmy, lęk przed przyszłością i przed tym, co może się wydarzyć, dla wielu z nas był nieodłącznym elementem rzeczywistości. A jeśli zostaniemy aresztowani? A jeśli stracimy pracę? A jeśli umrze nasz małżonek? A jeśli zbankrutujemy? I tak dalej... Spędzanie wielu godzin, a nawet całych dni, na rozmyślaniu o tym, co mogłoby się zdarzyć, było dla nas czymś zupełnie normalnym. Tworząc w wyobraźni całe dialogi i scenariusze, zanim jeszcze cokolwiek się wydarzyło, robiliśmy plany na podstawie „a co będzie, jeśli...”. W ten sposób, nastawialiśmy się na przeżywanie jednego rozczarowania za drugim. Słuchając na mityngach wypowiedzi innych, uczymy się, że jedynym sposobem, dzięki któremu możemy uniknąć naszych fatalistycznych, przygnębiających i samospełniających się przepowiedni jest życie teraźniejszością, a nie tym „co będzie, jeśli”. Stawiamy czoła jedynie temu, co jest realne dzisiaj, a nie naszym lękliwym fantazjom dotyczącym przyszłości. Zwalczać te lęki możemy wiarą w to, że Siła Wyższa ma przygotowane dla nas tylko to, co jest dla nas najlepsze. Na mityngach słyszymy, że nasza Siła Wyższa nie obarczy nas większym ciężarem, niż jesteśmy w stanie unieść jednego dnia. I wiemy też z doświadczenia, że jeśli o to poprosimy, to Bóg, jakkolwiek Go pojmujemy, z pewnością o nas zadba. Utrzymujemy czystość w trudnych chwilach dzięki praktykowaniu wiary w opiekę Siły Wyższej od nas samych. Gdy tak postępujemy, to coraz mniej boimy się tego „co będzie, jeśli” i coraz lepiej czujemy się z tym, co jest.', 'Będę spoglądać w przyszłość z wiarą w moją Siłę Wyższą. '),
(121, '04-30', '30 kwietnia', 'Bóg robi to dla nas\r\n', NULL, '„Ciągłość zdrowienia zależy od naszego stosunku do kochającego Boga, który się o nas troszczy i robi dla nas to, czego my sami dla siebie zrobić nie potrafimy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzęsto słyszymy na mityngach, że „Bóg robi dla nas to, czego my sami dla siebie zrobić nie potrafimy”. Czasem możemy utknąć w zdrowieniu, nie mogąc, bojąc się lub nie chcąc podjąć decyzji, o których wiemy, że są niezbędne do dalszego rozwoju. Być może czujemy, że nie jesteśmy  w stanie zerwać relacji, które ewidentnie nam przeszkadzają. Może nasza praca stała się źródłem wielu konfliktów. A może czujemy, że powinniśmy znaleźć nowego sponsora, lecz boimy się rozpocząć poszukiwania. Dzięki naszej kochającej Sile Wyższej zmiany następują właśnie w tych sprawach, o których myśleliśmy, że są nie do zmienienia.Czasami pozwalamy sobie utknąć przy jakimś problemie, zamiast iść do przodu i szukać rozwiązań. I właśnie w takich chwilach zauważamy, że Siła Wyższa robi dla nas to, czego my sami dla siebie zrobić nie potrafimy. Może się tak wydarzyć, że nasz partner podejmie decyzję o odejściu. Zaczynamy awanturować się i staramy się odwlec rozstanie. I wtedy nasz sponsor tłumaczy nam, że nie możemy już dłużej tworzyć z tą osobą pozytywnego związku i być może nadszedł czas, by zwrócić uwagę na kogoś innego.Czasem to, co dzieje się w naszym życiu może nas przerażać, jak zresztą każda zmiana. Lecz równocześnie słyszymy, że „Bóg nigdy nie zamyka jednych drzwi, nie otwierając innych”. Jeśli kroczymy naprzód z wiarą, to nasza Siłą Wyższa zawsze jest w pobliżu. Nasze zdrowienie wzmacnia się dzięki tym zmianom.', 'Wierzę, że Bóg, jakkolwiek Go pojmuję, zrobi dla mnie to, czego ja sam dla siebie zrobić nie potrafię. '),
(122, '05-01', '1 maja', 'Poczucie własnej wartości a służba', NULL, '„Zaangażowanie w służbę daje mi poczucie własnej wartość.”  \r\n\r\n~Tekst podstawowy  \r\n\r\nWiększość z nas przyszła do NA z resztkami poczucia własnej wartości. Wielu członków NA mówi, że poczucie to zaczęli rozwijać dzięki służbom, które pełnili we wczesnym okresie zdrowienia. Gdy zaczynamy mieć pozytywny wpływ na życie innych ludzi poprzez wkładany przez nas wysiłek w służbę, zachodzi coś na kształt małego cudu. Większość z nas po trzydziestu dniach czystości nie ma jeszcze zbyt wiele doświadczenia, siły lub nadziei, którą moglibyśmy się podzielić. Niektórzy członkowie NA mogą nawet doradzać nam, byśmy w tym okresie głównie skoncentrowali się na słuchaniu. Lecz mając trzydzieści dni czystości, mamy już coś do zaoferowania uzależnionemu, który właśnie pojawił się na mityngu, starając się przetrwać kolejne 24 godziny. Taki zupełnie nowy członek NA, którego jedynym pragnieniem jest zaprzestanie brania i który nie posiada do tego żadnych narzędzi, z trudem może sobie wyobrazić, że ktoś nie bierze już od roku, dwóch lub dziesięciu lat. Z łatwością jednak odniesie się do tych, którzy po trzydziestu dniach czystości odbierają swój breloczek z wyrazem dumy i niedowierzania wypisanymi na ich twarzach. Służba jest naszym niezwykłym darem - czymś, czego nikt nam nie może odebrać. Dajemy i dostajemy. Dzięki służbie wielu z nas rozpoczyna swoją drogę, czasem długą drogę, do tego, aby ponownie stać się pożytecznymi członkami społeczeństwa.', 'Będę wdzięczny za możliwość pełnienia służby. '),
(123, '05-02', '2 maja', 'Być może...', NULL, '„Jest jedna rzecz, która bardziej niż cokolwiek innego może zniweczyć nasze zdrowienie - jest nią postawa obojętności lub nietolerancji wobec zasad duchowych.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy po raz pierwszy zjawiliśmy się w NA, wielu z nas miało duże problemy z akceptacją duchowych zasad, na których oparty jest ten program - i mieliśmy ku temu konkretne powody. Odkryliśmy, że bez względu na to, jak bardzo byśmy nie próbowali kontrolować naszego uzależnienia, jesteśmy wobec niego bezsilni. Jeśli ktoś sugerował nam, że jest dla nas nadzieja, to rosła w nas złość i frustracja, ponieważ my wiedzieliśmy lepiej. Być może duchowe idee miały jakiś wpływ na życie innych ludzi, lecz nie na nasze. Pomimo naszej obojętności i nietolerancji wobec zasad duchowych zostaliśmy wciągnięci do NA. Tutaj spotkaliśmy innych uzależnionych. Swego czasu oni też byli w podobnej do naszej sytuacji, bezsilni  i pozbawieni wszelkiej nadziei, a jednak znaleźli sposób na to, aby nie tylko przestać brać, ale także żyć i cieszyć się życiem w czystości. Mówili o zasadach, które wskazały im drogę do nowego życia w zdrowieniu. Dla nich zasady te były nie tylko zwykłą teorią, lecz częścią ich rzeczywistego doświadczenia. Owszem, mieliśmy powody, by być sceptykami, lecz zasady duchowe, o których mówią inni członkowie NA, faktycznie wydają się być skuteczne. Gdy już raz to uznaliśmy, nie musieliśmy akceptować każdej poszczególnej duchowej idei, którą usłyszeliśmy, z osobna. Zaczęliśmy natomiast rozważać, że skoro te zasady okazały się skutecznie dla innych, to może również będą skuteczne w naszym przypadku. Na początek, taka gotowość okazała się wystarczającą.', 'Może okazać się, że duchowe zasady, o których mówi się w NA, zadziałają również na mnie. Jestem przynajmniej skłonny otworzyć swój umysł na taką możliwość.'),
(124, '05-03', '3 maja', 'Dzielimy się naszą wdzięcznością', NULL, '„Moja wdzięczność przemawia przeze mnie, gdy troszczę się i dzielę z innymi  drogą NA.”  \r\n\r\n~Modlitwa wdzięczności  \r\n\r\nIm dłużej jesteśmy czyści, tym częściej doświadczamy uczucia wdzięczności za nasze zdrowienie. Uczucie to nie ogranicza się do wdzięczności za konkretne dary, takie jak nowi przyjaciele lub zdolność do pracy. Powstaje ono coraz częściej z ogólnego poczucia radości, jaką czujemy w naszym nowym życiu. Dodatkowo wzmacnia je wyobrażenie o tym, jak potoczyłoby się nasze życie, gdyby nie cud, którego doświadczyliśmy w NA. Są to uczucia tak wszechogarniające, cudowne i czasem tak obezwładniające, że często brak nam słów. Zdarza się nam płakać otwarcie ze szczęścia podczas dzielenia się na mityngu, gdy szukamy odpowiednich słów, aby wyrazić to, co czujemy. Rozpiera nas chęć przekazania nowoprzybyłym uczucia wdzięczności, jakie mamy w sobie, ale naszemu językowi wydaje się brakować odpowiednich określeń na jego opisanie. Gdy dzielimy się, mając łzy w oczach, gdy milkniemy i nie możemy wydusić z siebie ani słowa - są to właśnie te chwile, kiedy nasza wdzięczność przemawia w sposób najbardziej oczywisty. Gdy dzielimy się nią z głębi naszego serca, inni słyszą nas i rozumieją swoimi sercami. Nasza wdzięczność jest w stanie przemawiać wymowniej niż nasze słowa. Nasza wdzięczność mówi sama za siebie, co nie zawsze udaje się słowom.', 'Moja wdzięczność ma swój własny głos - gdy przemawia, serce rozumie. Dzisiaj podzielę się swoją wdzięcznością z innymi, bez względu na to, czy umiem ją wyrazić, czy też nie.'),
(125, '05-04', '4 maja', 'A co z nowoprzybyłym?', NULL, '„Każda grupa ma jeden główny cel - nieść posłanie uzależnionemu, który wciąż jeszcze cierpi.”  \r\n\r\n~Tradycja Piąta  \r\n\r\nNasza domowa grupa jest dla nas bardzo ważna. W końcu, co by się z nami teraz działo bez naszego ulubionego mityngu NA? Czasami nasza grupa organizuje pikniki lub inne imprezy. Często członkowie naszej grupy idą razem do kina lub na kręgle. Dzięki naszej domowej grupie wszyscy zawarliśmy udane przyjaźnie i nie oddalibyśmy tego za nic  w świecie. Czasem jednak powinniśmy podsumować, co nasza grupa robi, aby spełniać swój główny cel - niesienie posłania uzależnionemu, który wciąż jeszcze cierpi. Czasami, kiedy przychodzimy na nasze mityngi, gdzie znamy prawie wszystkich, od razu dajemy się porwać atmosferze śmiechu i zabawy. A co z nowoprzybyłym? Czy pamiętamy o tym, aby wyciągnąć rękę do nowych osób, które być może siedzą sobie gdzieś z boku, samotne i przestraszone? Czy nie zapominamy powitać tych, którzy odwiedzili naszą grupę? Miłość, którą odnaleźliśmy na mityngach NA pomaga nam zdrowieć z uzależnienia. A gdy już uzyskamy czystość, musimy pamiętać, aby ofiarować innym to, co zostało nam tak obficie darowane. Powinniśmy wyjść naprzeciw temu, który wciąż jeszcze cierpi. Przecież to „nowoprzybyły jest najważniejszą osobą na każdym mityngu”.', 'Jestem wdzięczny za serdeczną atmosferę wspólnoty, którą odnalazłem w mojej grupie domowej. Wyciągnę rękę do  uzależnionego, który wciąż jeszcze cierpi, oferując mu to samo, co otrzymałem od wspólnoty.');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(126, '05-05', '5 maja', 'Za wszelką cenę', NULL, '„... byłem gotów za wszelką cenę pozostać czystym.”  \r\n\r\n~Tekst Podstawowy (Historie osobiste)  \r\n\r\n„Za wszelką cenę?” - pyta nowoprzybyły – „Co macie na myśli, mówiąc, za wszelką cenę”? W wyjaśnieniu tego pomóc nam może spojrzenie wstecz na okres, w którym braliśmy i na to wszystko, co byliśmy w stanie zrobić, aby być na haju. Czy byliśmy gotowi jechać wiele kilometrów tylko po to, by zdobyć narkotyki? Tak, zazwyczaj byliśmy gotowi. W takim razie oczywistą sprawą jest, że jeśli zależeć nam będzie na pozostaniu  w czystości tak samo, jak zależało nam na narkotykach, to zawsze znajdziemy sposób, aby dotrzeć na mityng. Czy biorąc narkotyki, nie robiliśmy często rzeczy idiotycznych i szalonych lub, słuchając sugestii innych aktywnie uzależnionych, nie zażywaliśmy nieznanych nam substancji? Dlaczego więc jest nam tak trudno podążać za wskazówkami, które otrzymujemy w zdrowieniu, szczególnie jeśli mogą one pomóc nam w rozwoju? A kiedy braliśmy, czy nie zdarzało się nam zwracać w desperacji do naszej Siły Wyższej, mówiąc: „Proszę, wyciągnij mnie z tego!” Dlaczego więc jest nam tak ciężko poprosić Boga o pomoc w zdrowieniu? Kiedy braliśmy, zazwyczaj byliśmy otwarci na poszukiwanie nowych dróg i sposobów zdobywania jak największej ilości narkotyków. Jeślibyśmy zastosowali tę samą zasadę otwartości w naszym zdrowieniu, moglibyśmy sami siebie zaskoczyć tym, z jaką łatwością zaczęlibyśmy pojmować program NA. Często się mówi, że to właśnie taki sposób myślenia przywiódł nas do Anonimowych Narkomanów. Jeśli jesteśmy gotowi użyć wszelkich możliwych sposobów, podążać za wskazówkami i zachowywać otwarty umysł, na pewno uda nam się pozostać w czystości.', 'Jestem gotów za wszelką cenę pozostać czystym. Będę na tyle otwarty i gotowy do przyjmowania wskazówek, na ile będzie to konieczne.'),
(127, '05-06', '6 maja', 'Czy umiemy się jeszcze bawić?', NULL, '„Z czasem będziemy mogli odprężyć się i cieszyć się atmosferą zdrowienia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWyobraźmy sobie jakby to było, gdyby nowoprzybyły przyszedł na jeden z naszych mityngów i został powitany przez grupę ludzi o ponurych twarzach, trzymających się kurczowo swoich krzeseł dłońmi zaciśniętymi aż do białych kostek. Prawdopodobnie zawróciłby szybko w stronę drzwi, mrucząc pod nosem: „A myślałem, że będę mógł rzucić narkotyki i być szczęśliwy”. Dzięki Bogu nasi nowoprzybyli zazwyczaj witani są przez grupę ludzi przyjaźnie nastawionych, uśmiechniętych i wyraźnie zadowolonych  z życia, które odnaleźli w NA. Jakżeż wielką daje to nadzieję! Atmosfera śmiechu i relaksu może mocno przyciągać nowoprzybyłego, którego życie do tej pory było śmiertelnie poważne. Przychodząc z miejsca, gdzie wszystko traktuje się poważnie a nieszczęście czai się za każdym rogiem, nowoprzybyły przyjmuje z ulgą spotkanie się z ludźmi, którzy generalnie traktują siebie z dystansem i gotowi są przeżyć coś wspaniałego. W zdrowieniu uczymy się rozchmurzać. Śmiejemy się z absurdalności naszego uzależnienia. Nasze mityngi - sale wypełnione zapachem parzącej się kawy, hałasem przesuwanych krzeseł i śmiechem uzależnionych - są miejscem spotkań, gdzie witamy nowoprzybyłych, którzy przyszli po raz pierwszy i pokazujemy im, że potrafimy bawić się  i cieszyć się życiem.', 'Potrafię śmiać się z siebie. Nie obrażam się na żarty moich przyjaciół. Dziś rozchmurzę się, odprężę się i będę się dobrze bawić.'),
(128, '05-07', '7 maja', 'Od zgiełku do spokoju', NULL, '„Czuję, że w pogrążonym w chaosie świecie, miejsce w którym się znalazłem jest dla mnie wielkim darem.”  \r\n\r\n~Test Podstawowy  \r\n\r\nW niektóre dni nie warto zwracać uwagi na wiadomości medialne, ponieważ jest tam zbyt wiele informacji o przemocy i okrucieństwie. Kiedy braliśmy, wielu z nas przywykło do przemocy. Poprzez mgłę naszego uzależnienia rzadko docierał do nas stan otaczającej nas rzeczywistości. Jednak teraz, kiedy zaczęliśmy zachowywać czystość, wielu z nas zauważa, że staliśmy się szczególnie wrażliwi na to, co dzieje się wokół nas. Co możemy zrobić, jako zdrowiejący ludzie, aby uczynić ten świat  lepszym miejscem? Jeśli zauważymy, że panujący w świecie zamęt wytrąca nas z równowagi, możemy znaleźć otuchę w modlitwie i medytacji. Gdy wydaje się, że wszystko stanęło na głowie, kontakt z Siłą Wyższą może być naszą oazą ciszy pośród każdej szalejącej burzy. Jeśli skoncentrujemy się na naszej duchowej ścieżce, możemy ze spokojem stawić czoła wszelkim lękom. Natomiast, żyjąc w zgodzie z samym sobą, zapraszamy ducha pokoju, by wkroczył do naszego świata. Jako zdrowiejący ludzie możemy dokonywać pozytywnych zmian, starając się żyć zasadami naszego programu najlepiej jak potrafimy.', 'Będę wzmacniać pokój na świecie, żyjąc, mówiąc i zachowując się pokojowo w swoim własnym życiu.'),
(129, '05-08', '8 maja', 'Zdolni do nauki', NULL, '„Zrozumieliśmy, że mamy prawo nie znać odpowiedzi na wszystkie pytania, ponieważ właśnie wtedy jesteśmy zdolni do tego, aby uczyć się i w nauce naszego nowego życia osiągać lepsze efekty.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nUzależnienie w pewien sposób jest wspaniałym nauczycielem. Jeśli nawet nie nauczy ono nas niczego konkretnego, to na pewno nauczy nas pokory. Słyszeliśmy, jak inni mówią, że to właśnie dzięki naszym „wspaniałym” życiowym pomysłom trafiliśmy do NA. Teraz jesteśmy tu po to, żeby się uczyć. Wspólnota NA jest dla zdrowiejących uzależnionych świetnym miejscem do nauki. Na mityngach nie musimy wcale czuć się głupio. Spotykamy tu ludzi, którzy byli dokładnie w takiej samej sytuacji jak my i którzy znaleźli drogę wyjścia. Musimy tylko przyznać się do tego, że nie znamy odpowiedzi na wszystkie pytania, a następnie posłuchać, jak inni dzielą się tym, co okazało się skuteczne w ich przypadku. Jako zdrowiejący uzależnieni i po prostu, jako ludzie, musimy jeszcze wiele się nauczyć. Od innych uzależnionych i od inny ludzi możemy nauczyć się dużo o tym, co działa, a co nie działa. Dopóki pozostajemy chłonni, możemy korzystać z doświadczeń innych.', 'Przyznaję, że nie znam odpowiedzi na wszystkie pytania. Aby znaleźć odpowiedzi, których potrzebuję, będę obserwować i słuchać doświadczeń innych.'),
(130, '05-09', '9 maja', 'Napisz o tym!', NULL, '„Siadamy z zeszytem, prosimy o wskazówki, bierzemy do ręki pióro i zaczynamy pisać.”  \r\n\r\n~Test Podstawowy   \r\n\r\nCzasami, kiedy ogarnia nas zamęt lub z jakiegoś powodu cierpimy, sponsor radzi nam, abyśmy o tym napisali. I chociaż, wyciągając zeszyt, zdarza się nam jęknąć z niezadowoleniem, wiemy, że to nam pomoże. Przelewając wszystkie swoje przeżycia na papier, dajemy sobie szansę dotarcia do tego, co tak na prawdę nas dręczy. Wiemy, że przykładając pióro do papieru, możemy dotrzeć do sedna naszej dezorientacji i poznać prawdziwe powody naszego cierpienia. Pisanie może przynieść bardzo pozytywne efekty, zwłaszcza w czasie pracy nad krokami. Wielu członków NA codziennie prowadzi dzienniczek. Rozmyślanie nad krokami, rozważanie ich znaczenia i analizowanie ich skuteczności dla większości z nas nie jest wystarczające. W samej fizycznej czynności pisania jest coś, co pomaga zasadom zdrowienia zakorzenić się w naszych umysłach i sercach.Zwykłe pisanie przynosi wiele korzyści. Przejrzystość myśli, klucze do zamkniętych obszarów naszego wnętrza czy głos sumienia, to zaledwie niektóre z nich. Pisanie pozwala nam na większą uczciwość wobec samych siebie. Siadamy, wyciszamy umysł i słuchamy serca. To, co słyszymy w tej ciszy stanowi prawdę, którą przelewamy na papier. ', 'Jednym ze sposobów poszukiwania prawdy w zdrowieniu jest pisanie. Dziś będę pisał o swoim zdrowieniu.'),
(131, '05-10', '10 maja', 'Stając się całkowicie gotowym', NULL, '„Widzimy wyraźnie, jak wady te wpływają na nasze życie. Zaczynamy tęsknić za uwolnieniem się od nich.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nDojście do stanu, w którym będziemy w pełni gotowi, aby nasze wady charakteru zostały usunięte może być długim procesem, a często może trwać nawet przez całe życie. Stan naszej gotowości rośnie w miarę wzrostu świadomości naszych wad i destrukcji, jaką one powodują. Zobaczenie tego, jakie spustoszenie poczyniły nasze wady w naszym życiu i życiu tych, którzy nas otaczają, może sprawiać nam trudność.  W tej sytuacji najlepszą rzeczą, jaką możemy zrobić jest poproszenie naszej Siły Wyższej o odsłonięcie tych wad, które stoją na drodze do naszego rozwoju. Gdy pozbywamy się naszych wad i widzimy, że ich działanie słabnie, zauważamy również, że w ich miejsce nasz kochający Bóg daje nam dobre cechy. Tam, gdzie byliśmy pełni obaw, znajdujemy odwagę. Tam, gdzie okazywaliśmy się samolubni, odkrywamy szczodrość. Nasze złudzenia co do samych siebie znikną, aby na ich miejsce mogła pojawić się samoakceptacja i uczciwość wobec siebie. Tak, jeśli stajemy się całkowicie gotowi, to znaczy, że się zmieniamy. Każdy nowy poziom gotowości niesie ze sobą nowe profity. Nasze pierwotne usposobienie zmienia się i szybko przekonujemy się, że podłożem naszej gotowości jest już nie tylko ból, lecz również pragnienie duchowego wzrostu.', 'Będę zwiększał swoją gotowość, stając się bardziej świadomym własnych wad.'),
(132, '05-11', '11 maja', 'Szukając równowagi', NULL, '„Wiele z naszych głównych obaw i problemów bierze się z braku doświadczenia w życiu bez narkotyków. Często, gdy pytamy kogoś z dłuższym okresem czystości co mamy robić, jesteśmy zaskoczeni prostotą odpowiedzi.”  \r\n\r\n~Test Podstawowy   \r\n\r\nOdnajdywanie równowagi w zdrowieniu jest jak siedzenie z wagą w jednej ręce i garścią piasku w drugiej. Chodzi o to, aby mieć na obu szalach wagi jednakową ilość piasku, osiągając w ten sposób jej równowagę. Na tym samym polega zdrowienie. Siadamy, mając za podstawę wagi nasz okres czystości i Dwanaście Kroków, następnie staramy się dodawać do każdej szali w równych ilościach pracę zawodową, obowiązki domowe, przyjaciół, podopiecznych, związki, mityngi i służby w taki sposób, aby waga pozostawała w równowadze. Pierwsza próba osiągnięcia równowagi może się nam nie udać. Być może z powodu zbytniego zaangażowania w służbę naraziliśmy się naszemu pracodawcy lub naszej rodzinie. Gdy jednak próbujemy naprawić ten błąd, całkowicie rezygnując ze służby w NA, znów naruszymy równowagę. Możemy poprosić o pomoc członków wspólnoty, którym udało się ustabilizować swoje wagi. Tych ludzi jest łatwo rozpoznać. Sprawiają wrażenie spokojnych, opanowanych i pewnych siebie. Uśmiechają się, identyfikując się z naszym dylematem, i dzielą się tym, jak im udało się zwolnić tempo oraz nie dodawać więcej niż po kilka ziarenek piasku na raz do każdej z szal i jak zostali nagrodzeni równowagą w zdrowieniu.', 'Poszukam równowagi we własnym życiu. Dzisiaj poproszę innych, aby podzielili się ze mną swoim doświadczeniem w odnajdywaniu równowagi. '),
(133, '05-12', '12 maja', 'Żyć, korzystając z wartości duchowych', NULL, '„Abyśmy mogli docenić medytację, jej rezultaty muszą być widoczne  w naszym codziennym życiu.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPodczas pracy nad naszym programem otrzymujemy wiele pośrednich znaków obecności Siły Wyższej w naszym życiu: poczucie oczyszczenia, które pojawia się u tak wielu z nas wraz z pracą nad Krokiem Piątym, wrażenie, że nareszcie jesteśmy na właściwej drodze, które pojawia się, gdy dokonujemy zadośćuczynienia, satysfakcja, którą daje nam pomoc drugiemu uzależnionemu. Medytacja natomiast daje nam czasami niezwykłe i zadziwiające oznaki obecności Boga w naszym życiu. Doświadczenia te nie świadczą o tym, że staliśmy się idealni, czy też „wyleczeni”. Są one przedsmakiem tego, co czeka nas w zdrowieniu, przypominają nam o istocie tego, do czego dążymy w NA i zachęcają nas do wytrwania na naszej duchowej ścieżce. Doświadczenia takie pokazują nam w jednoznaczny sposób, że mamy do czynienia z Siłą o wiele większą od nas samych. Lecz jak możemy uwzględnić tę niezwykłą Siłę w naszym codziennym życiu? Być może nasi przyjaciele z NA, nasz sponsor lub inni ludzie z naszej wspólnoty są bardziej doświadczeni w kwestiach duchowych od nas. Jeśli ich poprosimy, mogą nam pomóc dostosować nasze doświadczenia duchowe do naturalnego rytmu zdrowienia i duchowego rozwoju.', 'Poszukam wszystkich odpowiedzi, których potrzebuję, aby zrozumieć moje duchowe doświadczenia i włączyć je w codzienne życie.'),
(134, '05-13', '13 maja', 'Wciąż do przodu', NULL, 'Postęp w zdrowieniu jest nieustanną wędrówką w górę.”  \r\n\r\n~Test Podstawowy   \r\n\r\nIm dłużej jesteśmy czyści, tym węższa i stroma wydaje się być nasza ścieżka. Bóg jednak nie daje nam więcej niż możemy unieść. Bez względu na to, jak trudna byłaby ta droga, jak bardzo by się zwężała i stawała krętą, zawsze jest nadzieja. Nadzieja leży w naszym duchowym rozwoju. Jeśli w dalszym ciągu będziemy pojawiać się na mityngach i utrzymywać czystość, życie stanie się… po prostu inne. W wyniku nieustannych poszukiwań wyjaśnienia życiowych wzlotów i upadków możemy poddać w wątpliwość wszystkie aspekty naszego życia. Życie nie zawsze jest przyjemne. W takich sytuacjach musimy zwrócić się do naszej Siły Wyższej z jeszcze większą wiarą. Czasami, jedyne co możemy zrobić, to trzymać się i wierzyć, że wszystko ułoży się dobrze. Z czasem nasza wiara zaowocuje zrozumieniem. Zaczniemy widzieć nasze życie w pełniejszym wymiarze. W miarę rozwoju i pogłębiania się naszego kontaktu z Siłą Wyższą akceptacja staje się niemalże naszą drugą naturą. Bez względu na to, co by nie spotkało nas na drodze zdrowienia, polegamy na naszej wierze w kochającą Siłę Wyższą i podążamy dalej.', 'Godzę się z tym, że nie znam wszystkich odpowiedzi na pytania, jakie stawia przede mną życie. Pomimo to, będę wierzyć w Boga, jakkolwiek Go pojmuję, i będę kontynuować podróż w zdrowieniu.'),
(135, '05-14', '14 maja', 'Ups!', NULL, '„Szaleństwem jest powtarzanie wciąż tych samych błędów i oczekiwanie odmiennych rezultatów.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nBłędy! Wszyscy wiemy jakie to jest uczucie, gdy je popełniamy. Wielu z nas czuje, że całe nasze życie było pomyłką. Często patrzymy na nasze błędy ze wstydem lub poczuciem winy, albo przynajmniej z frustracją i niecierpliwością. Mamy tendencję do postrzegania ich jako dowodów na to, że nadal jesteśmy chorzy, szaleni, głupi lub zbyt zniszczeni, aby zdrowieć. Tak naprawdę, błędy są niezbędną i ważną częścią bycia człowiekiem. Dla szczególnie upartych ludzi (takich właśnie jak uzależnieni), błędy są często najlepszymi nauczycielami. To nie wstyd popełniać błędy. W rzeczywistości, popełnianie nowych błędów często ujawnia naszą chęć do podejmowania ryzyka i wzrastania. Chociaż uczenie się na własnych błędach jest pomocne, to jednak powtarzanie wciąż tych samych błędów może być sygnałem, że stoimy w miejscu. Natomiast oczekiwania innych rezultatów, gdy popełniamy te same stare błędy, jest właśnie tym, co nazywamy „szaleństwem”. To po prostu nie działa.', 'Błędy, to nie tragedia. Ale proszę Cię, Siło Wyższa, pomóż mi się na nich uczyć! '),
(136, '05-15', '15 maja', 'Strach przed Czwartym Krokiem', NULL, '„Kiedy dochodzimy do tego etapu, większość z nas obawia się potwora wewnątrz nas samych, który uwolniony zniszczy nas.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas boi się spojrzeć na siebie, zbadać własne wnętrze. Obawiamy się, że analizując nasze postępowanie i pobudki trafimy na ciemną, bezdenną otchłań egoizmu i nienawiści. Jednak w miarę pracy nad Czwartym Krokiem odkryjemy, że były to niepotrzebne obawy. Tak, jak wszyscy inni jesteśmy po prostu ludźmi - nie mniej, nie więcej. Wszyscy mamy takie cechy charakteru, z których nie jesteśmy specjalnie dumni. Mając zły dzień możemy pomyśleć, że nasze błędy są gorsze niż kogokolwiek innego. Będziemy mieć chwile zwątpienia. Będziemy poddawać w wątpliwość motywy naszego postępowania. Być może nawet zwątpimy w sens naszego istnienia. Lecz gdybyśmy mogli czytać w myślach członków naszej wspólnoty, odnaleźlibyśmy tam te same rozterki. Nie jesteśmy ani gorsi, ani lepsi niż inni. Zmienić możemy tylko to, co znamy i rozumiemy. Zamiast trwać w strachu przed tym, co się w nas kryje, możemy wypuścić to na zewnątrz. Nie będziemy się już bać, a nasze zdrowienie rozkwitnie w pełnym świetle samoświadomości.', 'Boję się tego, czego nie znam. Ujawnię swoje obawy i pozwolę im zniknąć.'),
(137, '05-16', '16 maja', 'Wola naszej Siły Wyższej', NULL, '„Wola Boga względem nas staje się naszą własną, prawdziwą wolą.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nDwanaście Kroków jest drogą do duchowego przebudzenia. Przebudzenie to przybiera formę rozwijającego się związku z kochającą Siłą Wyższą. Każdy następny krok umacnia tę relację. Gdy pracujemy nad krokami, związek ten rośnie i staje się w naszym życiu coraz ważniejszy. W trakcie pracy nad krokami podejmujemy osobistą decyzję poddania się przewodnictwu kochającej Siły Wyższej. Przewodnictwo to jest zawsze osiągalne, musimy tylko cierpliwie go szukać. Często przejawia się ono w wewnętrznej mądrości, którą nazywamy naszym sumieniem. Gdy otwieramy nasze serca na tyle szeroko, aby poczuć przewodnictwo naszej Siły Wyższej, czujemy spokój. Ten spokój jest światłem latarni, które prowadzi nas przez nasze pogmatwane uczucia, zapewniając klarowność kierunku, w którym podążamy, gdy nasz umysł jest zatłoczony i wytrącony z równowagi. Szukając woli Bożej i podążając za nią, odnajdujemy zadowolenie i radość, które często wymykają się nam, kiedy zaczynamy żyć po swojemu. Gdy próbujemy wypełniać wolę naszej Siły Wyższej, może nękać nas strach lub zwątpienie, lecz nauczyliśmy się już ufać chwilom przejrzystości. Nasze największe szczęście tkwi w podążaniu za wolą naszego kochającego Boga.', 'Postaram się umocnić mój związek z Siłą Wyższą. Wiem z doświadczenia, że poznanie woli mojej Siły Wyższej daje poczucie przejrzystości, ukierunkowania i spokoju.'),
(138, '05-17', '17 maja', '„Wady”', NULL, '\"Byliśmy całkowicie gotowi, aby Bóg uwolnił nas od wszystkich wad charakteru.”  \r\n\r\n~Krok Szósty   \r\n\r\nPo zrobieniu Piątego Kroku wielu z nas poświęca czas na rozmyślanie nad „istotą naszych błędów” i wpływem, jakie miały one na nasze życie i na nas samych. Jak wyglądałoby nasze życie, powiedzmy, bez naszej arogancji? Oczywiście, arogancja odseparowywała nas od otaczających nas ludzi, uniemożliwiając nam wspólne przeżywanie radości i korzystanie z ich doświadczenia. Lecz arogancja służyła nam również do podtrzymywania naszego ego w obliczu krytycznie niskiego poczucia własnej wartości. Co byśmy zyskali, gdyby usunięto naszą arogancję i z jakim wsparciem byśmy pozostali?Jeśli arogancja zostałaby usunięta, bylibyśmy o jeden krok bliżej tego, by zająć swoje właściwe miejsce wśród innych. Jako równi innym ludziom bylibyśmy w stanie docenić ich towarzystwo, mądrość i doświadczenie. Dostalibyśmy wsparcie i przewodnictwo, jeślibyśmy dokonali takiego wyboru, poprzez opiekę oferowaną nam przez naszą Siłą Wyższą, a wówczas niskie poczucie wartości przestałoby być naszym problemem. W ten sposób przebadaliśmy, jedną po drugiej, wady naszego charakteru, stwierdzając, że wpływają one negatywnie na nasze życie - w końcu, dlatego właśnie nazywamy je wadami. Czy byliśmy całkowicie gotowi, aby Bóg usunął je wszystkie? Tak.', 'Przyjrzę się dokładnie moim wadom charakteru, by odkryć czy jestem gotów, aby Bóg, jakkolwiek Go pojmuję, je usunął.'),
(139, '05-18', '18 maja', 'Przyjaciele i zadośćuczynienie – nie komplikuj', NULL, '„Zadośćuczyniliśmy osobiście tym, wobec których było to możliwe,  z wyjątkiem przypadków, w których zraniłoby to te lub inne osoby.”  \r\n\r\n~Krok Dziewiąty  \r\n\r\nNie zawsze w naszych związkach z innymi sprawy układają się tak, jak byśmy tego chcieli. Jednak przyjaźń wcale nie musi się zakończyć, gdy popełnimy jakieś błędy, ponieważ zawsze możemy za nie zadośćuczynić. Jeżeli jesteśmy otwarci na to, by przyjąć wiążące się z przyjaźnią zobowiązania i zadośćuczynienia, które jesteśmy winni, związki te mogą stać się jeszcze silniejsze i bogatsze niż dotąd. Zadośćuczynienie jest proste. Podchodzimy do osoby, którą skrzywdziliśmy i mówimy: „Myliłem się”. Czasami unikamy dotarcia do sedna sprawy, nie chcąc się przyznać do naszego udziału w danej sprawie. Jednak właśnie taka postawa udaremnia intencję Dziewiątego Kroku. Aby nasze zadośćuczynienie było skuteczne, powinno być proste. Przyznajemy się do naszego udziału w danej sprawie i tak to pozostawiamy. Może się okazać, że przyjaciele nie zaakceptują naszego zadośćuczynienia. Być może będą potrzebowali czasu na przetrawienie tego, co się wydarzyło. W takiej sytuacji powinniśmy dać im ten czas. W końcu to my popełniliśmy błędy, a nie oni. Zrobiliśmy już to, co do nas należało, reszta jest poza naszym zasięgiem.', 'Chcę być odpowiedzialnym przyjacielem. Będę dążyć do tego, by nie komplikować swoich zadośćuczynień.'),
(140, '05-19', '19 maja', 'Analiza rozwoju', NULL, '„Analizujemy nasze zachowanie z przeszłości i przyglądamy się naszym obecnym zachowaniom, żeby zobaczyć, co z tego chcemy zachować, a czego chcemy się pozbyć.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nPod koniec dnia wielu z nas zastanawia się nad minionymi dwudziestoma czterema godzinami i rozważa, jak moglibyśmy inaczej żyć w przyszłości. Nasze myśli często zostają uwięzione przez przyziemne sprawy: zmienić olej w samochodzie, posprzątać pokój lub opróżnić kosz na śmieci. Czasami musimy włożyć wiele wysiłku w to, by przekierować myśli z codziennej rutyny na wyższe pułapy. Jedno proste pytanie może pomóc nam w obraniu właściwego kierunku: „Czego, naszym zdaniem, oczekuje od nas jutro nasza Siła Wyższa?” Być może powinniśmy popracować nad naszym słabnącym świadomym kontaktem z Bogiem, jakkolwiek Go pojmujemy. Może czujemy się źle w swojej pracy lub związku, w którym tkwimy tylko ze strachu. Może skrywamy jakąś kłopotliwą wadę charakteru, bojąc się podzielić nią  z naszym sponsorem. Pytanie brzmi następująco: w jakich sferach naszego życia chcemy tak naprawdę rozwijać się?Odkrywamy, że dobrze jest zarezerwować kilka chwil pod koniec dnia, aby spędzić je z naszą Siłą Wyższą. Możemy zastanowić się nad tym, co mogłoby przynieść największą korzyść naszemu programowi duchowego rozwoju w nadchodzącym dniu. Myślimy o dziedzinach,  w których ostatnio doznaliśmy wzrostu i o tych planowanych obszarach, które nadal wymagają pracy. Czy może być lepszy sposób na zakończenie dnia?', 'Pod koniec dnia przeznaczę trochę czasu na obcowanie z moją Siłą Wyższą. Zastanowię się nad minionym dniem, medytując nad tym, co stoi pomiędzy mną, a wolą mojej Siły Wyższej odnośnie mojego życia.'),
(141, '05-20', '20 maja', 'Wychodząc z izolacji', NULL, '„Obecnie zajmujemy się i cieszymy się rzeczami, o których nigdy nie myśleliśmy, że będziemy mogli się nimi zajmować i cieszyć.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nAktywne uzależnienie trzymało nas w izolacji z wielu powodów. Najpierw unikaliśmy rodziny i przyjaciół, aby nie odkryli, że bierzemy. Niektórzy z nas unikali wszystkich osób nieuzależnionych, obawiając się gwałtownej reakcji i prawnych konsekwencji. Pogardzaliśmy ludźmi, którzy prowadzili normalne, wypełnione zainteresowaniami życie  z rodzinami, nazywaliśmy ich „nudziarzami”, mając przekonanie, że my nigdy nie będziemy w stanie cieszyć się prostymi przyjemnościami życia. W końcu, zaczęliśmy nawet unikać innych uzależnionych, ponieważ nie chcieliśmy dzielić się z nimi narkotykami. Nasze życie zawęziło się, a problemy ograniczały się do codziennego podtrzymywania naszej choroby. Dzisiaj nasze życie jest znacznie pełniejsze. Cieszy nas to, co robimy wspólnie z innymi zdrowiejącymi uzależnionymi. Mamy czas dla naszych rodzin, odkryliśmy wiele innych zajęć, które sprawiają nam przyjemność. Jak wielka to odmiana w porównaniu z przeszłością! Możemy prowadzić pełne życie tak jak „normalni” ludzie, którymi kiedyś gardziliśmy. Radość wróciła do naszego życia jako dar zdrowienia.', 'Mogę odnaleźć przyjemność w prostej rutynie codziennego życia.'),
(142, '05-21', '21 maja', 'Wracajcie!', NULL, '„Mityngi pomagają nam nie zapomnieć o tym skąd przyszliśmy, ważniejsze jednak jest to, że dzięki nim wiemy dokąd w zdrowieniu możemy dojść.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nUzależnieni różnią się od innych ludzi pod wieloma względami. Kiedy przyszliśmy do NA, spotkaliśmy ludzi takich jak my, ludzi, którzy nas rozumieli i których my byliśmy w stanie zrozumieć. Już nie czuliśmy się wszędzie obcymi lub odmieńcami. Na mityngach NA poczuliśmy się jak w domu, jak wśród przyjaciół. Gdy przez jakiś czas zachowujemy czystość, nie oznacza to, że przestajemy być uzależnieni. Nadal potrzebujemy utożsamiania się z innymi uzależnionymi. Chodzimy na mityngi NA po to, aby pamiętać kim jesteśmy, skąd przyszliśmy i dokąd zmierzamy. Każdy z mityngów przypomina nam, że nie jesteśmy w stanie używać bezpiecznie narkotyków. Każdy mityng przypomina nam, że nigdy nie zostaniemy wyleczeni, ale że dzięki stosowaniu zasad programu możemy zdrowieć. Każdy z mityngów daje nam doświadczenie i przykład innych zdrowiejących uzależnionych. Na mityngach widzimy jak różni ludzie pracują nad swoim programem i jak rezultaty tej pracy uwidaczniają się w ich życiu. Jeżeli chcemy takiego życia, jakie widzimy u innych, możemy dowiedzieć się co oni zrobili, aby dotrzeć do miejsca, w którym znajdują się obecnie. Mityngi Anonimowych Narkomanów pomagają nam uświadomić sobie gdzie byliśmy i dokąd możemy dojść - bez tej świadomości nie możemy się obejść i bez niej nic nie osiągniemy. To sprawia, że wracamy.', 'Będę chodzić na mityngi NA, aby pamiętać kim jestem, skąd przychodzę i dokąd mogę dojść w moim zdrowieniu.'),
(143, '05-22', '22 maja', 'Oznaki duchowego przebudzenia', NULL, '„Kroki prowadzą do przebudzenia duchowego. Świadczą o tym zmiany zachodzące w naszym życiu.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nWiemy jak rozpoznać chorobę zwaną uzależnieniem. Jej objawy są bardzo charakterystyczne. Poza niekontrolowaną chęcią brania,  cierpienie to przejawia się w egocentrycznym i egoistycznym zachowaniu. Kiedy nasze uzależnienie sięgało szczytu swej aktywności, byliśmy wyraźnie pogrążeni w wielkim bólu. Bezustannie ocenialiśmy siebie oraz innych i większość swego czasu spędzaliśmy, zamartwiając się lub próbując kontrolować konsekwencje, które ponosiliśmy. Tak jak choroba uzależnienia uwidacznia się poprzez określone symptomy, tak samo duchowe przebudzenie objawia się u zdrowiejących uzależnionych pewnymi oczywistymi znakami.  Możemy zauważyć tendencję do spontaniczności w myśleniu i działaniu, stratę zainteresowania w ocenianiu i interpretowaniu działań innych, wyraźną zdolność cieszenia się każdą chwilą i częste wybuchy śmiechu. Jeśli widzimy kogoś wykazującego oznaki duchowego przebudzenia, powinniśmy być świadomi, że takie przebudzenie jest zaraźliwe. Najlepsze, co możemy zrobić, to być blisko tych ludzi. Jeśli natomiast zaczniemy miewać częste, obezwładniające chwile wdzięczności, zwiększoną otwartość na miłość rozciągającą się na członków naszej wspólnoty i przemożną chęć dzielenia się tą miłością, będzie to oznaką, że my również doświadczyliśmy duchowego przebudzenia.', 'Moim największym pragnieniem jest doświadczenie duchowego przebudzenia. Będę szukać jego oznak i cieszyć się, gdy je odkryję.'),
(144, '05-23', '23 maja', 'Zadośćuczynienie i sponsorzy', NULL, '„Chcemy uwolnić się od poczucia winy, ale nie chcemy osiągnąć tego kosztem innych.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nSpójrzmy prawdzie w oczy: większość z nas pozostawiała za sobą ślady zniszczenia i krzywdziła każdego, kto stanął nam na drodze. Niektórzy spośród tych, których w swoim uzależnieniu skrzywdziliśmy najmocniej, byli ludźmi, których kochaliśmy najbardziej. Usiłując oczyścić się z poczucia winy związanego z naszymi uczynkami, możemy czuć wielką pokusę podzielenia się z naszymi bliskimi makabrycznymi szczegółami naszego życia, rzeczami, które powinny pozostać niewypowiedziane. Tego rodzaju wyznania mogą wyrządzić wiele krzywdy, przynosząc niewiele pożytku. Krok Dziewiąty nie dotyczy łagodzenia naszego nieczystego sumienia, natomiast mówi o wzięciu odpowiedzialności za wyrządzone przez nas krzywdy. Pracując nad Ósmym i Dziewiątym Krokiem, powinniśmy szukać przewodnictwa naszego sponsora i zadośćuczynić za nasze błędy w taki sposób, który nie spowoduje, że będziemy winni nowych zadośćuczynień. Szukamy nie tyle wolności od wyrzutów sumienia, co wolności od naszych wad. Nie chcemy już nigdy wyrządzać naszym bliskim krzywdy. Jedyną drogą zabezpieczenia się przed tego rodzaju sytuacjami jest odpowiedzialna praca nad Dziewiątym Krokiem, w czasie której analizujemy motywy swojego postępowania i omawiamy szczegółowo ze sponsorem planowane przez nas zadośćuczynienia jeszcze przed ich dokonaniem.', 'Chcę przyjąć odpowiedzialność za swoje działania. Zanim zacznę dokonywać zadośćuczynień, porozmawiam ze swoim sponsorem.'),
(145, '05-24', '24 maja', 'Ryzyko bycia zranionym', NULL, '„Gdy wzrastamy, uczymy się pokonywać naszą skłonność do uciekania  i ukrywania się przed sobą samym i swoimi uczuciami.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nByliśmy bardzo podatni na zranienia i wielu z nas, chcąc uniknąć ryzyka, rozwinęło w sobie nawyk trzymania ludzi na bezpieczny dystans. Takie wzorce emocjonalnej izolacji mogą sprawiać, że czujemy się beznadziejnie uwięzieni pod naszymi maskami. W przeszłości zwykliśmy ryzykować własnym życiem, teraz możemy podjąć ryzyko związane z naszymi uczuciami. Dzięki dzieleniu się z innymi uzależnionymi dowiadujemy się, że nie jesteśmy wyjątkowi, że nie staniemy się nadmiernie podatni na zranienia tylko dlatego, że pozwolimy innym, by poznali nas takimi, jakimi jesteśmy, tym bardziej, że znajdujemy się przecież w dobrym towarzystwie. Dzięki pracy nad Dwunastoma Krokami NA wzrastamy i zmieniamy się. Już nie chcemy i nie musimy kryć swojej wyłaniającej się osobowości. Obdarzono nas szansą pozbycia się swego emocjonalnego kamuflażu, który wypracowaliśmy, aby przetrwać w czasie aktywnego uzależnienia. Otwierając się na innych, narażamy się na zranienie, ale to ryzyko jest warte zachodu. Z pomocą sponsora i innych zdrowiejących uzależnionych uczymy się, jak uczciwie i otwarcie wyrażać swoje uczucia. W zamian, jesteśmy wzmacniani i zachęcani bezwarunkową miłością naszych uzależnionych przyjaciół. Stosując duchowe zasady, odnajdujemy siłę i wolność, zarówno w nas samych, jak i w otaczających nas ludziach. Możemy być sobą i cieszyć się towarzystwem naszych uzależnionych przyjaciół.', 'Otwarcie i uczciwie podzielę się z drugim zdrowiejącym uzależnionym. Podejmę ryzyko otwarcia się i będę cieszyć się sobą oraz swoją przyjaźnią z innymi członkami NA. Będę wzrastać.'),
(146, '05-25', '25 maja', 'Dobre i złe uczucia', NULL, '„W jednym dniu dzieje się zarówno wiele dobrego, jak i złego. Jeżeli nie nauczymy się doceniać jednego i drugiego, być może umknie nam coś, co pomogłoby nam we wzroście.”  \r\n\r\n~IP Nr 8\r\n\r\nKażdego dnia większość z nas bezwiednie ocenia wydarzenia zachodzące w naszym życiu jako dobre lub złe, uznając je za sukces lub za porażkę. Zazwyczaj czujemy się szczęśliwi z powodu tego, co „dobre”, a z powodu tego, co „złe” czujemy złość, frustrację lub mamy poczucie winy. Jednak dobre lub złe odczucia często mają niewiele wspólnego  z tym, co jest dla nas naprawdę dobre lub złe. Możemy czerpać więcej nauki z naszych niepowodzeń, niż z sukcesów, szczególnie, jeśli niepowodzenie było wynikiem podjętego ryzyka. Ciągłe ocenianie swoich reakcji emocjonalnych utrzymuje nas w starym sposobie myślenia. Możemy zmienić sposób postrzegania wydarzeń w naszym codziennym życiu, patrząc na nie jak na okazje do rozwoju, a nie jak na rzeczy dobre lub złe. Zamiast oceniać wydarzenia, możemy szukać okazji do nauki. Jeśli tak postępujemy, każdy dzień czegoś nas uczy. Nasz codzienny Dziesiąty Krok jest wspaniałym narzędziem do podsumowywania wydarzeń minionego dnia i wyciągania nauki zarówno z sukcesów jak i z porażek.', 'Dano mi możliwość stosowania zasad zdrowienia w taki sposób, bym się mógł dzięki nim uczyć i rozwijać. Gdy wyciągam nauki z tego, co dzieje się w moim życiu, odnoszę sukces.'),
(147, '05-26', '26 maja', 'Siła w grupie', NULL, '„Nasze pojmowanie Siły Wyższej zależy od nas. Możemy nazywać ją grupą, programem lub Bogiem.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nWielu z nas ma duże trudności z pojęciem Siły Wyższej, do czasu aż w pełni nie zaakceptujemy głębi naszej bezsilności wobec uzależnienia. Gdy już tego dokonamy, większość z nas jest przynajmniej skłonna rozważyć szukanie pomocy jakiejś Siły, która jest większa od naszej choroby. Pierwsze realne przejawy tego rodzaju Siły wielu z nas napotyka w grupie NA. Być może to tu właśnie powinniśmy rozpocząć rozwijanie naszego osobistego pojmowania Boga. Jedną z oznak Siły istniejącej w grupie jest bezwarunkowa miłość, która uwidacznia się, gdy jedni członkowie NA pomagają innym, nie oczekując niczego w zamian. Zbiorowe doświadczenie grupy w procesie zdrowienia jest samo w sobie Siłą większą od naszej własnej, ponieważ grupa posiada praktyczną wiedzę na temat tego, co działa, a co nie działa. I właściwie to, że uzależnieni wracają codziennie na mityngi, jest dowodem obecności Siły Wyższej, przyciągającej i troszczącej się siły, która pomaga uzależnionym zachować czystość i wzrastać. Wszystkie te rzeczy są przejawem Siły, którą można znaleźć w grupach NA. Gdy rozejrzymy się wokół z otwartym umysłem, każdy z nas będzie w stanie rozpoznać inne oznaki tej Siły. Nie ma znaczenia czy nazwiemy ją Bogiem, Siłą Wyższą lub czymkolwiek innym, o ile tylko znajdziemy sposób, aby uwzględnić ją w naszym codziennym życiu.', 'Otworzę swój umysł i oczy na oznaki Siły, która istnieje w mojej grupie NA. Zwrócę się do tej Siły, aby pomogła mi pozostać czystym.'),
(148, '05-27', '27 maja', 'Stawiając czoła codziennym wyzwaniom', NULL, '„Decyzja o tym, by prosić Boga o pomoc jest naszym największym źródłem  siły i odwagi.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWyzwaniem jest wszystko, co daje nam okazję do odniesienia sukcesu. Jako wyzwania służą nam rzeczy nowe i nieznane, bez względu na to, czy wydają się być dla nas dobre, czy złe. Stajemy w obliczu przeszkód  i oporów pochodzących zarówno z wnętrza nas samych, jak i z zewnątrz. Nowe skomplikowane rzeczy, przeszkody i przeciwności, wszystko to jest częścią „takiego życia, jakie ono w istocie jest”. Życie w czystości oznacza naukę stawiania czoła wyzwaniom. Wielu z nas, świadomie lub nieświadomie, brało narkotyki, aby uniknąć wyzwań. Wielu z nas w równej mierze bało się porażki, jak i sukcesu. Za każdym razem, kiedy unikaliśmy wyzwań, które przynosił nam kolejny dzień, cierpieliśmy z powodu utraty poczucia własnej wartości. Niektórzy z nas zażywali narkotyki, aby zniwelować uczucie wstydu. Postępując tak, stawaliśmy się coraz mniej zdolni do mierzenia się z życiowymi wyzwaniami i coraz bardziej skłonni do brania. Pracując nad programem NA, odnaleźliśmy narzędzia, których potrzebujemy, aby pomyślnie stawić czoła każdej trudności. Uwierzyliśmy w Siłę większą od nas samych, Siłę, która troszczy się o naszą wolę i nasze życie. Poprosiliśmy ją o usunięcie naszych wad charakteru, wszystkich tych rzeczy, które przyczyniły się do utraty kontroli nad naszym życiem. Podjęliśmy działania mające na celu poprawienie naszego świadomego kontaktu z tą Siłą Wyższą. Dzięki krokom dostaliśmy szansę na to, aby przestać brać narkotyki i zacząć żyć. Każdego dnia stajemy twarzą w twarz z nowymi wyzwaniami. I każdego dnia poprzez pracę nad programem zdrowienia doznajemy łaski stawienia im czoła. ', 'Poproszę moją Siłę Wyższą, aby pomogła mi stawić czoła dzisiejszym wyzwaniom.'),
(149, '05-28', '28 maja', 'W miarę poznawania', NULL, '„Przeanalizowaliśmy nasze życie i odkryliśmy, kim naprawdę jesteśmy. Prawdziwa pokora oznacza akceptację siebie i uczciwą próbę bycia sobą.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nKiedy braliśmy, wymagania naszej choroby zdeterminowały naszą osobowość. Aby dostać „działkę”, byliśmy gotowi stać się kimkolwiek lub czymkolwiek trzeba było. Byliśmy maszynami zaprogramowanymi na przeżycie, przystosowującymi się z łatwością do każdych okoliczności życia w nałogu. Rozpoczynając zdrowienie, weszliśmy w nowe, inne życie. Wielu z nas nie miało pojęcia jak się należy zachowywać w różnych napotkanych sytuacjach. Niektórzy z nas nie wiedzieli jak rozmawiać z ludźmi, jak się ubierać lub jak zachowywać się w miejscach publicznych. Nie mogliśmy być sobą, ponieważ sami nie wiedzieliśmy kim jesteśmy. Dwanaście Kroków daje nam prosty sposób, aby tego się dowiedzieć. Odkrywamy nasze zalety i wady, rzeczy, które w sobie lubimy i te, które nie napawają nas dumą. Dzięki uzdrawiającej mocy Dwunastu Kroków zaczynamy rozumieć, że jesteśmy jednostkami stworzonymi do bycia takimi, jacy jesteśmy, przez Siłę Wyższą taką, jak ją pojmujemy. Prawdziwe zdrowienie zaczyna się w chwili, kiedy zrozumiemy, że skoro nasza Siła Wyższa stworzyła nas w ten sposób, to nie ma nic złego w byciu sobą takim, jakim się naprawdę jest. ', 'Dzięki pracy nad krokami mogę doświadczyć wolności bycia sobą, bycia taką osobą, jaką moja Siła Wyższa zaplanowała, żebym był.'),
(150, '05-29', '29 maja', 'Prowadź mnie', NULL, 'Wierzymy, że nasza Siła Wyższa zatroszczy się o nas.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWszyscy mamy chwile, kiedy wydaje się nam, że nic się nam w życiu nie układa. Są takie dni, a nawet tygodnie, kiedy mamy wrażenie, że to wszystko, co może się złego wydarzyć właśnie się dzieje. Czy jest to utrata pracy, czy śmierć ukochanej osoby, czy też koniec związku, wydaje nam się, że nie podołamy zachodzącym w naszym życiu zmianom. To właśnie w takich chwilach, kiedy wokół nas cały świat zdaje się rozpadać na kawałki, znajdujemy w sobie największą wiarę w kochającą Siłę Wyższą. Żadna ludzka istota nie byłaby w stanie uśmierzyć naszego cierpienia; wiemy, że tylko opieka Boga może zapewnić nam pocieszenie, którego potrzebujemy. Czujemy się załamani, ale idziemy dalej  z przekonaniem, że nasze życie ulegnie poprawie. W miarę postępów w zdrowieniu i wzrostu naszej wiary w Siłę Wyższą, stajemy się pewni, że trudności, które mogą nas spotkać w przyszłości, pomimo bólu, jaki może nas ogarnąć, przyjmiemy z uczuciem nadziei. Nie musimy już rozpaczać, bo wiemy, że opieka naszej Siły Wyższej pomoże nam przetrwać wtedy, gdy nie będziemy w stanie iść o własnych siłach. ', 'W trudnych chwilach będę polegać na bożej opiece, wiedząc, że moja Siła Wyższa zawsze będzie przy mnie.'),
(151, '05-30', '30 maja', 'Samotność, a bycie samemu', NULL, '„Dzielenie się z innymi chroni nas przed poczuciem izolacji i osamotnienia.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nJest różnica pomiędzy przebywaniem samemu, a byciem osamotnionym. Osamotnienie jest stanem serca, pustką, która sprawia, że jest nam smutno i czasem beznadziejnie. Gdy wchodzimy w związki lub otaczamy się innymi ludźmi, poczucie osamotnienia nie zawsze ulega złagodzeniu. Niektórzy z nas potrafią czuć się samotni nawet w pokoju pełnym ludzi. Wielu z nas trafiło do NA z powodu rozpaczliwej samotności naszego uzależnienia. Po jakimś czasie chodzenia na mityngi znajdujemy nowych przyjaciół i nasze uczucie samotności często traci na swej mocy. Lecz wielu z nas musi borykać się z samotnością przez całe swoje zdrowienie. Jaki jest lek na samotność? Najlepszym lekarstwem jest rozwinięcie relacji z Siłą Wyższą, która jest w stanie pomóc nam wypełnić pustkę naszego serca. Odkrywamy, że jeśli jest w nas wiara w Siłę Wyższą, to nigdy już nie musimy czuć się samotni. Możemy o wiele lepiej znosić bycie samemu, jeśli mamy świadomy kontakt z Bogiem, jakkolwiek Go pojmujemy. W miarę rozwoju naszego zdrowienia, często znajdujemy głębokie spełnienie w naszych relacjach z innymi. Nie mniej jednak, odkrywamy również, że im bardziej zbliżamy się do naszej Siły Wyższej, tym mniej potrzebujemy otaczać się ludźmi. Zaczynamy odkrywać w naszym wnętrzu ducha, który stale towarzyszy nam w badaniu i zgłębianiu naszego związku z Siłą większą od nas samych. Zdajemy sobie sprawę, że jesteśmy duchowo połączeni z czymś od nas o wiele większym.', 'Doznam ukojenia w moim świadomym kontakcie z Siłą Wyższą. Nigdy nie jestem sam.'),
(152, '05-31', '31 maja', 'Nie komplikuj', NULL, '„Żyjemy dniem dzisiejszym i żyjemy również daną chwilą. Gdy przestajemy żyć tu i teraz, nasze problemy potęgują się.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nŻycie wydaje się czasem zbyt skomplikowane, by je zrozumieć, a szczególnie wydaje się tak tym, którzy zbyt długo przed nim uciekali. Kiedy przestaliśmy brać narkotyki, wielu z nas musiało stanąć twarzą  w twarz ze światem, który był dla nas niezrozumiały, a nawet przerażający. Próba przyjrzenia się równocześnie całemu swojemu życiu i wszystkim jego szczegółom może okazać się dla nas druzgocącym doświadczeniem. Dochodzimy do wniosku, że nie radzimy sobie z życiem i że nawet nie ma sensu próbować to robić. Takie myślenie samoczynnie nakręca się i dość szybko zostajemy sparaliżowani przez nasze wyobrażenia o zawiłości życia. Na szczęście nie musimy robić wszystkiego równocześnie. Jesteśmy natomiast w stanie rozwiązać jakiś jeden konkretny problem i dlatego też rozwiązujemy problemy po kolei, jeden po drugim. Zajmujemy się daną chwilą, a gdy następuje kolejna, wtedy zajmujemy się nią. Uczymy się pozostawać w czystości tylko dzisiaj i takie samo podejście mamy do wszystkich naszych problemów. Jeśli przeżywamy każdą chwilę życia z osobna, to przyszłość przestaje być tak przerażająca. Żyjąc daną chwilą, możemy zachować czystość i uczyć się życia.', 'Będę upraszczać swoje życie, żyjąc tylko daną chwilą. Dziś będę rozwiązywać tylko dzisiejsze problemy; jutrzejsze pozostawię na jutro.'),
(153, '06-01', '1 czerwca', 'Wracajcie', NULL, '„Nie musimy być czyści, gdy tu przychodzimy, ale sugerujemy, by po pierwszym swoim mityngu nowoprzybyli do nas wracali i wracali czyści. Aby otrzymać pomoc od Anonimowych Narkomanów, nie musimy czekać na przedawkowanie lub  więzienie.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nNieliczni z nas przyszli do NA kierowani dobrymi chęciami. Niektórzy zjawili się tutaj z powodu sądowego nakazu. Inni, by ratować swoje rodziny. Jeszcze inni pojawili się, by ocalić rozpadającą się karierę. Nie ma znaczenia z jakiego powodu tutaj znaleźliśmy się. Ważne jest, że tu jesteśmy. Słyszeliśmy, że „jeżeli przyniesiemy ciało, to umysł sam za nim podąży”. Być może przychodzimy na mityngi pełni pretensji i agresji do całego świata. Być może jesteśmy jednymi z tych, którzy siedzą z tyłu salki ze skrzyżowanymi na piersiach rękoma i posyłają groźne spojrzenia każdemu, kto się do nich zbliży. Prawdopodobnie też opuszczamy mityng przed końcową modlitwą. Lecz jeśli będziemy tutaj wracać, zauważymy, że nasze umysły zaczną się otwierać. Zaczniemy opuszczać gardę i słuchać uważnie tego, czym dzielą się inni. Możemy nawet usłyszeć kogoś rozmawiającego z kimś innym, z kim się utożsamimy. Rozpoczynamy proces zmiany. Po pewnym czasie pobytu w NA zauważymy, że na mityngi, które uczęszczamy, przychodzi nie tylko nasz rozum. Pojawia się tam również nasze serce. Gdy to następuje, naprawdę zaczynają dziać się cuda! ', 'Postaram się wsłuchać z otwartym umysłem w to, czym dzielą się inni. '),
(154, '06-02', '2 czerwca', 'Chorzy i zmęczeni ', NULL, 'Chcieliśmy po prostu znaleźć łatwą drogę wyjścia... a jeśli szukaliśmy pomocy, to tylko po to, aby uwolnić się od bólu...”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nCoś jest nie tak, jak być powinno. W zasadzie już od dawna coś szwankuje, przysparzając nam bólu i komplikując życie. Problem jednak tkwi w tym, że w danym momencie łatwiej nam jest znieść ból spowodowany naszymi wadami, niż poddać się wstrząsowi związanemu ze zmianą sposobu życia. Być może od dłuższego czasu chcemy uwolnić się od bólu, lecz bardzo rzadko jesteśmy gotowi zrobić to, co jest niezbędne, aby usunąć źródło tego bólu. Wielu z nas nie poszukiwało drogi zdrowienia dopóki nie staliśmy się „chorzy i zmęczeni byciem chorymi i zmęczonymi”. To samo odnosi się do uporczywych wad naszego charakteru, z którymi żyliśmy do tej pory. Dopiero wtedy, gdy nie mamy już siły radzić sobie z naszymi wadami, gdy zdajemy sobie sprawę, że ból spowodowany zmianą będzie mniejszy od bólu, którego doświadczamy teraz, większość z nas gotowa jest spróbować nowej drogi. Na szczęście kroki zawsze mamy pod ręką, bez względu na to, czego mamy dosyć i czym jesteśmy zmęczeni. Ironią jest fakt, że gdy tylko podejmiemy decyzję o rozpoczęciu pracy nad Dwunastoma Krokami, uświadamiamy sobie, że nasz lęk przed zmianą był nieuzasadniony. Kroki oferują łagodny program zmiany, krok po kroku. Żaden krok rozpatrywany z osobna nie jest na tyle przerażający, abyśmy nie potrafili nad nim pracować. A gdy kroki te zaczynamy stosować w naszym życiu, doświadczamy wyzwalającej zmiany. ', 'Bez względu na to, co przeszkadza mi w doświadczaniu pełnego i szczęśliwego życia, wiem, że program pomoże mi dokonać zmian - krok po kroku. Nie muszę obawiać się Dwunastu Kroków.'),
(155, '06-03', '3 czerwca', 'Bezpośrednie i pośrednie zadośćuczynienie', NULL, '„Dokonujmy zadośćuczynienia na miarę swoich możliwości.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nW Kroku Dziesiątym jest mowa o tym, abyśmy dokonali bezpośredniego zadośćuczynienia wszędzie tam, gdzie jest to możliwe. Nasze doświadczenie sugeruje nam, że to bezpośrednie zadośćuczynienie powinno być poparte zmianą naszych postaw i zachowań, czyli zadośćuczynieniem pośrednim. Powiedzmy, że na przykład z powodu naszej złości wybiliśmy komuś okno. Nie wystarczy po prostu przeprosić tę osobę, patrząc jej z uduchowieniem głęboko w oczy. Zadośćuczyniamy bezpośrednio za zło, którego się dopuściliśmy, przyznając się do winy i zastępując stare okno nowym - naprawiamy to, co uszkodziliśmy. Następnie, popieramy nasze bezpośrednie zadośćuczynienie zadośćuczynieniem pośrednim. Jeżeli wyładowaliśmy nasz gniew, niszcząc czyjeś okno, to najpierw analizujemy wzorce naszych zachowań i postaw. A następnie, zmieniamy nasze zachowanie i wkładamy wysiłek w to, by nie unosić się gniewem. Realizujemy bezpośrednie zadośćuczynienie, naprawiając wyrządzoną szkodę. Zadośćuczynienia pośredniego dokonujemy poprzez zmianę w pierwszej kolejności tych postaw, które przyczyniły się do wyrządzenia danej krzywdy, co pomaga nam zabezpieczyć się przed wyrządzaniem podobnych krzyw w przyszłości. ', 'Zadośćuczynię bezpośrednio wszędzie tam, gdzie będzie to możliwe. Dokonam również zadośćuczynienia pośredniego poprzez „poprawę swojego postępowania” oraz zmianę swoich postaw i zachowań.'),
(156, '06-04', '4 czerwca', 'Zamiast niszczyć, buduj ', NULL, '„Nasze negatywne postrzeganie siebie zostało zastąpione pozytywną troską o innych”.   \r\n\r\n~Tekst Podstawowy   \r\n\r\nRozsiewanie plotek zaspakaja ciemną stronę naszej duszy. Czasami myślimy, że jedynym sposobem na to, by poczuć się kimś wartościowym jest spowodowanie, aby ktoś w porównaniu z nami wypadł gorzej. Jednak ten rodzaj poczucia wartości, nabyty czyimś kosztem, jest pusty i bezwartościowy. W jaki więc sposób mamy sobie radzić z negatywnym postrzeganiem siebie samego? To proste. Zastępujemy je pozytywną troską o innych. Zamiast pogrążać się w poczuciu niskiej samooceny, zwracamy się w stronę tych, którzy są wokół nas i staramy się być dla nich wsparciem. Może to wyglądać na omijanie problemu, ale tak nie jest. Gdy skupiamy się na niskim poczuciu własnej wartości, nie możemy zrobić nic z wyjątkiem pogrążenia się w użalaniu się nad sobą. Natomiast, gdy zastępujemy użalanie się nad sobą aktywnym i pełnym miłości zaangażowaniem w sprawy innych, stajemy się ludźmi, których potrafimy szanować. Sposobem budowania poczucia własnej wartości nie jest poniżanie innych, lecz wzmacnianie ich poprzez miłość i troskę. Aby sobie pomóc, możemy zapytać siebie, czy skupiamy się na problemie, czy raczej na jego rozwiązaniu. Dziś możemy budować, zamiast niszczyć. ', 'Pomimo tego, że mogę czuć się mały, nie muszę poniżać innych, aby podbudować własną wartość. Dzisiaj zastąpię negatywne postrzeganie siebie samego pozytywną troską o innych. Będę budować, a nie niszczyć.'),
(157, '06-05', '5 czerwca', 'Uczciwa modlitwa ', NULL, '„Trudno jest być uczciwym, ale jest to bardzo opłacalne”.   \r\n\r\n~Tekst Podstawowy   \r\n\r\nJak trudno jest być uczciwym! Przychodzimy do NA tak bardzo zdezorientowani tym, co wydarzyło się w naszym życiu, że czasem trzeba miesięcy, a nawet lat, żeby to wszystko jakoś poukładać. Prawda o naszym życiu nie zawsze wygląda tak, jak ją przedstawiamy. Jak więc możemy stać się bardziej prawdomówni? Wielu z nas zauważyło, że najłatwiej być uczciwym w modlitwie. Czasem zauważamy, że mamy duże trudności z powiedzeniem naszym przyjaciołom ze wspólnoty całej prawdy o sobie. Jesteśmy przekonani, że nie będziemy zaakceptowani, jeżeli pozwolimy innym poznać siebie takimi, jacy naprawdę jesteśmy. Trudno jest sprostać wizerunkowi „twardziela”, który wielu z nas dotąd prezentowało. W modlitwie znajdujemy akceptację naszej Siły Wyższej, która pozwala nam uczciwie otworzyć nasze serca. Jeżeli jesteśmy uczciwi wobec Boga, jakkolwiek Go pojmujemy, to często zauważamy, że ma to swoje odbicie w naszych relacjach z innymi ludźmi. Nabywamy zwyczaju bycia uczciwymi. Zaczynamy praktykować uczciwość, dzieląc się na mityngach lub pracując z innymi nad programem. Zauważamy, że w rezultacie takiej postawy nasze życie wzbogaca się o coraz głębsze przyjaźnie. Zauważamy też, że jesteśmy w stanie być bardziej uczciwi wobec siebie, czyli najważniejszej osoby, w stosunku do której powinniśmy być prawdomówni! Uczciwość jest cechą, którą rozwija się poprzez praktykę. Nie jest łatwo być całkowicie prawdomównym, lecz jeśli zaczniemy być uczciwi wobec naszej Siły Wyższej, to zauważymy, że łatwiej nam przyjdzie być uczciwymi wobec innych. ', 'Będę uczciwy w wobec Boga, wobec siebie i wobec innych ludzi.');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(158, '06-06', '6 czerwca', 'Zdrowienie nie następuje z dnia na dzień ', NULL, '„Dwanaście Kroków Anonimowych Narkomanów to postępujący proces zdrowienia wdrożony w naszą codzienność.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nPo upływie pewnego czasu zdrowienia może okazać się, że stoimy twarzą w twarz z przytłaczającymi nas problemami osobistymi, uczuciem złości i zwątpieniem. Gdy zorientujemy się co się dzieje, możemy zacząć użalać się: „Przecież tak ciężko pracowałem. Myślałem, że jestem...”. Może wyleczony?! Chyba jednak nie. Cały czas słyszymy, że zdrowienie to ciągle trwający proces i że nigdy nie będziemy wyleczeni. Wciąż jednak zdarza nam się wierzyć, że jeśli tylko będziemy solidnie pracować nad Krokami, porządnie się modlić lub rzetelnie uczęszczać na mityngi, to będziemy wreszcie... No, może nie będziemy uzdrowieni, ale na pewno jacyś będziemy! Rzeczywiście jesteśmy „jacyś”. Jesteśmy zdrowiejącymi ludźmi - zdrowiejącymi z aktywnego uzależnienia. Nieważne z czym się uporaliśmy do tej pory w trakcie pracy nad Krokami, ponieważ zawsze jest jeszcze coś do zrobienia. To, o czym nie pamiętaliśmy lub co wydało nam się mało istotne podczas pierwszego obrachunku, na pewno samo objawi się później. Wciąż będziemy wracać do procesu pracy nad Krokami, żeby poradzić sobie z czymś, co sprawia nam trudności. Im bardziej będziemy korzystać z tego procesu, tym bardziej będziemy mu ufać, ponieważ będziemy zauważać rezultaty. Przechodzimy od gniewu i urazy do wybaczenia, od zaprzeczania, do uczciwości i akceptacji, od bólu do spokoju i pogody ducha. Zdrowienie nie następuje z dnia na dzień i nigdy nie będzie ono całkowite. Natomiast każdy dzień przynosi nową porcję zdrowienia i nadzieję na to, że jutro będzie go jeszcze więcej. ', 'Dziś zrobię dla mojego zdrowienia to, co jestem w stanie zrobić i zachowam nadzieję na jego nieustający proces.'),
(159, '06-07', '7 czerwca', 'Ktoś, kto we mnie wierzy ', NULL, '„Właśnie dzisiaj uwierzę komuś z NA, kto wierzy we mnie i chce pomóc mi w zdrowieniu.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nPo przyjściu do NA nie wszyscy zaczęliśmy automatycznie zachowywać czystość. Jeżeli jednak będziemy wracać na mityngi, znajdziemy we wspólnocie Anonimowych Narkomanów wsparcie, którego potrzebujemy do zdrowienia. Łatwiej jest zachować czystość, jeżeli mamy kogoś, kto wierzy w nas, nawet wtedy, kiedy my sami w siebie nie wierzymy. Nawet ktoś, kto najczęściej zalicza wpadki, ma w NA zazwyczaj jedną osobę, która w niego wierzy i wspiera go. Powinniśmy koniecznie znaleźć sobie jedną osobę lub grupę osób, która w nas wierzy. Gdy pytamy ich czy kiedykolwiek będziemy czyści, odpowiadają nam: „Tak, możesz być czysty i będziesz. Po prostu wracaj”. Wszyscy potrzebujemy kogoś, kto w nas wierzy, a zwłaszcza wtedy, gdy nie jesteśmy w stanie uwierzyć w samych siebie. Mając wpadkę, osłabiamy naszą i tak już mocno nadwyrężoną wiarę w siebie, czasem na tyle skutecznie, że zaczynamy odczuwać zupełny brak nadziei. W takich chwilach potrzebujemy wsparcia naszych lojalnych przyjaciół z NA. Oni powtarzają nam, że to może być nasza ostatnia wpadka. Wiedzą z doświadczenia, że jeżeli będziemy przychodzić na mityngi, to w końcu przestaniemy brać i pozostaniemy czyści. Dla wielu z nas wiara w siebie jest sprawą bardzo trudną. Jeżeli jednak ktoś bezwarunkowo nas kocha, oferując nam przy tym wsparcie bez względu na ilość naszych wpadek, zdrowienie w NA staje się dla nas trochę bardziej realne. ', 'Znajdę kogoś, kto we mnie wierzy. Będę także wierzyć w niego. '),
(160, '06-08', '8 czerwca', 'Jedyny warunek ', NULL, '„Ten program oferuje nadzieję. Ty musisz tylko przynieść ze sobą pragnienie zaprzestania zażywania i gotowość do wypróbowania tej nowej drogi życia.”   \r\n\r\n~IP nr 16   \r\n\r\nOd czasu do czasu zastanawiamy się, czy będąc w NA, „robimy to dobrze”. Czy chodzimy wystarczająco często na mityngi? Czy „należycie” korzystamy z naszego sponsora, czy „poprawnie” pracujemy nad krokami, czy mówimy, czytamy i żyjemy we „właściwy” sposób? Doceniamy wartość wspólnoty zdrowiejących uzależnionych - nie wiemy, co byśmy bez niej zrobili. A jeśli jednak sposób w jaki realizujemy nasz program okazałby się „niewłaściwy”? Czy to czyni nas „złymi” członkami NA? Możemy pozbyć się wątpliwości, przypominając sobie o naszej Trzeciej Tradycji, która zapewnia, że „jedynym warunkiem przynależności do NA jest pragnienie zaprzestania zażywania”. Nie ma żadnych reguł, które mówią, że branie udziału w określonej liczbie mityngów, czy w ogóle w określonych mityngach, lub praca nad krokami w jakiś określony sposób, z określoną szybkością, lub prowadzenie życia w sposób, który podoba się określonym ludziom czyni nas poprawnie zdrowiejącymi członkami NA. Prawdą jednak jest, że jeżeli chcemy takiego zdrowienia, jakie widzimy u innych członków, których szanujemy, to będziemy również chcieli stosować program w taki sposób, który umożliwił im zdrowienie. NA jest jednak wspólnotą wolności; pracujemy nad programem w sposób, który jest najlepszy dla nas, a nie dla kogoś innego. Jedynym warunkiem przynależności jest pragnienie zaprzestania brania narkotyków. ', 'Spojrzę na program, nad którym pracuję, przez pryzmat własnego zdrowienia. Będę praktykować ten program najlepiej, jak potrafię.'),
(161, '06-09', '9 czerwca', 'Dawne marzenia nie muszą umrzeć ', NULL, '„Utracone marzenia powracają do życia i pojawiają się nowe możliwości.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nW młodości większość z nas miała jakieś marzenia. Obojętnie, czy marzyliśmy o wspaniałej karierze, kochającej rodzinie, czy dalekich podróżach, wszystkie te marzenia umarły, gdy nasze uzależnienie przejęło nad nami kontrolę. Wszystko, czego dotąd dla siebie pragnęliśmy, zostało pogrzebane w imię brania. Nasze marzenia nie przebiły kolejnej dawki narkotyku ani eutrofii, którą, jak oczekiwaliśmy, miał on nam zapewnić. Teraz, kiedy zdrowiejemy, mamy wszelkie podstawy ku temu, aby mieć nadzieję, że nasze utracone marzenia naprawdę mogą się jeszcze spełnić. Bez względu na to ile mamy lat, jak wiele utraciliśmy w wyniku uzależnienia i jak nieprawdopodobnym może się to wydawać, to wolność od aktywnego uzależnienia daje nam swobodę realizacji naszych ambicji. Może okazać się, że mamy jakieś wyjątkowe talenty, możemy odnaleźć jakieś ulubione hobby lub odkryć, że kontynuując naukę, osiągamy świetne wyniki. Dotychczas traciliśmy większość naszej energii na wyszukiwanie wymówek i racjonalizowanie naszych niepowodzeń. Dziś odważnie idziemy naprzód i robimy użytek z okazji, których dostarcza nam życie. Możemy nawet sami siebie zadziwić tym, na co nas stać. Jeśli naszym fundamentem jest zdrowienie, to sukces, spełnienie i satysfakcja są wreszcie w zasięgu naszej ręki. ', 'Zaczynając od dziś, zrobię coś, co pomoże mi w realizacji moich marzeń.'),
(162, '06-10', '10 czerwca', 'Zmiana motywów ', NULL, '„Gdy wreszcie pozbędziemy się samolubnych motywów naszego postępowania, zaczniemy odnajdywać spokój, który dotąd wydawał się być nieosiągalny.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nAnalizując w trakcie zdrowienia swoje poglądy, zachowania i motywy postępowania, odkrywamy, że czasami robimy pewne rzeczy, kierując się niewłaściwymi pobudkami. We wczesnym etapie zdrowienia możemy poświęcać ludziom czas i pieniądze tylko po to, by zyskać ich sympatię. Na dalszym etapie możemy zauważyć, że nadal wydajemy pieniądze na innych, lecz nasze motywy uległy zmianie. Robimy to, bo ich lubimy. Być może też wdawaliśmy się w przelotne związki uczuciowe, ponieważ odczuwaliśmy pustkę wewnętrzną i próbowaliśmy wypełnić ją drugą osobą. Teraz powodem naszego zaangażowania uczuciowego jest pragnienie dzielenia się dającym nam satysfakcję życiem z równym sobie partnerem. Może wcześniej pracowaliśmy nad Krokami, ponieważ baliśmy się, że jeśli nie będziemy tego robić, to zaliczymy wpadkę. Dzisiaj pracujemy nad Krokami, ponieważ chcemy rozwijać się duchowo. Dzisiaj mamy nowy cel w życiu, a odzwierciedlają go nasze zmieniające się motywy postępowania. Mamy o wiele więcej do zaoferowania, niż naszą nieudolność i niepewność siebie. Rozwinęliśmy w sobie życie duchowe i spokój umysłu, które kierują nasze zdrowienie ku nowej rzeczywistości. Z całą hojnością wyrażamy swoją miłość i dzielimy się naszym zdrowieniem, a zmianę, której doznaliśmy, przekazujemy w spadku tym, którzy jeszcze do nas dołączą.  ', 'W zdrowieniu zmieniły się motywy mojego postępowania. Chcę w swoim postępowaniu kierować się słusznymi pobudkami, a nie tylko własną korzyścią. Dzisiaj przeanalizuję motywy swojego postępowania.'),
(163, '06-11', '11 czerwca', 'Żyjąc w czystości ', NULL, '„Zdrowiejąc, zyskujemy nowy pogląd na to, co znaczy pozostawać czystym... Życie może stać się dla nas nową przygodą”.   \r\n\r\n~Tekst Podstawowy   \r\n\r\nŻycie z narkotykami nie jest czystym życiem - nikt nie wie tego lepiej od nas. Niektórzy spośród nas żyli na skraju fizycznego wyczerpania, nie dbając ani o otoczenie, ani o siebie. Jednak jeszcze gorsze od zewnętrznego brudu było nasze wewnętrzne samopoczucie. To, co robiliśmy w celu zdobycia narkotyków i sposób, w jaki traktowaliśmy innych, a także samych siebie, powodowało, że czuliśmy się zbrukani. Wielu z nas pamięta, jak często budziliśmy się rano z pragnieniem, żeby chociaż jeden jedyny raz poczuć się w porządku wobec siebie i wobec swojego życia. Dzisiaj mamy szansę poczuć się czyści dzięki życiu w czystości. Dla nas, uzależnionych, czyste życie rozpoczyna się wtedy, gdy przestajemy brać - bądź co bądź, właśnie w tym znaczeniu Anonimowi Narkomani używają zwykle słowa „czysty”. Gdy jednak pozostajemy „czyści” i pracujemy nad Dwunastoma Krokami, odkrywamy nowe znaczenie tego słowa. Jest to czystość pochodząca z uznania prawdy o naszym uzależnieniu, prawdy, która zastępuje ukrywanie lub zaprzeczanie naszej choroby. Jest to także uczucie świeżości, które przychodzi wraz z przyznaniem się do naszych błędów i z dokonanym za nie zadośćuczynieniem. Jest to witalność, której źródłem jest nowy system wartości rozwijany w trakcie poszukiwania woli naszej Siły Wyższej. Gdy stosujemy zasady naszego programu we wszystkich naszych poczynaniach, nie musimy już czuć się brudni z powodu naszego życia lub jego stylu - żyjemy w czystości i jesteśmy wdzięczni za to, że wreszcie możemy tak żyć. „Czyste życie” traktowaliśmy jak „życie dla frajerów”. Dziś życie w czystości jest jedynym sposobem, w jaki chcemy żyć. ', 'Czuję się czysty, gdyż żyję w czystości - i to jest sposób życia, który chcę prowadzić.'),
(164, '06-12', '12 czerwca', 'Źródło nadziei ', NULL, '„Tak, jesteśmy obrazem nadziei...”\r\n\r\n~Tekst Podstawowy   \r\n\r\nZanim osiągnęliśmy kres naszej drogi, wielu z nas straciło wszelką nadzieję na życie wolne od zażywania narkotyków. Byliśmy przekonani, że przeznaczone nam było umrzeć z powodu naszej choroby. Jak wielką inspiracją był dla nas, gdy przyszliśmy na nasz pierwszy mityng, widok sali pełnej zachowujących czystość uzależnionych! Czysty uzależniony naprawdę jest źródłem nadziei. Dzisiaj dajemy tę samą nadzieję innym. Nowoprzybyli widzą radosny błysk w naszych oczach, zauważają jak dbamy o siebie, słuchają nas, gdy mówimy na mityngach i często poszukują tego, co my odnaleźliśmy. Wierzą w nas, do czasu aż nauczą się wierzyć w samych siebie. Nowoprzybyli słuchają nas, gdy niesiemy im posłanie nadziei. Mają w zwyczaju patrzeć na nas trochę jakby przez „różowe okulary”. Nie zawsze rozpoznają nasze zmagania z jakąś określoną wadą charakteru lub nasze problemy z poprawianiem świadomego kontaktu z Siłą Wyższą. Trochę czasu musi upłynąć zanim zdadzą sobie sprawę z tego, że my, tzw. „staruszkowie”, z trzema, pięcioma lub dziesięcioma latami czystości, często stawiamy osobiste pragnienia przed zasadami lub cierpimy z powodu jakichś innych paskudnych wad charakteru. Tak, czasami nowoprzybyły stawia nas na piedestale. Dobrze jest jednak ujawniać nasze zmagania w zdrowieniu, ponieważ z czasem nowoprzybyły również będzie przechodził przez podobne próby. I ten nowoprzybyły będzie pamiętał, że inni, przechodząc przez takie trudności, pozostali czyści.  ', 'Będę pamiętać że jestem drogowskazem dla wszystkich, którzy podążają tą ścieżką. Będę pamiętać, że jestem źródłem nadziei.'),
(165, '06-13', '13 czerwca', 'Pełne życie ', NULL, '„Program czyni cuda w naszym życiu... Stajemy się wolni, aby żyć.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nJeżeli zdrowiejemy już od jakiegoś czasu, to z pewnością słyszeliśmy na mityngach, jak niektórzy członkowie naszej wspólnoty narzekają na to, że są okropnie przepracowani i zbyt zajęci, by uczęszczać na mityngi, sponsorować lub jakkolwiek inaczej działać we wspólnocie. Może to my właśnie jesteśmy tą narzekającą osobą. Dni wydają się być tak bardzo wypełnione: praca, rodzina, przyjaciele, mityngi, różne działania, sponsorowanie, praca nad krokami. Dzień ma po prostu za mało godzin, aby wszystko załatwić i dla każdego znaleźć czas! Gdy padają takie słowa, rozlega się śmiech innych uczestników mityngu, prawdopodobnie tych, którzy zamierzali narzekać na to samo. Powodem tego śmiechu jest uświadomienie sobie faktu, że narzekamy na cud, jakim jest dzisiaj nasze życie. Jeszcze całkiem niedawno niewielu z nas mogło mieć w swoim życiu którykolwiek z tych „problemów”. Całą energię poświęcaliśmy naszemu aktywnemu uzależnieniu. Dzisiaj mamy pełne życie, ze wszystkimi uczuciami i problemami, które ono ze sobą niesie.  ', 'Przypomnę sobie o tym, że moje życie jest cudem. Zamiast złościć się na to, jak wiele mam do zrobienia, będę wdzięczny za to, że moje życie jest takie pełne.'),
(166, '06-14', '14 czerwca', 'Utrzymywanie naszej wiary', NULL, '„Jeżeli codziennie będziemy dbać o swoją kondycję duchową, łatwiej będzie nam uporać się z cierpieniem i niepewnością.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nKiedy po raz pierwszy zaczęliśmy szukać Siły większej od nas samych, wielu z nas uwięzionych było w swoich starych przekonaniach i poglądach. Przejawiało się to strachem przed karzącym i mściwym Bogiem lub nawet zupełnym brakiem wiary. Niektórzy z nas byli przekonani, że z powodu wszystkich tych okropnych rzeczy, których się dopuściliśmy, kochająca Siła nie będzie w stanie nic z nami zrobić. Inni przekonani byli, że te „złe” rzeczy, które nam się przytrafiły, nie miałyby miejsca, gdyby kochająca Siła rzeczywiście istniała. Potrzeba czasu, wysiłku, otwartości umysłu i wiary, abyśmy nabrali przeświadczenia, że kochająca Siła Wyższa poprowadzi nas przez życiowe zmagania. Nawet wtedy, gdy mamy gotowość, żeby uwierzyć w Siłę większą od nas samych, nasze stare przekonania mogą powrócić, by nas prześladować. Poważne życiowe problemy i związane z nimi wydarzenia wywołujące niepewność mogą spowodować powrót naszych starych, błędnych przekonań na temat Boga. W takiej sytuacji musimy zapewniać sami siebie, że nasza Siła Wyższa nie opuściła nas, lecz tylko czeka, by pomóc nam przejść przez trudne chwile w zdrowieniu. Bez względu na to, jak bolesne spotkałyby nas doświadczenia, przetrwamy wszelkie niepowodzenia i będziemy kontynuować nasz rozwój, jeżeli tylko będziemy utrzymywać oferowaną nam przez nasz program wiarę. ', 'Ciężko pracowałem, by budować wiarę w kochającą i troszczącą się o mnie Siłę Wyższą, która poprowadzi mnie przez życiowe zmagania. Dziś zaufam tej Sile.'),
(167, '06-15', '15 czerwca', 'Opór przed zmianą', NULL, '„Wielu z nas trzyma się swoich lęków, wątpliwości, obrzydzenia lub nienawiści do samego siebie, z tego tylko powodu, że znajomy ból daje nam fałszywe poczucie bezpieczeństwa. Bezpieczniejszym wydaje się nam trzymanie się tego, co znamy, niż rezygnacja z tego na rzecz czegoś nieznanego.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzęsto słyszymy, że: „zaczynamy zmieniać się wtedy, gdy ból  pozostawania tym, kim jesteśmy staje się większy od bólu  powodowanego zmianą”. Gdy stajemy w obliczu zerwania związku,  zmiany kariery, uczęszczania na nowe mitingi, nowej przyjaźni lub próby podjęcia się czegokolwiek wykraczającego ponad zwyczajność, nasze  lęki mogą przeszkadzać nam w rozwoju. Tkwimy w niekorzystnych dla  nas sytuacjach tylko dlatego, że znane sytuacje wydają się być  bezpieczniejsze niż nieznane. Każda zmiana wymaga od nas pokonania  lęku. Rozważając zostawienie kochanki, myślimy: „A może już na  zawsze pozostanę sam?”. Gdy zastanawiamy się nad zmianą kariery,  zadajemy sobie pytanie: „A jeśli okaże się, że jestem niekompetentny?”.  Możemy powstrzymywać się przed uczęszczaniem na nowe mitingi,  ponieważ będziemy musieli otworzyć się na nowe kontakty i wyjść do  ludzi. Nasze umysły, bojąc się spróbować czegoś nowego, tworzą setki  wymówek, abyśmy tylko pozostali w miejscu, w którym jesteśmy. Zauważamy, że powodem większości naszego bólu nie są zmiany,  lecz opór przed zmianami. W NA uczymy się, ze zmiana jest tym, co  powoduje postęp w naszym życiu. Nowi przyjaciele, nowe związki, nowe  zainteresowania i wyzwania zastąpią stare. Razem z tymi nowymi  rzeczami w naszym życiu odnajdujemy nową radość i nową miłość.', 'Uwolnię się od starego, uchwycę się nowego i będę się rozwijał.'),
(168, '06-16', '16 czerwca', 'Akceptacja życia', NULL, '„Niektóre rzeczy musimy zaakceptować, inne możemy zmienić. Mądrość rozróżniania tych rzeczy przychodzi wraz ze wzrostem w naszym duchowym programie”.   \r\n\r\n~Tekst Podstawowy   \r\n\r\nW miarę łatwo przychodzi nam akceptacja tego, co nam się podoba, natomiast trudność sprawia nam zaakceptowanie tego, co nam się nie podoba. Jednak próby zmieniania świata i wszystkich ludzi na nim żyjących tak, by pasowali do naszych wyobrażeń, nic nie rozwiążą. Poza tym, obarczanie świata odpowiedzialnością za wszystkie nasze problemy było postawą, która utrzymywała nas w aktywnym uzależnieniu - i taka właśnie postawa niemalże nas zabiła. W trakcie pracy nad krokami, zaczynamy zadawać sobie trudne pytania dotyczące naszego udziału w tym, że nasze życie stało się aż tak bardzo nieznośne. Dochodzimy do wniosku, że w większości przypadków to nasze postawy i zachowania wymagają zmiany, a nie ludzie, miejsca czy rzeczy nas otaczające. Zdrowiejąc, modlimy się o mądrość, abyśmy mogli odróżnić to, co możemy zmienić, od tego czego zmienić nie możemy. I wtedy, gdy już ujrzymy prawdziwy obraz naszej sytuacji, zaczniemy modlić się o gotowość do zmiany siebie.', 'Siło Wyższa, użycz mi mądrości, abym odróżniał to, co mogę zmienić od tego, co muszę zaakceptować. Pomóż mi proszę zaakceptować z wdzięcznością życie, jakie otrzymałem.'),
(169, '06-17', '17 czerwca', 'Mury ', NULL, '„Wychodzenie innym na przeciw jest początkiem zmagania, które przyniesie nam wolność. Zburzy ono mury, które nas więziły.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nWielu z nas przyszło do NA ze zrujnowanymi emocjami. Lata wykorzystywania innych ludzi i pozwalania im na to, by nas wykorzystywali, odcisnęły piętno na naszej umiejętności ufania innym, włączając w to zaufanie do samego siebie. Lecz miłość i akceptacja, które znaleźliśmy we wspólnocie Anonimowych Narkomanów, dodały nam odwagi do tego, abyśmy zaczęli wyciągać rękę do innych i przybliżać się do nich. Im dłużej pozostawaliśmy czyści, tym bardziej zaczęliśmy tęsknić za bliskością z osobami, które kochamy. Zaczęliśmy podążać w stronę głębszych, bardziej znaczących relacji, nawet wtedy, gdy zachodziła obawa, że możemy zostać zranieni. Pomimo naszych lęków przed odrzuceniem, zdecydowaliśmy się zaryzykować odsłonięcie siebie, naszych przekonań i potrzeb. Zdecydowaliśmy się pozwolić runąć naszym murom obronnym. Wolność, której doświadczyliśmy, była warta podjętego ryzyka. Wiemy, że mamy jeszcze wiele do zrobienia, zanim staniemy się całkowicie wolni od barier budowanych przez lata naszego aktywnego uzależnienia. Jednak wychodząc naprzeciw innym uzależnionym i pozwalając im, pomimo naszych ludzkich słabości, na to, by wyszli naprzeciw nam, dowiedzieliśmy się, że mamy ogromną zdolność do miłości i bliskości. Uwalniamy się od ograniczających nas murów, nasze serca wypełnia wielka moc. ', 'Pozwolę runąć moim osobistym murom i wyjdę naprzeciw innym. Uwolnię moje serce i pozwolę mu kochać i być kochanym. '),
(170, '06-18', '18 czerwca', 'Zadośćuczynienie pośrednie ', NULL, '„W sytuacjach, gdy bezpośrednie zadośćuczynienie mogłoby sprawić komuś przykrość lub wyrządzić krzywdę, koniecznym może okazać się zadośćuczynienie pośrednie.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nKiedy braliśmy, nie pozwalaliśmy, aby cokolwiek stanęło nam na drodze do uzyskania kolejnego odlotu. W rezultacie, wielu z nas często nie wiedziało nawet kogo krzywdzi, czy to finansowo, czy też emocjonalnie. Kiedy nadszedł czas na zadośćuczynienie w Kroku Dziewiątym, zorientowaliśmy się, że nie jesteśmy w stanie przypomnieć sobie wszystkich skrzywdzonych przez nas osób, ponieważ było ich tak wiele. Z pomocą naszego sponsora i innych zdrowiejących członków NA znaleźliśmy rozwiązanie tego problemu. Przyrzekliśmy dokonać anonimowego zadośćuczynienia poprzez rekompensatę na rzecz naszego społeczeństwa. Skupiliśmy się na pomocy uzależnionym, którzy wciąż jeszcze cierpią. W ten sposób znaleźliśmy sposób na oddanie czegoś społeczeństwu. Dzisiaj, dzięki miłości i pomocy członków NA, więcej oddajemy otaczającemu nas światu niż od niego bierzemy. Ulepszamy społeczność, w której żyjemy poprzez niesienie posłania zdrowienia tym, których na co dzień spotykamy.', 'Dokonam pośredniego zadośćuczynienia, wychodząc naprzeciw uzależnionemu, który potrzebuje pomocy. Postaram się mieć skromny wkład w to, aby środowisko, w którym się obracam na co dzień stało się lepszym miejscem do życia.'),
(171, '06-19', '19 czerwca', 'Poczucie humoru ', NULL, '„Odkrywamy, że pozbywając się obsesji na własnym punkcie, możemy dowiedzieć się, co znaczy być szczęśliwym, wolnym i pełnym radości człowiekiem.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nCzęsto, nowoprzybyły jest zaskoczony tym, że na naszych mityngach jest tak dużo śmiechu. Jako grupa, doceniamy uzdrawiającą moc śmiechu. Nawet wtedy, gdy jesteśmy czymś bardzo zmartwieni, radość wypełniająca nasze salki mityngowe pozwala nam na jakiś czas zapomnieć o kłopotach i cieszyć się zdrowieniem. Humor może tymczasowo uwolnić nas od obsesji na własnym punkcie. Życie często bywa mało zabawne. Jeśli jednak potrafimy spojrzeć na siebie z dystansem i poczuciem humoru, jesteśmy w stanie znieść sprawy, które zwykle nas przerastają. Jak często zamartwialiśmy się wydarzeniami, które potraktowane z odrobiną humoru okazywały się o wiele łatwiejsze do zniesienia? Gdy zaczynają nas drażnić jacyś ludzie lub jakieś wydarzenia, poszukanie humorystycznej strony danej sytuacji może pomóc nam spojrzeć na nią z przymrużeniem oka. Umiejętność traktowania z humorem trudnych sytuacji jest darem, który warto rozwijać.', 'Postaram się traktować z humorem przeciwności losu. Gdy popełnię błędy, znajdę sposób, by pośmiać się ze swoich niedoskonałości. '),
(172, '06-20', '20 czerwca', 'Medytacja dla początkujących ', NULL, '„Dla niektórych modlitwa jest proszeniem o bożą pomoc, a medytacja słuchaniem bożych odpowiedzi. Wyciszanie umysłu poprzez medytację przynosi spokój wewnętrzny, który z kolei umożliwia nam wewnętrzne spotkanie z Bogiem.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nNiektórym z nas powiedziano: „Gdy uczysz się medytować, bądź cierpliwy. Aby dowiedzieć się czego należy słuchać, niezbędna jest praktyka”. Jesteśmy wdzięczni, że ktoś nam to powiedział, bo inaczej wielu z nas zrezygnowałoby z medytacji po jednym lub dwóch tygodniach. Być może przez pierwszych parę tygodni siadaliśmy codziennie rano i tak jak sugeruje to Tekst Podstawowy, wstrzymując myśli, „nasłuchiwaliśmy” i nic nie „słyszeliśmy”. Zanim cokolwiek się wydarzyło mogło nam upłynąć kolejnych kilka tygodni na praktykowaniu medytacji. I nawet wtedy, to, co następowało, było często ledwo odczuwalne. Po naszej porannej medytacji mieliśmy trochę lepsze samopoczucie, trochę bardziej optymistycznie patrzyliśmy na życie, mieliśmy trochę więcej empatii dla spotkanych w trakcie dnia osób i byliśmy w trochę lepszym kontakcie z naszą Siłą Wyższą. Większość z nas nie doświadczała żadnych radykalnych przeżyć - żadnych błysków piorunów ani grzmotów burzy. Było to raczej coś cichego i pełnego mocy. Poświęcaliśmy czas usuwaniu z drogi naszego ego i naszych koncepcji. W tej oczyszczonej przestrzeni udoskonalaliśmy nasz świadomy kontakt ze źródłem naszego codziennego zdrowienia - Bogiem, jakkolwiek Go pojmujemy. Medytacja była czymś nowym w naszym życiu i wymagała czasu oraz wyrobienia nawyku. Jednak, podobnie jak z krokami, to działa wtedy, gdy nad tym pracujemy. ', 'Będę praktykować „wsłuchiwanie się” w wolę Boga, nawet wtedy, gdy jeszcze nie będę wiedzieć czego „słuchać”.'),
(173, '06-21', '21 czerwca', 'Nowy poziom uczciwości ', NULL, '„Byliśmy mistrzami samooszukiwania się i racjonalizacji.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nKiedy przychodzimy na nasz pierwszy mityng i słyszymy, że powinniśmy być uczciwi, myślimy sobie: „Teraz to nie powinno sprawiać mi większych trudności. Muszę tylko przestać kłamać”. Niektórym z nas przychodzi to łatwo. Nie musimy już kłamać naszym pracodawcom, usprawiedliwiając swoją nieobecność w pracy. Nie musimy okłamywać naszych rodziców odnośnie miejsca, w którym przebywaliśmy zeszłej nocy. Gdy nie używamy narkotyków, odkrywamy, że mamy mniej powodów do kłamania. Niektórzy z nas mogą mieć trudności nawet z tego rodzaju uczciwością, ale nauka niekłamania jest prosta - po prostu, co by się nie działo, nie robisz tego. Z odwagą, determinacją, wsparciem przyjaciół ze wspólnoty NA i pomocą naszej Siły Wyższej większość z nas prędzej czy później odnosi sukces w tego rodzaju uczciwości. Jednak uczciwość to coś więcej niż tylko powstrzymywanie się od kłamstw. W zdrowieniu niezbędna jest uczciwość wobec siebie samego, którą nie tak łatwo jest osiągnąć. W naszym uzależnieniu wywołaliśmy nawałnicę samooszukiwania się i racjonalizacji, gdzie wir kłamstw zagłuszał cichy głos uczciwości wobec siebie. Aby osiągnąć taką uczciwość, powinniśmy w pierwszej kolejności przestać się okłamywać. W rezultacie praktykowania medytacji zaczerpnietej z jedenastego kroku, stajemy się wyciszeni. Następnie w stanie wewnętrznej ciszy, wsłuchujemy się w prawdę. Gdy się wyciszymy, będziemy mogli osiągnąć uczciwość wobec siebie. ', 'Wsłuchując się w wewnętrzny głos prawdy, będę cichy i spokojny. Odniosę się z szacunkiem do prawdy, którą odnajdę.'),
(174, '06-22', '22 czerwca', 'Akceptując życie takim, jakie jest ', NULL, '„W trakcie zdrowienia odkrywamy, jak niezbędną rzeczą jest zaakceptowanie rzeczywistości. Gdy raz to osiągniemy, nie musimy już używać narkotyków po to, by zmieniać nasze postrzeganie rzeczywistości ”.   \r\n\r\n~Tekst Podstawowy   \r\n\r\nZażywanie narkotyków odgradzało nas od witalnej siły życia. Gdy przestajemy zażywać narkotyki i rozpoczynamy zdrowienie, stajemy z życiem twarzą w twarz. Możemy doświadczać rozczarowań, frustracji lub gniewu. Wydarzenia mogą nie toczyć się tak, jakbyśmy sobie tego życzyli. Koncentracja na sobie, którą kultywowaliśmy w trakcie naszego uzależnienia, zniekształciła nasze postrzeganie życia; trudno jest zrezygnować z oczekiwań i zaakceptować życie takim, jakie jest. Uczymy się akceptować nasze życie poprzez pracę nad Dwunastoma Krokami Anonimowych Narkomanów. Odkrywamy, w jaki sposób możemy zmienić nasze postawy i pozwolić odejść naszym wadom charakteru. Nie musimy już oszukiwać się lub uciekać przed różnymi sytuacjami. Im dłużej praktykujemy duchowe zasady zawarte w Krokach, tym łatwiej przychodzi nam zaakceptowanie życia takiego, jakim ono jest.', 'Będę praktykować samoakceptację poprzez pracę nad Dwunastoma Krokami.'),
(175, '06-23', '23 czerwca', 'Poddanie się ', NULL, '„Nie przyszliśmy do tej wspólnoty pełni miłości, uczciwości, otwartości czy też gotowości... Dopiero wtedy, gdy zostaliśmy pokonani, staliśmy się gotowi.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nPoddanie się jest niezbędnym elementem stanowiącym fundament zdrowienia, czasem jednak walczymy, nie chcąc się poddać. Po pewnym okresie zachowywania czystości większość z nas, patrząc wstecz, zastanawia się, dlaczego tak bardzo zaprzeczaliśmy naszej bezsilności, skoro poddanie się było tym, co ostatecznie ocaliło nam życie. Gdy zdrowiejemy, pojawiają się nowe możliwości poddania się. Możemy walczyć ze wszystkim i ze wszystkimi, których napotykamy, ale możemy też przypomnieć sobie korzyści, jakie odnieśliśmy z pierwszego poddania się i zaprzestać walki. Większość bólu, którego doświadczamy, wynika z walki, a nie z poddania się. W rzeczywistości, gdy poddajemy się, ból znika, a w jego miejsce pojawia się nadzieja. Zaczynamy wierzyć, że wszystko będzie dobrze i po pewnym czasie uświadamiamy sobie, że w wyniku poddania się nasze życie polepsza się. Czujemy się tak, jak wtedy, kiedy porzuciliśmy iluzję, że możemy kontrolować nasze branie - czujemy ulgę, jesteśmy wolni i przepełnieni nową nadzieją. ', 'Czy jest coś, wobec czego muszę się dzisiaj poddać? Będę pamiętać o moim pierwszym poddaniu się i przypomnę sobie, że nie muszę już dłużej walczyć.'),
(176, '06-24', '24 czerwca', 'Tolerancja ', NULL, '„... przypominając nam zawsze o pierwszeństwie zasad przed osobistymi pragnieniami.”   \r\n\r\n~Tradycja Dwunasta   \r\n\r\nCzasami ciężko jest zaakceptować czyjeś wady charakteru. Zdrowiejąc razem, w czasie mityngów nie tylko słuchamy innych, lecz obserwujemy również, jak wygląda ich zdrowienie. Im lepiej ich poznajemy, tym więcej dowiadujemy się o ich życiu. Być może tworzymy własne opinie na temat ich sposobu „pracy nad programem”. Może się też okazać, że niektórzy spośród członków NA nas denerwują, a nawet przyłapujemy się na tym, jak mówimy: „gdybym w taki sposób pracował nad programem, to na pewno wróciłbym do brania”. Odkryliśmy, że tolerancja jest zasadą, która nie tylko wzmacnia nasze własne zdrowienie, lecz także nasze związki z osobami, które nas denerwują. Akceptowanie słabości innych stanie się łatwiejsze, jeśli będziemy pamiętać o tym, że sami również rzadko chcemy pozbyć się własnych wad charakteru, dopóki świadomość ich obecności nie zacznie sprawiać nam cierpienia. ', 'Postaram się zaakceptować innych takimi, jacy są. Spróbuję ich nie osądzać. Skoncentruję się na zasadach miłości i akceptacji.'),
(177, '06-25', '25 czerwca', 'Nie tylko fart ', NULL, '„Proces dochodzenia do wiary przywraca nam jasność umysłu. Siła do działania pochodzi z tej wiary.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nDojście do wiary jest procesem, który ma swoje źródło w doświadczeniu osobistym. Każdy z nas ma takie doświadczenie. Wszyscy uzależnieni, którzy znajdują zdrowienie w NA, mają mocne dowody na istnienie życzliwej Siły, która działa w ich życiu na ich korzyść. Ci spośród nas, którzy dziś zdrowieją, są szczęściarzami. Naprawdę wielu uzależnionych umiera na naszą chorobę, nigdy nie doświadczywszy tego, co my znaleźliśmy w NA. Proces dojścia do wiary zawiera w sobie gotowość do rozpoznawania cudów takimi, jakie są. Dzielimy się cudem pozostawania w czystości, ale poza tym, każdego z nas spotkały w życiu inne cuda, które czekają na to, byśmy je rozpoznali. Ileż to razy przeżyliśmy wypadki samochodowe, przedawkowanie narkotyków lub inne grożące utratą życia sytuacje? Czy nie widzimy, spoglądając wstecz na swoje życie, że nie był to tylko zwykły „fart”? Nasze doświadczenie ze zdrowienia dostarcza nam wielu przykładów na to, że Siła Wyższa działa dla naszego dobra. Gdy spoglądając wstecz, widzimy dowody tego, że nasza kochająca Siła Wyższa działa na naszą korzyść, jesteśmy w stanie uwierzyć, że ta sama Siła Wyższa w przyszłości nadal będzie nam pomagać. A wiara ta daje nam siłę, aby iść naprzód.  ', 'Moje zdrowienie jest czymś więcej, niż tylko zbiegiem okoliczności. Źródłem mojej siły jest świadomość tego, że moja Siła Wyższa nigdy mnie nie zawiodła i że nadal będzie mnie prowadzić.'),
(178, '06-26', '26 czerwca', 'Poddawanie własnej woli ', NULL, '„Nasze obawy osłabną, a wiara zacznie się wzmacniać, gdy poznamy prawdziwe znaczenie poddania. Nie walczymy już z lękiem, złością, poczuciem winy, użalaniem się nad sobą lub depresją.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nPoddanie się jest początkiem nowej drogi życia. Przedtem, kierowani własną wolą, stale martwiliśmy się o to, czy dobrze ukryliśmy nasze podłe kombinacje, czy we właściwy sposób zmanipulowaliśmy jakąś osobę, chcąc osiągnąć swoje cele, czy nie przegapiliśmy ważnego szczegółu w trakcie naszych zabiegów o to, by wszystko mieć pod kontrolą i kierować światem. Obawialiśmy się, że nasze plany nie powiodą się i złościliśmy się lub użalaliśmy nad sobą, gdy rzeczywiście tak się działo, albo też mieliśmy poczucie winy, gdy udało nam się je zrealizować. Życie oparte na własnej woli było bardzo ciężkie, lecz nie znaliśmy innej drogi postępowania. Poddanie się nie jest wcale łatwe. Wręcz przeciwnie, może być ono bardzo trudne, zwłaszcza na początku. Jednak łatwiej jest zaufać Bogu, Sile zdolnej do pokierowania naszym życiem, niż sobie samemu, czyli osobie, której życie wymyka się spod kontroli. Im bardziej poddajemy się, tym jest nam łatwiej. Gdy powierzamy naszą wolę i nasze życie opiece Siły Wyższej, musimy robić tyko to, co do nas należy, na tyle odpowiedzialnie i sumiennie, na ile potrafimy. Następnie, efekty naszych działań możemy pozostawić naszej Sile Wyższej. Poprzez poddawanie się, działanie w wierze i życie zgodnie z prostymi zasadami duchowymi tego programu, możemy przestać martwić się i zacząć żyć. ', 'Poddam moją samowolę. Będę starać się poznać wolę Boga wobec mnie i poszukam siły, by móc tę wolę spełniać. Rezultaty pozostawię w rękach mojej Siły Wyższej.'),
(179, '06-27', '27 czerwca', 'Zmiana i rozwój ', NULL, '„Gdy ktoś zauważa jakąś (naszą) wadę, nasza pierwsza reakcja może być obronna. Zawsze (jednak) istnieje możliwość samodoskonalenia.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nZdrowienie jest procesem, który niesie ze sobą zmianę naszego życia. Potrzebujemy tej zmiany, by kontynuować nasz rozwój w kierunku wolności. Ważne jest, by w sytuacji, gdy ktoś wytyka nam nasze wady, mieć otwarty umysł, ponieważ ujawnianie tych wad stwarza nam sposobność do zmiany i rozwoju. Reagowanie obroną ogranicza naszą możliwość otrzymania oferowanej przez innych pomocy. Natomiast rezygnacja z postawy obronnej otwiera przed nami drzwi ku zmianie, rozwojowi i wolności. Każdy dzień w procesie zdrowienia niesie możliwość dalszej zmiany i rozwoju. Im bardziej będziemy wychodzić naprzeciw zmianom z otwartym umysłem i sercem, tym większy będzie nasz wzrost i tym bardziej komfortowo będziemy czuć się w naszym zdrowieniu. ', 'Z otwartym umysłem skorzystam z każdej możliwości rozwoju.'),
(180, '06-28', '28 czerwca', 'Sumienie grupy ', NULL, '„Praca z innymi jest zaledwie początkiem służby.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nPraca w ramach służby wzywa nas do bezinteresownego poświęcenia się niesieniu posłania uzależnionemu, który wciąż jeszcze cierpi. Lecz służba na tym się nie kończy. Służba wymaga od nas obserwacji siebie i motywów swojego postępowania. Dzięki wysiłkom włożonym w służbę stajemy się wyraźnie widoczni we wspólnocie. W NA łatwo stać się „grubą rybą w małym stawie”. Jednak taka kontrolująca postawa może skutecznie zniechęcić i odstraszyć nowoprzybyłego. Sumienie grupy jest jedną z najistotniejszych zasad, jaką należy kierować się w służbie. Powinniśmy pamiętać, że liczy się sumienie grupy, a nie tylko nasze indywidualne przekonania i pragnienia. Powierzamy nasze przemyślenia i poglądy na rzecz rozwoju sumienia grupy. Gdy sumienie grupy już się skrystalizuje, akceptujemy jego wskazówki. Kluczem jest współpraca z innymi, a nie działanie przeciwko nim. Jeżeli będziemy pamiętać, że naszym wspólnym celem jest rozwój grupowego sumienia, zauważymy, że każda ze stron wnosi coś dobrego. A kiedy wszystkie dyskusje już się zakończą, będziemy razem nieść ujednolicone posłanie. Często ogarnia nas pokusa myślenia, że wiemy co dla grupy jest najlepsze. Jeżeli jednak będziemy pamiętać o tym, by nie forsować za wszelką ceną swoich pomysłów, to wtedy łatwiej będzie nam pozwolić służbie pełnić rolę maszyny wykonującej swoje podstawowe zadanie - niesienie posłania uzależnionemu, który wciąż jeszcze cierpi.  ', 'Będę miał swój udział w rozwoju sumienia grupy. Będę pamiętać, że świat się nie skończy, jeżeli nie postawię na swoim. We wszystkich swoich wysiłkach związanych ze służbą pomyślę o naszym podstawowym celu. Wyjdę naprzeciw nowoprzybyłemu. '),
(181, '06-29', '29 czerwca', 'Utrzymywać zdrowienie w formie ', NULL, '„Samozadowolenie jest wrogiem członków wspólnoty z dłuższym okresem czystości. Jeżeli przez jakiś czas pozwolimy sobie pozostawać w stanie samozadowolenia, proces zdrowienia ustanie.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nPo paru pierwszych latach zdrowienia większość z nas zaczyna się czuć tak, jakby nie istniały sprawy nie do przejścia. Jeżeli byliśmy pilni w pracy nad krokami, przeszłość mamy już w dużej mierze przepracowaną i mamy solidny fundament, na którym można budować przyszłość. Nauczyliśmy się wychodzić życiu naprzeciw. Znajomość kroków pozwala nam rozwiązywać problemy prawie tak szybko, jak tylko się pojawiają. Gdy po raz pierwszy zaznamy tego rodzaju komfortu, możemy mieć skłonność do potraktowania go jako „przystanku wypoczynkowego” na naszej drodze zdrowienia. Jednak postępując w ten sposób, nie doceniamy natury naszej choroby. Uzależnienie jest cierpliwe, subtelne, postępujące i nieuleczalne. Jest także śmiertelne - możemy umrzeć na tę chorobę, jeżeli nie będziemy kontynuować jej leczenia. Natomiast leczenie uzależnienia jest niezbędną i ciągłą pracą nad programem zdrowienia. Dwanaście Kroków jest procesem, ścieżką, którą podążamy, aby być zawsze o krok przed naszą chorobą. Mityngi, sponsorowanie, służba oraz kroki zawsze będą niezbędne do zachowania ciągłości zdrowienia. Chociaż po pięciu latach czystości możemy praktykować nasz program w jakiejś mierze inaczej niż wtedy, kiedy mieliśmy pięć miesięcy czystości, to nie oznacza to, że program się zmienił lub coś stało się mniej ważne. Oznacza to tylko tyle, że nasze praktyczne rozumienie programu zmieniło się i rozwinęło. Chcąc utrzymać nasze zdrowienie w dobrej formie i aktywności, musimy zawsze zachowywać gotowość do praktykowania naszego programu. ', 'W miarę swojego wzrostu w zdrowieniu poszukam nowych sposobów praktykowania mojego programu.'),
(182, '06-30', '30 czerwca', 'Wzmacnianie fundamentów ', NULL, '„W przyszłości nasza na nowo odkryta wiara stanowić będzie mocny fundament naszej odwagi.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nFundamentem naszego życia jest to, na czym opieramy całą naszą egzystencję. Kiedy braliśmy, fundament ten miał wpływ na wszystko, co robiliśmy. Kiedy zdecydowaliśmy, że zdrowienie jest ważne, zaczęliśmy wkładać w nie naszą energię. W rezultacie, nasze życie uległo zmianie. Aby zachować to nowe życie, musimy też zachować fundament, na którym zostało ono zbudowane: nasz program zdrowienia. Gdy zachowujemy czystość i zmieniamy styl naszego życia, nasze wartości również ulegają zmianie. Praca i szkoła mogą stać się ważne, ponieważ poprawiają jakość naszego życia. Nowe związki natomiast mogą przynieść ekscytację i ogromne wsparcie. Musimy jednak pamiętać, że program zdrowienia jest fundamentem, na którym zostało zbudowane nasze nowe życie. Każdego dnia musimy odnawiać nasze zobowiązanie wobec zdrowienia, czyniąc je naszym głównym priorytetem. ', 'Chcę nadal cieszyć się życiem, które odnalazłem w zdrowieniu. Dziś wykonam kroki, dzięki którym umocnię ten fundament.'),
(183, '07-01', '1 lipca', 'Prosty program ', NULL, 'Program jest po prostu dzieleniem się, pracą nad Dwunastoma Krokami, uczęszczaniem na mityngi i praktykowaniem zasad programu.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nNasze skomplikowane życie może stać się o wiele mniej skomplikowanym, jeżeli skoncentrujemy się na paru prostych rzeczach: dzieleniu się doświadczeniem, siłą i nadzieją z innymi uzależnionymi, regularnej obecności na mityngach oraz na praktykowaniu zasad programu w naszym codziennym życiu. Poprzez dzielenie się doświadczeniem, siłą i nadzieją z innymi uzależnionymi dajemy nowoprzybyłym mocny przykład do naśladowania. Wysiłek wkładany przez nas w pomaganie innym pomaga również nam w ujarzmianiu egocentryzmu, który jest sednem naszej choroby. Wielu z nas wybiera sobie jedną grupę, „grupę domową”, na którą sumiennie uczęszczamy. Ta regularność wprowadza pewną rutynę do naszego życia i pozwala innym dowiedzieć się, gdzie mogą nas znaleźć, jeżeli będą nas potrzebować. Praktykowanie Dwunastu Kroków w naszym codziennym życiu jest tym, co czyni różnicę pomiędzy pełnowartościowym zdrowieniem, a po prostu nie zażywaniem. Kroki dają nam tak bardzo potrzebne przewodnictwo w radzeniu sobie z wydarzeniami dnia codziennego. Tak, jesteśmy skomplikowanymi ludźmi. Natomiast program NA upraszcza nasze życie, umożliwiając nam przy tym życie wolne od aktywnego uzależnienia. Gdy żyjemy zgodnie z przewodnictwem prostych zasad zawartych w naszym Programie, nasze życie może być wypełnione pogodą ducha i nadzieją. ', 'Będę pamiętać, że jestem skomplikowaną osobą, a NA jest dla mnie najprostszą drogą, by uczynić moje życie mniej skomplikowanym.'),
(184, '07-02', '2 lipca', 'Porównywanie', NULL, '„Nasze osobiste historie mogą różnić się w szczegółach, jednak wszyscy mamy coś, co nas łączy.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nMy, uzależnieni, jesteśmy zróżnicowaną grupą ludzi, pochodzimy z różnych środowisk, w przeszłości używaliśmy różnych narkotyków i mamy różne doświadczenia. Gdy zdrowiejemy, różnice pomiędzy nami nie zanikają, wręcz przeciwnie, u niektórych mogą być nawet bardziej widoczne. Wolność od czynnego uzależnienia daje nam zarazem wolność bycia sobą. Fakt, że wszyscy zdrowiejemy nie oznacza, że musimy mieć takie same potrzeby i cele. Każdy z nas w trakcie zdrowienia ma do odrobienia własne lekcje. W jaki sposób pomagamy sobie nawzajem w zdrowieniu i jak korzystamy z naszych doświadczeń przy tak wielu różnicach pomiędzy poszczególnymi uzależnionymi? Zbieramy się razem, aby dzielić się naszym życiem w świetle zasad zdrowienia. Mimo, iż różnimy się pod względem sposobu życia, zasady duchowe, które stosujemy, są takie same. I właśnie światłem tych zasad przebijającym przez nasze różnice oświetlamy sobie nawzajem drogi naszych indywidualnych ścieżek. Wszyscy mamy dwie rzeczy, które nas łączą: uzależnienie i zdrowienie. Gdy uważnie słuchamy, możemy usłyszeć innych uzależnionych mówiących o cierpieniu spowodowanym tą samą chorobą, na którą my cierpimy, bez względu na jej określone podłoże. Gdy otworzymy nasze uszy, słyszymy innego uzależnionego mówiącego o stosowaniu zasad duchowych, które zapewniają także i nam nadzieję, bez względu na nasze osobiste cele. ', 'Mam swoją własną drogę do przejścia, jednak jestem wdzięczny wspólnocie ludzi, którzy doświadczyli cierpienia z powodu uzależnienia, i którzy, podobnie jak ja, uczą się stosować zasady zdrowienia.'),
(185, '07-03', '3 lipca', 'Czas ciszy', NULL, '„Wielu z nas odkryło, że zarezerwowanie sobie czasu na wyciszenie się jest pomocne w budowaniu świadomego kontaktu z naszą Siłą Wyższą.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nWiększość z nas przykłada zbyt małą wagę do wartości świadomego kontaktu z Siłą Wyższą. Jak wielu z nas poświęca konsekwentnie czas na poprawienie tego rodzaju kontaktu? Jeżeli jeszcze nie wprowadziliśmy do swojego trybu życia regularnej modlitwy i medytacji, dzisiaj jest dobry dzień, by to rozpocząć. „Czas wyciszenia” nie musi być długi. Wielu z nas dostrzega, że dwadzieścia do trzydziestu minut wystarczy, by się wyciszyć, skupić uwagę na duchowym przesłaniu, podzielić się myślami i zmartwieniami w modlitwie i przeznaczyć kilka chwil na uzyskanie odpowiedzi w medytacji. Nasz „czas wyciszenia” nie musi być bardzo długi, by przynieść efekty, pod warunkiem, że stosujemy go wytrwale. Dwadzieścia minut poświęcone na modlitwę raz w miesiącu będzie prawdopodobnie trochę nas frustrowało mizerną jakością naszego świadomego kontaktu. Natomiast dwadzieścia minut poświęcone regularnie każdego dnia odnawia i wzmacnia realny kontakt z naszą Siłą Wyższą. W krzątaninie i zgiełku dnia zdrowiejącego uzależnionego wielu z nas goni od rana do nocy, nie znajdując czasu na polepszanie naszego świadomego kontaktu z Bogiem, jakkolwiek Go pojmujemy. Jeżeli jednak zarezerwujemy sobie konkretny czas w ciągu dnia, każdego dnia, jako „czas wyciszenia”, możemy być pewni, że nasz świadomy kontakt z Siłą Wyższą poprawi się. ', 'Gdy skończę czytać dzisiejszy tekst, zarezerwuję sobie kilka chwil na modlitwę i medytację. To będzie początek mojego nowego modelu zdrowienia. '),
(186, '07-04', '4 lipca', 'Konflikt ', NULL, '„Uczymy się tego, że konflikty są częścią rzeczywistości i zamiast od nich uciekać poznajemy nowe sposoby ich rozwiązywania.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nOd czasu do czasu wszyscy doświadczamy jakichś konfliktów. Być może nie możemy dogadać się z nowym kolegą w pracy. Może przyjaciele doprowadzają nas do szału. A może nasz partner nie spełnia naszych oczekiwań. Radzenie sobie z konfliktami przysparza zdrowiejącym uzależnionym wiele trudności. Jeśli w trakcie jakiegoś konfliktu temperatura rośnie, często warto się wycofać aż do chwili, gdy emocje opadną. Zawsze przecież możemy wrócić do dalszej dyskusji, gdy się już uspokoimy. Nie unikniemy kłopotliwych sytuacji, ale możemy dać sobie trochę czasu i nabrać dystansu, by spojrzeć na daną sytuację z innej perspektywy. Konflikt jest częścią życia. Nie możemy przejść przez całe nasze zdrowienie bez narażania się na niezgodności i różnice zdań. Czasami możemy wycofać się z jakiejś konfliktowej sytuacji, dając sobie czas na zastanowienie się, ale zawsze nadchodzi chwila, kiedy konflikt musi zostać rozwiązany. A gdy chwila ta już najedzie, bierzemy głęboki oddech, odmawiamy modlitwę i stosujemy zasady, które zaoferował nam program: uczciwość, otwartość, odpowiedzialność, wybaczanie, zaufanie i wszystkie pozostałe. Nie po to staliśmy się czyści, by uciekać przed życiem. Zdrowiejąc, nie musimy już dłużej uciekać. ', 'Zasady, których dostarczył mi mój program są wystarczające, by przeprowadzić mnie przez każdą sytuację. Będę starać się stawiać czoła konfliktom w zdrowy sposób.'),
(187, '07-05', '5 lipca', 'Odkrywając prawa duchowe ', NULL, '„Charakter naszej wiary określa sposoby modlitwy i medytacji.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nW jaki sposób modlimy się? Dla każdego członka wspólnoty NA jest to głęboko osobistą kwestią. Wielu z nas odkrywa, że po jakimś czasie rozwijamy sposób modlitwy i medytacji oparty na tym, czego się nauczymy od innych i z czym jest nam wygodnie. Niektórzy z nas przybyli do NA z zamkniętym umysłem wobec Siły większej niż nasza własna. Gdy jednak siadamy ze sponsorem i omawiamy nasze trudności z Krokiem Drugim, jesteśmy zadowoleni, dowiadując się, że możemy wybrać którąkolwiek z odpowiadających nam koncepcji Siły Wyższej. Podobnie, jak definicja Siły większej niż nasza własna jest inna u każdego uzależnionego, tak samo sposób osiągania świadomego kontaktu z tą Siłą jest różny. Niektórzy uczęszczają na spotkania religijne, inni śpiewają, inni z kolei siedzą w ciszy, rozmawiając z kimkolwiek „gdzieś tam obecnym”, a inni odnajdują duchową łączność poprzez obcowanie z naturą. Właściwą drogą ku modlitwie i medytacji jest którakolwiek0 z dostępnych dróg, jeżeli tylko pomaga nam ona doskonalić świadomy kontakt z naszą osobistą Siłą Wyższą. Pytanie innych o to, jak oni odnaleźli swoje duchowe przewodnictwo jest zawsze dobrym sposobem rozpoczęcia poszukiwań. Czytanie literatury przed wkroczeniem w obszary medytacji również może być pomocnym. Wielu z nas kroczyło tą drogą w trakcie poszukiwania. Gdy szukamy wzrostu duchowego, możemy w dużym stopniu korzystać z doświadczenia innych. ', 'Zbadam swoje możliwości, dzięki którym będę mógł poprawić świadomy kontakt z Bogiem, jakkolwiek Go pojmuję.'),
(188, '07-06', '6 lipca', 'Przepraszam ', NULL, '„Krok Ósmy przede wszystkim buduje naszą świadomość stopniowego nabywania wglądu w nas samych i poznawania naszych sposobów wchodzenia w relacje z innymi ludźmi.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nPowiedzenie „przepraszam“ nie jest większości z nas obce. W czynnym uzależnieniu być może było to dość często używanym przez nas zwrotem. Zawsze mówiliśmy ludziom, że jest nam bardzo przykro i byliśmy bardzo zaskoczeni, gdy ktoś znużony naszymi pozbawionymi znaczenia przeprosinami odpowiadał nam: „To oczywiste, że jest ci przykro! Faktycznie, nie słyszałem bardziej żałosnego usprawiedliwiania się...”. Być może po raz pierwszy zdaliśmy sobie sprawę z tego, że dla osób, które skrzywdziliśmy, nic się nie zmieniało przez to, że powiedzieliśmy im „przepraszam”, szczególnie wtedy, gdy obydwie strony dobrze wiedziały, że znowu zrobimy to samo. Wielu z nas myślało, że zadośćuczynienie polega na kolejnym „przepraszam”. Jednak to, co robimy w tym kroku jest czymś zupełnie innym. Zadośćuczynić - oznacza zmienić się i przede wszystkim naprawić daną sytuację. Jeżeli ukradliśmy pieniądze, nie ograniczamy się wyłącznie powiedzeniem: „Przepraszam, teraz, będąc czystym, już nigdy tego nie zrobię”. Oddajemy pieniądze. Jeżeli zaniedbaliśmy lub wykorzystaliśmy naszą rodzinę, nie tylko przepraszamy. Zaczynamy traktować ich z szacunkiem. Zadośćuczynienie za nasze zachowania i sposoby, w jaki traktowaliśmy siebie i innych jest głównym celem pracy nad tym krokiem. Już nie tylko jest nam po prostu „przykro”, lecz bierzemy na siebie odpowiedzialność. ', 'Wezmę odpowiedzialność za siebie i za moje zdrowienie. Dzisiaj zadośćuczynię za jakąś określoną rzecz, z powodu której czuję skruchę');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(189, '07-07', '7 lipca', 'Bóg w każdym z nas ', NULL, '„Jeden element naszego przebudzenia duchowego pochodzi od nowego zrozumienia naszej Siły Wyższej, co następuje dzięki braniu udziału w zdrowieniu innego uzależnionego.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nSłyszeliśmy, jak inni mówią, że często Boga najwyraźniej możemy zobaczyć w sobie nawzajem. Dostrzegamy prawdziwość tych słów, gdy praktykujemy Dwanaście Kroków. Niosąc posłanie innemu uzależnionemu, możemy wyczuć obecność Siły większej od nas samych. Natomiast, gdy widzimy, że to posłanie przynosi efekty, uświadamiamy sobie coś jeszcze. To właśnie posłanie przynosi zdrowienie, a nie sam posłaniec. To Siła Wyższa, a nie nasza własna siła, jest źródłem zmiany, która rozpoczyna się, gdy niesiemy posłanie wciąż cierpiącemu uzależnionemu. Gdy to posłanie staje się skuteczne, odmieniając życie kolejnego uzależnionego, widzimy Siłę Wyższą w działaniu. Obserwujemy, jak akceptacja i nadzieja zajmują miejsce zaprzeczania i desperacji. Widzimy pierwsze pojawiające się ślady uczciwości, otwartości umysłu i gotowości. Coś dzieje się we wnętrzu tej osoby, coś większego i silniejszego od każdego z nas. Obserwujemy Boga, do pojmowania którego już doszliśmy, działającego w życiu innych ludzi. Widzimy w nich Siłę Wyższą. I bardziej niż kiedykolwiek jesteśmy pewni tego, że ta Siła Wyższa jest również w nas, jako moc prowadząca nas w zdrowieniu. ', 'Kiedy będę nieść posłanie innemu uzależnionemu, postaram się zwrócić uwagę na Siłę kryjącą się za tym posłaniem. Dziś, patrząc na innych zdrowiejących uzależnionych, postaram się dostrzec w nich Boga i dzięki temu wyraźniej ujrzę Boga w sobie.'),
(190, '07-08', '8 lipca', 'Słowo na „B” ', NULL, '„Ważne jest, byś wiedział, że na mityngach NA usłyszysz wzmiankę o Bogu. To, do czego się odnosimy, to Siła większa niż nasza własna, która czyni możliwym to, co nie jest możliwe.”  \r\n\r\n~IP nr 22   \r\n\r\nWiększość z nas przybyło do NA z bardzo różnymi wyrobionymi z góry opiniami na temat znaczenia słowa Bóg. Wiele z tych opinii było negatywnych. Jak do tej pory, słowo to jest używane w NA regularnie, jeżeli nie stale. Pojawia się 92 razy na pierwszych 103 stronach naszego Tekstu Podstawowego, a w trzecim z naszych Dwunastu Kroków uwydatnia się w sposób szczególny. Raczej zamiast skupiać się na unikaniu rozdrażnienia, które większość z nas czuje wobec tego słowa, spróbujmy się nad nim zastanowić. Prawdą jest, że NA jest programem duchowym. Nasz program Dwunastu Kroków oferuje drogę ku odnalezieniu wolności od uzależnienia poprzez pomoc duchowej Siły większej od nas. Program sam w sobie nie mówi nam niczego na temat tego, co mamy myśleć o tej Sile. Faktem jednak jest, że w kółko słyszymy w naszej literaturze, krokach i na mityngach o „Bogu, jakkolwiek Go pojmujemy”, cokolwiek by się nie kryło pod tym pojęciem. Używamy słowa „Bóg”, ponieważ jest ono używane w naszym Tekście Podstawowym oraz dlatego, że najskuteczniej informuje ono większość ludzi o podstawowym pojęciu Siły leżącej u podłoża naszego zdrowienia. Jest to słowo, którego używamy dla wygody. Jednakże Siła ukryta pod tym słowem jest używana przez nas w innym celu, niż dla wygody. Używamy tej Siły, żeby utrzymywać naszą wolność od uzależnienia i zapewnić sobie postępujące zdrowienie. ', 'Niezależnie od tego, czy wierzę w Boga, czy nie, użyję Siły, która utrzymuje mnie w czystości i wolności.'),
(191, '07-09', '9 lipca', 'Naprawdę zdrowiejemy! ', NULL, '„Nadszedł czas, aby to wytarte, stare kłamstwo: ‘Osoba czynnie uzależniona jest skazana na zażywanie do końca życia’, przestało funkcjonować w społeczeństwie i wśród samych uzależnionych. Naprawdę zdrowiejemy.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nOd czasu do czasu słyszymy spikerów, którzy mówią, że nie rozumieją jeszcze w pełni zasad duchowych. Mówią, że gdybyśmy wiedzieli, co naprawdę dzieje się teraz w ich głowach, bylibyśmy zaskoczeni, widząc, jak bardzo wciąż jeszcze są chorzy. Mówią nam, że im dłużej są czyści, tym mniej wiedzą o czymkolwiek. Następnie, ci sami spikerzy opowiadają nam o gruntownych zmianach, jakich dokonało w ich życiu zdrowienie. Przeszli z zupełnej desperacji do niezawodnej nadziei, z niekontrolowanego zażywania narkotyków do całkowitej abstynencji, z chronicznego nie radzenia sobie z życiem do odpowiedzialności - i wszystko to dzięki pracy nad Dwunastoma Krokami Anonimowych Narkomanów. Która z tych opowieści jest prawdziwa? Zdrowiejemy czy nie zdrowiejemy? Może się nam wydawać, że umniejszając zmiany, jakie zdrowienie wniosło w nasze życie, okazujemy pokorę lub wdzięczność. To prawda, niesprawiedliwie oceniamy program, jeśli przypisujemy sobie zasługę za ten cud. Lecz dokonujemy tego samego niesprawiedliwego osądu wobec siebie i innych, z którymi się dzielimy, gdy nie rozpoznajemy istotnej wagi tego cudu. Naprawdę zdrowiejemy. Jeśli trudno jest nam dostrzec cud zdrowienia, powinniśmy ponownie temu się przyjrzeć. Zdrowienie jest wciąż żywe i wciąż działa we wspólnocie Anonimowych Narkomanów - w naszych doświadczonych członkach NA, a także w nowoprzybyłych, którzy tłumnie przychodzą na nasze mityngi i, co więcej, w nas samych. Powinniśmy tylko szerzej otworzyć oczy.  ', 'Uznam cud mojego zdrowienia i będę wdzięczny za to, że je odnalazłem.'),
(192, '07-10', '10 lipca', 'Pozytywne nastawienie ', NULL, '„Zakorzeniony we mnie negatywizm podążał za mną wszędzie, gdziekolwiek bym się nie ruszył.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nNegatywne nastawienie jest „znakiem firmowym” aktywnego uzależnienia. Wszystko, co wydarzyło się w naszym życiu było czyjąś lub czegoś winą. Obwinialiśmy innych za nasze błędy w bardzo wyrafinowany sposób. W zdrowieniu, jedną z pierwszych rzeczy, które staramy się w sobie rozwijać, jest nowy stosunek do rzeczywistości. Zaważamy, że żyje się nam o wiele łatwiej, jeżeli zastąpimy nasze negatywne myślenie pozytywnymi zasadami. Pomimo tego, że negatywne nastawienie utrzymywało nas w aktywnym uzależnieniu, to często może ono również podążać za nami na mityngi Anonimowych Narkomanów. W jaki sposób możemy rozpocząć poprawę naszych postaw? Poprzez zmianę naszego postępowania. Nie jest to łatwe, lecz jest to wykonalne. Możemy rozpocząć od przysłuchiwania się temu, w jaki sposób prowadzimy rozmowę. Zanim otworzymy usta, zadajmy sobie kilka prostych pytań: Czy to, co mam zamiar powiedzieć przyczyni się jakkolwiek do rozwiązania omawianego problemu? Czy to, co mam zamiar mówić jest ubrane w odpowiednią formę? Czy to, co muszę powiedzieć jest ważne, czy też inni poradzą sobie doskonale bez mojego gadania? Czy mówię tylko po to, żeby usłyszeć siebie mówiącego, czy też jest jakiś cel w tych „słowach mądrości”? Nasze postawy wyrażają się poprzez nasze postępowanie. Często naprawdę liczy się nie to, co mówimy, lecz jak mówimy. Jeśli będziemy się uczyć mówić w bardziej pozytywny sposób, zauważymy, że nasze postawy zaczną się poprawiać. ', 'Chcę być wolny od negatywizmu. Dzisiaj będę wyrażać się i działać pozytywnie.'),
(193, '07-11', '11 lipca', 'Wsparcie ', NULL, '„Dzielimy się otuchą i wsparciem z innymi.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nNad wieloma z nas czuwano, jak nad dziećmi stawiającymi swe pierwsze kroki. Matka podtrzymuje stojące dziecko. Ojciec klęczy w pobliżu, zachęcając maleństwo, z rozwartymi ramionami i twarzą wyrażającą oddanie. Dziecko robi parę małych kroków w kierunku ojca. Starszy brat i siostra wykrzykują z radości. Dziecko upada. Jego matka, szepcząc słowa otuchy, podnosi dziecko i zaczyna od nowa. Tym razem, dziecko utrzymuje się aż do momentu, gdy jest wystarczająco blisko, żeby bezpiecznie wpaść w ramiona ojca. Jako nowoprzybyli, w większości przychodzimy do NA jak małe dzieci. Przyzwyczajeni do życia okaleczonego uzależnieniem, pełni strachu i niepewności, potrzebujemy pomocy, by utrzymać się na nogach. Dokładnie tak, jak dziecko zaczynające swój marsz w kierunku dorosłości, podejmujemy pierwsze niepewne kroki w kierunku zdrowienia. Uczymy się kroczyć tą nową drogą życia, ponieważ inni, którzy szli przed nami, wspierali nas i dodawali nam otuchy poprzez mówienie nam, co zadziałało, a co nie zadziałało w ich przypadku. Nasz sponsor zawsze gotów jest pchnąć nas we właściwym kierunku, gdy będziemy tego potrzebować. Wiele razy czuliśmy, że nie jesteśmy w stanie podjąć się następnego kroku w naszym zdrowieniu. Podobnie jak dziecko uczące się chodzić, czasami potykamy się i upadamy. Ale nasza Siła Wyższa zawsze oczekuje na nas z rozwartymi ramionami. I w podobny sposób, jak dziecko wspierane jest okrzykami otuchy starszych braci i sióstr, my także jesteśmy wspierani przez innych członków wspólnoty, w miarę naszego podążania w kierunku pełnego życia w zdrowieniu.', 'Poszukam wsparcia u innych. Będę wspierał tych, którzy mogą potrzebować mojej siły.'),
(194, '07-12', '12 lipca', 'Cierpliwość ', NULL, '„Wpadliśmy w sidła naszej potrzeby natychmiastowej gratyfikacji, którą zapewniały nam narkotyki.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\n„Chcę tego, czego chcę i chcę tego natychmiast!” - tak właśnie przejawiała się cierpliwość u większości z nas w naszym czynnym uzależnieniu. Obsesja i kompulsja naszej choroby przekazały nam „jednopoziomową” drogę myślenia: gdy czegoś chcieliśmy, myśleliśmy tylko o tym. A narkotyki, które braliśmy, nauczyły nas, że tylko kolejna działka jest w stanie dać nam natychmiastowe zaspokojenie. Nie dziwmy się więc, że większość z nas przybyła do Anonimowych Narkomanów z zupełnym brakiem cierpliwości. Problem polega na tym, że nie zawsze możemy dostać to, czego chcemy, wtedy, gdy tego chcemy. Niektóre z naszych życzeń to czysta fantazja. Jeżeli się nad nimi zastanowimy, to uświadomimy sobie, że nie mamy żadnych podstaw, by przypuszczać, że będą one kiedykolwiek spełnione. Prawdopodobnie nie jesteśmy w stanie spełnić nawet naszych realnych pragnień, a na pewno nie możemy spełnić ich wszystkich na raz. Żeby zdobyć lub osiągnąć niektóre rzeczy, będziemy musieli poświęcić inne. W trakcie czynnego uzależnienia szukaliśmy natychmiastowego zaspokojenia, trwoniąc na to wszystkie nasze siły. W zdrowieniu musimy nauczyć się ustalać priorytety, czasami odmawiając sobie zaspokojenia niektórych swoich pragnień w imię osiągnięcia ważniejszych, długoterminowych celów. By móc tak postępować, potrzebna jest cierpliwość. By odnaleźć tę cierpliwość, praktykujemy nasz program zdrowienia, poszukując takiego rodzaju pełnego przebudzenia duchowego, które pozwoli nam żyć i cieszyć się życiem takim, jakie ono jest. ', 'Siło Wyższa, pomóż mi odkryć to, co jest najważniejsze w moim życiu. Pomóż mi uczyć się cierpliwości, żebym mógł poświęcić swoje siły naprawdę ważnym sprawom.'),
(195, '07-13', '13 lipca', 'Pokora w działaniu ', NULL, 'Jeśli cierpimy, a większość z nas od czasu do czasu cierpi, to uczymy się prosić o pomoc.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nCzasami zdrowienie staje się naprawdę trudne. Jeszcze trudniejszym natomiast może okazać się osiągnięcie takiego poziomu pokory, by poprosić o pomoc. Myślimy tak: „Mam już pewien okres czystości. Powinienem więc wykazać się czymś więcej!” Rzeczywistość zdrowienia jest jednak prosta: niezależnie, czy mamy trzydzieści dni, czy trzydzieści lat czystości, musimy mieć gotowość proszenia o pomoc, gdy jej potrzebujemy. Pokora, to wspólny temat naszych Dwunastu Kroków. Program Anonimowych Narkomanów nie uczy nas zachowywania pozorów. Program pomaga nam czerpać jak najwięcej z naszego zdrowienia. Jeżeli chcemy odnaleźć rozwiązanie problemów, które pojawiają się w naszym życiu, musimy być gotowi ujawnić nasze trudności. Czasami słyszy się w NA stare powiedzenie: „Nie możemy zachować twarzy i równocześnie uratować tyłka”. Nie jest łatwo, mając za sobą lata czystości, dzielić się na mityngu, gdy rozklejamy się z powodu tego, że warunki, jakie postawiło przed nami życie uświadomiły nam naszą bezsilność. Kiedy jednak mityng się kończy i kolejny członek wspólnoty podchodzi do nas i mówi: „Naprawdę potrzebne mi było usłyszenie tego, co powiedziałeś”, wiemy, że Bóg działa w naszym życiu. Smak pokory nigdy nie jest gorzki. Nagroda za ukorzenie się poprzez prośbę o pomoc osładza nasze zdrowienie. ', 'Jeżeli będę potrzebował pomocy, poproszę o nią. Wprowadzę pokorę do swojego życia.'),
(196, '07-14', '14 lipca', 'Praca wewnętrzna ', NULL, 'Akceptacja społeczna nie równa się zdrowieniu.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nJedną z pierwszych rzeczy, która u wielu z nas następuje w trakcie zdrowienia, jest poprawa naszego wyglądu. Poprawia się nasze zdrowie, kąpiemy się i ubieramy się bardziej stosownie. Nie będąc już pod wpływem czynnego uzależnienia, wielu z nas przestało kraść, kłamać i wyzyskiwać innych. Zaczynamy wyglądać normalnie - przez samą tylko nieobecność narkotyków. Jednakże, wyglądać normalnie jest czymś zupełnie innym niż być normalnym. Akceptacja w oczach świata jest korzyścią płynącą ze zdrowienia, ale to nie to samo, co zdrowienie. Możemy cieszyć się zyskami, które przynosi zdrowienie, lecz musimy też zadbać o podtrzymywanie jego prawdziwego źródła. Długotrwałe zdrowienie nie przychodzi wraz z akceptacją innych ludzi, lecz z wewnętrznym wzrostem, któremu bieg nadaje Dwanaście Kroków. ', 'Wiem, że nie wystarczy po prostu dobrze wyglądać. Długotrwałe zdrowienie jest pracą wewnętrzną.'),
(197, '07-15', '15 lipca', 'Związki z innymi', NULL, '„Sporządziliśmy listę wszystkich osób, które skrzywdziliśmy i staliśmy się gotowi zadośćuczynić im wszystkim.”\r\n \r\n~Krok Ósmy   \r\n\r\nWszystkie istoty ludzkie zmagają się z własnym egocentryzmem. Chroniczne skupianie się na sobie, które leży u podłoża uzależnienia, czyni to zmaganie dwa razy trudniejszym dla ludzi takich jak my. Wielu z nas żyło tak, jakbyśmy wierzyli w to, że jesteśmy jedynymi ludźmi na ziemi, będąc całkowicie ślepi na to, jakie skutki wywierały nasze zachowania na otaczających nas ludzi. Krok Ósmy jest oferowanym nam przez program procesem, dzięki któremu będziemy mogli uczciwie zweryfikować nasze dotychczasowe związki. Przyglądamy się temu, co napisaliśmy w Kroku Czwartym, aby zidentyfikować skutki naszych zachowań w stosunku do otaczających nas ludzi. Gdy rozpoznamy krzywdy, których się dopuściliśmy w stosunku do niektórych z tych osób, odnajdziemy w sobie chęć wzięcia odpowiedzialności za nasze postępowanie poprzez zadośćuczynienie im wszystkim. Różnorodność ludzi, których spotykamy w ciągu dnia oraz jakość naszych relacji z nimi, determinuje w znacznym stopniu jakość naszego życia. Miłość, humor, ekscytacja, troska - oto rzeczy, które czynią nasze życie wartym przeżycia, a nabierają one jeszcze większego znaczenia, jeśli dzielimy je z innymi. Poprzez zrozumienie tego, chcemy odkrywać prawdziwą naturę naszych związków z innymi ludźmi oraz naprawić wszystko to, co stanowi w tych relacjach przeszkodę. Chcemy pracować nad Ósmym Krokiem.', 'Chcę w pełni cieszyć się towarzystwem moich bliźnich. Przeanalizuję związki z innymi ludźmi w moim życiu. Gdy odkryję, że kogoś zraniłem, postaram się odnaleźć w sobie chęć zadośćuczynienia mu.'),
(198, '07-16', '16 lipca', 'Poczucie własnej wartości ', NULL, '„W głębi duszy czułem się gorszy i nie pasujący do tego świata.”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nW którymś momencie życia wielu z nas rozwinęło w sobie mocne poczucie nieadekwatności i bezwartościowości. Gdzieś z głębi nas samych dobiegał nieustający głos: „Jesteś bezwartościowy!” Wielu z nas uczy się rozpoznawać tę cechę niskiego poczucia własnej wartości na samym początku swojego zdrowienia. Być może niektórzy spośród nas czują, że to właśnie poczucie niższości było przyczyną wszystkich naszych problemów. Bez względu na to, czy nabawiliśmy się tego poczucia niższości w naszych rodzinach, czy też poprzez kontakty z innymi ludźmi, we wspólnocie Anonimowych Narkomanów dostajemy narzędzia, dzięki którym możemy się zregenerować. Odbudowywanie naszego zniszczonego poczucia własnej wartości rozpoczyna się czasem od zwykłego zaangażowania się w służby. Może pierwszy raz w życiu ktoś telefonuje do nas, aby po prostu spytać jak się mamy. Nie chce od nas niczego. Po prostu chce nam zaoferować swoją pomoc. Następnie, znajdujemy sponsora, kogoś, kto uczy nas, że jesteśmy wartościowi i wierzy w nas do czasu, aż sami zaczniemy wierzyć w siebie. Sponsor prowadzi nas przez Dwanaście Kroków, dzięki którym poznajemy, kim naprawdę jesteśmy, a nie kim próbowaliśmy być. Niskie poczucie wartości nie znika w ciągu jednego dnia. Czasem trzeba wielu lat, aby nauczyć się tego, jak być w kontakcie z samym sobą. Jednak z pomocą innych członków NA, którzy dzielą z nami te same uczucia, a także dzięki pracy nad Dwunastoma Krokami stajemy się osobami szanowanymi przez innych, a przede wszystkim przez samych siebie. ', 'Będę pamiętać, że zasługuję na miłość mojej Siły Wyższej. Wiem, że jestem wartościową istotą ludzką.'),
(199, '07-17', '17 lipca', 'Używając naszych „snów o zażywaniu” ', NULL, '„Czy w pełni akceptujemy fakt, że każda nasza próba zaprzestania zażywania lub kontrolowania naszego zażywania nie powiodła się?”   \r\n\r\n~Tekst Podstawowy   \r\n\r\nW pokoju jest ciemno. Czoło masz zroszone zimnym potem. Twoje serce bije jak opętane. Otwierasz oczy pewny, że właśnie zniszczyłeś swój okres czystości. Miałeś sen o zażywaniu i był on bardzo realistyczny - ludzie, miejsca, rutyna, znajome ssanie w żołądku itp. Musiało upłynąć kilka dobrych chwil, zanim zdałeś sobie sprawę z tego, że to był tylko koszmar, że to się nie wydarzyło naprawdę. Powoli uspokajasz się i znów zasypiasz. Następnego ranka nadchodzi czas, żeby przyjrzeć się temu, co się wydarzyło zeszłej nocy. Nie zażywałeś zeszłej nocy, ale jak blisko zażywania jesteś dzisiaj? Czy żyjesz iluzjami o możliwości kontrolowania swojego zażywania? Czy wiesz bez żadnych wątpliwości, co by się stało, gdybyś raz zażył narkotyk? Co dzieli cię od prawdziwej wpadki w rzeczywistości? Jak mocny jest twój program? Jak się mają twoje związki ze sponsorem, grupą domową i Siłą Wyższą? Sny o zażywaniu wcale nie muszą być oznaką niedociągnięć w naszym programie; dla uzależnionego od narkotyków nie ma niczego bardziej naturalnego, niż tego rodzaju sny. Niektórzy z nas uważają sny o zażywaniu za dary od Siły Wyższej. Przypomina nam Ona jasno o obłędzie aktywnego uzależnienia, zachęcając nas do tego, byśmy wzmacniali nasze zdrowienie. Jeśli spojrzymy na te sny w takim świetle, możemy być za nie wdzięczni. W swej zatrważającej postaci sny te mogą okazać się dla nas błogosławieństwem, jeśli tylko wykorzystamy je w celu wzmocnienia naszego zdrowienia. ', 'Przeanalizuję mój osobisty program. Porozmawiam ze sponsorem o tym, co odkryłem oraz poszukam sposobów na wzmocnienie swojego zdrowienia. '),
(200, '07-18', '18 lipca', 'Dar rozpaczy', NULL, '„Nasza choroba wciąż wracała i pogłębiała się, aż wreszcie, zrozpaczeni, postanowiliśmy szukać pomocy u siebie nawzajem, we Wspólnocie Anonimowych Narkomanów.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy myślimy o rozpaczy, wyobrażamy sobie nieprzyjemny stan biednej, przesiąkniętej strachem duszy, z rozpaczą gorączkowo  czepiającej się czegoś przeraźliwie potrzebnego. Myślimy o  upolowanych zwierzętach, głodnych dzieciach i o sobie z okresu zanim  odnaleźliśmy wspólnotę NA. Jeszcze wtedy, przed przyjściem do NA, czuliśmy rozpacz, która  zmusiła nas do zaakceptowania Pierwszego Kroku. Skończyły nam się  pomysły na życie i staliśmy się otwarci na coś nowego. Nasz obłęd w  końcu przerósł ścianę zaprzeczania, popychając nas ku uczciwemu  spojrzeniu na naszą chorobę. Nasze największe wysiłki związane z  kontrolowaniem uzależnienia zupełnie nas wykończyły, w efekcie czego  staliśmy się chętni, by się poddać. Otrzymaliśmy dar rozpaczy, w  rezultacie czego zaakceptowaliśmy duchowe zasady, które uczyniły  możliwym nasze zdrowienie. Rozpacz jest tym, co w końcu prowadzi nas ku poproszeniu o pomoc.  Gdy już raz osiągnęliśmy ten stan, możemy zawrócić i zacząć wszystko  od nowa. Podobnie jak zdesperowane, zaszczute zwierzę szuka  bezpiecznej kryjówki, tak samo my szukamy jej we wspólnocie  Anonimowych Narkomanów.', 'Dar rozpaczy wyposażył mnie w uczciwość, otwartość umysłu i gotowość. Jestem wdzięczny za ten dar, ponieważ uczynił on moje zdrowienie możliwym'),
(201, '07-19', '19 lipca', 'Spełniając marzenia', NULL, '„Marzenia, z których kiedyś zrezygnowaliśmy, mogą teraz urzeczywistnić się.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWszystkie rzeczy mają swój początek w marzeniach. Ale jak wielu z  nas spełniało swoje marzenia, gdy zażywaliśmy narkotyki? Jeżeli nawet  udało nam się zakończyć coś, co zaczęliśmy, nasze uzależnienie zwykle  okradało nas z jakiejkolwiek dumy związanej z naszymi osiągnięciami.  Możliwe, że gdy braliśmy, marzyliśmy o dniu, gdy będziemy czyści. Ten  dzień nadszedł. Możemy wykorzystać ten dzień, by urzeczywistnić nasze marzenia. Żeby je spełnić, musimy zacząć działać, ale nasz brak pewności siebie może odciągnąć nas od podjęcia jakiejkolwiek próby działania. Możemy  zacząć od rzeczywistych wyzwań. Sukces, którego doświadczamy,  realizując nasze założenia, pozwala nam następnym razem marzyć o  większych sprawach. Niektórzy z naszych członków, dzieląc się doświadczeniem, mówią, że gdy porównają swoje ambicje z okresu, kiedy po raz pierwszy zostali  czyści z tym, co aktualnie osiągnęli w zdrowienia, są zdumieni.  Odkrywamy, że w zdrowieniu, często urzeczywistnia się więcej marzeń  niż potrafimy sobie wyobrazić.', 'Będę pamiętał, że wszystkie sprawy mają swój początek w marzeniach. Dzisiaj, pozwolę sobie, by moje marzenia stały się rzeczywistością.'),
(202, '07-20', '20 lipca', 'Krok Pierwszy', NULL, '„Przyznaliśmy, że jesteśmy bezsilni wobec uzależnienia i że przestaliśmy kierować naszym życiem.”  \r\n\r\n~Krok Pierwszy  \r\n\r\nNie bez powodu Krok Pierwszy zaczyna się od słowa „my”. W ustnym  przyznaniu się do bezsilności ukryta jest ogromna siła. A kiedy chodzimy  na mitingi i dokonujemy tego przyznania się, zyskujemy coś więcej niż  tylko osobistą siłę. Stajemy się członkami wspólnoty, częścią wspólnego  „my”, a to pozwala nam razem zdrowieć z uzależnienia. Wraz z  członkostwem we wspólnocie przychodzi bogactwo doświadczeń:  doświadczeń innych uzależnionych, którzy odnaleźli drogę zdrowienia ze swojej choroby. Nie musimy już dłużej próbować samemu rozwiązywać układanki  naszego uzależnienia. Kiedy uczciwie uznamy naszą bezsilność wobec  choroby, możemy rozpocząć poszukiwania lepszej drogi życia. Nie  będziemy jej szukać sami - jesteśmy w dobrym towarzystwie. ', 'Zacznę dzień od przyznania się do bezsilności wobec uzależnienia. Przypomnę sobie, że Pierwszy Krok rozpoczyna się od słowa „my” i będę wiedział, że już nigdy nie muszę pozostawać sam ze swoją chorobą.'),
(203, '07-21', '21 lipca', ' Poddanie się dotyczy wszystkich', NULL, '„Jeśli po jakimś czasie dostrzegamy, że mamy problemy z naszym zdrowieniem, to prawdopodobnie zaprzestaliśmy wykonywania jednej lub więcej z tych czynności, które pomagały nam we wcześniejszych etapach zdrowienia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPoddanie się dotyczy tylko nowoprzybyłych, prawda? Nieprawda! Gdy jesteśmy we wspólnocie już od jakiegoś czasu, niektórzy z nas ulegają typowej dla starych członków wspólnoty postawie. Myślimy, że już wiemy coś o zdrowieniu, o Bogu, o NA, o nas samych - i faktycznie tak jest. Problem jednak leży w naszym przekonaniu, że wiemy wystarczająco dużo, i że sama ta wiedza nam wystarczy. Ważne jest natomiast to, jakie wyciągniemy wnioski i co zrobimy po tym, gdy pomyślimy, że już wszystko wiemy. Zarozumiałość i samozadowolenie mogą wpędzić nas w kłopoty. Gdy zobaczymy, że „stosowanie zasad” opartych na naszej własnej sile po prostu nie działa, możemy zastosować to, co działało na nas na początku - poddanie się. Gdy zobaczymy, że wciąż jesteśmy bezsilni a życie wymknęło się nam spod kontroli, musimy poszukać opieki Siły większej od nas samych. I gdy odkryjemy, że auto-terapia nie jest skutecznym lekiem na wszystko, musimy skorzystać z „terapeutycznej wartości pomocy jednego uzależnionego drugiemu”.', 'Potrzebuję przewodnictwa, wsparcia i Siły większej ode mnie. Pójdę na mityng, wyjdę naprzeciw nowoprzybyłemu, zadzwonię do sponsora, pomodlę się do mojej Siły Wyższej - zrobię coś, co można wyrazić jednym słowem: „poddam się”. '),
(204, '07-22', '22 lipca', 'Śmierć duchowa', NULL, '„Dla nas zażywanie oznacza śmierć, często na wiele innych sposobów, niż jeden.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas przyszło na swój pierwszy miting z nikłą iskierką życia w sobie. Ta iskra, czyli nasz duch, chce przeżyć. Anonimowi Narkomani ożywiają tego ducha. Miłość wspólnoty szybko rozdmuchuje iskrę w płomień. Z Dwunastoma Krokami i miłością innych uzależnionych, zaczynamy kwitnąć już jako pełne, żywotne istoty ludzkie, zgodne w swej strukturze z zamierzeniami Siły Wyższej. Zaczynamy cieszyć się życiem, znajdując przy tym cel naszej egzystencji. Każdego dnia, gdy decydujemy się pozostawać czyści, nasz duch jest odżywiony, a nasz związek z Siłą Wyższą wzmacnia się. Nasz duch staje się silniejszy każdego dnia, gdy wybieramy życie w czystości. Pomimo tego, że nasze nowe życie w zdrowieniu przynosi nam wiele korzyści i radości, chęć zażycia narkotyku może być czasami obezwładniająca. Gdy wszystko w naszym życiu wydaje się toczyć złym torem, powrót do brania może objawić się nam jako jedyna droga wyjścia z tej sytuacji. Wiemy natomiast, że gdy zaczniemy brać, konsekwencją będzie strata naszej starannie ożywionej duchowości. Za długo podróżowaliśmy duchową ścieżką, żeby teraz zhańbić naszego ducha poprzez zażywanie. Zdmuchnięcie duchowego płomienia, na który tak ciężko pracowaliśmy, by zachować nasze zdrowienie, jest zbyt wysoką ceną za odlot.', 'Jestem wdzięczny za to, że mój duch jest taki silny i żywotny. Dzisiaj uhonoruję tego ducha poprzez pozostanie czystym.'),
(205, '07-23', '23 lipca', ' Poddanie własnej woli', NULL, '„Oczekujemy i wymagamy tego, by wszystko szło po naszej myśli. Jednak nasze doświadczenia z przeszłości wskazują, nasze pomysły na życie nie przynosiły pozytywnych rezultatów.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKażdy z nas ma swoje pomysły na życie, plany i cele. W programie NA nie ma nigdzie mowy o tym, że nie powinniśmy myśleć o sobie, podejmować inicjatywy lub zamieniać rozsądne plany w czyny. Kłopoty natomiast zaczynają się wtedy, gdy nasze życie jest zdominowane przez samowolę. Jeśli jesteśmy zbyt uparci, wychodzimy dużo dalej poza myślenie o sobie - myślimy tylko o sobie. Zapominamy, że jesteśmy jedynie częścią świata i jakąkolwiek posiadamy siłę, pochodzi ona od naszej Siły Wyższej. Możemy nawet zajść tak daleko, że zaczniemy myśleć, że inni ludzie żyją tylko po to, by spełniać nasze zachcianki. Szybko zauważamy, że nie możemy dojść do porozumienia z otaczającym nas światem. W takiej sytuacji mamy dwa wyjścia. Możemy kontynuować kierowanie się samowolą, pełni bezpodstawnych oczekiwań i sfrustrowani tym, że świat nie kręci się wokół nas. Możemy też poddać się, odprężyć, odkryć wolę Bożą i siłę, która może zmienić nasze położenie; siłę, która pomoże nam powrócić do stanu pokoju ze światem. Myślenie, podejmowanie inicjatywy, robienie rozsądnych planów - nie ma nic złego w tych rzeczach, dopóki są one wypełnieniem woli Bożej, a nie tylko naszej własnej.', 'Zamierzam wypełniać wolę Boga, a nie moją własną. Jeśli zobaczę, że jestem w niezgodzie ze wszystkim co mnie otacza, poddam swoją wolę.'),
(206, '07-24', '24 lipca', 'Musimy pozbyć się masek\r\n', NULL, '„...ukrywaliśmy niskie poczucie własnej wartości za fałszywymi wizerunkami siebie, w nadziei, że uda nam się nimi oszukać ludzi. Musimy pozbyć się masek.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNadwrażliwość, niepewność i brak osobowości są często kojarzone z  aktywnym uzależnieniem. Wielu z nas niesie ze sobą te przywary wraz  ze zdrowieniem; nasze lęki związane z nieudolnością, odrzuceniem i  brakiem ukierunkowania w życiu nie znikają z dnia na dzień. Wielu z nas  posiada pewien zewnętrzny wizerunek fałszywych osobowości, które  skonstruowaliśmy po to, by zarówno chronić siebie jak i zadowalać  innych. Niektórzy z nas używają masek, gdyż nie są pewni, kim  naprawdę są. Czasami myślimy, że wizerunki stworzone, by chronić nas  w trakcie brania, mogą spełniać tę samą rolę w zdrowieniu. Używamy fałszywych masek, by ukryć naszą prawdziwą osobowość,  zamaskować brak pewności siebie. Te maski kryją nas przed innymi  ludźmi, ale także przed nami samymi. Poprzez życie w kłamstwie  chcemy powiedzieć, że nie jesteśmy w stanie żyć ze świadomością  prawdy o sobie. Im bardziej ukrywamy nasze prawdziwe oblicza, tym  bardziej niszczymy naszą pewność siebie. Jednym z cudów zdrowienia jest uznanie siebie takimi, jakimi jesteśmy - całościowo, z naszymi zaletami i wadami. Pewność siebie zaczyna się  od tego uznania. Na przekór naszym lękom przed byciem  niezabezpieczonym, musimy wzbudzić w sobie chęć zrzucenia naszego  przebrania. By zaufać sobie, musimy zrzucić maski.', 'Pozbędę się masek i pozwolę, by moja pewność siebie wzrastała.'),
(207, '07-25', '25 lipca', '„Niepowodzenie” Kroku Dwunastego?', NULL, '„Przebudzeni duchowo w rezultacie realizacji tych kroków staraliśmy się nieść posłanie innym uzależnionym i stosować te zasady we wszystkich sferach naszego życia.”  \r\n\r\n~Dwunasty Krok  \r\n\r\nNie ma czegoś takiego jak „nieudany” telefon dotyczący Dwunastego  Kroku. Nawet jeżeli nie zdołaliśmy zapewnić komuś czystości,  osiągnęliśmy dwa cele. Zasialiśmy ziarno zdrowienia w umyśle  uzależnionego, z którym dzieliliśmy się doświadczeniem, siłą i nadzieją.  My sami, natomiast, pozostaliśmy czyści przez kolejny dzień. Rzadko  zdarza się, aby zdrowiejący uzależniony po dwunastokrokowym telefonie pozostawał z czymś innym niż głębokim poczuciem wdzięczności. Czasami praktykujemy ten krok, nie zdając sobie z tego sprawy. Jeśli  nasi współpracownicy lub inni znajomi znają część naszej historii i widzą, jakimi osobami jesteśmy dzisiaj, wiedzą gdzie się udać, gdy mają  przyjaciela lub ukochaną osobę w potrzebie. Jesteśmy często najlepszą  atrakcją, jaką NA ma do zaoferowania. Dla wielu uzależnionych Dwunasty Krok jest „kamieniem węgielnym”  zdrowienia. Naprawdę wierzymy, że: „możemy zachować to, co mamy,  przekazując to dalej”. Paradoks Dwunastego Kroku jest oczywisty:  poprzez dawanie otrzymujemy.', 'Zapamiętam, że jestem żywym przykładem na działanie Dwunastego Kroku. Nie może mi się „nie udać”, jeśli próbuję nieść posłanie innemu uzależnionemu.'),
(208, '07-26', '26 lipca', 'Bezwarunkowe poddanie się', NULL, '„Pomoc dociera do uzależnionego dopiero wtedy, gdy jest on skłonny przyznać się do całkowitej porażki. Ten fakt może być zatrważający, ale jest to fundament, na którym zbudowaliśmy nasze życie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas spróbowała wszystkiego, co tylko można sobie wyobrazić, angażując wszystkie możliwe siły, by wypełnić istniejącą wewnątrz nas duchową pustkę. Nic - ani narkotyki, ani kontrola lub kierowanie, ani seks, ani pieniądze, ani władza, ani bogactwo lub prestiż nie były w stanie jej wypełnić. Jesteśmy bezsilni, nasze życie stało się trudne do opanowania, a zwłaszcza przez nas samych. Nasze zaprzeczanie nie zmieni tego faktu. Dlatego poddajemy się. Prosimy Siłę Wyższą, by zaopiekowała się naszą wolą i naszym życiem. Czasami, poddając się, nie wiemy, że istnieje Siła Większa od nas samych, która może przywrócić nam zdrowie. Czasami nie jesteśmy pewni, czy Bóg, jakkolwiek go pojmujemy, zatroszczy o nasze trudne do opanowania życie. Lecz nasz brak pewności i tak nie zmienia podstawowej prawdy: jesteśmy bezsilni. Przestaliśmy kierować naszym życiem. Musimy się poddać. Tylko poprzez takie myślenie i postępowanie możemy bardziej się otworzyć - na tyle, by nasze stare poglądy i wszelkie pozostałości z przeszłości mogły zostać usunięte, a nasza Siła Wyższa swoim działaniem mogła zająć ich miejsce.', 'Poddam się bezwarunkowo. Mogę uczynić to łatwym, bądź trudnym, w zależności od tego, co wybiorę. W obydwu przypadkach, zrobię to.'),
(209, '07-27', '27 lipca', 'Zdrowiejemy', NULL, '„Po przyjściu do NA znaleźliśmy się w dość specyficznej grupie ludzi, którzy cierpieli tak samo, jak my i odnaleźli zdrowienie. W ich doświadczeniach odnaleźliśmy dla siebie nadzieję. Jeżeli program zadziałał na nich - zadziała również na nas.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\n\r\nNowoprzybyły przychodzi na swój pierwszy miting roztrzęsiony i zakłopotany. Ludzie krzątają się po sali. Napoje i literatura są wystawione. Gdy wszyscy już usiądą na swoich krzesłach, miting rozpoczyna się. Nowoprzybyły rzuca zdezorientowane ukradkowe spojrzenie na dość oryginalną grupkę ludzi znajdujących się na sali i zadaje sobie pytanie: „Z jakiej racji mam powierzyć moje życie tej grupie? W końcu, są oni po prostu gronem ludzi, podobnie jak ja, uzależnionych,.” I chociaż, być może, prawdą jest, że nielicznym spośród nas na początku szło dobrze, to nowoprzybyły dość szybko zaczyna się orientować, że tak naprawdę liczy się tylko to, w jaki sposób żyjemy dzisiaj. Nasze mitingi są wypełnione uzależnionymi, których życie całkowicie się zmieniło. Na przekór przeciwnościom, naprawdę zdrowiejemy. Nowoprzybyły może utożsamić się z naszą przeszłością, a nasze teraźniejsze życie zaszczepi w nim nadzieję. Dzisiaj, każdy z nas ma możliwość zdrowienia. Tak, możemy bezpiecznie powierzyć nasze życie Sile Wyższej i Anonimowym Narkomanom. Dopóki pracujemy nad programem, możemy być pewni wolności od czynnego uzależnienia i pewni lepszego życia.', 'Zdrowienie, które odnalazłem w Anonimowych Narkomanach jest sprawą pewną. Ugruntowując na nim swoje życie, wiem, że będę wzrastał. '),
(210, '07-28', '28 lipca', 'Tajemnice i bliskość', NULL, '„Baliśmy się, że jeśli odkryjemy się przed innymi i pozwolimy im zobaczyć jacy naprawdę jesteśmy, zostaniemy odrzuceni.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nZwiązki, w których nie ma żadnych barier, w których możemy całkiem  otwarcie wyrażać nasze uczucia, są czymś, czego wielu z nas pragnie.  Równocześnie jednak możliwość doświadczenia takiej bliskości  powoduje więcej strachu, niż jakakolwiek inna sytuacja w naszym życiu. Jeśli przyjrzymy się temu, co nas przeraża, zwykle odkrywamy, że jest  to chęć ukrycia tej części naszej osobowości, której się wstydzimy,  czegoś, do czego nie przyznaliśmy się nawet przed samym sobą. Nie  chcemy, by inni wiedzieli o naszym braku poczucia bezpieczeństwa, o  bólu lub poczuciu bezużyteczności, więc po prostu odmawiamy  pokazywania im tego. Wydaje nam się, że jeśli inni nie dowiedzą się o  naszych wadach, przestaną one istnieć. I jest to punkt, w którym nasze związki urywają się. Ktokolwiek pojawia się w naszym życiu nie przejdzie miejsca, w którym zaczynają się nasze  tajemnice. Do utrzymania bliskości w związku niezbędne jest uznanie  swoich braków i ich zaakceptowanie. Jeśli to zrobimy, runie mur  zaprzeczania wzniesiony po to, by te rzeczy ukrywać, pozwalając nam  na budowanie związków z innymi.  ', 'Mam okazje, by dzielić się swoim wnętrzem. Skorzystam z tych okazji i zbliżę się do osób, które kocham.'),
(211, '07-29', '29 lipca', 'Oczekiwania', NULL, '„Jeśli uświadomimy sobie naszą potrzebę, by nam wybaczano, będzie nam łatwiej wybaczać innym.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNasze zachowanie w stosunku do otaczających nas ludzi jest odzwierciedleniem naszego zachowania w stosunku do siebie samych. Jeżeli będziemy wymagać doskonałości od siebie, będziemy jej wymagać także od innych. W trakcie zdrowienia, gdy naprawiamy i uzdrawiamy nasze życie, możemy oczekiwać od innych, by pracowali nad sobą tak samo mocno i w takim samym tempie, jak my. I dokładnie tak często, jak nie wybaczamy sobie naszych błędów, możemy ograniczać naszych przyjaciół i członków rodziny, gdy oni nie spełniają naszych oczekiwań. Praca nad krokami pomaga nam zrozumieć nasze własne ograniczenia i nasze ludzkie cechy. Zaczynamy postrzegać nasze braki jako normalne ludzkie błędy. Zdajemy sobie sprawę, że nigdy nie będziemy idealni, że czasami będziemy rozczarowywać siebie samych i innych. Mamy nadzieję na wybaczenie. Jeśli nauczymy się łagodnie traktować siebie, możemy zacząć postrzegać innych z taką samą akceptacją i tolerancją. Ci ludzie są również tylko ludźmi, którzy starają się robić wszystko najlepiej, jak potrafią, ale czasem też im się zdarzają małe upadki. ', 'W stosunku do innych będę tolerancyjny i wybaczający, podobnie, jak oczekuję tego w stosunku do siebie.'),
(212, '07-30', '30 lipca', 'Regularny obrachunek moralny', NULL, '„Kontynuowanie obrachunku moralnego oznacza, że kształtujemy w  sobie zwyczaj obserwowania samych siebie, naszych działań, postaw i  związków z ludźmi, oparty na zasadzie regularności.”  \r\n\r\n~Tekst Podstawowy \r\n \r\nProwadzenie obrachunku moralnego jest głównym elementem  naszego nowego stylu życia. Kiedy braliśmy, przyglądaliśmy się sobie na tyle rzadko, na ile tylko było to możliwe. Takie życie nie przynosiło nam szczęścia, jednak nie wierzyliśmy, że możemy je zmienić. Czuliśmy  natomiast, że samoanaliza byłaby wyłącznie bolesnym i próżnym  dręczeniem się. Dzisiaj wszystko to ulega zmianie. Gdy przyznaliśmy, że jesteśmy  bezsilni wobec uzależnienia, znaleźliśmy Siłę większą od nas samych,  która pomogła nam przestać brać. Gdy poczuliśmy się zagubieni w  labiryncie życia, znaleźliśmy wsparcie i przewodnictwo w  doświadczeniach innych uzależnionych oraz w ciągle rozwijającym się  kontakcie z naszą Siłą Wyższą. Nie musimy już czuć się uwięzieni przez  nasze stare, destrukcyjne wzorce. Możemy żyć inaczej, jeśli tylko się na  to zdecydujemy. Wypracowując w sobie nawyk robienia regularnego obrachunku  moralnego, dajemy sobie możliwość zmiany w naszym życiu  wszystkiego, co nie działa jak należy. Jeśli zaczęliśmy robić coś, co  powoduje problemy, możemy zacząć zmieniać nasze zachowanie, zanim wymknie się ono nam spod kontroli. A gdy robimy coś, co może zapobiec nadchodzącym problemom, możemy ująć to w naszym obrachunku, zachęcając się tym samym do kontynuowania podobnych działań w przyszłości. ', 'Zobowiążę się wprowadzić regularny obrachunek moralny do swojego nowego stylu życia.'),
(213, '07-31', '31 lipca', 'Wolność od aktywnego uzależnienia', NULL, '„Anonimowi Narkomani oferują tylko jedną obietnicę, a jest nią wolnośćod aktywnego uzależnienia, rozwiązanie, które umykało nam przez tak długi czas.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNA nie oferuje innych, niż wolność od aktywnego uzależnienia, obietnic. Faktem jest, że niektórzy z naszych członków odnoszą finansowy sukces w zdrowieniu. Kupują ładne domy, jeżdżą nowymi samochodami, noszą świetne ubrania, tworzą wspaniałe rodziny. Jednakże te zewnętrzne oznaki powodzenia nie występują u wielu naszych członków. Większość z nas nigdy nie osiągnie sukcesu finansowego. To niekoniecznie jednak jest odzwierciedleniem jakości naszego zdrowienia. Kiedy pochłania nas porównywaniem się z tymi, którzy żyją w dostatku, dobrze jest przypomnieć sobie, dlaczego trafiliśmy do NA. Przyszliśmy tu, ponieważ nasze życie rozpadło się. Byliśmy emocjonalnie, fizycznie i duchowo pokonani. Nasz Tekst Podstawowy przypomina nam, że: „w desperacji szukaliśmy pomocy u siebie nawzajem w NA.” Przybyliśmy tu, ponieważ byliśmy pobici. Dla uzależnionego nawet jeden dzień czystości jest cudem. Gdy pamiętamy, dlaczego przybyliśmy do NA i w jakiej trafiliśmy tu kondycji, zdajemy sobie sprawę z tego, że bogactwo materialne blednie w porównaniu do bogactw duchowych, które zyskaliśmy w zdrowieniu. ', 'Ofiarowano mi prezent duchowy, który jest większy od bogactwa materialnego: moje zdrowienie. Podziękuję Bogu, jakkolwiek go pojmuję, za moją wolność od aktywnego uzależnienia.'),
(214, '08-01', '1 sierpnia', 'Wolność od poczucia winy', NULL, '„Nasze uzależnienie nas zniewoliło. Byliśmy uwięzieni przez nasze umysły i potępieni przez nasze poczucie winy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPoczucie winy jest najpowszechniej spotykaną przeszkodą w naszym zdrowieniu. Jedną z najczęściej występujących form poczucia winy jest wstręt do samego siebie, który pojawia się, gdy próbujemy wybaczyć sobie, ale nie czujemy przebaczenia. W jaki sposób mamy wybaczyć sobie, żebyśmy mogli to poczuć? Po pierwsze, pamiętajmy, że wina i porażka nie są ogniwami łańcucha, którego się nie da przerwać. Uczciwe dzielenie się z naszym sponsorem i z innymi uzależnionymi pokazuje, że jest to prawda. Często w rezultacie takich rozmów zwiększa się nasza świadomość roli, jaką my sami odegraliśmy w zdarzeniach, w których braliśmy udział. Czasami zdajemy sobie sprawę, że nasze oczekiwania były zbyt wygórowane. Zwiększamy swoją gotowość do tego, by rozwiązywać problemy, zamiast w nich tkwić. Gdzieś podczas tej drogi odkrywamy kim naprawdę jesteśmy. Zwykle zauważamy, że nie jesteśmy istotami ani tak doskonałymi, ani tak beznadziejnymi, jak często się nam to wydawało. Nie musimy wcale dążyć do sprostania tym iluzjom; musimy po prostu żyć w rzeczywistości.', 'Jestem wdzięczny za swoje zalety i akceptuję swoje ograniczenia oraz ułomności. Poprzez gotowość i pokorę zyskuję możność robienia postępów w zdrowieniu i uwalniam się od poczucia winy. '),
(215, '08-02', '2 sierpnia', 'Praktykowanie uczciwości', NULL, 'Gdy czujemy się schwytani w pułapkę lub jesteśmy zestresowani, potrzebujemy wielkiej duchowej i emocjonalnej siły, by być uczciwym.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas próbowało wybrnąć z trudnej sytuacji poprzez  nieuczciwość, by potem musieć upokorzyć się i przyznać do prawdy.  Niektórzy z nas kłamią i konfabulują, jakby to było rzeczą naturalną,  nawet wtedy, gdy mogliby powiedzieć po prostu prawdę. Za każdym  razem, gdy jesteśmy nieuczciwi, wraca to do nas jak bumerang.  Uczciwość może być niewygodna, ale problemy, które nas spotykają w  wyniku tej nieuczciwości, są zwykle o wiele gorsze, niż dyskomfort  związany z mówieniem prawdy. Uczciwość jest jedną z fundamentalnych zasad zdrowienia. Stosujemy tą zasadę właściwie od początku naszego zdrowienia, gdy przyznajemy  się do naszej bezsilności i nieumiejętności kierowania własnym życiem.  Kontynuujemy stosowanie zasady uczciwości za każdym razem, gdy  jesteśmy postawieni przed dwoma rozwiązaniami: życiem w świecie  fantazji lub życiem na warunkach, jakie ono stawia. Nauka bycia  uczciwym nie zawsze jest prosta, a zwłaszcza po przekrętach i  oszustwach, których wielu z nas dopuszczało się w naszym  uzależnianiu. Gdy będziemy wypróbowywać naszą nowoodkrytą  uczciwość, głos może nam się łamać. Lecz niedługo prawda płynąca z  naszych ust rozwieje wszelkie wątpliwości: dobrze być uczciwym! Łatwiej jest żyć w prawdzie niż w kłamstwie.', 'Uczciwie zaakceptuję życie ze wszystkimi jego trudnościami i wymaganiami. Będę praktykował uczciwość, nawet wtedy, gdy będzie to sprawiać mi trudność. Uczciwość pomoże mi, a nie przeszkodzi, żyć w czystości i w zdrowieniu.'),
(216, '08-03', '3 sierpnia', 'Zaufanie do ludzi', NULL, '„Wielu z nas nie miałoby dokąd pójść, gdybyśmy nie zaufali grupom NA i ich członkom.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nUfanie ludziom wiąże się z ryzykiem. Istoty ludzkie są notorycznie  zapominalskie, trudno na nich polegać, nie są idealne. Większość z nas  pochodzi ze środowisk, gdzie zdrada i brak wrażliwości wśród przyjaciół  były normą. Nawet nasi „najbardziej zaufani przyjaciele” nie byli tymi, na  których mogliśmy w pełni polegać. Zanim przybyliśmy do NA, wielu z nas miało setki doświadczeń, utrwalających nas w przekonaniu, że ludziom  nie warto ufać. Nasze zdrowienie wymaga, byśmy ufali ludziom.  Jesteśmy postawieni przed następującym dylematem: ludzie nie zawsze  są godni zaufania, a pomimo to musimy im zaufać. Jak mamy to zrobić,  biorąc pod uwagę nasze doświadczenia z przeszłości? Po pierwsze, przypominamy sobie, że zasady aktywnego uzależnienia nie mają zastosowania w zdrowieniu. Większość naszych kolegów ze  wspólnoty osiąga swój najwyższy poziom poprzez życie zgodnie z  zasadami duchowymi, których uczy nas program. Po drugie,  przypominamy sobie, że na nas także nie można polegać w 100%. Na  pewno rozczarujemy kogoś w naszym życiu, niezależnie od tego jak  bardzo staralibyśmy się, żeby tak się nie stało. Po trzecie, co  najważniejsze, zdajemy sobie sprawę z tego, że musimy zaufać naszym  kolegom ze wspólnoty NA. Nasze życie jest zagrożone, a jedyną drogą  pozostania w czyści jest zaufanie tym kumplom z dobrymi intencjami,  którzy przyznają, że nie są idealni.', 'Zaufam moim przyjaciołom ze wspólnoty. I chociaż nie są oni z pewnością idealni, są jednak moją największą nadzieją'),
(217, '08-04', '4 sierpnia', 'Kiedy tajemnica przestaje być tajemnicą?', NULL, '„Uzależnieni mają tendencję do prowadzenie życia w tajemnicy... Pozbycie się wszystkich tajemnic i podzielenie się ciężarem z przeszłości przynosi wielką ulgę.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzęsto słyszeliśmy, że: „poziom naszej choroby jest wprost proporcjonalny do nieujawnionych przez nas tajemnic”. Co trzymamy w tajemnicy, a przede wszystkim, dlaczego? Utrzymujemy w tajemnicy wszystkie te sprawy, które są powodem naszego wstydu. Być może trzymamy się tych spraw, ponieważ nie chcemy z nich zrezygnować. Jeśli jednak jakieś rzeczy są powodem naszego wstydu, czyż nie lepiej by się nam żyło samym ze sobą, gdybyśmy się ich pozbyli? Niektórzy z nas trzymają się spraw powodujących wstyd z innego powodu. Nie chodzi o to, że nie chcemy się ich pozbyć; po prostu nie wierzymy, że możemy się ich pozbyć. Dręczą nas już od tak dawna, próbowaliśmy już tak wiele razy ich się pozbyć, że straciliśmy już nadzieję na ulgę. I pomimo, że wciąż są powodem naszego wstydu, nadal trzymamy je w tajemnicy. Musimy pamiętać kim jesteśmy: zdrowiejącymi uzależnionymi. Jesteśmy tymi, którzy najpierw długo próbowali zataić nasze zażywanie narkotyków, i którzy w końcu znaleźli wolność od obsesji i przymusu ich zażywania. Chociaż wielu z nas odczuwało przyjemność aż do końca brania, to i tak szukaliśmy zdrowienia. Po prostu nie mogliśmy znieść kosztów, które musieliśmy ponosić w związku z braniem. Gdy uznaliśmy naszą bezsilność i poszukaliśmy pomocy u innych, ciężar tej tajemnicy został z nas zdjęty. To samo dotyczy wszystkich innych tajemnic w naszym życiu. Tak, poziom naszej choroby jest wprost proporcjonalny do nieujawnionych przez nas tajemnic. Tylko wtedy, gdy nasze tajemnice przestaną być tajemnicami, możemy odnaleźć ulgę od spraw, które są powodem naszego wstydu. ', 'Moje tajemnice mogą czynić mnie chorym tylko tak długo, jak długo pozostają w tajemnicy. Porozmawiam dzisiaj ze sponsorem o moich tajemnicach.'),
(218, '08-05', '5 sierpnia', ' Kształt naszych myśli', NULL, '„Kształtując nasze myśli zgodnie z duchowymi ideałami, zyskujemy możliwość stania się tym, kim chcemy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nUzależnienie ukształtowało nasze myśli na swój własny sposób. Jakiekolwiek by one kiedyś nie były, od chwili, gdy nasza choroba przejęła władzę nad naszym życiem, zdeformowały się. Nasza obsesja na punkcie narkotyków i samych siebie modelowała nasze nastroje, postępowanie i całokształt istnienia. Każdy z duchowych ideałów programu służy prostowaniu jednego, bądź innego skrzywienia w naszym myśleniu, które zdążyło się rozwinąć w trakcie naszego aktywnego uzależnienia. Zaprzeczaniu przeciwstawiamy przyznanie się, skrytości - uczciwość, izolacji - wspólnotę, a rozpaczy - wiarę w kochającą Siłę Wyższą. Duchowe ideały, które odnajdujemy w zdrowieniu przywracają naszemu życiu i naszym myślom naturalny stan. Czym jest ten „naturalny stan?” Jest to stan, którego naprawdę poszukujemy dla siebie samych, odzwierciedlenie naszych najważniejszych marzeń. Skąd o tym wiemy? Wiemy, ponieważ nasze myśli są kształtowane w zdrowieniu poprzez duchowe ideały, które odnajdujemy w trakcie naszej rozwijającej się relacji z Bogiem, takim, jakim go pojęliśmy w NA. Uzależnienie już dłużej nie kształtuje naszych myśli. Dzisiaj nasze życie kształtowane jest poprzez nasze zdrowienie i naszą Siłę Wyższą.', 'Pozwolę duchowym ideałom kształtować moje myśli. Bazując na tym wzorze, odnajdę kształt mojej własnej Siły Wyższej.'),
(219, '08-06', '6 sierpnia', 'Radość wewnętrzna', NULL, '„Na samym początku naszego zdrowienia odkryliśmy, że radość nie ma źródła w rzeczach materialnych, lecz wypływa z naszego wnętrza.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNiektórzy z nas przybyli do NA zupełnie zubożali z powodu naszej choroby. Wszystko, co posiadaliśmy, straciliśmy na rzecz uzależnienia. Gdy po raz pierwszy stajemy się czyści, wkładamy całą energię w „uzdrowienie” naszych dóbr materialnych, tylko po to, by czuć się jeszcze mniej usatysfakcjonowani życiem, niż wcześniej. Inni spośród nas szukali w dobrach materialnych ukojenia od bólu emocjonalnego. Potencjalny partner do randki nas odrzucił? Kupmy coś! Zdechł nam pies? Pójdźmy do centrum handlowego. Problem polega na tym, że spełnienia emocjonalnego nie można kupić, nawet w prostym systemie ratalnym. Z natury, nie ma nic złego w rzeczach materialnych. Mogą one uczynić życie dogodniejszym lub bardziej luksusowym, ale nie mogą one same z siebie nas zmienić. Gdzie, w takim razie, można odnaleźć prawdziwą radość? Wiemy; odpowiedź tkwi wewnątrz nas. Kiedy odnaleźliśmy radość? Gdy zaoferowaliśmy siebie w służbie innym, bez oczekiwania nagrody. Odnaleźliśmy prawdziwe ciepło w kontaktach z innymi ludźmi, nie tylko w NA, ale także w naszych rodzinach, w związkach i w środowisku, w którym się obracamy. Odnaleźliśmy też najpewniejsze źródło satysfakcji w świadomym kontakcie z naszym Bogiem. Wewnętrzny spokój, pewność podążania we właściwym kierunku, bezpieczeństwo emocjonalne nie pochodzą z rzeczy materialnych, lecz z naszego wnętrza.', 'Prawdziwej radości nie da kupić. Poszukam mojej radości w służbie, we wspólnocie, w Sile Wyższej - poszukam jej w swoim wnętrzu.');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(220, '08-07', '7 sierpnia', 'Lista wdzięczności', NULL, '„Koncentrujemy się na sprawach, które nie idą po naszej myśli i ignorujemy całe piękno życia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nŁatwo jest być wdzięcznym, kiedy wszystko idzie gładko. Gdy dostaniemy podwyżkę w pracy, jesteśmy wdzięczni. Gdy weźmiemy ślub, jesteśmy wdzięczni. Gdy ktoś nas nieoczekiwanie zaskoczy ładnym prezentem lub przysługą, jesteśmy wdzięczni. Gdy jednak zostaniemy zwolnieni z pracy, rozwiedziemy się lub coś nas rozczaruje, nasza wdzięczność trafia do kosza. Zauważamy, że wpadamy w obsesję na punkcie spraw, które źle się toczą, nawet wtedy, gdy wszystko inne układa się znakomicie. Jest to moment, w którym możemy użyć listy wdzięczności. Siadamy z kartką papieru i długopisem i wymieniamy ludzi, za których jesteśmy wdzięczni. Wszyscy znamy takie osoby, które wspierały nas w trudnych chwilach. Wymieniamy duchowe osiągnięcia, do których udało nam się dojść. Zdajemy sobie sprawę, że nigdy nie udałoby się nam dzisiaj iść przez życie, gdyby nie te osiągnięcia. I na końcu poruszamy nie mniej ważną sprawę, czyli wymieniamy nasze zdrowienie samo w sobie. Wszystko, co posiadamy i za co jesteśmy wdzięczni umieszczamy na tej liście. Jesteśmy pewni, że odnajdziemy dosłownie setki rzeczy w naszym życiu, które zainspirują nas do wdzięczności. Nawet ci z nas, którzy cierpią z powodu choroby, albo którzy stracili bogactwo materialne, odnajdą błogosławieństwa duchowej natury, za które także mogą być wdzięczni. Przebudzenie duchowe jest najbardziej wartościowym darem, jaki my, uzależnieni, możemy otrzymać.', 'Sporządzę pisemną listę rzeczy, materialnych i duchowych, za które jestem wdzięczny.'),
(221, '08-08', '8 sierpnia', 'Odpowiedzialne zdrowienie', NULL, '„...akceptujemy odpowiedzialność za nasze problemy i widzimy, że jesteśmy równie odpowiedzialni za ich rozwiązywanie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCi z nas, którzy przyzwyczaili się do zrzucania odpowiedzialności na innych, mogą przejawiać te same tendencje w zdrowieniu. Szybko jednak zauważamy, że to nie działa. Przykładowo, rozważając zmianę w naszym życiu, dzwonimy do sponsora i pytamy, co powinniśmy zrobić. Pod pozorem szukania odpowiedniego rozwiązania, właściwie prosimy naszego sponsora, by wziął odpowiedzialność za podejmowane w naszym życiu decyzje. Może mieliśmy spięcie z kimś na mitingu i poprosiliśmy najlepszego przyjaciela tej osoby, by złożył on za nas przeprosiny. Być może parę razy w tym miesiącu zrzuciliśmy na naszego przyjaciela obowiązki wynikające z naszej służby. A może zdarzyło się nam poprosić przyjaciela, by przeanalizował nasze zachowania i zidentyfikował nasze braki, zamiast samemu zabrać się za osobisty obrachunek moralny? Zdrowienie jest czymś, nad czym trzeba pracować. Nie zostanie ono nam podane na srebrnej tacy. Nie możemy też oczekiwać od naszych przyjaciół, czy sponsora, by byli odpowiedzialni za pracę, którą musimy wykonać sami. Zdrowiejemy poprzez podejmowanie własnych decyzji, wykonywanie naszych własnych obowiązków wynikających ze służby i dzięki własnej pracy nad krokami. Poprzez robienie tego dla siebie samych otrzymujemy wynagrodzenie.', 'Zaakceptuję odpowiedzialność za moje życie i moje zdrowienie.'),
(222, '08-09', '9 sierpnia', 'Siła miłości', NULL, '„Zaczynamy zauważać, że boża miłość cały czas była obecna, czekając tylko na moment, byśmy ją zaakceptowali.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nMiłość Boga jest przeobrażającą siłą, która kieruje naszym zdrowieniem. Z pomocą tej miłości uwalniamy się od beznadziejnego, desperackiego cyklu brania, nienawiści do samego siebie i dalszego brania. Z tą miłością zyskujemy poczucie sensu i celowości w naszym, niegdyś pozbawionym celu, życiu. Z tą miłością są nam ofiarowane nowe wewnętrzne wskazówki i siła, której potrzebujemy do rozpoczęcia nowej drogi życia; drogi NA. Wraz z tą miłością zaczynamy inaczej postrzegać rzeczy, tak, jakbyśmy otrzymali nowe oczy. Gdy badamy nasze życie oczami miłości, dochodzimy do zaskakującego odkrycia: kochający Bóg, którego ostatnio było nam dane pojąć, zawsze był przy nas i zawsze nas kochał. Przywołujemy czasy, gdy prosiliśmy o pomoc Siłę Wyższą i była nam ona ofiarowana. Przypominamy sobie nawet te czasy, gdy nie prosiliśmy o żadną pomoc, a i tak ją otrzymywaliśmy. Zdajemy sobie sprawę, że ta kochająca Siła Wyższa opiekowała się nami przez cały czas, zachowując nas przy życiu, aż do dnia, gdy byliśmy w stanie zaakceptować jej miłość. Moc miłości była z nami przez cały czas. Dzisiaj, jesteśmy wdzięczni, że przetrwaliśmy wystarczająco długo, by stać się świadomi obecności tej miłości w naszym świecie i w naszym życiu. Jej żywotność przepełnia całe nasze istnienie, prowadząc nas w zdrowieniu i pokazując nam, jak żyć.', 'Zaakceptuję miłość Siły Wyższej w moim życiu. Jestem świadomy przewodnictwa i mocy tej Siły, która mi towarzyszy. Dzisiaj stwierdzam to z przekonaniem. '),
(223, '08-10', '10 sierpnia', 'Regularna modlitwa i medytacja', NULL, '„Większość z nas modli się wtedy, gdy cierpimy. Uczymy się, że jeżeli modlimy się regularnie, nie będziemy cierpieć tak często lub tak intensywnie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nRegularna modlitwa i medytacja są dwoma kluczowymi elementami w naszym nowym stylu życia. Nasze aktywne uzależnienie było czymś więcej niż tylko złym zwyczajem oczekiwania na klęskę spowodowaną samowolą. Nasze uzależnienie było negatywną, wyczerpującą zależnością, która zabierała nam całą pozytywną energię. Ta zależność była tak wszechogarniająca, że nie pozwała nam na rozwinięcie jakichkolwiek relacji z Siłą Wyższą. Od samego początku zdrowienia nasza Siła Wyższa stała się siłą, która prowadzi nas ku wolności. Najpierw uwolniła nas od kompulsywnego zażywania narkotyków, które braliśmy pomimo świadomości, że nas zabijają. Następnie, dała nam wolność od głębiej zakorzenionych aspektów naszej choroby. Nasza Siła Wyższa pokazała nam kierunek i dała siłę oraz odwagę, by rozliczyć samych siebie, by opowiedzieć drugiej osobie, być może po raz pierwszy w życiu, o tym, jakie naprawdę było nasze życie, by poszukać uwolnienia od chronicznych wad charakteru, stanowiących przyczynę naszych kłopotów, i w końcu, by zadośćuczynić za zło, którego się dopuściliśmy. Ten pierwszy kontakt z Siłą Wyższą oraz ta pierwsza wolność przerodziły się w życie przepełnione wolnością. Podtrzymujemy tę wolność poprzez wzmacnianie naszego świadomego kontaktu z Siłą Wyższą. Jesteśmy w stanie osiągnąć to poprzez regularną modlitwę i medytację.', 'Zobowiążę się włączyć regularną modlitwę i medytacja w swój nowy styl życia.'),
(224, '08-11', '11 sierpnia', 'Słuchanie ze zrozumieniem', NULL, '„Słuchanie ze zrozumieniem pozwala nam usłyszeć rzeczy, które działają na naszą korzyść.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas przybyła do Anonimowych Narkomanów z bardzo nikłą umiejętnością słuchania. Aby jedna odnieść korzyść z „terapeutycznej wartości pomocy jednego uzależnionego drugiemu” musimy nauczyć się słuchać ze zrozumieniem. Czym jest dla nas słuchanie ze zrozumieniem? Na mitingach, koncentrujemy się na tym, czym dzieli się inna wypowiadając się osoba. Odkładamy na bok nasze myśli i opinie aż do końca mitingu. Wtedy segregujemy to, co usłyszeliśmy i decydujemy, które pomysły chcemy wykorzystać teraz, a które w przyszłości. Możemy również w sponsoringu zastosować naszą umiejętność słuchania ze zrozumieniem. Nowoprzybyli często rozmawiają z nami o jakimś „wielkim wydarzeniu” w ich życiu. Podczas gdy wydarzenia te mogą wydawać się nam mało istotne, być może są one ważne dla nowoprzybyłego, który ma bardzo małe doświadczenie w realnym życiu. Słuchanie ze zrozumieniem pomaga nam wczuć się w uczucia wywołane tymi wydarzeniami w życiu naszego sponsorowanego. Dzięki takiemu podejściu łatwiej jest nam uzmysłowić sobie, czym możemy się z nim w danej sytuacji podzielić. Umiejętność słuchania ze zrozumieniem innych była nam obca, gdy trwaliśmy w izolacji spowodowanej naszym uzależnienie. Dzisiaj, ta umiejętność pomaga nam aktywnie angażować się w zdrowienie. Dzięki słuchaniu ze zrozumieniem otrzymujemy wszystko, co NA ma nam do zaoferowania i możemy pełniej dzielić się z innymi miłością i opieką, którą zostaliśmy obdarzeni.', 'Postaram się być uważnym słuchaczem. Będę praktykował słuchanie ze zrozumieniem wtedy, gdy inni dzielą się i gdy ja dzielę się z innymi.'),
(225, '08-12', '12 sierpnia', 'Dosyć!', NULL, '„Jakiś głos skomli wewnątrz tych ludzi: „dosyć, dosyć, mam tego dosyć”, a następnie są oni gotowi wykonać ten pierwszy i często najtrudniejszy krok w kierunku poradzenia sobie z chorobą.”\r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy naprawdę mieliśmy dosyć? Oto kluczowe pytanie, które musimy sobie zadać w trakcie przygotowywania się do pracy nad Pierwszym Krokiem we wspólnocie Anonimowych Narkomanów. Nie ma znaczenia, czy przybyliśmy do NA z nieskazitelną sytuacją rodzinną, sukcesami zawodowymi i z całą gamą pozorów zewnętrznych. Ważne jest to, że osiągnęliśmy emocjonalne i duchowe dno, które uniemożliwia nam powrót do czynnego uzależnienia. Jeżeli tak jest, to będziemy naprawdę gotowi na wszystko, by zaprzestać brania. Kiedy analizujemy naszą bezsilność, zadajemy sobie parę prostych pytań. Czy jestem w stanie kontrolować moje zażywanie narkotyków w jakiejkolwiek formie? Czy w efekcie mojego zażywania narkotyków zdarzyło się coś, czego chciałem uniknąć? Co to było? W jaki sposób nie kieruję moim życiem? Czy wierzę z całego serca, że jestem uzależniony? Jeżeli odpowiedzi na te pytania prowadzą nas do wspólnoty Anonimowych Narkomanów, oznacza to, że jesteśmy gotowi, by iść dalej ku następnemu krokowi, który poprowadzi nas do życia wolnego od czynnego uzależnienia. Jeżeli naprawdę mamy dość, to będziemy gotowi za wszelką cenę odnaleźć zdrowienie.', 'Przyznaję, że naprawdę miałem dość. Jestem gotowy do pracy nad moim Pierwszym Krokiem. '),
(226, '08-13', '13 sierpnia', 'Trudni ludzie', NULL, '„Poprzez dzielenie się bezwarunkową miłością... stajemy się bardziej kochający, a poprzez dzielenie się duchowym wzrostem stajemy się bardziej uduchowieni.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas ma w swoim otoczeniu jedną bądź dwie wyjątkowo trudne osoby. Jak sobie radzimy w naszym zdrowieniu z taką osobą? Po pierwsze, dokonujemy własnego obrachunku molarnego. Czy czasem nie skrzywdziliśmy tej osoby? Czy jakieś nasze zachowanie lub postawa nie prowokowały sposobu w jaki nas traktują te osoby? Jeżeli tak jest, będziemy chcieli oczyścić atmosferę, przyznać się do błędu i poprosić naszą Siłę Wyższą, by usunęła wszelkie wady charakteru, które mogą przeszkadzać nam w byciu pomocnym i konstruktywnym. Następnie, jako ludzie poszukujący życia zorientowanego na duchowość, podchodzimy do problemu z punktu widzenia danej osoby. Być może osoby te stykają się z wieloma trudnościami, których my nie zauważamy lub nic o nich nie wiemy, a które właśnie są powodem tego, że ta osoba jest tak nieprzyjemna. Tak, jak się przyjęło mówić, w zdrowieniu dążymy do tego, żeby „raczej wybaczać, niż by nam wybaczano, raczej rozumieć, niż być rozumianym”. W końcu, jeżeli nie jest to ponad nasze siły, poszukujemy sposobów, by pomagać innym w przezwyciężaniu ich trudności, nie raniąc przy tym ich godności. Modlimy się za ich powodzenie i rozwój duchowy oraz za to, byśmy byli w stanie zaoferować im bezwarunkową miłość, która w naszym zdrowieniu miała tak wielkie znaczenie. Nie jesteśmy w stanie zmienić trudnych ludzi, którzy są w naszym otoczeniu, jak również nie możemy wszystkich zadowolić. Natomiast poprzez stosowanie zasad duchowych, których nauczyliśmy się w NA, możemy nauczyć się ich kochać.', 'Siło Wyższa, pomóż mi służyć innym ludziom i nie żądać, by oni służyli mi.'),
(227, '08-14', '14 sierpnia', 'Uwalniając się od ograniczeń', NULL, '„Nie musimy godzić się z naszym ograniczeniami z przeszłości. Może się przeanalizować i zweryfikować nasze stare poglądy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość z nas przybyła do NA z mnóstwem narzuconych sobie ograniczeń, które blokowały wyzwolenie naszego całego potencjału, ograniczeń, które nie pozwalały nam odnaleźć wartości leżących u podłoża naszego bytu. Ograniczamy się w możliwości bycia uczciwymi wobec siebie, ograniczamy się w możliwości funkcjonowania w pracy, ograniczamy się nie podejmując ryzyka, które chcielibyśmy podjąć... ta lista wydaje się być bez końca. Jeżeli nasi rodzice lub nauczyciele powiedzieli nam, że nigdy nie osiągniemy sukcesu, a my im uwierzyliśmy, prawdopodobnie nigdy nie osiągniemy zbyt wiele. Jeżeli nasze otocznie nie nauczyło nas stać na własnych nogach, nigdy naprawdę do tego nie dojdziemy, nawet wtedy, gdy wszystko w nas będzie krzyczało, by to zrobić. We wspólnocie Anonimowych Narkomanów zaoferowano nam metodę, dzięki której możemy rozpoznać te fałszywe ograniczenia i zobaczyć je w prawdziwym świetle. Poprzez nasz Czwarty Krok odkrywamy, że nie chcemy dłużej trzymać się wszystkich wyuczonych zasad. Nie musimy być dożywotnimi ofiarami naszych przeszłych doświadczeń. Zyskujemy wolność, dzięki której możemy wyzbywać się poglądów spowalniających nasz rozwój. Możemy poszerzyć nasze horyzonty tak, byśmy mogli przyjąć nowe poglądy i nowe doświadczenia. Jesteśmy zdolni śmiać się, płakać, a ponad wszystko, jesteśmy zdolni cieszyć się naszym zdrowieniem.', 'Uwolnię się od narzuconych samemu sobie ograniczeń i otworzę się na nowe idee.'),
(228, '08-15', '15 sierpnia', 'Wraz z upływem czasu, a nie z dnia na dzień', NULL, '„Zauważyliśmy, że nie odzyskujemy zdrowia fizycznego, psychicznego i duchowego z dnia na dzień.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy kiedykolwiek zbliżałeś się do rocznicy czystości z poczuciem, że powinieneś być znacznie dalej w zdrowieniu, niż jesteś? Może słuchałeś dzielących się na mitingu nowoprzybyłych lub innych członków z krótszym czasem czystości i pomyślałeś: „Dopiero zaczynam rozumieć, o czym oni mówią!” W jakiś dziwny sposób uważamy, że zaczynając zdrowienie powinniśmy od razu poczuć się wspaniale, że życie już więcej nie dostarczy nam żadnych trudnych splotów zdarzeń ani zmian. Oczekujemy, że nasze problemy materiale rozwiążą się same, że zaczniemy myśleć racjonalnie, a nasza duchowość rozwinie się z dnia na dzień. Zapominamy, że spędziliśmy całe lata, nadużywając naszych ciał, oszałamiając umysły i tłumiąc naszą świadomość Siły Wyższej. Nie jesteśmy w stanie zniwelować tych szkód w jeden dzień. Jednakże możemy zastosować kolejny krok, pójść na następny miting lub pomóc jeszcze jednemu nowoprzybyłemu. Leczymy się i zdrowiejemy stopniowo, krok po kroku - nie z dnia na dzień, lecz wraz z upływem czasu.', 'Moje ciało trochę się podleczy, mój umysł stanie się trochę bardziej przejrzysty, a mój związek z Siłą Wyższą wzmocni się.'),
(229, '08-16', '16 sierpnia', 'W górę lub w dół', NULL, '„Jest to nasza droga do wzrostu duchowego. Zmieniamy się każdego dnia... Ten wzrost nie jest rezultatem naszych życzeń, lecz działania i modlitwy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNasza kondycja duchowa nigdy nie jest statyczna; jeżeli nie wzrasta, rozpada się. Jeżeli stoimy w miejscu, nasz duchowy postęp traci tempo wzrastania. Nasz rozwój stopniowo będzie spowalniał, następnie zatrzyma się, a w końcu zacznie się cofać. Nasza tolerancja się skurczy, nasza chęć służenia innym zmaleje, nasze umysły zamkną się i ograniczą. Niedługo po tym, znajdziemy się dokładnie w tym samym miejscu, z którego zaczęliśmy: w konflikcie ze wszystkimi i wszystkim co nas otacza, nawet siebie samych nie będziemy już mogli znieść. Dla nas jedynym dobrym rozwiązaniem jest aktywny udział w programie wzrostu duchowego. Modlimy się, poszukując przy tym wiedzy większej, niż nasza własna, pochodzącej od Siły większej, niż my sami. Otwieramy nasze umysły i utrzymujemy je otwartymi, stając się równocześnie podatnymi na naukę i czerpiąc korzyści z tego, czym dzielą się z nami inni. Okazujemy naszą gotowość spróbowania nowych pomysłów oraz nowych dróg postępowania, doświadczając przy tym pełni życia. Nasz duchowy postęp nabiera tempa i rozmachu, kierowani zaś przez Siłę Wyższą zaczynamy lepiej rozumieć naszą codzienność. Postęp lub cofanie się - jedno bądź drugie, w przypadku rozwoju duchowego nie ma właściwie nic pośredniego. Odkryliśmy, że zdrowienie nie jest napędzane życzeniami i marzeniami, lecz modlitwą i działaniem.', 'W mojej kondycji duchowej trwała jest tylko zmiana. Nie mogę polegać na wczorajszym planie. Dzisiaj, poszukam nowego wzrostu duchowego poprzez modlitwę i działanie.'),
(230, '08-17', '17 sierpnia', 'Powiedz prawdę', NULL, '„Symptomem naszej choroby jest alienacja, natomiast szczere dzielenie się umożliwi nam zdrowienia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPrawda łączy nas z życiem, podczas gdy strach, izolacja i nieuczciwość izolują nas od niego. Jako zażywający uzależnieni, ukrywaliśmy prawdę o nas przed światem na tyle, na ile było to możliwe. Strach powstrzymywał nas przed otwarciem się wobec otaczających nas ludzi, zapewniając nam ochronę przed tym, co inni mogliby nam zrobić, jeślibyśmy ujawnili swoją bezbronność. Lecz również ten sam strach uniemożliwiał nam kontakt ze światem. Żyliśmy niczym obce stworzenia na własnej planecie, zawsze samotni i z minuty na minutę coraz bardziej samotni. Dwanaście Kroków i wspólnota zdrowiejących uzależnionych daje ludziom, takim jak my, miejsce, w którym, ujawniając prawdę o sobie, możemy czuć się bezpiecznie. Jesteśmy skłonni uczciwie przyznać się do naszej frustrujące i upokarzającej bezsilności wobec uzależnienia, ponieważ spotykamy tu wielu ludzi, którzy znaleźli się w takiej samej sytuacji. Jesteśmy bezpieczni wśród tych ludzi. W trakcie kontynuowania pracy nad krokami zaczynamy mówić coraz więcej prawdy o sobie. Im bardziej to robimy, tym bardziej realnie czujemy się połączeni z otaczającym nas światem. Dzisiaj nie musimy ukrywać się przed rzeczywistością naszych relacji z innymi ludźmi, miejscami i różnymi sprawami w naszym życiu. Akceptujemy te relacje po prostu takimi, jakie są i mamy swój udział w każdej z nich. Codziennie poświęcamy chwilę na to, by zadać sobie pytanie: „Czy mówię prawdę o sobie?” Za każdym razem, gdy to robimy, coraz bardziej oddalamy się od tak charakterystycznej dla uzależniania alienacji i coraz bardziej przybliżamy się do wolności, którą może nam przynieść zdrowienie.', 'Prawda jest moim łącznikiem z rzeczywistością. Dzisiaj zadam sobie pytanie: „Czy jestem prawdomówny?”'),
(231, '08-18', '18 sierpnia', 'Jak długo jeszcze będę musiał iść?', NULL, '„Aby stać się produktywnym i odpowiedzialnym członkiem społeczeństwa, musimy umieścić zdrowienie na pierwszym miejscu.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nMitingi wydawały się być wspaniałe!! Uczęszczaliśmy na nie codziennie. Spotykaliśmy się z innymi uzależnionymi, by dzielić się doświadczeniem, siłą i nadzieją. Każdego dnia korzystaliśmy z tego, czego nauczyliśmy się na mitingach, żeby kontynuować nasze zdrowienie. Tymczasem życie trwa nadal. Praca, rodzina, przyjaciele, szkoła, sport, rozrywka, wspólnotowa aktywność, zobowiązania społeczne - wszystkie te sprawy domagają się naszego czasu. Wymagania codziennego życia doprowadzają nas czasem do pytania: „ Jak długo jeszcze będę musiał uczęszczać na te mitingi?” Pomyślmy o tym. Czy przed przyjściem do Anonimowych Narkomanów byliśmy w stanie pozostać czyści o własnych siłach? Za jakich powodów uważamy, że teraz jesteśmy w stanie to osiągnąć? Następnie rozważmy chorobę samą w sobie - chroniczne skupianie się na sobie, obsesyjność, kompulsywne schematy zachowań, które uzewnętrzniają się w tak wielu obszarach naszego życia. Czy jesteśmy w stanie żyć i cieszyć się życiem bez skutecznego leczenia naszej choroby? Nie. „Zwyczajni” ludzie nie muszą martwić się o tego typu sprawy, ale my nie jesteśmy „zwyczajnymi” ludźmi. Jesteśmy uzależnieni. Nie możemy udawać, że nie jesteśmy chorzy na postępującą i śmiertelną chorobę. Bez programu zdrowienia możemy nie przetrwać wymagań w pracy, szkole, rodzinie albo jakichkolwiek innych. Mitingi NA dają nam wsparcie i wskazówki potrzebne nam do zdrowienia z naszego uzależnienia i umożliwiające życie tak pełne i wartościowe, jak tylko jest to możliwe.', 'Chcę żyć i cieszyć się życiem. Aby to osiągnąć, postawię moje zdrowienie na pierwszym miejscu.'),
(232, '08-19', '19 sierpnia', 'Najpierw sprawy najważniejsze', NULL, '„Wkładamy cały nasz wysiłek w to, by rozwiązać najważniejsze problemy i pozostawiamy resztę. Pracujemy na bieżąco, a w trakcie osiągania postępów nowe możliwości doskonalenia się pojawiają się same.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzyż nie mówi się, że zdrowienie jest proste? Jedyną rzeczą, którą musimy zrobić, to zmienić wszystko! Może się to wydawać nie lada wyzwaniem, zwłaszcza, gdy po raz pierwszy pojawiamy się wśród Anonimowych Narkomanów. Poza tym, niewielu z nas pojawiło się na swoim pierwszym mitingu z tego powodu, że nasze życie było cudowne. Wręcz przeciwnie - większość z nas przybyła do NA, znajdując się w najgorszym kryzysie swojego życia. Potrzebowaliśmy zdrowienia i to szybko! Ogrom zmian, jakich musimy dokonać w naszym życiu może paraliżować. Wiemy, że nie jesteśmy w stanie zająć się wszystkimi potrzebami naraz, tak, żeby zostały one zrealizowane. W jaki sposób się do tego zabrać? Prawdopodobnie już się za coś zabraliśmy. Zrobiliśmy pierwsze, najbardziej oczywiste rzeczy, które miały zostać zrobione: przestaliśmy zażywać narkotyki i zaczęliśmy chodzić na mitingi. Co następnie musimy zrobić? Prawie to samo, ale z większym natężeniem. W danej chwili staramy się zrobić to, co możemy. Podążamy ścieżką zdrowienia poprzez unoszenie stopy i pokonywanie kolejnego kroku, który jest przed nami. Dopiero wtedy, gdy coś zostało zrealizowane, możemy zastanawiać się nad tym, co pojawi się w następnej kolejności. Zauważamy, że w trakcie tej drogi powoli, ale stanowczo, w sposób widoczny z dnia na dzień robimy postępy, stając się takimi ludźmi, jakimi chcemy być naprawdę.', 'Będę podążał ścieżką zdrowienia, pokonując następny stopień, który w danej chwili znajduje się przed mną.'),
(233, '08-20', '20 sierpnia', 'W obliczu śmierci', NULL, '„Często, w trakcie naszego zdrowienia musimy się zetknąć z różnego rodzaju kryzysami. Przykładem może być śmierć ukochanej osoby...”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKażde życie ma swój początek i swój kres. Jednakże, gdy ktoś, kogo darzymy wielką miłością umiera, zaakceptowanie nagłej i nieodwracalnej nieobecności tej osoby może sprawić nam ogromną trudność. Potęga tego żalu może wywołać w nas obawy, że ten ból nas przerośnie - ale tak się nie stanie. Nasz smutek może boleć bardziej, niż cokolwiek innego z naszych wspomnień, ale ten ból minie. Nie musimy uciekać od emocji, które powstaną wskutek śmierci ukochanej osoby. Śmierć i żałoba są częścią pełni życia, takiego, jakie ono jest. Pozwalając sobie na doświadczanie tych uczuć, przeżywamy głębiej zarówno swoje zdrowienie, jak i swoją ludzką naturę. Czasami realność śmierci drugiej osoby pozwala nam głębiej uświadomić sobie naszą własną śmiertelność. Weryfikujemy nasze priorytety. Jeszcze bardziej doceniamy naszych ukochanych, którzy nadal są przy nas. Nasze życie oraz nasze wspólne z nimi życie nie będzie trwało wiecznie. Chcemy zdziałać jak najwięcej, póki jeszcze mamy taką możliwość. Możemy odkryć, że śmierć kogoś, kogo kochamy pomaga nam wzmocnić nasz świadomy kontakt z Siłą Wyższą. Jeżeli będziemy pamiętać, że w razie kłopotów zawsze możemy się zwrócić do tego źródła siły, będziemy w stanie pozostać w skupieniu, bez względu na to, co dzieje się wokół nas.', 'Zaakceptuję stratę kogoś, kogo kocham i zwrócę się do mojej Siły Wyższej o siłę do zaakceptowania swoich odczuć. Okażę więcej miłości ludziom, których dziś kocham.'),
(234, '08-21', '21 sierpnia', 'Przyjaźnie', NULL, '„Nasze przyjaźnie stają się głębsze. Doświadczamy ciepła i troski, które są rezultatem wzajemnego dzielenia się uzależnionych zdrowieniem i nowym życiem.”  \r\n\r\n~IP nr 19  \r\n\r\nWiększość z nas przybyła do wspólnoty Anonimowych Narkomanów, mając kilka prawdziwych przyjaciół. Jednak większość z nas przybyła tu, nie mając pojęcia o tym, co oznacza budowanie trwałych przyjaźni. Z czasem jednak zaczynamy rozumieć, że przyjaźń wymaga pracy. Od czasu do czasu wszystkie przyjacielskie stosunki poddawane są próbom. Podobnie jak większość relacji, przyjaźń jest procesem uczenia się. Nasi przyjaciele kochają nas na tyle mocno, by powiedzieć nam prawdę o nas samych. Stare powiedzenie: „Prawda cię uwolni, ale najpierw doprowadzi do furii” wydaje się być tutaj bardzo zasadne. To jednak może uczynić przyjaźń niewygodną. Możemy zauważyć, że specjalnie unikamy spotkań z niektórymi przyjaciółmi, zamiast pozwolić sobie na konfrontację z nimi. Zrozumieliśmy jednak, że nasi przyjaciele są otwarci wobec nas, ponieważ się o nas troszczą. Chcą dla nas jak najlepiej. Nasi przyjaciele akceptują nas pomimo naszych wad. Rozumieją, że wciąż pracujemy nad tym, by się zmieniać. Przyjaciele są przy nas, gdy nie możemy sobie poradzić sami ze sobą. Przyjaciele pomagają nam dostrzec pozytywną stronę wydarzeń zachodzących w naszym życiu i w naszym zdrowieniu. Ważne jest, byśmy dbali o nasze przyjaźnie, ponieważ nauczyliśmy się, że nie jesteśmy w stanie zdrowieć sami.', 'Jestem wdzięczny za przyjaciół, których mam. Będę angażował się w moje przyjaźnie.'),
(235, '08-22', '22 sierpnia', 'Ofiara', NULL, '„Rozpoznajemy nasz duchowy rozwój po tym, że zaczynamy być zdolnie do wychodzenia na przeciw innym i pomagania im.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nZmienienie świata poprzez ofiarowanie czegoś nadzwyczajnego jest  prawdopodobnie najwyższą aspiracją ludzkiego serca. Każdy z nas, bez  względu na to, co myślimy o sobie, ma do zaoferowania światu coś  wyjątkowego. Prawdopodobnie w czasie naszego zdrowienia spotkaliśmy kogoś, kto  do nas dotarł, podczas gdy nikomu innemu nie udało się tego osiągnąć.  Niezależnie, czy był to ktoś, kto nas rozśmieszył na naszym pierwszym  mitingu, czy był to współczujący sponsor lub rozumiejący nas przyjaciel,  który wspierał nas w trakcie przechodzenia przez emocjonalną burzę, ta  osoba dokonała zmiany w naszym świecie. Wszyscy otrzymaliśmy dar zdrowienia, którym dzielimy się z drugim  zdrowiejącym uzależnionym. Jesteśmy za to wdzięczni. Uzewnętrzniamy naszą wdzięczność poprzez dobrowolne dzielenie się z innymi tym, co  było nam ofiarowane. Indywidualne posłanie, które niesiemy, pomóc  może tylko temu nowoprzybyłemu, do którego jesteśmy w stanie dotrzeć. Jest wiele sposobów, byśmy mogli służyć wspólnocie. Każdy z nas  odkryje, że niektóre rzeczy robimy lepiej od innych, lecz powinniśmy  pamiętać, że każda praca związana ze służbą jest równie ważna. Jeżeli  mamy chęć służenia, to na pewno odkryjemy właściwy sposób, by robić  to jak najlepiej.', 'Mogę przyczynić się do jakiejś pozytywnej zmiany. Ofiaruję dziś komuś pomocną dłoń.'),
(236, '08-23', '23 sierpnia', 'Podejmowanie decyzji', NULL, '„Zanim staliśmy się czyści, w większości sytuacji działaliśmy pod wpływem impulsu. Dziś już tak nie reagujemy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nŻycie składa się z serii decyzji, działań oraz ich konsekwencji. Kiedy  braliśmy, nasze decyzje były zwykle podejmowane pod wpływem  choroby i w rezultacie kończyło się to autodestrukcyjnymi działaniami i  zgubnymi konsekwencjami. Patrzyliśmy na kwestię podejmowania  decyzji jak na zagmatwaną grę, w której staraliśmy się brać jak  najmniejszy udział. Mając takie podejście, wielu z nas w zdrowieniu miało wielką trudność  z nauczeniem się podejmowania decyzji. Powoli, poprzez pracę nad  Dwunastoma Krokami, zyskujemy praktykę w podejmowaniu zdrowych  decyzji, takich decyzji, które przynoszą pozytywne rezultaty. Prosimy Siłę Wyższą, by się nami zaopiekowała w tych sferach, na które przedtem  wpływała nasza choroba. Dokonujemy obrachunku naszych wartości i  działań., dzielimy się naszymi odkryciami z tymi, którym możemy ufać  oraz prosimy Boga, jakkolwiek go pojmujemy, by usunął nasze braki. W  trakcie pracy nad Krokami uwalniamy się od wpływu naszej choroby i  uczymy się podejmowania decyzji, które pomagają nam przejść przez  bieżące życiowe sprawy. Dzisiaj, nasze decyzje oraz ich konsekwencje nie muszą podlegać  wpływom naszej choroby. Nasza wiara daje nam odwagę i wskazówki,  dzięki którym możemy podejmować dobre decyzje oraz daje nam siłę do  ich realizacji. Rezultatem tego rodzaju podejmowania decyzji jest życie,  które warto przeżyć. ', 'Użyję zasad Dwunastu Kroków, by podejmować zdrowe decyzje. Poproszę moją Siłę Wyższą o siłę do ich realizacji.'),
(237, '08-24', '24 sierpnia', 'Poszukiwanie woli Boga', NULL, '„Uczymy się zachowywać ostrożność w modlitwach o określone sprawy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW naszym czynnym uzależnieniu zwykle nie modliliśmy się o wolę  Boga wobec nas oraz o siłę do jej spełnienia. Przeciwnie, najczęściej w  naszych modlitwach prosiliśmy Boga, by uporządkował zrobiony przez  nas bałagan. Oczekiwaliśmy cudów na żądanie. Ten rodzaj myślenia i  modlitwy zmienia się, gdy zaczynamy praktykować Jedenasty Krok.  Jedyną drogą wyjścia z kłopotów, do których sami doprowadziliśmy jest  poddanie się Sile większej, niż nasza własna. W zdrowieniu uczymy się akceptacji. W naszych modlitwach i  medytacjach poszukujemy wiedzy o tym, w jaki sposób przyjąć  pojawiające się na naszej drodze okoliczności. Przestajemy walczyć,  powierzamy nasze własne pomysły dotyczące tego, jak powinny  wyglądać niektóre sprawy, prosimy o wiedzę i słuchamy odpowiedzi.  Odpowiedzi te zwykle nie pojawiają się w postaci błysku jasnego światła przy akompaniamencie werbla. Zazwyczaj odpowiedzi pojawią się wraz  z cichym poczuciem pewności, że nasze życie podąża we właściwym  kierunku, ponieważ Siła większa, niż nasza własna, prowadzi nas na  naszych ścieżkach. Mamy wybór. Możemy poświęcić cały nasz czas walce o to, by sprawy toczyły się po naszej myśli lub możemy poddać się woli Boga. Pokój  możemy odnaleźć w zaakceptowaniu przypływów i odpływów życia. ', 'Poddam moje oczekiwania, zwrócę się do mojej Siły Wyższej o przewodnictwo i zaakceptuję życie.'),
(238, '08-25', '25 sierpnia', 'Dziewiąty Krok - odzyskiwanie życia', NULL, '„Uwalniamy się od pozostałości z przeszłości.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy rozpoczynamy pracę nad Dziewiątym Krokiem, osiągamy  fascynujący etap w naszym zdrowieniu. Zniszczenie dokonane w  naszym życiu jest tym, co w pierwszej kolejności doprowadziło nas do  szukania pomocy. Teraz mamy szansę uprzątnąć śmietnik z naszej  przeszłości i odzyskać życie. Spędziliśmy dużo czasu i włożyliśmy sporo wysiłku, przygotowując się  do tego kroku. Gdy przychodzimy do NA, mierzenie się z  pozostałościami z przeszłości jest prawdopodobnie ostatnią rzeczą,  którą chcielibyśmy robić. Zaczęliśmy robić to prywatnie poprzez nasz  osobisty obrachunek. Następnie, ujawniliśmy naszą przeszłość do  wglądu wybranym osobom. Zaufaliśmy paru osobom: nam samym,  naszej Sile Wyższej oraz drugiej osobie. Przyjrzeliśmy się naszym  wadom, które są źródłem prawie całego chaosu w naszym życiu i  poprosiliśmy o usunięcie tych wad charakteru. W końcu, zrobiliśmy listę  zadośćuczynień potrzebną do naprawienia wszystkich naszych błędów i  staliśmy się gotowi, by ją zrealizować. Teraz, mamy możliwość, aby zadośćuczynić, by uwolnić się od  duchów przeszłości. Wszystko, co do tej pory zrobiliśmy w NA  doprowadziło nas do tego miejsca. W tym punkcie procesu naszego  zdrowienia Krok Dziewiąty jest dokładnie tym, co chcemy zrobić. Z  Dwunastoma Krokami i pomocą naszej Siły Wyższej, oczyszczamy  gruzowisko, które przez tak długi czas stało nam na drodze do postępu  w zdrowieniu, zyskujemy wolność, by żyć.', 'Zrobię użytek z tych możliwości, żeby odzyskać moje życie. Doświadczę uwolnienia od pozostałości z przeszłości.'),
(239, '08-26', '26 sierpnia', 'Obrachunek w Dziesiątym Kroku', NULL, '„Prowadziliśmy nadal obrachunek moralny, natychmiast przyznając się do popełnianych błędów.”   \r\n\r\n~Krok Dziesiąty  \r\n\r\nDziesiąty Krok, praktykowany codziennie, pomaga nam zachowywać  zdrowie duchowe. Każdy członek wspólnoty stawia inne pytania, jednak  niektóre z nich okazują się być pomocne prawie dla wszystkich. Dwoma  kluczowymi pytaniami w Kroku Dziesiątym są: „Czy jestem uczciwy  wobec siebie samego, wobec swoich działań i motywów?” oraz „Czy  modliłem się o poznanie woli Boga wobec mnie oraz o siłę do jej  spełnienia?” Te dwa pytania, zadane sobie w sposób uczciwy  zaprowadzą nas ku głębszemu spojrzeniu na miniony dzień. Gdy skupiamy się na naszych relacjach z innymi, możemy zapytać:  „Czy kogoś dzisiaj zraniłem? Pośrednio lun bezpośrednio?”, „Czy  powinienem komuś zadośćuczynić w rezultacie moich dzisiejszych  działań?” Nie skomplikujemy zbytnio naszego obrachunku, jeżeli  będziemy pamiętać, by zadać sobie pytanie: „W którym momencie się  myliłem?”, „Jak mogę lepiej postąpić następnym razem?” Członkowie NA często odkrywają, że ich obrachunek zawiera inne  ważne pytania: „Czy byłem dzisiaj dla siebie dobry?”, „Czy zrobiłem coś  dla kogoś innego, nie oczekując nic w zamian?”, „Czy utrwaliłem moją  wiarę w kochającą Siłę Wyższą?”8 Krok Dziesiąty jest krokiem  utrzymującym nas w programie NA. Krok Dziesiąty pomaga nam żyć w  zdrowieniu komfortowo.', 'Będę pamiętał, aby przeanalizować miniony dzień. Jeżeli kogoś skrzywdziłem, zadośćuczynię mu. Pomyślę, w jaki sposób mogę postąpić inaczej.'),
(240, '08-27', '27 sierpnia', 'Wybierając życie', NULL, '„Zmiana autodestrukcyjnego stylu życia stała się koniecznością.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzynne uzależnienie jest nieustającym pragnieniem śmierci. Każdy z  nas igrał ze śmiercią za każdym razem, gdy zażywaliśmy narkotyk. Nasz styl życia także wystawiał nas na ryzyko. Życie uzależnionego jest  sprzedawane za grosze każdego dnia, w każdej działce.  W zdrowieniu, pierwszym zachowaniem, które zmieniamy, jest nawyk  zażywania. Pozostawanie czystym jest początkiem podróży w głąb życia. Jednakże nasze autodestrukcyjne zachowania zwykle sięgały daleko  głębiej poza nasze zażywanie. Nawet w zdrowieniu możemy nadal  tratować siebie tak, jakbyśmy byli nic nie warci. Gdy traktujemy siebie  źle, źle się czujemy. A gdy źle się czujemy, szukamy ulgi - być może  nawet w naszym starym rozwiązaniu, jakim są narkotyki. Wybranie zdrowienia oznacza wybranie życia. Każdego dnia  podejmujemy decyzję, że chcemy żyć i być wolni. Za każdym razem, gdy unikamy autodestrukcyjnych zachowań, wybieramy zdrowienie. ', 'Postawię na życie, wybierając zdrowienie. Zatroszczę się o siebie samego.'),
(241, '08-28', '28 sierpnia', 'Światło ujawnienia', NULL, '„Te wady rosną w ciemności, a ujawnione giną.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPiąty Krok wymaga od nas, byśmy podzielili się naszą prawdziwą naturą z Bogiem, z nami samymi i z drugą istotą ludzką. Nie zachęca nas to do mówienia każdemu o naszych wszystkich najskrytszych tajemnicach. Nie prosi się nas o to, byśmy ujawniali całemu światu każdą wstydliwą lub zatrważającą myśl, jaką kiedykolwiek mieliśmy. Krok Piąty po prostu sugeruje nam, że nasze tajemnice zachowywane wyłącznie dla siebie powodują więcej cierpienia niż dobra. Jeżeli ulegniemy niechęci do ujawnienia naszej prawdziwej natury nawet jednej istocie ludzkiej, ta tajemnicza strona naszego życia stanie się jeszcze potężniejsza. Natomiast, gdy sekrety są pod kontrolą, wzmacniają więź między nami, naszą Siłą Wyższą oraz sprawami, które cenimy najbardziej w naszym zdrowieniu. Gdy podzielimy się naszą tajemnicą chociażby z jedną istotą ludzką, prawdopodobnie z naszym sponsorem lub bliskim przyjacielem, ta osoba zwykle nas nie odrzuci. Uzewnętrzniamy się przed kimś i zostajemy nagrodzeni akceptacją. Kiedy to ma miejsce, zdajemy sobie sprawę, że uczciwe dzielenie się nie zagraża życiu. Nasze tajemnice straciły nad nami moc.', 'Jestem w stanie rozbroić tajemnice w moim życiu poprzez dzielenie się nimi z drugą osobą.'),
(242, '08-29', '29 sierpnia', 'Nie patrz wstecz', NULL, '„Kroki oferują nam wielką zmianę naszego życia zdominowanego poczuciem winy i wyrzutami sumienia. Nasza przyszłość zmieniła się, ponieważ nie musimy unikać tych, których zraniliśmy. W rezultacie... otrzymujemy nową wolność, która może zakończyć naszą izolację.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas przybyło do NA za dużym bagażem żalu dotyczącego  naszej przeszłości. Weryfikujemy nasze życie, przyznajemy się do  błędów, zadośćuczynimy za te błędy i szczerze próbujemy zmienić  nasze zachowanie. Postępując w ten sposób, odkrywamy radość  płynącą z wolności. Już dłużej nie musimy zaprzeczać naszej przeszłości lub jej żałować.  Gdy dokonaliśmy już zadośćuczynień, przeszłość naprawdę skończyła  się i odeszła. Ten moment w zdrowieniu jest dla nas najważniejszą  chwilą. Liczy się to, dokąd zmierzamy. W NA, zaczynamy spoglądać w przyszłość. Prawdą jest, że żyjemy i  pozostajemy czyści właśnie dzisiaj. Jednakże odkrywamy, że zaczynamy osiągać korzyści, marzyć oraz spodziewać się przyjemności płynących z  życia, które są nam oferowane w zdrowieniu. Patrzenie w przyszłość  pomaga nam koncentrować się na tym, dokąd idziemy, a nie na poczuciu winy lub użalaniu się nad przeszłością. Poza tym, trudno jest iść się  naprzód, jeżeli spoglądamy wstecz.', 'Kroki uwalniają mnie od żalu związanego z przeszłością. Dziś wyjdę naprzeciw mojemu nowemu życiu w zdrowieniu'),
(243, '08-30', '30 sierpnia', 'Postępując słusznie, czujemy się dobrze', NULL, '„Analizujemy nasze działania, reakcje i motywy postępowania. Często zauważamy, że postępujemy lepiej, niż się czujemy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nSposób, w jaki traktujemy innych, często ujawnia nasz stan ducha.  Gdy czujemy spokój, najprawdopodobniej traktujemy innych z  szacunkiem i współczuciem. Jednakże, gdy jesteśmy wytrąceni z  równowagi, z pewnością reagujemy brakiem tolerancji i cierpliwości. Gdy podejmujemy regularny obrachunek, prawdopodobnie odkryjemy pewną  prawidłowość: źle traktujemy innych wtedy, gdy źle się czujemy sami ze  sobą. Jest też druga strona medalu, która może nam umknąć w naszym  obrachunku: gdy innych traktujemy prawidłowo, czujemy się ze sobą  dobrze. Gdy dodamy tę pozytywną prawdę do negatywnych faktów, które odkrywamy podczas obrachunku, zaczynamy inaczej się zachowywać. Gdy źle się czujemy, możemy się zatrzymać, aby pomodlić się o  przewodnictwo i siłę. Następnie, podejmujemy decyzję, by traktować  otaczających nas ludzi z uprzejmością, łagodnością oraz z taką samą  uwagą, jaką chcielibyśmy, by nam okazywano. Decyzja o byciu miłym  ożywi i podtrzyma poczucie szczęścia i spokój umysłu, którego wszyscy  tak pragniemy. Radość, którą wyzwalamy w sobie, może dodać otuchy  otaczającym nas ludziom, a to z kolei pozytywnie wzmocni naszego  ducha.', 'Będę pamiętał, że jeżeli zmienię swoje działania, moje myśli pójdą za nimi same.'),
(244, '08-31', '31 sierpnia', 'Wdzięczność', NULL, '„Beznadziejne problemy życiowe zostały szczęśliwie rozwiązane. Nasza choroba została powstrzymana i teraz wszystko jest możliwe.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nProgram NA daje nam więcej wolności, niż kiedykolwiek moglibyśmy  sobie wymarzyć. Jednakże czasami, podczas codziennej rutyny, tracimy  świadomość tego, ile zostało nam ofiarowane. Jak właściwie nasze życie zmieniło się we wspólnocie Anonimowych Narkomanów? Podstawą w zdrowieniu jest oczywiście wolność od kompulsywnego  zażywania. Już nie musimy dłużej zużywać całej naszej energii na  karmienie naszego uzależnienia. Już nie musimy dłużej narażać się,  upokarzać albo nadużywać siebie lub innych tylko po to, żeby zdobyć  następną działkę. Abstynencja sama w sobie wniosła wiele wolności do  naszego życia. Jednak NA oferuje nam znacznie więcej, niż tylko abstynencję. Zostało nam dane całkiem nowe życie. Podjęliśmy się obrachunku moralnego i  zidentyfikowaliśmy wady, które raniły nas przez tak długi czas,  odgradzając nas od życia i czerpania z niego radości. Powierzyliśmy te wady, wzięliśmy za nie odpowiedzialność oraz  poszukaliśmy przewodnictwa oraz siły, której potrzebujemy, żeby żyć  inaczej. Nasza grupa domowa ofiarowała nam osobiste ciepło i wsparcie, które pomaga nam w kontynuacji życia w zdrowieniu. A ponad to, mamy  miłość, opiekę i przewodnictwo Boga, którego dane nam było zrozumieć  w NA. Czasami, w codzienności zdrowienia, zapominamy jak bardzo nasze  życie już się zmieniło we wspólnocie Anonimowych Narkomanów. Czy w  pełni doceniamy to, co dał nam Program? ', 'Zdrowienie dało mi wolność. Przywitam ten dzień z nadzieją i wdzięcznością za to, że wszystko jest dzisiaj możliwe.'),
(245, '09-01', '1 września', 'Prawdziwe wartości', NULL, '„Stajemy się zdolni do podejmowania mądrych i przepełnionych miłością decyzji, opartych na zasadach i ideałach, które mają w naszym życiu prawdziwą wartość.  \r\n\r\n~Tekst Podstawowy  \r\n\r\nUzależnienie wyposażyło nas w określony zestaw wartości oraz  zasad, które stosowaliśmy w naszym życiu. Jedna z tych zasad głosiła,  że jeśli „ty mnie pchnąłeś, to ja odepchnę cię mocniej”. „To jest moje”  było kolejną wartością wytworzoną przez nasza chorobę. „Dobrze, może  to i nie było moje, ale spodobało mi się, więc sobie to przywłaszczyłem.”  Te wartości nie były tak naprawdę wartościami, były raczej  racjonalizacjami i na pewno nie pomagały nam w podejmowaniu  mądrych i przepełnionych miłością decyzji. W rzeczywistości  przyczyniały się one głównie do pogłębiania grobu, który już wcześniej  dla siebie wykopaliśmy. Dwanaście Kroków daje nam solidną porcję prawdziwych wartości,  takich wartości, które pomagają nam żyć w harmonii z sobą i z  otoczeniem. Pokładamy naszą wiarę nie w nas samych, w naszych  rodzinach czy społecznościach, lecz w Sile Wyższej - i dzięki temu  jesteśmy na tyle bezpieczni, że możemy zaufać naszym  społecznościom, rodzinom, a nawet samym sobie. Uczymy się być  uczciwi bez względu na wszystko. Uczymy się powstrzymywać od  robienia rzeczy, które moglibyśmy później chcieć ukryć. Uczymy się  akceptowania odpowiedzialności za nasze działania. „To moje” zostaje  zastąpione duchem bezinteresowności. To ten rodzaj wartości, który  pomaga nam stać się odpowiedzialną i produktywną częścią otoczenia.  Te wartości przywracają nas do świata żywych. ', 'Jestem wdzięczny za wartości, które w sobie wykształciłem. Jestem wdzięczny za możliwości, które dzięki nim przede mną się otworzyły. Jestem wdzięczny za możliwość podejmowania mądrych i przepełnionych miłością decyzji, już jako odpowiedzialny i produktywny członek społeczeństwa.'),
(246, '09-02', '2 września', 'Kierowani Siłą Wyższą', NULL, '„Codzienne praktykowanie naszego programu Dwunastu Kroków umożliwia nam zmianę z ludzi, jakimi byliśmy w ludzi kierowanych przez Siłę Wyższą.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKim byliśmy i kim się staliśmy? Jest kilka odpowiedzi na to pytanie.  Jedna z nich jest bardzo prosta: przybyliśmy do Anonimowych  Narkomanów jako uzależnieni, nasze uzależnienie zabijało nas. W NA  zostaliśmy uwolnieni od obsesji na punkcie narkotyków i od ich  kompulsywnego zażywania. Nasze życie zmieniło się. Jest to jednak tylko wierzchołek góry lodowej. Kim byliśmy naprawdę?  W przeszłości byliśmy ludźmi zdezorientowanymi, pozbawionymi siły.  Czuliśmy się tak, jakbyśmy nie mieli celu, ani powodu, by żyć. Nasze  życie nie miało dla nas sensu, podobnie zresztą jak dla naszych rodzin,  przyjaciół i sąsiadów. Kim naprawdę stajemy się? Dzisiaj, nie jesteśmy jedynie  zachowującymi czystość uzależnionymi, lecz ludźmi, którzy mają  poczucie sensu i kierunku, w którym podążają, mają swój cel oraz Siłę  większą od siebie. Poprzez codzienne praktykowanie zasad Dwunastu  Kroków zaczęliśmy rozumieć, jak bardzo nasze uzależnienie wypaczyło  nasze uczucia, motywy działania i zachowanie. Stopniowo, destrukcyjna  moc naszej choroby zaczęła być zastępowana przez życiodajną moc  naszej Siły Wyższej. Zdrowienie jest czymś więcej niż tylko zachowywaniem czystości - jest wzrastaniem w siłę. Osiągamy coś więcej niż tylko pozbywanie się złych  nawyków; stajemy się nowymi ludźmi, kierowanymi przez Siłę Wyższą. ', 'Przewodnictwo, którego potrzebuję, by stać się nową osobą jest w zasięgu ręki. Dziś zrobię kolejny krok ku mojej Siły Wyższej, odsuwając się od mojej przeszłości.'),
(247, '09-03', '3 września', 'Pokora wyrażana przez anonimowość', NULL, '„Pokora pozwala nam wzrastać i rozwijać się w atmosferze wolności i usuwa nasz strach przed tym, że nasi współpracownicy, rodziny i przyjaciele dowiedzą się, że jesteśmy uzależnieni.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas nie mogło zrozumieć idei głoszącej, że „anonimowość jest  duchową podstawą wszystkich naszych tradycji”. Bardzo nas to dziwiło.  Co wspólnego ma anonimowość z życiem duchowym? Odpowiedź brzmi: ma wiele wspólnego!! Chroniąc i szanując naszą  anonimowość, otrzymujemy wynagrodzenie duchowe przekraczające  zrozumienie. Wielką cnotą jest zrobienie dla kogoś coś miłego i nie  mówienie o tym nikomu. W myśl tej zasady, przeciwstawianie się  impulsowi, by dumnie ogłaszać światu nasze członkostwo we  wspólnocie, co nie oznacza nic innego jak zapewnianie każdego, jacy to wspaniali jesteśmy, czyni nasze zdrowienie wartościowym. Zdrowienie jest darem, który otrzymaliśmy od Siły Większej niż nasza  własna. Szczycenie się zdrowieniem w taki sposób, jakby było to naszym osiągnięciem, prowadzi do zadufania i manii wielkości. Natomiast,  zachowywanie naszej anonimowości prowadzi do pokory i uczucia  wdzięczności. Zdrowienie jest nagrodą samą w sobie. Publiczne  oświadczenia nie uczynią go bardziej wartościowym, niż jest w  rzeczywistości.', 'Zdrowienie jest nagrodą samą w sobie. Nie potrzebuję publicznej aprobaty. Będę zachowywał anonimowość i dbał o nią.'),
(248, '09-04', '4 września', 'Zaśmiecone wnętrze', NULL, '„Staramy się pamiętać, że naprawiając wyrządzone szkody, robimy to dla siebie.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nDopóki pozostajemy winni zadośćuczynienia nasze wnętrze będzie  zaśmiecone zbędnymi rzeczami. Dźwigamy dodatkowy ciężar  przeprosin, które jesteśmy komuś winni, utrzymywanych uraz czy też  ukrywanego przed innymi poczucia winy. To tak, jakby mieszkać w  zaniedbanym domu. Nie chcąc patrzeć na ten bałagan, moglibyśmy się  wyprowadzić lub przechodzić nad stertami odpadków i rupieci, udając,  że ich tam nie ma. Jednak ignorowanie tego bałaganu nie spowoduje, że zniknie on samoczynnie. I tak te brudne naczynia, pokryty okruchami  dywan i przepełnione kosze na śmieci wciąż tam będą, czekając na  uprzątnięcie. Zagracone wnętrze jest równie uciążliwe, jak życie w brudnym domu.  Wciąż mamy wrażenie, że potykamy się o wczorajsze pozostałości. Za  każdym razem, gdy próbujemy obrócić się i gdzieś dojść, coś blokuje  nam przejście. Im bardziej lekceważymy naszą odpowiedzialność za  naprawienie wyrządzonych przez nas szkód, tym bardziej zagracamy  nasze wnętrze. Nie możemy też nikogo wynająć, by za nas posprzątał.  Musimy zrobić to sami. Naprawiając wyrządzone przez nas krzywdy, zyskujemy głębokie  poczucie satysfakcji. Podobnie jak czujemy się po uprzątnięciu naszego  domu, mając chwilę, by cieszyć się z promyków słońca wpadającego  przez połyskujące okna, tak też nasze dusze cieszyć się będą wolnością, dzięki której będziemy mogli w pełni sycić się naszym zdrowieniem. A  gdy już raz ten wielki bałagan zostanie uprzątnięty, pozostanie nam do  roboty tylko jedno - sprzątanie po sobie na bieżąco.', 'Posprzątam to, co zaśmieca moją duszę, zadośćuczyniając za wyrządzone przeze mnie krzywdy.'),
(249, '09-05', '5 września', 'Nie jesteśmy beznadziejnie czy źli', NULL, '„Odkryliśmy, że cierpimy na chorobę, a nie na zepsucie moralne. Jesteśmy ciężko chorzy, a nie beznadziejnie źli.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nDla wielu z nas NA było odpowiedzią na długotrwałą, osobistą  zagadkę. Dziwiło nas dlaczego zawsze, nawet w tłumie, czuliśmy się  samotni? Dlaczego dopuściliśmy się tak wielu szalonych i  autodestrukcyjnych zachowań? Dlaczego prawie zawsze czuliśmy się  tak źle ze sobą? Dlaczego nasze życie tak się skomplikowało?  Myśleliśmy, że byliśmy beznadziejnie źli lub beznadziejnie obłąkani. Uwzględniając to, jakżeż wielką ulgę poczuliśmy, gdy dowiedzieliśmy  się, że cierpimy na chorobę zwaną uzależnieniem. To właśnie  uzależnienie było źródłem naszych problemów. Zdaliśmy sobie też  sprawę, że choroba ta może być leczona. A gdy leczymy naszą chorobę, zaczynamy zdrowieć. Dzisiaj, dostrzegając w naszym życiu symptomy naszej choroby, nie  musimy rozpaczać. Wiemy, że tę chorobę można leczyć. Nie jest to  kwestia zepsutej moralności. Możemy być wdzięczni za możliwość  zdrowienia z choroby uzależnienia poprzez stosowanie Dwunastu  Kroków NA.', 'Jestem wdzięczny, że cierpię na chorobę, którą można leczyć, a nie na zepsucie moralne. Będę kontynuował leczenie choroby uzależnienia poprzez praktykowanie Programu NA');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(250, '09-06', '6 września', 'Regularna obecność na mitingu', NULL, '„Doświadczenie wspólnoty nauczyło nas, że ci, którzy regularnie uczestniczą w naszych mitingach, pozostają czystymi.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nProgram NA daje nam nowy sposób na życie. Jednym z  podstawowych elementów tego nowego sposobu jest regularne  uczestnictwo w mitingach. Dla nowoprzybyłego życie w czystości jest  całkowicie nowym doświadczeniem. Wszystko co do tej pory było znane  zmieniło się. Starzy znajomi, stare miejsca i rzeczy, które służyły nam za  rekwizyty na scenie naszego życie, zniknęły. Pojawiły się nowe stresy,  które już nie są maskowane lub zagłuszane przez narkotyki. Właśnie  dlatego sugerujemy nowoprzybyłemu, żeby uczęszczał na miting  codziennie. Bez względu na to, jakim trudnościom musimy sprostać, jak  szalonym może wydawać się nam nasz kolejny dzień, wiemy, że nasz  codzienny miting czeka na nas. Właśnie tam możemy odnowić kontakt z  innymi zdrowiejącymi uzależnionymi, czyli z tymi, którzy wiedzą przez co przechodzimy, ponieważ sami przez to przechodzili. Żaden dzień nie  powinien nam minąć bez ulgi, którą otrzymać możemy tylko od takiej  wspólnoty. W miarę naszego dojrzewania w zdrowieniu doznajemy wciąż takich  samych korzyści z regularnego uczestniczenia w mitingach. Bez względu na długość okresu naszej czystości nigdy nie przestaniemy być  uzależnieni. Oczywiście, jeżeli przegapimy kilka mitingów przez  kolejnych kilka dni, prawdopodobnie nie zaczniemy od razu zażywać  ogromnej ilości narkotyków. Natomiast, im bardziej regularnie  uczęszczamy na mitingi NA, tym bardziej umacniamy się i  identyfikujemy, jako zdrowiejący uzależnieni. Każdy mityng pomaga nam  coraz bardziej oddalić się od powrotu do czynnego uzależnienia.  ', 'Zobowiążę się włączyć regularne uczestnictwo w mitingach do mojego nowego sposobu na życie.'),
(251, '09-07', '7 września', 'Uraza i przebaczenie', NULL, '„Jeśli spotyka nas coś złego, program uczy nas przebaczania.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW NA zaczynamy wchodzić w interakcje z otaczającym nas światem.  Wyrywamy się z izolacji. Jednak wolność od izolacji ma swoją cenę: im  więcej mamy do czynienia z ludźmi, tym częściej będziemy doświadczać kontaktu z kimś, kto będzie wchodził nam na odcisk. W takich  okolicznościach często rodzą się urazy. Uzasadnione lub nieuzasadnione urazy są niebezpieczne dla naszego postępującego zdrowienia. Im dłużej chowamy urazy, tym bardziej stają  się one gorzkie, właściwie nas przy tym zatruwając. Żeby pozostać  czyści, musimy odnaleźć zdolność uwalniania się od uraz, czyli zdolność wybaczania. Najpierw rozwijamy tę zdolność, pracując nad Krokiem  Ósmym i Krokiem Dziewiątym. Następnie utrzymujemy tę zdolność przy  życiu, regularnie podejmując się Kroku Dziesiątego. Czasami, gdy jesteśmy niechętni wybaczaniu, pomaga nam w tym  świadomość, że my także możemy kiedyś potrzebować czyjegoś  wybaczenia. Czyż nie zdarzyło się nam kiedyś zrobić czegoś, czego  głęboko żałowaliśmy? Czyż nie czuliśmy dużej ulgi, kiedy ktoś przyjął  nasze szczere zadośćuczynienie? Postawę wybaczania jest trochę łatwiej rozwijać, gdy pamiętamy, że  wszyscy staramy się postępować najlepiej jak potrafimy. Pewnego dnia  my także będziemy potrzebowali wybaczenia. ', 'Odpuszczę sobie moje urazy. Jeżeli dziś zostanę skrzywdzony, będę praktykował wybaczanie, pamiętając, że sam także go potrzebuję.'),
(252, '09-08', '8 września', 'Bunt', NULL, '„Nie powinniśmy tracić wiary, gdy ogarnie nas bunt.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas przeżyło swoje życie, wciąż się buntując. Nasza pierwsza  reakcja na jakiekolwiek próby ukierunkowania nas zawsze była  negatywna. Odruchowe odrzucanie autorytetów wydaje się być bardzo  uciążliwą wadą charakteru u wielu uzależnionych. Gruntowny obrachunek moralny może pokazać nam, jak reagujemy na otaczający nas świat. Możemy zadać sobie pytanie czy nasz bunt  przeciwko ludziom, miejscom i instytucjom jest uzasadniony. Jeśli  piszemy wystarczająco długo, przestajemy zajmować się uczynkami  innych i odkrywamy nasz własny udział w tym, co robiliśmy. Odkrywamy,  że to, co zrobili nam inni nie było aż tak istotne, jak sposób, w jaki  zareagowaliśmy na sytuacje, w których się znaleźliśmy. Regularny obrachunek moralny pozwala nam zweryfikować nasz  sposób reagowania na życie i zobaczyć, że jesteśmy podatni na  chroniczne buntowanie się. Czasami możemy zauważyć, że w  sytuacjach, gdy robimy coś, co jest nam sugerowane tylko z tego  powodu, że boimy się odmówić, zaczynamy taić urazę do autorytetów.  Urazy te, pozostawione same sobie, mogą odsunąć nas daleko od  naszego programu zdrowienia. Proces obrachunku pozwala nam odkryć, ocenić i usunąć nasze buntownicze postawy. Nie możemy zmienić  świata poprzez dokonanie obrachunku moralnego, ale możemy zmienić  sposób, w jaki na ten świat reagujemy. ', 'Pragnę uwolnić się od zgiełku buntowniczości. Zanim podejmę się jakichkolwiek działań, przyjrzę się sobie i pomyślę o moich prawdziwych wartościach.'),
(253, '09-09', '9 września', 'Gliniane nogi', NULL, '„Jednym z największych błędów blokujących zdrowienie wydaje się być stawianie nierzeczywistych oczekiwań wobec... innych.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas przybyło do NA z bardzo niską samooceną. W porównaniu do nas, inni zdrowiejący uzależnieni, których spotykamy na mitingach  mogą wydawać się nam nadludzko spokojni. Ci mądrzy, kochani ludzie  mają za sobą miesiące, bądź lata życia w zgodzie z zasadami  duchowymi. Są gotowi dawać siebie innym bez oczekiwania czegoś w  zamian. Ufamy im, pozwalając, by kochali nas tak długo, aż będziemy w  stanie pokochać samych siebie. Spodziewamy się, że ci ludzie  uporządkują nasze życie. Po pewnym czasie blask wczesnego zdrowienia blednie i zaczynamy  zauważać ludzką stronę naszych przyjaciół z NA i sponsora. Być może  nasz kolega z grupy domowej naciągnie nas na kawę lub zobaczymy  dwóch weteranów sprzeczających się w czasie mityngu  organizacyjnego. Możemy zdać sobie też sprawę z jednej lub z dwóch  wad charakteru naszego sponsora. Jesteśmy zdruzgotani i pozbawieni  złudzeń - okazało się, że ci zdrowiejący uzależnieni nie są idealni!! Jak  możemy im nadal ufać? Prawda leży gdzieś pomiędzy „bohaterami zdrowienia” a „marnymi  dupkami z NA” - nasi koledzy ze wspólnoty nie są ani całkowicie źli, ani  też całkowicie dobrzy. Przecież gdyby byli idealni, nie potrzebowaliby  tego programu. Nasi przyjaciele i nasz sponsor są zwykłymi  zdrowiejącymi uzależnionymi. Dokładnie tak samo, jak my. Możemy  polegać na ich zwyczajnym doświadczeniu w zdrowieniu i użyć go w  naszym własnym programie. ', 'Moi przyjaciele i mój sponsor są tak samo jak ja po prostu ludźmi - z tego powodu zaufam ich doświadczeniu jeszcze bardziej. '),
(254, '09-10', '10 września', 'Potężniejsze niż słowa', NULL, '„Uczymy się, że prosty, pełen miłości uścisk może odmienić świat.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nByć może, kiedyś w naszym zdrowieniu byliśmy blisko z kimś, kto  straszliwie cierpiał. Zmagaliśmy się z pytaniem: „Co mogę zrobić, by ten  ktoś poczuł się lepiej?” Czuliśmy gniew, spowodowany świadomością  niemocy ukrócenia czyjegoś cierpienia. Chcieliśmy mieć więcej  doświadczenia, żeby móc się z nim dzielić. Nie wiedzieliśmy, co  powiedzieć. Czasami jednak życie zadaje takie rany, które nie mogą być  złagodzone nawet słowami płynącymi prosto z serca. Słowa nigdy nie  wyrażą wszystkiego, co mamy na myśli, nawet, gdy zaangażowane są w to nasze najgłębsze wyrazy współczucia. Język jest niewystarczającym  środkiem, by dotrzeć do zranionej duszy. Tylko dotyk kochającej Siły  Wyższej może uzdrowić tę ranę. Gdy ci, których kochamy są pogrążeni w bólu, nasza zwykła obecność będzie prawdopodobnie najlepszą forma wyrażenie współczucia, jaką  możemy im zaoferować. Możemy być pewni, że nasza kochająca Siła  Wyższa ciężko pracuje nad uzdrawianiem ducha, a do nas jedynie  należy bycie obecnym. Nasza obecność, wyrażający miłość uścisk oraz  życzliwe słowo na pewno wyrażą głębię naszych uczuć. Będą w stanie  zdziałać więcej, by dotrzeć w chwili bólu do serca istoty ludzkiej, niż  jakiekolwiek wypowiedziane słowa. ', 'Zaoferuję moją obecność, uścisk i życzliwe słowo komuś, kogo kocham.'),
(255, '09-11', '11 września', 'Poddając się podmuchom wiatru', NULL, '„Uczymy się być bardziej elastyczni... ”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPojęcie elastyczności było nam zupełnie obce, gdy braliśmy. Ogarnęła  nas obsesja na punkcie dość prymitywnej przyjemności, którą dawały  nam narkotyki i staliśmy się odporni na wszelkie inne, bardziej delikatne i subtelne przyjemności otaczającego nas świata. Nasza choroba zmieniła nasze życie, stale zagrażając nam więzieniem, szpitalami i śmiercią.  Coraz trudniej było nam się przeciwstawiać tym zagrożeniom. W końcu  zastaliśmy pokonani. Zwykłe życie nas przerosło, skruszyło i złamało, nie zostawiając nam praktycznie innego wyboru, jak poddanie się. Jakże wspaniałą ironią w naszym zdrowieniu jest fakt, że w poddaniu  się odnajdujemy elastyczność, którą straciliśmy w naszym uzależnieniu.  Brak tej elastyczności pokonał nas. Odzyskaliśmy umiejętność  poddawania się powiewom życia bez ponoszenia uszczerbku. Gdy  powiał wiatr, odczuliśmy go niczym miłosne pieszczoty, a kiedyś przecież napięlibyśmy się tak, jak pod naporem sztormu. Powiewy życia przynoszą wciąż nowe masy powietrza. Niosą ze sobą  nowe zapachy i nowe przyjemności, subtelnie różniące się między sobą.  Gdy ugniemy się pod naciskiem wiatru życia, czujemy, słyszymy,  dotykamy, wąchamy i smakujemy wszystkiego, co on ze sobą niesie.  Gdy nadchodzą nowe podmuchy, czujemy się niczym odnowieni.', 'Siło Wyższa, pomóż mi ugiąć się pod naporem życiowego wiatru, wychwalając jego przemijanie. Uwolnij mnie od sztywności. '),
(256, '09-12', '12 września', 'Nowe horyzonty', NULL, '„Moje życie jest bogate i urozmaicone, a ja staję się coraz bardziej spełnionym człowiekiem, nie zaś neurotycznym, nudnym typem, którym myślałem, że będę bez narkotyków.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy naprawdę istnieje życie bez narkotyków? Nowoprzybyli są  przekonani, że jeśli zrezygnują z zażywania, zostaną skazani na  monotonną egzystencję. Obawy te nie mają jednak nic wspólnego z  rzeczywistością. Wspólnota Anonimowych Narkomanów otwiera dla swoich członków  drzwi do nowego stylu życia. Jedyną rzeczą, którą tracimy po przybyciu  do NA jest nasze zniewolenie narkotykami. Zyskujemy nowych  przyjaciół, czas na realizację zainteresowań, umiejętność zdobycia  stałego zatrudnienia, a nawet zdolność do edukowania się, jeżeli tego  zapragniemy. Możemy podejmować nowe wyzwania, realizować je i  doprowadzać do końca. Możemy iść potańczyć i czuć się komfortowo  nawet wtedy, gdy nie mamy pojęcia o tańcu. Zaczynamy odkładać  pieniądze na podróże, nawet wtedy, gdy jest to wypad pod namiot do  jakiejś pobliskiej miejscowości. Zdrowiejąc, odkrywamy nasze  zainteresowania i nowe pasje. Mamy odwagę marzyć. Nasze życie zupełnie się zmienia, gdy mamy możliwość chodzenia na  mityngi Anonimowych Narkomanów. Poprzez miłość, którą odnajdujemy  we wspólnocie, zaczynamy w siebie wierzyć. Wzbogaceni o tą wiarę,  ryzykujemy pójście w świat z zamiarem odkrywania nowych horyzontów.  I często jakiś kawałeczek świata staje się lepszym miejscem, ponieważ  znalazł się tam jeden z członków NA.', 'Mogę żyć wspaniałym, bogatym i urozmaiconym życiem - życiem, o którym nawet nie marzyłem, że może istnieć. Zdrowienie otworzyło przede mną nowe horyzonty i wyposażyło mnie tak, bym mógł je odkrywać.'),
(257, '09-13', '13 września', 'Coś innego', NULL, '„Szukaliśmy czegoś innego i myśleliśmy, że znajdziemy to w narkotykach.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas zawsze czuło, że różnimy się od innych ludzi. Wiemy, że  nie tylko my tak czujemy. Słyszymy, jak wielu uzależnionych dzieli się  podobnymi odczuciami na mitingach. Całe życie szukaliśmy czegoś, co  sprawiłoby, że poczujemy się dobrze, czegoś, co naprawiłoby tę naszą  wewnętrzną „inność”, uzdrowiło nas i uczyniło nas bardziej  akceptowalnymi . Wydawało się nam, że narkotyki zaspokoją te  potrzeby. Gdy byliśmy na haju, wreszcie nie odczuwaliśmy pustki ani żadnych  potrzeb. Był w tym jednak jeden minus: narkotyki, które wydały się być  rozwiązaniem, szybko stały się naszym problemem. Gdy po raz pierwszy zrezygnowaliśmy z narkotyków, powróciło  uczucie pustki. Na początku czuliśmy się zdesperowani, ponieważ nie  mieliśmy żadnego pomysłu na rozwiązanie tego paskudnego i  ciągnącego się bez końca stanu. Byliśmy jednak gotowi przyjąć  wskazówki i podjąć się pracy nad krokami. Gdy tak zrobiliśmy,  zauważyliśmy, że jest to właśnie to „coś innego”, czego szukaliśmy.  Dzisiaj wierzymy, że przez całe nasze życie tęskniliśmy przede  wszystkim za świadomością Siły Wyższej, a tym „czymś innym”, czego  potrzebowaliśmy, było związek z kochającym Bogiem. Kroki  podpowiadają nam w jaki sposób zapoczątkować ten związek.', 'Moja Siła Wyższa jest tym „czymś innym”, czego zawsze brakowało mi w moim życiu. Użyję kroków, żeby odzyskać ten brakujący element mojej duchowości'),
(258, '09-14', '14 września', 'Tajemnice nas ograniczają', NULL, '„W końcu, przekonujemy się, że musimy być uczciwi albo znowu wrócimy do brania.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKażdy ma swoje tajemnice, prawda? Niektórzy z nas mają małe tajemnice, takie, z powodu których, poczulibyśmy tylko niewielkie  skrępowanie, gdyby wyszły na jaw. Niektórzy z nas mają większe tajemnice, całe obszary życia zamaskowane w gęstej i mrocznej ciemności. Duże tajemnice mogą stanowić zdecydowanie większe zagrożenie dla naszego zdrowienia. Małe tajemnice jednak też są niebezpieczne, właściwie są bardziej podstępne, gdyż myślimy, że są one „nieszkodliwe”. Nasze wielkie i małe tajemnice stanowią terytorium duchowe, którego nie mamy chęci poddać zasadom zdrowienia. Im dłużej pozwalamy, by niektóre sfery naszego życia były kierowane samowolą oraz im bardziej zawzięcie bronimy naszego „prawa” do zachowania ich dla siebie, tym większe czynimy szkody. Stopniowo, niepoddane terytoria naszego życia mają tendencję do zajmowania coraz większego obszaru, zatruwania coraz większego, bardziej rozległego terenu. Niezależnie, czy tajemnice w naszym życiu są małe czy duże, wcześniej lub później doprowadzą one nas do tego samego punktu. Musimy wybrać - albo poddajemy wszystko naszemu programowi, albo stracimy nasze zdrowienie.', 'Pragnę takiego rodzaju zdrowienia, które wynika z całkowitego poddania się programowi. Dzisiaj porozmawiam z moim sponsorem i wyjawię mu swoje tajemnice, i te małe, i te duże.'),
(259, '09-15', '15 września', 'Wypełnianie pustki', NULL, '„..myślimy, że jeśli tylko moglibyśmy mieć wystarczającą ilość jedzenia, seksu lub pieniędzy, bylibyśmy usatysfakcjonowani i wszystko byłoby w porządku.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW naszym czynnym uzależnieniu nigdy nie mieliśmy dosyć narkotyków, pieniędzy, seksu lub czegokolwiek innego. Nawet jeśli mieliśmy czegoś nadmiar, nigdy nie mieliśmy dość! Wewnątrz mieliśmy duchową pustkę. Chociaż ze wszystkich sił próbowaliśmy wypełnić tą pustkę, nigdy nam się to nie udało. W końcu zdaliśmy sobie sprawę z tego, że brakowało nam siły, by ją wypełnić. Potrzebowaliśmy Siły większej, niż nasza własna, by tego dokonać. Przestaliśmy brać i przestaliśmy zapychać tę pustkę w naszym wnętrzu różnymi rzeczami. Zwróciliśmy się do Siły Wyższej, prosząc o jej opiekę, siłę i wskazówki. Poddaliśmy się i otworzyliśmy tym samym drogę tej Sile, by mogła ona rozpocząć wypełnianie naszej wewnętrznej otchłani. Przestaliśmy chwytać się byle czego i zaczęliśmy otrzymywać dar miłości, którą zaoferowała nam nasza Siła Wyższa. Powoli, nasza pustka wewnętrzną zaczęła być wypełniana. Co powinniśmy zrobić teraz, kiedy zostaliśmy obdarzeni darem miłości naszej Siły Wyższej? Jeśli go zbyt mocno zaciśniemy w ramionach, zdusimy go. Musimy pamiętać, że miłość rozrasta się tylko wtedy, kiedy się nią dzielimy. Możemy zachować ten dar tylko wówczas, gdy będziemy przekazywać go dalej. Świat uzależnienia polega na braniu czegoś od innych i byciu ogołacanym, natomiast świat zdrowienia jest miejscem, gdzie się daje i jest się obdarowywanym. W którym z tych światów chcemy żyć?  ', 'Wybiorę życie w pełni zdrowienia. Będę celebrował mój świadomy kontakt z Bogiem, jakkolwiek go pojmuję, poprzez dzielenie się z innymi tym, co sam otrzymałem.'),
(260, '09-16', '16 września', 'Równowaga emocjonalna', NULL, '„Równowaga emocjonalna jest jednym z pierwszych rezultatów medytacji, a nasze doświadczenie to potwierdza.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nChociaż każdy z nas trochę inaczej definiuje „równowagę emocjonalną”, wszyscy musimy ją odnaleźć. Równowaga emocjonalna może oznaczać odkrywanie i podtrzymywanie pozytywnego spojrzenia na życie, bez względu na zachodzące wokół nas wydarzenia. Dla niektórych może to oznaczać zrozumienie swoich emocji, co pozwala odwzajemniać nasze uczucia, a nie przeciwdziałać im. Może to także oznaczać, że doświadczymy naszych uczuć tak intensywnie, jak potrafimy, przy równoczesnym łagodzeniu ich nadmiernego wyrażania. Równowaga emocjonalna przychodzi wraz z praktykowaniem modlitwy i medytacji. Wyciszamy się i dzielimy naszymi przemyśleniami, nadzieją oraz świadomością Boga, jakkolwiek go pojmujemy. Następnie słuchamy wskazówek i oczekujemy siły, dzięki której będziemy mogli postępować zgodnie z nimi. Stopniowo, nasza umiejętność utrzymywania równowagi polepsza się i szalone skoki wahania nastrojów, których doświadczaliśmy, zaczynają się wyrównywać. Rozwijamy zdolność nie ograniczania innych w przeżywaniu ich uczuć; nie czujemy potrzeby ich osądzania. Natomiast, ogarniamy w pełni całą gamę naszych osobistych emocji.', 'Poprzez regularną modlitwę i medytację odkryję, co oznacza dla mnie równowaga emocjonalna.'),
(261, '09-17', '17 września', 'Wykraczając poza Krok Piąty', NULL, '„Może się nam wydawać, że, opisując naszą przeszłość, zrobiliśmy już wystarczająco dużo. Nie możemy jednak sobie pozwolić na popełnienie takiego błędu.  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNiektórzy z nas nie kwapią się zbytnio do pisania Czwartego Kroku,  inni natomiast podchodzą do niego krańcowo obsesyjnie. W końcu, nasz sponsor zaczyna się niepokoić naszymi nieustającymi obrachunkami.  Usiłujemy dotrzeć do wszystkiego, co pomogłoby nam zrozumieć  dlaczego nasze życie potoczyło się tak, a nie inaczej. Wydaje się nam,  że myślenie, pisanie i rozmawianie o naszej przeszłości jest samo w  sobie wystarczające. Nie słuchamy żadnych sugestii sponsora na temat  tego, byśmy stali się całkowicie gotowi, by nasze wady charakteru  zostały usunięte albo zadośćuczynili za krzywdy, które wyrządziliśmy.  Piszemy coraz więcej i więcej na temat naszych różnych wad, a  następnie, zachwyceni, dzielimy się naszym świeżym wglądem w  samych siebie. Wreszcie nasz wyczerpany sponsor rezygnuje ze  sponsorowania nam, w ramach samoobrony. Właśnie w tak skrajnej sytuacji znalazło się wielu z nas. Myślenie,  pisanie, rozmawianie o tym, co było z nami nie tak, stworzyło nam  złudzenie, że mamy wszystko pod kontrolą. Jednakże wcześniej czy  później zdaliśmy sobie sprawę, że utknęliśmy w naszych problemach,  nie mając żadnych rozwiązań. Zrozumieliśmy, że chcąc żyć inaczej,  musimy ruszyć w naszym programie dalej, poza Krok Piąty. Zaczęła w  nas dojrzewać gotowość do tego, by Siła Wyższa usunęła te wady  charakteru, których staliśmy się tak bardzo świadomi. Zadośćuczyniamy  za szkody, które wyrządziliśmy innym, na tyle, na ile jesteśmy w stanie to zrobić. Tylko wtedy zaczniemy doświadczać wolności płynącej z  budzącej się duchowości. Dzisiaj przestaliśmy być ofiarami i wyzwoleni,  możemy podążać dalej w naszym zdrowieniu.', 'Kroki Czwarty i Piąty, pomimo, że zrobienie ich jest konieczne, same w sobie nie przyniosą nam emocjonalnego i duchowego zdrowienia. Wykonam je, a następnie będę postępował zgodnie z nimi.'),
(262, '09-18', '18 września', 'Uczciwe relacje\r\n', NULL, '„Jedna z najgłębszych zmian w naszym życiu zachodzi w sferze związków osobistych.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nDzięki zdrowieniu wielu z nas ma o wiele bliższe i bardziej intymne  związki, niż mieliśmy kiedykolwiek wcześniej. Z czasem zauważamy, że  ciągnie nas ku tym, którzy potem stają się naszymi przyjaciółmi,  sponsorami lub życiowymi partnerami. Dzielenie śmiechu, łez, zmagań  niesie za sobą dzielenie się szacunkiem i trwałą empatią. A jeśli po jakimś czasie, odkryjemy, że nie we wszystkim zgadzamy się z naszymi przyjaciółmi? To co wtedy? Możemy zauważyć, że nie mamy  takich samych gustów muzycznych, jak nasz najukochańszy przyjaciel,  że nie zgadzamy się z naszą partnerką lub partnerem w kwestii  umeblowania mieszkania, możemy nawet głosować za innymi  ustaleniami niż nasz sponsor na mitingu organizacyjnym. Czy konflikt  oznacza, że nasza przyjaźń, małżeństwo lub sponsoring zbliżają się ku  końcowi? Wcale nie! Można się spodziewać, że tego typu konflikty nastąpią w każdym  długotrwałym związku, lecz świadczą one wyłącznie o emocjonalnym  zdrowiu i uczciwości osób ze sobą związanych. W każdym związku,  gdzie dwoje osób zgadza się absolutnie we wszystkim, istnieje  prawdopodobieństwo, że tylko jedna z tych osób jest uczciwa. Jeżeli  poświęcamy naszą uczciwość tylko po to, by uniknąć konfliktów lub  nieporozumień, pozbywamy się tego, co najlepszego możemy wnieść do związku. Aby w pełni doświadczyć partnerstwa, musimy być całkowicie  uczciwi wobec drugiej istoty ludzkiej.', 'Zaakceptuję różnice, które czynią każdego z nas wyjątkowym. Dzisiaj popracuję nad tym, by być sobą.'),
(263, '09-19', '19 września', 'Wspólnota', NULL, '„W NA, nasza radość mnoży się, gdy dzielimy się tym, co spotyka nas dobrego, a nasz smutek pomniejsza się, gdy dzielimy się tym, co spotka nas złego. Po raz pierwszy w życiu, nie musimy doświadczać niczego w samotności.”  \r\n\r\n~IP nr 16\r\n\r\nGdy do pokonywania naszych życiowych trudności używamy kroków i  innych narzędzi programu, jesteśmy w stanie czerpać zadowolenie i  radość z życia w czystości. Jednak wszystkie nasze radości mijają zbyt  szybko, jeżeli nie dzielimy się nimi z innymi. Trudne chwile mogą ciągnąć się w nieskończoność, jeżeli zostaniemy z nimi sami. We wspólnocie  Anonimowych Narkomanów często pomnażamy nasze radości oraz  dzielimy nasze zmartwienia poprzez dzielenie się nimi z drugą osobą. My, uzależnieni, zdrowiejąc, doświadczamy tego rodzaju zadowolenia, które docenić może tylko drugi uzależniony. Członkowie wspólnoty  rozumieją nas, kiedy opowiadamy im o naszej dumie spowodowanej  wywiązaniem się z jakichś zobowiązań, kiedy mówimy o uniesieniu,  którego doświadczamy przy naprawianiu naszego zniszczonego  związku, o uldze, której doświadczamy, gdy nie musimy brać narkotyków, żeby jakoś przebrnąć przez kolejny dzień. Kiedy dzielimy się tymi  doświadczeniami ze zdrowiejącymi uzależnionymi, a oni odpowiadają  podobnymi historiami, nasza radość rośnie. Te same zasady stosujemy,  gdy jako zdrowiejący uzależnieni napotykamy na różne przeciwności  losu. Poprzez dzielenie się swoimi trudnościami i pozwolenie innym  członkom NA, by podzielili się z nami swoją siłą, nasz ciężar zostaje  zmniejszony. Wspólnota, którą odnajdujemy w NA jest bezcenna. Poprzez wspólne  dzielenie się wzmacniamy radość i zmniejszamy ciężar życia w  zdrowieniu. ', 'Podzielę się moimi radościami i zmartwieniami z innymi uzależnionymi. Podzielę również ich radości i smutki. Jestem wdzięczny za mocne więzi, które znalazłem we wspólnocie Anonimowych Narkomanów.'),
(264, '09-20', '20 września', 'Odwaga do zmiany', NULL, '„Boże, użycz mi pogody ducha, abym, godził się z tym, czego nie mogę zmienić, siły, abym zmieniał to, co mogę zmienić i mądrości, abym odróżniał jedno od drugiego.”  \r\n\r\n~Modlitwa o pogodę ducha \r\n\r\nZdrowienie dotyczy zmian, a zmiany oznaczają robienie wielu rzeczy  w inny, niż dotychczas, sposób. Problem polega na tym, że wielu z nas  opiera się przed tym, by zacząć działać w inny sposób; być może to, co  robimy nie działa, ale przynajmniej jesteśmy z tym oswojeni. By zrobić  krok w nieznane, potrzebna jest odwaga. Jak znaleźć tę odwagę? Możemy na mitingach NA rozejrzeć się wokół siebie. Widzimy tam  tych, którzy potrzebowali zmiany swojego postępowania i którzy dokonali jej pomyślnie. Pomaga to nam nie tylko zniwelować strach przed tym, że  każda zmiana oznacza nieszczęście, ale także daje nam pożyteczne  doświadczenie tych, którzy wiedzą, co faktycznie działa, doświadczenie,  którego możemy użyć w zmienianiu tego, co nie działa. Możemy też spojrzeć na nasze własne doświadczenie w zdrowieniu.  Nawet, jeśli to doświadczenie ogranicza się wyłącznie do zaprzestania  zażywania narkotyków, to i tak dokonaliśmy już wielu zmian w naszym  życiu - i to zmian na lepsze. Jeśli w którejkolwiek dziedzinie naszego  życia zastosujemy krok, to zawsze odkrywamy, że poddanie się jest  lepsze od zaprzeczania, a zdrowienie lepsze od uzależnienia. Nasze własne doświadczenie i doświadczenie innych członków  wspólnoty mówi nam, że zmienianie tego, co możemy zmienić, stanowi  dużą część zdrowienia. Kroki i ich praktykowanie dają nam wskazówki i  odwagę potrzebną do zmiany. Nie mamy się czego obawiać.', 'Przyjmę z radością zmiany. Z pomocą mojej Siły Wyższej odnajdę odwagę, aby zmienić to, co mogę zmienić.'),
(265, '09-21', '21 września', 'Modlitwa', NULL, '„Modlitwa wymaga praktyki i musimy pamiętać, że nikt nie rodzi się fachowcem.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas, rozpoczynając swoje zdrowienie, nie miało żadnego  doświadczenia w modlitwie i martwiło się tym, że nie zna „odpowiednich  słów”. Niektórzy z nas pamiętali słowa, których nauczono nas w  dzieciństwie, ale nie byli pewni czy jeszcze wierzą w te słowa. Bez  względu na nasze doświadczenia z przeszłości, staramy się znaleźć  słowa, które płynęłyby z głębi naszych serc. Często naszą pierwszą próbą modlitwy jest zwrócenie się do Siły  Wyższej z prośbą o pomoc w codziennym utrzymywaniu czystości.  Możemy prosić o przewodnictwo i odwagę lub po prostu modlić się o  poznanie woli Boga względem nas i o siłę do jej spełnienia. Jeśli w  naszej modlitwie napotykamy na jakieś trudności, możemy poprosić  innych członków wspólnoty, by podzielili się z nami tym, jak oni nauczyli  się modlić. Nie ma większego znaczenia czy nasze modlitwy wypływają  z jakichś potrzeb, czy z radości, ważne jest, by starać się modlić. Nasze modlitwy będą ukształtowane przez nasze doświadczenie w  pracy nad Dwunastoma Krokami i osobiste pojmowanie Siły Wyższej. W  miarę rozwijania się naszego związku z Siłą Wyższą, będziemy czuli się  w modlitwie coraz wygodniej. Z czasem modlitwa stanie się naszym  źródłem siły i otuchy. Uciekamy się do tego źródła często i chętnie.', 'Wiem, że modlitwa może być prosta. Zacznę ją praktykować od tej chwili. '),
(266, '09-22', '22 września', 'Dbając o dar', NULL, 'Życie nabiera nowego znaczenia, gdy otwieramy się na ten dar.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nZaniedbywanie naszego zdrowienia jest podobne zaniedbywaniu  jakiegoś prezentu, który otrzymaliśmy. Przypuśćmy, że ktoś podarował ci nowy samochód. Czy pozwoliłbyś mu stać na dworze aż mu zgniją  opony? Czy jeździłbyś nim, ignorując okresowe przeglądy, dopóki nie  rozkraczyłby się na drodze? Oczywiście że nie! Podjąłbyś spory wysiłek,  by utrzymać w dobrym stanie tak wartościowy prezent. Zdrowienie jest także darem i musimy o niego dbać, jeśli chcemy go  zachować. Choć nasze zdrowienie nie posiada przedłużonej gwarancji,  istnieje jednak plan rutynowych zabiegów konserwacyjnych.  Pielęgnowanie zdrowienia polega, między innymi, na regularnym  uczęszczaniu na mityngi oraz na angażowaniu się w różne służby.  Będziemy musieli dokonywać codziennych porządków - nasz Dziesiąty  Krok - i co pewien czas wymagany również będzie solidny  czwartokrokowy przegląd. A jeśli będziemy pielęgnować ten dar  zdrowienia, dziękując Darczyńcy każdego dnia, to nie ulegnie on  zużyciu. Dar zdrowienia rośnie, będąc rozdawanym. Jeśli nie będziemy się nim  dzielić, nie będziemy mogli go zachować. A dzieląc się naszym  zdrowieniem z innymi, doceniamy go coraz bardziej.', 'Moje zdrowienie jest darem i chcę go zachować. Będę go pielęgnował tak, jak on tego wymaga i będę się dzielił moim zdrowieniem z innymi.'),
(267, '09-23', '23 września', 'Radząc sobie z plotkami', NULL, '„Zgodnie z zasadami zdrowienia staramy się nie oceniać, nie szufladkować i nie pouczać się nawzajem.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nSpójrzmy prawdzie w oczy: we wspólnocie Anonimowych  Narkomanów żyjemy jak w przeźroczystym, szklanym domu. Wszyscy  wiedzą tutaj o naszym życiu osobistym więcej, niż ktokolwiek dotąd.  Wiedzą z kim spędzamy wolny czas, gdzie pracujemy, na etapie którego  kroku jesteśmy, ile mamy dzieci itp. itd. A to czego nasi przyjaciele nie  wiedzą o nas, prawdopodobnie mogą sobie łatwo wyobrazić. Prawdopodobnie nie jesteśmy zbyt szczęśliwi, gdy inni plotkują o nas.  Jednak, jeśli wycofujemy się ze wspólnoty i izolujemy się, by uniknąć  plotek, okradamy się jednocześnie z miłości, przyjaźni i niezastąpionego  doświadczenia w zdrowieniu, które inni uzależnieni mają do  zaoferowania. Lepszym sposobem poradzenia sobie z plotkami jest po  prostu akceptacja rzeczy takimi, jakie są i akceptacja siebie takimi, jacy  jesteśmy oraz życie zgodne z zasadami. Im pewniejsi stajemy się  własnego programu zdrowienia, własnych decyzji oraz wskazówek, które otrzymujemy od kochającego Boga, tym mniej wagi przykładamy do  cudzych opinii.  ', 'Zdecydowałem się związać ze Wspólnotą NA. Opinie innych nie będą wpływać na moje zaangażowanie w zdrowienie.'),
(268, '09-24', '24 września', 'Rozwijające się pojęcie Boga', NULL, '„Sugerowane jest jedynie, by ta Siła była kochająca, troskliwa i większa od nas samych. Nie musimy być religijni, aby zaakceptować tę ideę. Najważniejsze jest otwarcie umysłu na wiarę.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW trwającym całe życie procesie rozwijania się wiary nasze  pojmowanie Boga będzie się zmieniać. Pojmowanie, które posiadamy na początku zdrowienia, po kilku miesiącach czystości nie będzie już takie  same, inne też będzie, gdy będziemy mieli za sobą kilka lat czystości. Nasze początkowe rozumienie Siły większej od nas będzie  najprawdopodobniej ograniczone. Być może sądzimy, że Siła ta będzie  tylko utrzymywać nas w czystości, ale nic poza tym. Być może ociągamy się z modlitwą, ponieważ stawiamy warunki dotyczące naszych próśb i  tego, co Siła Wyższa miałaby dla nas zrobić. Być może mówimy: \"To  jest tak okropne, że nawet Bóg nie może nic z tym zrobić\", albo: „Bóg ma tyle ludzi na głowie, że na pewno nie ma czasu dla mnie \". W miarę naszych postępów w zdrowieniu, rozwija się nasze  pojmowanie Boga. Zauważymy, że jedynymi ograniczeniami bożej  miłości i łaski są te, które my sami narzucamy poprzez niechęć do  usunięcia się na bok. Kochający Bóg, w którego uwierzyliśmy, jest  nieograniczony i tą siłą oraz miłością, odnalezioną w naszej wierze,  dzielą się prawie wszyscy zdrowiejący uzależnieni na całym świecie.', 'Bóg, w którego wierzę i taki, jakim zaczynam Go pojmować, ma niezmierzone zasoby miłości i nieograniczone możliwości opieki. Zaufam, że mój Bóg jest większy od wszystkich moich problemów'),
(269, '09-25', '25 września', 'Czwarty Krok - lęk przed uczuciami', NULL, '„Możemy się obawiać, że bycie w kontakcie z naszymi uczuciami wywoła przytłaczającą reakcję łańcuchową bólu i paniki.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nZwykle, skargi odnośnie Czwartego Kroku dotyczą tego, że czyni on  nas boleśnie świadomymi naszych wad charakteru. Możemy odczuwać  pokusę, by zawiesić pracę nad naszym programem zdrowienia. W tej  sytuacji źródło energii niezbędnej do kontynuacji pracy nad krokami  możemy odnaleźć w poddaniu się i akceptacji. To nie świadomość naszych wad charakteru sprawia nam ból, lecz  właśnie same wady. Gdy braliśmy, czuliśmy tylko narkotyki; mogliśmy  ignorować cierpienie powodowane naszymi wadami. Teraz, gdy narkotyki odeszły, czujemy ból. Wzbranianie się przed uświadomieniem sobie  źródła naszego bólu nie spowodujemy jego odejścia. Zaprzeczanie  chroni ból i czyni go silniejszym. Dwanaście Kroków pomaga nam  uporać się z cierpieniem wywołanym naszymi wadami, ponieważ  zajmują się one bezpośrednio tymi wadami. Jeśli nasze wady charakteru sprawiają nam ból, przypomnijmy sobie  koszmar aktywnego uzależnienia, z którego teraz się ocknęliśmy. Możemy przypomnieć sobie nadzieję na ulgę, którą dał nam Krok Drugi.  Poprzez Trzeci Krok możemy znów oddać naszą wolę i nasze życie pod  opiekę Boga, jakkolwiek go pojmujemy. Nasza Siła Wyższa troszczy się  o nas, udzielając nam pomocy, potrzebnej do pracy nad resztą Dwunastu Kroków. Nie musimy obawiać się naszych uczuć. ', 'Nie będę się bać swoich uczuć. Z pomocą mojej Siły Wyższej będę kontynuować zdrowienie.'),
(270, '09-26', '26 września', 'Dostrzeganie siebie w innych\r\n', NULL, '„Ocenianie cudzych błędów nie uczyni nas lepszymi ludźmi.”   \r\n\r\n~Tekst Podstawowy  \r\n\r\nJakże łatwo jest wytykać błędy innych. Istnieje ku temu powód: wady,  które najłatwiej dostrzegamy w innych, są często wadami, które znamy  najlepiej na przykładzie naszego własnego charakteru. Możemy  zauważyć u naszego najlepszego przyjaciela tendencję do zbytniego  szastania pieniędzmi. Jeśli jednak przeanalizujemy swój własny sposób  wydawania pieniędzy, prawdopodobnie odnajdziemy tam ten sam rodzaj  braku kontroli. Możemy uznać, że nasz sponsor jest zbyt mocno  zaangażowany w służbę, a przyjrzawszy się sobie, zauważamy, że w  czasie ostatnich trzech miesięcy nie spędziliśmy ani jednego weekendu  z naszymi rodzinami z powodu podobnego zaangażowania w służbę. To, czego nie lubimy w naszych bliskich, często okazuje się być tym,  czego najbardziej nie lubimy w sobie. Możemy to spostrzeżenie  wykorzystać dla dobra naszej duchowości. Gdy ogarnie nas przymus  oceniania kogoś innego możemy wykorzystać ten impuls w celu  lepszego rozeznania się we własnych wadach. To, co zobaczymy,  poprowadzi nasze działania w kierunku zdrowienia i pomoże nam stać  się zdrowymi emocjonalnie i szczęśliwymi osobami. ', 'Będę przymykał oko na cudze wady charakteru i rozpoznawał własne.'),
(271, '09-27', '27 września', 'Pozbieraj się', NULL, '„W naszej autodestrukcyjnej osobowości jest coś takiego, co wieści porażkę.”\r\n\r\n~Tekst Podstawowy \r\n\r\n„Zobacz jaki jestem biedny i godny pożałowania, spójrz na mnie, moje życie jest koszmarem! Upadłem i nieważne ile razy nie próbowałbym stanąć, zawsze upadam”.   Wielu z nas przybyło do NA, marudząc pod nosem w podobny sposób. Teraz, nasze życie już nie jest takie. Prawdą jest, że czasem się jeszcze potykamy, a czasami nawet upadniemy. Chwilami czujemy, że wbrew naszym wysiłkom nie udaje się nam posunąć do przodu. Prawdą jednak również jest fakt, że z pomocą zdrowiejących uzależnionych w NA, zawsze znajdziemy pomocną dłoń, która postawi nas na nogi, otrzepie i pomoże nam zacząć od nowa. Nie mówimy już więcej: „Jestem nieudacznikiem i nigdy nigdzie nie dojdę\". Najczęściej mówimy raczej tak: „ Kurcze, znów wpadłem w tę samą koleinę, może się w końcu nauczę zwalniać tempo, albo całkiem ją omijać.\" Nim to nastąpi, możemy jeszcze nie raz upaść, lecz nauczyliśmy się, że zawsze możemy znaleźć pomocną dłoń, która postawi nas na nogi', 'Jeżeli zacznę narzekać na niepowodzenie, przypomnę sobie, że jest sposób, aby iść naprzód. Zaakceptuję zachętę i wsparcie NA.'),
(272, '09-28', '28 września', 'Nadzieja', NULL, 'Stopniowo, w miarę tego, jak zaczynamy bardziej koncentrować się na Bogu, niż na sobie, nasza rozpacz przemienia się w nadzieję.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy braliśmy, rozpacz była naszym nierozłącznym towarzyszem.  Zabarwiała ona każdą naszą świadomą chwilę. Rozpacz zrodziła się z naszego doświadczenia z aktywnym uzależnieniem: niezależnie od tego, jakich byśmy środków nie próbowali, by uczynić nasze życie lepszym, zawsze staczaliśmy się jeszcze niżej. Próby kontrolowania naszego życia najczęściej kończyły się niepowodzeniem. W pewnym sensie, uznając w Pierwszym Kroku naszą bezsilność, przyznaliśmy się do rozpaczy. Kroki Drugi i Trzeci wyprowadziły nas stopniowo z tej rozpaczy, dając  nam nową nadzieję, towarzystwo zdrowiejących uzależnionych. Gdy  zaakceptowaliśmy fakt, że tak wiele naszych prób zmienienia się nie powiodło się, uwierzyliśmy, że istnieje Siła większa od nas samych. Wierzymy, że ta Siła może nam pomóc i to uczyni. Praktykujemy Drugi i  Trzeci Krok jako wyraz naszej nadziei na lepsze życie, zwracając się do tej Siły o przewodnictwo. W miarę, jak zaczynamy coraz bardziej polegać w kierowaniu naszym codziennym życiem na Sile Wyższej, rozpacz,  wypływająca z naszego długiego doświadczenia z samowystarczalnością, znika.  ', 'Ugruntuję moją decyzję z Trzeciego Kroku. Wiem, że jeśli w moim życiu jest Siła Wyższa, to jest też nadzieja.'),
(273, '09-29', '29 września', 'Właśnie dzisiaj\r\n', NULL, '„Jeśli przestajemy żyć tu i teraz, to nasze problemy zaczynają się bezzasadnie rozrastać.”   \r\n\r\n~Tekst Podstawowy \r\n\r\n„Właśnie dzisiaj” - to idea dodająca otuchy. Jeśli będziemy próbować żyć przeszłością, możemy być szarpani przez pełne bólu i niepokoju wspomnienia. Lekcje, płynące z naszego zażywania, nie dadzą nam tego, czego poszukujemy w zdrowieniu. Życie dniem jutrzejszym oznacza życie w ciągłym strachu. Nie możemy wiedzieć, co czeka nas w przyszłości, a niepewność budzi obawę. Gdy przestajemy koncentrować się na dniu dzisiejszym, nasze życie staje się przytłaczające. Życie daną chwilą oferuje nam wolność. W danej chwili wiemy, że jesteśmy bezpieczni. Nie zażywamy i mamy wszystko, czego potrzebujemy. Co więcej - życie dzieje się właśnie tu i teraz. Przeszłość już odeszła, przyszłość jeszcze nie nadeszła, a nasze martwienie się nic nie zmieni. Dzisiaj, właśnie w tej chwili, możemy cieszyć się naszym zdrowieniem.  ', 'Zostanę tu i teraz. Dzisiaj, w danej chwili, jestem wolny.'),
(274, '09-30', '30 września', 'Bycie sobą', NULL, '„Bycie sobą jest prawdziwą wartością.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielokrotnie próbowaliśmy spełniać oczekiwania otaczających nas  ludzi. Być może czuliśmy się lepiej, wierząc, że byliśmy w porządku, jeśli przynosiliśmy dobre stopnie, sprzątaliśmy nasz pokój czy ubieraliśmy się w określony sposób. Nieustannie pragnąc do kogoś przynależeć i być  kochanym, wielu z nas poświęcało sporo czasu temu, by dostosować się do oczekiwań innych - nigdy jednak nie udało nam się w pełni dorównać  tym oczekiwaniom. Teraz, w procesie zdrowienia, jesteśmy akceptowani takimi, jakimi  jesteśmy. Dla innych ludzi naszą prawdziwą wartością jest to, że  jesteśmy sobą. Pracując nad krokami, uczymy się akceptować siebie  takimi, jakimi jesteśmy. Kiedy to się nam udaje, zyskujemy wolność bycia tym, kim chcemy być. Każdy z nas ma wiele zalet, którymi możemy  dzielić się z innymi. Nasze doświadczenia, którymi się szczerze dzielimy, pomagają innym odnaleźć potrzebny im do rozpoczęcia własnego  zdrowienia poziom identyfikacji. Odkrywamy, że mamy szczególny dar,  który możemy zaoferować tym, którzy nas otaczają.', 'Moje doświadczenie w programie zdrowienia jest największym darem, który mogę ofiarować innym uzależnionym. Będę szczerze dzielił się z innymi tym, co mam. '),
(275, '10-01', '1 października', 'Nie tylko motywacja do wzrostu', NULL, '„Uczymy się, że ból może być motywującym czynnikiem w zdrowieniu”  \r\n\r\n~Tekst Podstawowy  \r\n\r\n„Ból - któż go potrzebuje!” myślimy, gdy go doznajemy. Nie jesteśmy w stanie dostrzec czemu dobremu ma służyć ból. Wydaje się on być tylko  bezsensownym ćwiczeniem cierpienia. Jeśli ktoś wspomni o rozwoju  duchowym, gdy jesteśmy pogrążeni w bólu, zazwyczaj parskamy  zdegustowani i odwracamy się, myśląc, że nigdy nie spotkaliśmy  bardziej nieczułej osoby. Lecz co by było, gdyby człowiek nie odczuwał bólu, zarówno  fizycznego jak i emocjonalnego? Brzmi to jak idealny świat? Niezupełnie. Gdybyśmy nie czuli fizycznego bólu, nie bylibyśmy zdolni do tego, aby  wypłakać drzazgę z oka, nie wiedzielibyśmy, kiedy przestać ćwiczyć, nie  wiedzielibyśmy kiedy odwrócić się na drugi bok podczas snu. Po prostu  nadużywalibyśmy siebie z powodu braku naturalnego systemu  ostrzegawczego. To samo dotyczy bólu emocjonalnego. Skąd byśmy wiedzieli, że nasze życie wymknęło się nam spod kontroli, gdybyśmy nie czuli bólu?  Podobnie jak ból fizyczny, ból emocjonalny pomaga nam przestać robić  te rzeczy, które przynoszą nam cierpienie. Jednak ból jest czymś więcej niż tylko czynnikiem motywującym.  Emocjonalne cierpienie dostarcza nam podstaw, by porównać je z  doświadczeniem radości. Nie bylibyśmy w stanie docenić radości, nie  doświadczywszy wcześniej cierpienia.', 'Zaakceptuję ból jako konieczną część mojego życia. Wiem, że w takim samym stopniu, w jakim odczuwam ból, mogę także poczuć radość'),
(276, '10-02', '2 października', 'Zachowywanie wiary\r\n', NULL, '„Dopóki zachowujemy wiarę i regularnie ją odnawiamy, mamy dostęp do nieograniczonej siły, którą otrzymujemy poprzez codzienną modlitwę i poddanie się.\"   \r\n\r\n~Tekst Podstawowy  \r\n\r\nSą dwie części zdrowienia: stać się czystym i pozostać w czystości. Stać się czystym jest łatwiejsze niż pozostawanie w czystości, ponieważ robimy to jednorazowo. Pozostanie w czystości jest trudniejsze, ponieważ wymaga od nas codziennej uwagi. Jednak obydwie te części zasilane są wiarą. Staliśmy się czyści dzięki wierze. Przyznaliśmy, że nasze uzależnienie było silniejsze od nas i przestaliśmy z nim walczyć na własna rękę. Oddaliśmy tę bitwę w ręce Siły większej od nas i ta Siła Wyższa sprawiła, że staliśmy się czyści. Pozostajemy czyści każdego dnia w ten sam sposób - poprzez wiarę. Właśnie dziś poddajemy się. Życie może okazać się zbyt trudne, byśmy mogli zmagać się z nim wyłącznie własnymi silami. Gdy tak się dzieje, szukamy pomocy Siły większej od nas. Modlimy się, prosząc naszą Siłę Wyższą o wskazówki i siłę, by za nimi podążać. Poprzez codzienne stosowanie i odnawianie naszej wiary uzupełniamy zasoby potrzebne nam do życia w czystości, do życia pełnią życia. Mamy do dyspozycji nieograniczoną moc, gdy tylko jej potrzebujemy. Aby móc z niej korzystać, wystarczy tylko zachowywać wiarę w Siłę Wyższą, która sprawiła, iż staliśmy się czyści, i która utrzymuje nas w czystości.', 'Wiara sprawiła, że stałem się czysty i wiara zachowanie w czystości. Dziś zachowam swoją wiarę.'),
(277, '10-03', '3 października', 'Rezygnacja z samowoli\r\n', NULL, '„Nasze ego, kiedyś wielkie i dominujące, od chwili, gdy żyjemy w harmonii z kochającym Bogiem, zeszło na drugi plan. Zauważamy, że prowadzimy bogatsze, szczęśliwsze i dużo pełniejsze życie, jeśli tylko rezygnujemy z samowoli.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nUzależnienie i samowola idą w parze. Nieumiejętność kierowania własnym życiem, do której przyznaliśmy się w Kroku Pierwszym, jest rezultatem zarówno samowoli jak i chronicznego nadużywania narkotyków. Również i dzisiaj, jeżeli będziemy kierować się samowolą, nasze życie może wymknąć się nam spod kontroli, tak jak wtedy, gdy braliśmy. Gdy nasze pomysły, pragnienia i wymagania wysuwają się na pierwszy plan, znajdujemy się w nieustannym konflikcie ze wszystkimi i wszystkim co nas otacza. Samowola odzwierciedla nasze poleganie na ego. Jedynym sposobem, który może nas uwolnić od samowoli i wynikających z niej konfliktów, jest przezwyciężenie naszej zależności od ego i w zamian zdanie się na przewodnictwo i siłę oferowaną nam przez kochającego Boga. Podejmując różne decyzje, uczymy się kierować zasadami duchowymi, a nie samolubnymi pragnieniami. Uczymy się szukać przewodnictwa Siły Wyższej, kogoś z szerszym od naszego spojrzeniem na świat. Robiąc tak, dostrzegamy, że nasze życie coraz bardziej wtapia się w otaczający nas porządek rzeczy. Już dłużej nie wykluczamy się z nurtu życia; stajemy się teraz jego częścią i odkrywamy pełnię tego, co oferuje nam zdrowienie.', 'Postaram się wyzwolić się od ego i konfliktów wynikających z samowoli. Będę starać się poprawić swój świadomy kontakt z Bogiem, jakkolwiek go pojmuję, szukając przewodnictwa i siły, której potrzebuję do życia w harmonii z moim światem.'),
(278, '10-04', '4 października', 'Trzydziestodniowy cud', NULL, '„Gdy po raz pierwszy zaczynamy się cieszyć tym, że wyrwaliśmy się z niewoli uzależnienia, pojawia się ryzyko, że znów zechcemy przejąć kontrolę nad swoim życiem. Zapominamy o udręce i cierpieniu, którego zaznaliśmy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas było \"trzydziestodniowym cudem\". Gdy pojawiliśmy się na naszym pierwszym mitingu NA, byliśmy zdesperowani i umierający. Utożsamialiśmy się z uzależnionymi, których tam spotkaliśmy i z  posłaniem, którym się dzielili. Z ich wsparciem byliśmy wreszcie zdolni do tego, aby przestać brać i złapać świeży oddech. Po raz pierwszy od bardzo, bardzo dawna czuliśmy się jak w domu. Nagle nasze życie uległo przemianie: chodziliśmy, mówiliśmy, jedliśmy, piliśmy, spaliśmy i śniliśmy w sposób NA. Później NA utraciło swoja świeżość. Mityngi, które uprzednio były ekscytującym wydarzeniem, stały się monotonne. Nasi wspaniali przyjaciele z NA stali się nudziarzami, a ich podnoszący na duchu  przekaz NA, zrzędzeniem. Gdy nasi wcześniejsi znajomi do nas zadzwonili, zapraszając nas z powrotem do starych zabaw, pożegnaliśmy czule nasze zdrowienie. Jednak prędzej czy później znów wracaliśmy do pomieszczeń, w których odbywały się mityngi Anonimowych Narkomanów. Przekonaliśmy się, że tam na zewnątrz nic nie uległo zmianie - ani my, ani nasi znajomi, ani narkotyki, nic. A jeśli cokolwiek uległo zmianie, to tylko na gorsze. Prawdą jest, że mitingi NA być może nie są najweselszym miejscem na ziemi, a nasi przyjaciele z NA być może nie są duchowymi gigantami. Jednak w mitingach jest siła, jest wspólna więź pomiędzy członkami wspólnoty, jest życie według programu, bez którego nie możemy się obejść. Dziś nasze zdrowienie jest czymś więcej niż tylko kaprysem czy przemijającą modą - jest sposobem na życie. Mamy zamiar żyć według programu tak, jakby od tego zależało nasze życie, ponieważ faktycznie zależy. ', 'Nie jestem „trzydziestodniowym cudem”. Droga NA jest moją życiową drogą i wytrwam tu do końca. '),
(279, '10-05', '5 października', 'Prośmy o miłosierdzie, a nie o sprawiedliwość', NULL, '„Wielu z nas miało problem z przyznaniem się do tego, że krzywdziliśmy innych... Pozbyliśmy się naszych usprawiedliwień i myślenia o sobie jako o ofiarach.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNasze życie polepsza się z dnia na dzień. Wszystko jest w porządku, a program zdrowienia obdarza nas materialnymi i duchownymi darami. Być może mamy trochę pieniędzy w banku, samochód i może jesteśmy  w związku. Mamy więcej pewności siebie, a nasza wiara w Siłę Wyższą ciągle rośnie. Nagle coś się dzieje. Ktoś włamał się do naszego nowego samochodu i ukradł radio, albo nasz partner zaczyna nas zdradzać. Czujemy się pokrzywdzeni i pytamy “gdzie jest sprawiedliwość”? Jeśli jednak przyjrzymy się naszym zachowaniom z przeszłości, to okazuje się, że sami też robiliśmy innym to, co nam uczyniono. Uświadamiamy sobie, że tak naprawdę nie chcemy sprawiedliwości, ani dla siebie, ani dla innych. Chcemy miłosierdzia. Dziękujemy kochającemu Bogu za współczucie, które nam okazał i znajdujemy czas, aby docenić wszystkie cenne dary, które przyniosło nam zdrowienie.', 'Będę prosił o miłosierdzie, a nie sprawiedliwość. Jestem wdzięczny za okazaną mi litość i zaoferuję miłosierdzie innym.'),
(280, '10-06', '6 października', 'Zadośćuczynienie bez oczekiwań\r\n', NULL, '„Wyobrażanie sobie tego, w jaki sposób obecnie mamy dokonywać zadośćuczynień może być wielką przeszkodą w tworzeniu listy i w procesie stawania się gotowym.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW Ósmym Kroku stajemy się gotowi, aby zadośćuczynić wszystkim, których skrzywdziliśmy. Zastanawiamy się, jakie rezultaty przyniesie nasze zadośćuczynienie. Czy dostaniemy przebaczenie? Czy opuści nas poczucie winy? A może zostaniemy odepchnięci przez osobę, którą skrzywdziliśmy? Jeżeli chcemy otrzymać duchowe korzyści, jaki przynosi Krok Ósmy i Krok Dziewiąty, musimy zrezygnować z szukania przebaczenia. Jeżeli podejmiemy się tego kroku z jakimikolwiek oczekiwaniami, rezultaty mogą nas bardzo rozczarować. Musimy zadać sobie pytanie, czy pokładamy jakiekolwiek nadzieje, że uzyskamy przebaczenie od osoby, której zadośćuczyniamy? A może mamy nadzieję, że nasza smutna historia życia wzruszy do łez wierzycieli, którym zalegamy i zostaniemy zwolnieni od obowiązku spłacania długu. Powinniśmy być gotowi zadośćuczynić wszystkim, których skrzywdziliśmy, bez względu na to, jakie będą tego efekty. Planujmy zadośćuczynienie, nie planujmy rezultatów. Chociaż nie każdy nam wszystko i do końca wybaczy, nauczymy się wybaczać sobie. W tym procesie zauważymy, że nie musimy juz dźwigać ciężaru naszej przeszłości.', 'Pozbędę się wszelkich oczekiwań w stosunku do osób, którym winny jestem zadośćuczynienie. ');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(281, '10-07', '7 października', 'Zależni od naszej Siły Wyższej\r\n', NULL, '„Odkrywamy, że jako zdrowiejący uzależnieni wciąż jeszcze jesteśmy od czegoś zależni, lecz teraz jesteśmy zależni nie od otaczających nas rzeczy, lecz od kochającego Boga, a siłę wewnętrzną czerpiemy z relacji z nim.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nDla wielu z nas buntowniczość jest drugą naturą. Nie chcieliśmy zależeć od niczego ani od nikogo, a zwłaszcza od Boga. Myśleliśmy, że piękno brania polega właśnie na tym, że możemy być i czuć się kim tylko zechcemy, i to bez niczyjej pomocy. Niestety, ceną, którą zapłaciliśmy za tę iluzję wolności, był koszmar uzależnienia. Zamiast być wolni, staliśmy się zniewoleni. Po przyjściu do NA uświadomiliśmy sobie, że zależność od Boga jest czymś zupełnie innym, niż myśleliśmy. Jeśli zapragniemy odzyskać zdrowie duchowe, musimy poprosić o to „Siłę większą niż nasza własna”. Sami jednak możemy wybrać własną koncepcję tej Siły Wyższej. Odkrywamy, że zależność od Siły Wyższej nie ogranicza nas, wręcz przeciwnie, czyni nas wolnymi. Siła, którą znajdujemy w programie zdrowienia, jest siłą, której nie mamy sami z siebie. Jest miłością, której baliśmy się przyjmować od innych ludzi. Jest poczuciem osobistego drogowskazu, którego nigdy nie mieliśmy, przewodnikiem, przed którym wcześniej nie ugięlibyśmy się, bo nie ufaliśmy nikomu. Tym wszystkim jest ta Siła i jest to tylko nasza Siła. Dziś jesteśmy wdzięczni, że mamy Siłę Wyższą, na której możemy polegać.', 'Będę zależny od miłości i siły wewnętrznej, którą czerpię od Boga, jakkolwiek go pojmuję.'),
(282, '10-08', '8 października', 'Nowy styl życia\r\n', NULL, '„Obawiamy się, że jeżeli nie będziemy używać tego, co mamy, to stracimy to.”  \r\n\r\n~Tekst podstawowy  \r\n\r\nUzależnienie narzuciło naszemu życiu określony styl, a wraz z nim, sens - bez wątpienia, mroczny i chory sens, niemniej jednak, sens. Program Anonimowych Narkomanów daje nam nowy styl życia w miejsce naszej starej rutyny. Natomiast, ten nowy styl nadaje nowy sens naszemu życiu, pełen światła i nadziei. Czym więc jest ten nowy styl naszego życia? W miejsce izolacji znaleźliśmy teraz wspólnotę. Zamiast z klapkami na oczach powtarzać wciąż te same błędy, poddajemy się regularnej samoanalizie, potrafimy zatrzymać to, co pomaga nam w rozwoju i pozbywać się tego, co nam nie pomaga. Zamiast ciągłych prób przetrwania o własnych ograniczonych siłach, rozwijamy świadomy kontakt z kochającą Siłą większą niż my sami. Nasze życie musi przebiegać według jakiegoś wzorca. Aby kontynuować nasze zdrowienie, musimy postępować zgodnie z tymi nowymi wzorcami, których nauczył nas program. Zwracając na nie uwagę regularnie, utrzymamy wolność od śmiertelnej choroby uzależnienia i tym samym zachowamy ten sens, który zdrowienie nadało naszemu nowemu życiu. ', 'Zacznę stosować w swoim życiu nowy wzorzec: regularne pielęgnowanie mojego zdrowienia.'),
(283, '10-09', '9 października', 'Porządkowanie', NULL, '„Przywiązujemy dużą wagę do tego, aby nasze sprawy były uporządkowane, ponieważ to przynosi nam ulgę.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nObserwowanie zachowania innych osób może nam w dużym stopniu ułatwić obserwowanie samych siebie. Jednak jedną z tajemnic sukcesu NA jest upewnianie się w tym, że nasze własne sprawy są uporządkowane. Co to jednak właściwie znaczy: „uporządkować własne sprawy”? Oznacza to pracę nad krokami, dzięki której możemy zobaczyć, jaki jest nasz własny udział w relacjach z innymi ludźmi. Gdy mamy problem z jakąś osobą, możemy zrobić nasz własny obrachunek, aby zorientować się, jaki jest nasz udział w tym problemie. Z pomocą naszego sponsora staramy się wszystko uporządkować. Następnie, codziennie kontynuujemy nasz obrachunek, aby w przyszłości uniknąć powtarzania tych samych błędów. Jest to dosyć proste. Traktujemy innych tak, jakbyśmy sami chcieli być przez nich traktowani. Dokonujemy zadośćuczynienia, jeżeli kogoś  skrzywdziliśmy. Kiedy powierzamy życie codziennej opiece naszej Siły Wyższej, możemy przestać budować nasze życie na samowoli, co było charakterystyczne dla naszego czynnego uzależnienia. Poprzez  poddanie się Sile, która pragnie szczęścia dla każdego z nas, nasze relacje z innymi na pewno się poprawią.  ', 'Uporządkuję moje własne sprawy. Dzisiaj przyjrzę się temu, jaki jest mój udział w moich życiowych problemach. Jeżeli okaże się, że jestem komuś winny zadośćuczynienia, dokonam go.'),
(284, '10-10', '10 października', 'Konsekwencje', NULL, 'Zanim staliśmy się czyści, większość decyzji podejmowaliśmy pod wpływem impulsu. Dzisiaj, ten sposób myślenia już nas nie ogranicza.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy miałeś kiedyś ochotę zrobić coś, chociaż dokładnie wiedziałeś, że skutki tego będą katastrofalne? Czy zdarzyło ci się kiedyś ulec pokusie, pomimo, iż wcześniej zdawałeś sobie sprawę z bolesnych konsekwencji jakie potem nastąpią? Mówi się, że każde działanie ma swoje konsekwencje. Zanim staliśmy się czyści, wielu z nas po prostu w to nie wierzyło. Teraz jednak, wiemy dokładnie co to znaczy. Kiedy coś robimy, wiemy dokładnie, że będziemy musieli ponieść tego konsekwencje. Nie możemy już dłużej robić rzeczy z niewiedzy, gdy doskonale wiemy, że cena, którą będziemy musieli zapłacić nie będzie się nam podobać. Każda wygrana ma swoją cenę. Nie ma nic złego w robieniu czegoś pomimo spodziewanych konsekwencji, jeśli jesteśmy gotowi za to płacić, a zawsze jest jakaś cena do zapłacenia. ', 'Zanim coś zrobię, zastanowię się nad konsekwencjami moich działań.'),
(285, '10-11', '11 października', 'Okulary a postawy', NULL, '„Dzięki naszym świetnym pomysłom na życie zawsze mieliśmy problemy... Zdrowienie oznacza aktywną zmianę naszych poglądów i  postaw.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPodczas naszego aktywnego uzależnienia świat jawił się nam prawdopodobnie jakimś okropnym miejscem. Branie pomagało nam  znieść świat takim, jaki jest. Dzisiaj już wiemy, że problemem nie jest ten świat. To nasze poglądy i postawy wobec świata uniemożliwiały nam znalezienie w nim przytulnego miejsca dla siebie. Nasze poglądy i postawy są jak okulary, przez które patrzymy na świat. Jeśli nasze „szkła” są zaparowane lub brudne, nasze życie wygląda mętnie. Jeśli nasze postawy nie są dobrze ustawione, to  widzimy świat zniekształcony. Aby widzieć świat przejrzyście, musimy utrzymywać nasze poglądy i postawy w czystości, wolne od urazy,  zaprzeczania, użalania się i ograniczeń. Aby mieć pewność, że widzimy świat odpowiednio ostro, musimy dostosować nasze poglądy do  rzeczywistości. W czasie aktywnego uzależnienia nasze poglądy nie pozwalały nam  jasno spojrzeć na świat i na rolę, jaką w nim odgrywamy. Zdrowienie służy do tego, aby skorygować ostrość okularów, przez które patrzymy na świat. Poprzez odrzucenie zaprzeczanie i zastąpienie go wiarą,  uczciwością, pokorą i odpowiedzialnością, kroki pomagają nam zobaczyć nasze życie w zupełnie nowym świetle. Poza tym, kroki  pomagają nam utrzymać w czystości nasze duchowe soczewki i dopingują nas do regularnej analizy naszych poglądów, postaw i działań. Dzisiaj, patrząc przez czyste okulary wiary i zdrowienia, postrzegamy świat jako przytulne i gościnne miejsce do życia. ', 'Będę spoglądał na świat i na moje życie przez czyste duchowe soczewki mojego programu.'),
(286, '10-12', '12 października', 'Mieć rację', NULL, '„Kiedy uznajemy, że nasze życie wymknęło się nam spod kontroli, nie musimy już obstawać przy swoim punkcie widzenia… Nie musimy już ciągle mieć racji.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNic nie izoluje nas szybciej od życzliwości i koleżeństwa naszych przyjaciół z NA, niż nasza nieustająca potrzeba posiadania „racji”. W  poczuciu niepewności pretendujemy do bycia pewnego rodzaju autorytetami. Cierpiąc z powodu niskiego poczucia wartości, próbujemy  dowartościować się poprzez pomniejszanie wartości innych. W najlepszym przypadku taka taktyka odtrąca od nas ludzi; w najgorszym -  wywołuje ich agresję. Im bardziej próbujemy udowodnić innym naszą „racją”, w tym większym jesteśmy błędzie. Nie musimy mieć racji, żeby poczuć się pewnie. Chcąc, by inni nas kochali i szanowali, nie musimy postępować tak, jakbyśmy mieli na wszystko odpowiedź. W rzeczywistości, jest to przeciwieństwem prawdy: nikt z nas przecież nie zna wszystkich odpowiedzi. Jesteśmy skazani na siebie wzajemnie, aby uzupełniać luki w naszym rozumieniu rzeczy i jesteśmy zdani na Siłę większą od nas samych, abyśmy mogli poradzić sobie z naszą własną bezsilnością. O wiele łatwiej żyje się nam z innymi, jeśli oferujemy im swoją wiedzę, przyznajemy się, że nie wiemy wszystkiego i staramy się uczyć od nich, jako od równych sobie. Nasze życie z samym sobą staje się bezpieczniejsze, jeśli przestajemy polegać  na własnej mocy a zaczynamy polegać na Bogu, jakim przyjęliśmy się go pojmować w zdrowieniu. Nie musimy ciągle mieć racji, musimy po prostu zdrowieć. ', 'Boże, przyznaję, że jestem bezsilny i nie kieruję swoim życiem. Pomóż mi żyć z innymi na równi i zdawać się na twoje wskazówki i siłę.'),
(287, '10-13', '13 października', 'Wnieść odmianę\r\n', NULL, '„Kiedy dajemy coś innej osobie, nie ważne ile, doświadczamy stanu duchowej świadomości, którego nie da się opisać słowami.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzasami wygląda na to, że świat jest tak źle urządzony, że nawet nie ma szansy by go odmienić. Myślimy: „Co ja tutaj z tym wszystkim mogę zdziałać? Jestem przecież tylko pojedynczą osobą”. Nieważne, czy  pragniemy pokoju na całym świecie, czy też chcemy, by zdrowienie było dostępne dla wszystkich potrzebujących uzależnionych - wszystkie te zadania wydają się być zbyt przytłaczające. „Tak dużo do zrobienia, a tak mało czasu” -wzdychamy i zastanawiamy się czy wogóle możemy zrobić coś dobrego. To niesamowite, że nawet jakiś najmniejszy wkład może dokonać ogromnej odmiany. To, aby życie uczynić czymś więcej, niż tylko  przeciętną i pełną trudu egzystencją, wymaga od nas niewielkiego wkładu. Doznajmy odmiany, poprzez poczucie głębokiej satysfakcji, której doświadczamy, dodając komuś otuchy. Kiedy uśmiechamy się do  osoby, która patrzy ponuro na świat, kiedy na autostradzie pozwalamy jakiemuś kierowcy wjechać na nasz pas, kiedy dzwonimy do  nowoprzybyłego, po to tylko, by powiedzieć mu, że o nim myślimy - wtedy wkraczamy do królestwa nadzwyczajności. Chcesz odmienić świat? Zacznij od uzależnionych, którzy dzisiaj wieczorem usiądą obok ciebie i wyobraź sobie, że twoje gesty życzliwości pomnożą się. Każdy z nas, w każdej chwili, może wnieść jakąś odmianę.', 'Gest życzliwości nic mnie nie kosztuje, a dla kogoś może być bezcenny. Dzisiaj będę dla kogoś życzliwy.'),
(288, '10-14', '14 października', 'Koniec samotności', NULL, '„Dzięki miłości, którą poznałem we wspólnocie Anonimowych Narkomanów, nie mam już usprawiedliwienia dla samotności.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nUzależnienie jest chorobą samotności. Możemy być otoczeni ludźmi, ale wcześniej czy później uzależnienie wpycha klina pomiędzy nas, a najbliższe nam osoby. Wielu z nas przywiodła do NA rozpaczliwa samotność. Chociaż być może przychodzimy na mityngi NA powściągliwi i nieufni, zostajemy powitani uściskiem, uśmiechem i serdecznym „przychodź ponownie.” Prawdopodobnie jest to pierwsze od dłuższego czasu miejsce, w którym czujemy się mile widziani. Widzimy innych członków NA jak się śmieją i rozmawiają, a potem jak niektórzy z nich idą do pobliskiej kawiarenki, aby dalej rozmawiać. Zastanawiamy się, czy kiedykolwiek będziemy mogli należeć do tej przyjaznej gromadki. Nasz nawyk do życia w izolacji może utrudnić nam przyłączenie się do tej grupy. Z czasem jednak zaczynamy odczuwać bardziej przynależność niż izolację. Wkrótce na mityngu czujemy się jak u siebie. Zaczynamy nawiązywać przyjaźnie i nasze życie zaczyna się zmieniać. NA uczy nas, jak możemy przezwyciężyć naszą izolację. Poprzez  nasze pierwsze nieśmiałe przyjaźnie, które tworzą się w naszej grupie domowej, zaczynamy dostrzegać, że nawiązywanie przyjaźni wcale nie jest takie trudne. Poczucie przynależności powstaje, gdy dzielimy nasze  życie z innymi.', 'Jestem wdzięczny za przyjaźnie, które dała mi Siła Wyższa w NA. Dzięki nim nie jestem już samotny.'),
(289, '10-15', '15 października', 'Wybory', NULL, 'Nie mieliśmy zamiaru zostać uzależnionymi.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy byliśmy mali, wszyscy mieliśmy marzenia. Każde dziecko słyszało od krewnych lub sąsiadów pytanie: „Kim chciałbyś zostać, gdy dorośniesz?” Nawet jeśli niektórzy z nas nie mieli górnolotnych marzeń o sukcesie, większość marzyła o pracy, o rodzinie, o przyszłości pełnej szacunku i podziwu. Ale nikt nie pytał: „Czy chciałbyś zostać narkomanem, gdy dorośniesz?” Nie mieliśmy zamiaru zostać uzależnionymi, ale nie mamy też możliwości przestać być uzależnionymi. Nie jesteśmy odpowiedzialni za naszą chorobę, ale za nasze zdrowienie - jesteśmy. Zdobywszy wiedzę o tym, że jesteśmy ludźmi chorymi, i że istnieje droga do zdrowienia, możemy przestać przypisywać winę okolicznościom lub samemu sobie i zacząć żyć rozwiązywaniem naszego problemu. Nie wybieraliśmy tego, czy będziemy uzależnieni, czy nie, ale możemy wybrać zdrowienie.', 'Wybiorę zdrowienie. '),
(290, '10-16', '16 października', 'Najprostsza modlitwa', NULL, '„... modliliśmy się tylko o poznanie Jego woli wobec nas oraz o siłę do jej spełnienia.” \r\n\r\n~Krok Jedenasty  \r\n\r\nJak się modlimy? Ponieważ mamy mało doświadczenia odnośnie modlitwy, wielu z nas nie wie, jak ją zacząć. Nie jest to jednak ani trudne, ani skomplikowane. Przyszliśmy do NA z powodu naszego uzależnienia od narkotyków. Poza tym, wielu z nas przyszło z głębokim poczuciem dezorientacji we własnym życiu. Samym sobie wydawaliśmy się być zagubieni i wędrowaliśmy przez pustynię bez drogi, bez kogokolwiek, kto by nas prowadził. Modlitwa jest drogą do tego, by otrzymać życiowe wskazówki i siłę bo podążania za nimi. Ponieważ w zdrowieniu w NA modlitwa odgrywa centralną rolę, wielu z nas zarezerwowało na nią stały punkt w naszym codziennym planie dnia i na tym buduje jego konstrukcję. W tym czasie skupienia rozmawiamy z naszą Siłą Wyższą słowami lub w milczeniu. Dzielimy się z nią naszymi myślami, odczuciami i mówimy o naszym dniu. Pytamy: „Co według twojej woli powinienem zrobić?” Jednocześnie mówimy: „Daj mi, proszę, siłę do spełnienia twojej woli”. Nauka modlitwy jest prosta. Prosimy o „poznanie Jego woli oraz o siłę do jej spełnienia.” Robiąc to, znajdujemy wskazówki, których nam brakowało i siłę potrzebną nam do wypełnienia woli naszego Boga. ', 'Zarezerwuję sobie chwilę skupienia, w której porozmawiam z moją Siłą Wyższą. Poproszę tę Siłę o wskazówki i o siłę do podążania za nimi. '),
(291, '10-17', '17 października', 'Prawda', NULL, '„Cała nasza dotychczasowa wiedza powinna być zweryfikowana, a szczególnie nasza wiedza dotycząca prawdy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas sądziło, że jesteśmy w stanie rozpoznać „Prawdę”. Uważaliśmy, że prawda jest czymś pewnym i niezmiennym, czymś, co  łatwo i bez wątpliwości potrafimy pojąć. W rzeczywistości jednak, często nie dostrzegaliśmy prawdy nawet wtedy, gdy zetknęliśmy się z nią twarzą w twarz. Nasza choroba koloryzowała wszystko w naszym życiu, szczególnie nasze postrzeganie prawdy - w rzeczywistości jednak to, co „wiedzieliśmy” o prawdzie o mało nas nie zabiło. Zanim będziemy zdolni rozpoznawać prawdę, musimy zmienić naszą wierność wobec uzależnienia na wierność wobec Siły Wyższej, która jest źródłem wszystkiego co jest dobre i prawdziwe. Prawda zmienia się w miarę wzrostu naszej wiary w Siłę Większą.  Jeśli pracujemy nad krokami, poprzez uzdrawiającą siłę zasad zdrowienia zaczyna zmieniać się całe nasze życie. Aby otworzyć się na zmianę, musimy zrezygnować z przywiązania do niezmiennej i sztywnej  prawdy. Za każdym razem, kiedy stykamy się z prawdę, staje się ona bardziej klarowna i prostsza. I tak, jak kroki zmieniają nasze życie, gdy im na to pozwolimy, tak też nasze rozumienie prawdy może zmieniać się każdego dnia, jeżeli wzrastamy.', 'Otworzę oczy i serce na zmianę, którą powodują kroki. Poprzez otwartość mogę dziś rozpoznać prawdę w moim życiu.'),
(292, '10-18', '18 października', 'Wszyscy przynależymy do tego miejsca\r\n', NULL, '„I chociaż, jak mówi stare przysłowie - polityka dzieli nawet małżeństwo - to uzależnienie łączy nas poprzez to, że czyni nas jedynymi w swoim rodzaju.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW NA stanowimy bardzo różnorodną grupę ludzi. Na każdym mityngu, obojętnie jakiego dnia, spotykają się ludzie, którzy są tak różni, że prawdopodobnie nigdy nie znaleźliby się razem w jednym pomieszczeniu, gdyby nie choroba uzależnienia. Pewien lekarz, będący członkiem NA, opowiadał, że gdy przyszedł na  swój pierwszy mityng, poczuł niechęć do zidentyfikowania się z tym miejscem, ponieważ nie chciał być „w pomieszczeniu pełnym ćpunów.” Inna osoba, z historią licznych pobytów w więzieniach i ośrodkach,  opowiadała podobną historię, z tą różnicą, że była zaszokowana, że było tam tylu „porządnych ludzi w garniturach!” Obydwoje świętowali niedawno swoją siódmą rocznicę ślubu. W NA ludzie bardzo różni od siebie zawierają przyjaźnie, sponsorują sobie nawzajem i pełnią razem służby. Zbieramy się razem w miejscach zdrowienia i jesteśmy ze sobą związani cierpieniem z przeszłości i  nadzieją na przyszłość. Spotykamy się na wspólnym gruncie i koncentrujemy się na dwóch, wspólnych dla nas, rzeczach: na  uzależnieniu i na zdrowieniu. ', 'Nie ma znaczenia jakie są moje osobiste uwarunkowania - przynależę do tego miejsca.'),
(293, '10-19', '19 października', 'Trwając przy czymś', NULL, '„... mogliśmy poczuć czas, dotknąć rzeczywistości i docenić dawno utracone przez wielu z nas wartości duchowe.”                                                                                                         \r\n\r\n~Tekst Podstawowy  \r\n\r\nPodczas naszego czynnego uzależnienia, chcąc zdobyć więcej narkotyków, byliśmy gotowi zdradzić wszystko, w co wierzyliśmy. Okradaliśmy naszych przyjaciół, sprzedając samych siebie, czy okłamując naszych pracodawców, deptaliśmy nasze najcenniejsze wartości. Za każdym razem, gdy zdradzaliśmy kolejne nasze pieczołowicie chronione ideały, coraz bardziej niszczyliśmy nasz charakter. Do chwili przyjścia na nasz pierwszy miting wielu z nas nie było niczym więcej, jak tylko ruiną swojego wcześniejszego ja.  Odzyskam nasze zagubione wartości, gdy dokonamy pierwszej uczciwej auto-analizy. Aby odbudować na nowo nasz charakter, musimy dbać o te wartości, jakkolwiek wielka jest pokusa, by odsunąć je na bok. Musimy być uczciwi wobec siebie, gdy wierzymy, że moglibyśmy oszukać wszystkich jednym kłamstwem. Gdy ignorujemy nasze wartości, stwierdzamy, że to my sami jesteśmy największą ofiarą naszych oszustw.  Nie chcemy znowu zaczynać niszczenia naszej duszy, szczególnie po całej pracy, którą włożyliśmy w jej odbudowę. Konieczna musimy na coś postawić, ponieważ w przeciwnym razie ryzykujemy, że stracimy wszystko. Cokolwiek byśmy nie uznali za ważne, trzymajmy się tego. ', 'Trwam przy tym, co jest dla mnie ważne. Moja siła jest wynikiem tego, że żyję według moich wartości.'),
(294, '10-20', '20 października', 'Wolność wyboru\r\n', NULL, '„Narzucona moralność pozbawiona jest siły, którą otrzymujemy, gdy wybieramy życie duchowe.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW naszym czynnym uzależnieniu wielu z nas żyło na zasadzie przypadku. Nie byliśmy gotowi ani zdolni do podejmowania decyzji dotyczących naszego zachowania i postępowania. Być może nie potrafiliśmy nawet zdecydować się na miejsce zamieszkania. Pozwalaliśmy narkotykom lub otaczającym nas ludziom podejmować za nas najbardziej podstawowe decyzje dotyczące nas samych. Wolność od czynnego uzależnienia oznacza między innymi wolność w podejmowaniu samodzielnych decyzji. Wolność wyboru jest wspaniałym prezentem, ale jest również dużą odpowiedzialnością. Wolność ta pozwala nam odkryć kim jesteśmy i w co wierzymy. Jednakże, korzystając z niej, jesteśmy wzywani do tego, by rozważyć nasze decyzje i zaakceptować ich konsekwencje. To z kolei powoduje, że niektórzy z nas szukają kogoś, kto, tak samo jak czyniła to nasza choroba w czasie, gdy braliśmy, podejmowałby za nas decyzje. Nie jest to jednak zdrowieniem. Czym innym jest pytanie innych osób o ich doświadczenia, a czym innym przenoszenie na drugie osoby odpowiedzialności. Jeżeli nie będziemy korzystać z prezentu, jakim jest wolność, jeżeli odrzucimy zaakceptowanie odpowiedzialności, która jest związana z tą wolnością, stracimy nasz prezent i nasze życie będzie ograniczone. Jesteśmy odpowiedzialni za nasze własne zdrowienie i za nasze własne decyzje. Nawet, jeśli ciężko nam to przychodzi, musimy podejmować decyzje i być gotowi na zaakceptowanie ich konsekwencji.', 'Jestem wdzięczny za wolność, dzięki której mogę żyć w taki sposób, na jaki się zdecyduję. Dzisiaj zaakceptuję odpowiedzialność za moje zdrowienie, podejmę własne decyzje i zaakceptuję ich konsekwencje.'),
(295, '10-21', '21 października', 'Wola Boga na dziś', NULL, '„Decyzja ta wymaga trwałej akceptacji, wciąż rosnącej wiary i codziennego zaangażowania w zdrowienie.”  \r\n\r\n~IP nr 14\r\n\r\nCzasami naprawdę udaje nam się żyć według Kroku Trzeciego - i to jest wspaniałe! Nie żałujemy naszej przeszłości, nie boimy się  przyszłości i jesteśmy całkowicie zadowoleni z teraźniejszości. Czasem jednak gubimy wizję woli bożej w naszym życiu. Wielu z nas marzy o tym, aby wymazać błędy z przeszłości, jednak przeszłości nie da się wymazać. Wielu z nas odczuwa wdzięczność, że tak jest, ponieważ nasze doświadczenia z przeszłości przyprowadziły nas do zdrowienia, którym się dzisiaj cieszymy. Pracując nad programem, możemy się nauczyć akceptacji przeszłości i możemy się z nią pogodzić, naprawiając nasze błędy. Dwanaście Kroków może nam też pomóc w pozbyciu się troski o przyszłość. Jeśli codziennie praktykujemy zasady NA we wszystkich naszych poczynaniach, możemy pozostawić rezultaty tych działań naszej Sile Wyższej. Wydaje się, że to ci spośród naszych członków posiadają najmocniejszą wiarę, którzy najlepiej potrafią żyć chwilą obecną. Radość, poczucie wartości, wdzięczność za jakość naszego życia - to rezultaty wiary w samo życie. Jeśli praktykujemy zasady programu, dzień dzisiejszy jest jedynym dniem, który jest nam potrzebny. ', 'Z dnia dzisiejszego wezmę wszystko, co najlepsze, a dzień wczorajszy i jutrzejszy powierzę opiece Boga. '),
(296, '10-22', '22 października', 'Zorientujmy się, kto do nas przemawia', NULL, '„Nasza choroba jest tak przebiegła, że potrafi wpędzić nas w sytuacje trudne do przewidzenia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJedni z nas mówią: „Moja choroba przemawia do mnie.” Inni mówią: „Moje myśli nie chcą się wyłączyć.” Jeszcze inni wciąż powtarzają o  „rozbieżnościach w świadomości” lub o „diable, który szepce nam do ucha”. Spójrzmy prawdzie w oczy: cierpimy na nieuleczalną chorobę, która nawet w zdrowieniu ma na nas nieustający wpływ. Nasza choroba sprawia, że mamy wypaczony obraz tego, co się dzieje w naszym życiu. Podpowiada nam, że nie powinniśmy analizować siebie, ponieważ to, co ujrzymy, może okazać się zbyt przerażające. Czasami mówi nam, że nie jesteśmy odpowiedzialni za siebie i za to, co robimy, innym zaś razem mówi nam, że wszystko, co się dzieje złego na świecie jest naszą winą. Nasza choroba używa różnych sztuczek, chcąc skłonić nas do tego, abyśmy jej uwierzyli. Program NA daje nam do dyspozycji wiele głosów, które przeciwstawiają się naszej chorobie, głosów, którym możemy zaufać. Możemy zadzwonić do naszego sponsora i poprosić go o realną ocenę danej sytuacji. Możemy posłuchać głosu uzależnionego, który stara się zachować czystość. Najlepszym jednak rozwiązaniem jest praca nad krokami i czerpanie siły od Siły Wyższej. To przeprowadzi nas przez okresy, w których „przemawia do nas nasza choroba”.', 'Zignoruję „głosy” mojej choroby. Będę słuchać głosu mojego programu i Siły, która jest większa ode mnie. '),
(297, '10-23', '23 października', 'Poddanie się\r\n', NULL, '„Rezygnując z kontroli, otrzymujemy dużo większą siłę.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy braliśmy, robiliśmy wszystko, aby sprawy toczyły się tak, jak my tego chcieliśmy. Próbowaliśmy wszelkich możliwych sposobów, by panować podporządkować sobie nasz świat. Jeżeli dostawaliśmy to, czego chcieliśmy, czuliśmy się pełni władzy i niezwyciężeni; a jeżeli tego nie dostawaliśmy, to czuliśmy się zranieni i pokonani. Nic jednak nie mogło nas powstrzymać - wciąż coraz więcej wysiłku wkładaliśmy w to, by poprzez kontrolę i manipulacje podporządkować sobie życie. Poprzez wymyślanie coraz to nowszych sposobów kontroli próbowaliśmy zaprzeczyć naszej bezsilności. Dopóki udawało się nam zwodzić siebie swoimi planami, mogliśmy odsunąć od siebie uznanie faktu, że straciliśmy kontrolę. Stopniowo uświadamialiśmy sobie, że życie wymknęło się nam spod kontroli i żadne kombinacje ani manipulacje nie są w stanie przywrócić mu porządku. Gdy uznajemy naszą bezsilność, rezygnujemy z prób kontrolowania swojego życia i kierowania nim na swój własny sposób - poddajemy się. Nie posiadając wystarczająco dużo własnej siły, szukamy Siły większej od nas samych. Potrzebując wsparcia i przewodnictwa, prosimy tę Siłę, aby wzięła pod opiekę naszą wolę i nasze życie. Zamiast próbować żyć według własnego programu, prosimy innych zdrowiejących uzależnionych, aby dzielili się z nami swoimi doświadczeniami z życia programem NA. Siła i wskazówki których szukamy, znajdują się wokół nas; aby je znaleźć, wystarczy tylko przestać koncentrować się na sobie. ', 'Zaniecham prób podporządkowania sobie życia drogą kombinacji i manipulacji. Poprzez program NA powierzę moje życie opiece mojej Siły Wyższej.'),
(298, '10-24', '24 października', 'Odpowiedzialność', NULL, '„Nie jesteśmy odpowiedzialni za naszą chorobę, lecz jedynie za nasze zdrowienie. Gdy zaczynamy stosować to, czego się nauczyliśmy, nasze życie zaczyna zmieniać się na lepsze.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nIm głębiej wchodzimy w program, tym rzadziej unikamy odpowiedzialności za siebie i za nasze działanie. Stosując zasady Anonimowych Narkomanów, jesteśmy w stanie  zmienić swoje życie. Nasza egzystencja nabiera innego znaczenia, kiedy akceptujemy odpowiedzialność i wolność wyboru zakładaną przez pojęcie odpowiedzialności. Nie przyjmujemy naszego zdrowienia za coś  oczywistego. Bierzemy odpowiedzialność za nasze zdrowienie, pracując nad Dwunastoma Krokami ze sponsorem. Chodzimy regularnie na mityngi i dzielimy się z nowoprzybyłymi tym, co było nam tutaj za darmo dane: darem zdrowienia. Angażujemy się w nasza grupę domową i akceptujemy odpowiedzialność za swój udział w dzieleniu się zdrowieniem z wciąż jeszcze cierpiącymi uzależnionymi. W miarę naszej nauki efektywnego stosowania duchowych zasad we wszystkich sferach naszego życia, jakość naszego życia poprawia się. ', 'Korzystając z duchowych narzędzi zdobytych w zdrowieniu, jestem gotowy i zdolny do podjęcia odpowiedzialnych decyzji.'),
(299, '10-25', '25 października', 'Zasady przed osobistymi ambicjami\r\n', NULL, '„Anonimowość jest duchową podstawą wszystkich naszych tradycji, przypominając nam zawsze o pierwszeństwie zasad przed osobistymi ambicjami.”  \r\n\r\n~Tradycja Dwunasta  \r\n\r\n„Zasady przed osobistymi ambicjami”. Wielu z nas, za każdym razem, gdy czytane są nasze Tradycje, powtarza te słowa za czytającym. Choć słowa te stały się w pewnym sensie frazesem, nie oznacza to, że są przez to mniej ważne w służbie czy w naszym życiu. Słowa te są potwierdzeniem następującego zdania: „Słuchamy naszego sumienia i robimy to, co słuszne, bez względu na to, kogo by to nie dotyczyło”. Zasada ta jest kamieniem węgielnym zarówno naszego zdrowienia, jak i naszych tradycji. Co tak naprawdę znaczy: „zasady przed osobistymi ambicjami”? Znaczy to, że praktykujemy uczciwość, pokorę, współczucie, tolerancję i cierpliwość wobec wszystkich osób, bez względu na to, czy ich lubimy, czy też nie. Stawianie zasad przed osobistymi ambicjami uczy nas traktowania wszystkich równo. Dwunasty Krok wzywa nas do stosowania zasad programu we wszystkich naszych poczynaniach; Dwunasta Tradycja sugeruje, żeby je stosować we wszystkich naszych relacjach z ludźmi. Praktykowanie zasad nie powinno kończyć się na relacjach z naszymi przyjaciółmi lub w chwili wyjścia z mityngu. Powinniśmy je praktykować na co dzień, wobec każdego i we wszystkich sferach naszego życia. ', 'Będę słuchać sumienia i robić to, co słuszne. Skupię się na zasadach, a nie na osobistych ambicjach.'),
(300, '10-26', '26 października', 'Droga do samoakceptacji\r\n', NULL, '„Najskuteczniejszym sposobem osiągnięcia samoakceptacji jest stosowanie Dwunastu Kroków zdrowienia.”  \r\n\r\n~IP nr 19 \r\n\r\nDla wielu z nas uzależnienie było źródłem wstydu. Ukrywaliśmy się przed innymi, ponieważ byliśmy pewni, że zostaniemy odrzuceni, jeśli ktokolwiek odkryje, kim naprawdę jesteśmy. NA pomaga nam uczyć się samoakceptacji. Wielu z nas odnalazło ogromne wsparcie poprzez samo tylko uczestniczenie w mityngach, poprzez słuchanie innych uzależnionych ze wspólnoty, dzielących się swoimi historiami i poprzez odkrywanie tego, że inni czuli w stosunku do siebie to samo, co my. Kiedy inni szczerze dzielą się z nami tym, kim są, czujemy, że możemy zrobić to samo. Ucząc się mówić prawdę o sobie, uczymy się akceptować siebie. Powiedzenie prawdy o sobie jest jednak tylko początkiem. Jeżeli już podzieliliśmy się sprawami, które powodują, że czujemy się z naszym życiem niekomfortowo, to musimy znaleźć nowy sposób na życie - i tu właśnie wkraczają kroki. Rozwijamy pojęcie Siły Wyższej. Robimy szczegółowy obrachunek naszego życia i omawiamy go ze sponsorem. Prosimy Boga, jakkolwiek go pojmujemy, aby usunął nasze wady charakteru i te braki, które są źródłem naszych problemów. Bierzemy odpowiedzialność za to, co zrobiliśmy i dokonujemy za nie zadośćuczynienia. Wszystko to wcielamy w nasze codzienne życie i \"stosujemy te zasady we wszystkich sferach naszego życia\". Poprzez pracę nad krokami możemy stać się ludźmi, z których będziemy dumni. Bez obaw możemy powiedzieć prawdę o sobie, ponieważ nie mamy nic do ukrycia. ', 'Będę kroczyć drogą do samoakceptacji. Wyjdę do ludzi, będę mówić prawdę i będę pracować nad krokami.'),
(301, '10-27', '27 października', 'Wybierając życie\r\n', NULL, '„Zmiana autodestrukcyjnego stylu życia stała się koniecznością.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzynne uzależnienie jest nieustającym pragnieniem śmierci. Każdy z nas igrał ze śmiercią za każdym razem, gdy zażywaliśmy narkotyk. Nasz styl życia także wystawiał nas na ryzyko. Życie uzależnionego jest sprzedawane za grosze każdego dnia, w każdej działce. W zdrowieniu, pierwszym zachowaniem, które zmieniamy, jest nawyk zażywania. Pozostawanie czystym jest początkiem podróży w głąb życia. Jednakże nasze autodestrukcyjne zachowania zwykle sięgały daleko głębiej poza nasze zażywanie. Nawet w zdrowieniu możemy nadal traktować siebie tak, jakbyśmy byli nic nie warci. Gdy traktujemy siebie źle, źle się czujemy. A gdy źle się czujemy, szukamy ulgi - być może nawet w naszym starym rozwiązaniu, jakim są narkotyki. Wybranie zdrowienia oznacza wybranie życia. Każdego dnia podejmujemy decyzję, że chcemy żyć i być wolni. Za każdym razem, gdy unikamy autodestrukcyjnych zachowań, wybieramy zdrowienie.  ', 'Postawię na życie, wybierając zdrowienie. Zatroszczę się o siebie samego.'),
(302, '10-28', '28 października', 'Postawy\r\n', NULL, '„Kroków możemy używać również do tego, aby ulepszyć nasze postawy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy zdarzają się wam takie dni, kiedy wszystko wydaje się obracać przeciwko wam? Czy przeżywacie okresy, w których oceniając innych ludzi, ledwo jesteście w stanie znieść sami siebie? Jak się czujecie, gdy przyłapujecie siebie na tym, że bezpodstawnie wydzieracie się na swoich kolegów z pracy lub na ukochane osoby? Gdy zorientujemy się, że znajdujemy się w tak kiepskim stanie, musimy zacząć działać. Możemy w ciągu dnia w każdej chwili poświęcić trochę czasu na błyskawiczne podsumowanie sytuacji. Analizujemy swoje reakcje na zewnętrzne bodźce i na innych ludzi. W ten sposób możemy odkryć, że cierpimy z powodu zwykłych starych „złych postaw”. Negatywna postawa może szkodzić naszej relacji z Siłą Wyższą i z innymi ludźmi. Kiedy jesteśmy uczciwi wobec siebie, często zauważamy, że problem tkwi w nas i w naszej postawie. Nie mamy żadnej kontroli nad wyzwaniami, które przynosi nam życie. Ale możemy mieć kontrolę nad tym, jak reagujemy na te wyzwania. Możemy w każdej chwili zmienić nasze postawy. Jedyne, co zmienia się dzięki NA, to my sami. Dwanaście Kroków daje nam narzędzia do tego, żeby nas wyciągnąć z problemu i pchnąć w kierunku rozwiązania.', 'W ciągu dnia przyjrzę się swoim postawom. Aby je ulepszyć, użyję kroków.'),
(303, '10-29', '29 października', 'Właśnie dzisiaj\r\n', NULL, '„Życie jednym dniem, właśnie dzisiaj, uwalnia nas od ciężaru przeszłości i strachu przed przyszłością.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nMyślenie o tym, jak było źle lub jak mogło być źle w przeszłości może pozbawić nas nadziei na zdrowienie. Fantazje na temat tego, jak  wspaniale było lub mogłoby być mogą odwodzić nas od działania w świecie rzeczywistym. Dlatego w NA mówimy o życiu i zdrowieniu „właśnie dzisiaj”. W NA wiemy, że możemy się zmienić. Uwierzyliśmy, że nasza Siła Wyższa może przywrócić zdrowie naszego umysłu i serca. Zgliszcza naszej przeszłości możemy sprzątnąć, pracując nad krokami. Dbając o nasze zdrowienie - właśnie dzisiaj - możemy uniknąć stwarzania problemów w przyszłości. Życie w zdrowieniu, to nie fantazja. Fantazjowanie o tym, jak wspaniałe było branie lub o tym, jak moglibyśmy z powodzeniem brać w przyszłości, złudzenia o tym, jak wspaniałe mogą być narkotyki, przesadzone oczekiwania, które narażają nas na rozczarowania i powrót do czynnego uzależnienia - wszystko to traci swoją moc dzięki programowi. Poszukujemy woli Boga, a nie naszej własnej. Próbujemy służyć innym, a nie sobie. Nasza obsesja na własnym punkcie znika i nie jest już ważne to, jak wspaniale mogłoby być lub być powinno. W świetle zdrowienia rozpoznajemy różnicę pomiędzy fantazją a rzeczywistością. ', 'Jestem wdzięczny za zasady zdrowienia i nową rzeczywistość, którą one mi dały.'),
(304, '10-30', '30 października', 'Odwaga', NULL, '„W przyszłości, nasza na nowo odnaleziona wiara będzie tworzyć solidną podstawę naszej odwagi.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNA nie jest dla tchórzy! Nie zawsze jest łatwo żyć życiem na warunkach, jakie ono stawia. Zdrowienie wymaga czegoś więcej niż tylko ciężkiej pracy, wymaga również dość sporej odwagi. Czym jest w ogóle odwaga? Szybkie spojrzenie w słownik da nam odpowiedź. Wykazujemy się odwagą, gdy pomimo świadomości tego, że czeka nas coś, co postrzegamy jako trudne, niebezpieczne lub bolesne, robimy to, zamiast się wycofać. Mieć odwagę - znaczy być dzielnym, mieć cel, mieć wizję. Czym więc w istocie jest odwaga? Odwaga jest postawą, postawą wytrwałości. Wytrwałość jest tym, czego uzależnieni naprawdę potrzebują. Zobowiązujemy się do trzymania się programu i nie zażywania  narkotyków - bez względu na to, co by się nie działo. Odważni uzależnieni, to uzależnieni, którzy nie biorą narkotyków, tylko przez jeden dzień, bez względu na okoliczności. A co daje nam odwagę? Relacja z Siłą Wyższą daje nam siłę do tego, abyśmy mogli pozostać czyści. Wiemy, że tak długo, jak długo jesteśmy pod opieką Boga, mamy wystarczającą siłę, aby żyć życiem na warunkach, jakie ono stawia.', 'Mam Siłę Wyższą, która troszczy się o mnie bez względu na okoliczności. Mając tego świadomość, postaram się dzisiaj o postawę pełną odwagi.'),
(305, '10-31', '31 października', 'Nasza relacja z Siłą Wyższą\r\n', NULL, '„Postępujące zdrowienie zależy od naszej relacji z kochającym Bogiem, który się o nas troszczy i robi dla nas to, czego my nie potrafimy zrobić dla samych siebie.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPraca nad Dwunastoma Krokami NA pozwala nam ponownie wystartować i daje określone wskazówki na życie tym świecie. Kroki są jednak czymś więcej niż tylko nowym początkiem. Gdy pracujemy nad krokami na tyle dobrze, na ile potrafimy, rozwijamy relację z naszą osobistą Siłą Wyższą. W Kroku Trzecim decydujemy się na to, aby pozwolić kochającemu Bogu mieć wpływ na nasze życie. Dużo odwagi, zaufania i gotowości, których potrzebujemy, aby kontynuować pracę nad kolejnymi krokami, pochodzi właśnie z tej decyzji. W Kroku Siódmym idziemy nawet dalej, prosząc naszą Siłę Wyższą, aby zmieniła nasze życie. Krok Jedenasty jest dla nas drogą do pogłębiania tej relacji. Zdrowienie jest procesem wzrostu i zmiany, dzięki którym nasze życie zostaje odnowione. Dwanaście Kroków to drogowskazy, szczegółowe wskazówki, których używamy w określonej kolejności, by kontynuować zdrowienie. Lecz wsparcie, którego potrzebujemy, aby przystąpić do każdego kolejnego kroku, pochodzi od naszej Siły Wyższej i z wiary w to, że wszystko będzie dobrze. Wiara daje nam odwagę do działania. Każdy krok, nad którym pracujemy, wspierany jest naszą relacją z kochającym Bogiem. ', 'Będę pamiętać o tym, że źródłem mojej odwagi i gotowości jest relacja z moją Siłą Wyższą.'),
(306, '11-01', '1 listopada', 'Przebudzenie\r\n', NULL, '„Bóg pomaga nam, jeśli pomagamy sobie nawzajem.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nNasze uzależnienie powodowało, że myśleliśmy wyłącznie o sobie. Nawet nasze modlitwy, jeżeli w ogóle się modliliśmy, dotyczyły głównie nas samych. Prosiliśmy Boga, aby rozwiązał nasze problemy, lub żeby pomógł nam w trudnościach. Dlaczego? Dlatego, że nie chcieliśmy żyć z problemami, których sami sobie przysporzyliśmy. Byliśmy wobec nich bezbronni. Myśleliśmy, że w życiu chodzi wyłącznie o to, żeby dostawać i chcieliśmy dostawać coraz więcej. W zdrowieniu, faktycznie dostajemy więcej - więcej niż tylko samą abstynencję. Duchowe przebudzenie, którego doznajemy w pracy nad Dwunastoma Krokami, otwiera przed nami życie, o jakim nawet nie marzyliśmy. Nie musimy już troszczyć się o to, czy nam „wystarczy”, ponieważ w coraz większym stopniu zdajemy się na Siłę Wyższą, która zaspokaja wszystkie nasze codzienne potrzeby. Wolni od naszej ciągłej niepewności już nie postrzegamy świata wyłącznie, jako miejsca, w którym musimy walczyć z innymi o zaspokojenie wszystkich naszych życzeń. Zamiast tego, widzimy świat, jako miejsce, w którym żyjemy miłością ukazaną nam przez Siłę Wyższą. W naszych modlitwach nie prosimy już o natychmiastowe zaspokojenie naszych potrzeb, lecz o pomoc w pomaganiu sobie nawzajem. Zdrowienie budzi nas z koszmaru egocentryzmu, konfliktów i niepewności, które są rdzeniem naszego uzależnienia. Wszystko to, co jest dla nas cenne, możemy zachować jedynie poprzez przekazywanie tego innym.', 'Mój Bóg pomaga mi, jeśli ja pomagam innym. Dziś poszukam pomocy w przekazywaniu innym miłości, którą dostałem od mojej Siły Wyższej, wiedząc, że jest to droga do jej zachowania.'),
(307, '11-02', '2 listopada', 'Życie z nierozwiązanymi problemami', NULL, '„Ważne jest, by mieć przyjaciół, którzy się martwią, kiedy coś nas boli.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWiększość naszych problemów ma proste rozwiązanie. Dzwonimy do naszego sponsora, modlimy się, pracujemy nad krokami i chodzimy na mityngi. Ale co mamy zrobić w sytuacji, gdy jakieś problemy ciągną się od dłuższego czasu i nie widać ich końca? Większość z nas wie, jak to jest żyć w sytuacji pełnej cierpienia - z problemami, które po prostu nie chcą zniknąć. Dla niektórych z nas problemem takim może być jakaś nieuleczalna, śmiertelna choroba. Niektórzy mają wychowawcze problemy z dziećmi. Niektórym z nas nie udaje się zarobić pieniędzy na pokrycie koszów utrzymania. Ktoś inny opiekuje się obłożnie chorym przyjacielem lub członkiem rodziny. Ci z nas, którzy już kiedyś musieli żyć z jakimś nierozwiązanym problemem, znają to uczucie ulgi, które przynosi zwykła rozmowa o naszych problemach ze zdrowiejącymi przyjaciółmi. Być może ulgę przynosi nam czyjeś poczucie humoru i trochę wspólnego śmiechu. Nasi przyjaciele mogą również wyrazić nam swoje współczucie lub popłakać razem z nami. Cokolwiek robią, przynoszą nam ulgę w naszym cierpieniu. Być może nasi przyjaciele nie są w stanie rozwiązać naszych problemów ani zabrać nam bólu, lecz poprzez samą świadomość tego, że jesteśmy kochani, i że innym na nas zależy, nasze problemy stają się łatwiejszymi do zniesienia. Nie musimy już nigdy pozostawać sami z naszym bólem.', 'Problemy, których nie mogę rozwiązać, mogę lepiej znieść, jeśli porozmawiam o nich z moimi przyjaciółmi. Dzisiaj zadzwonię do kogoś, komu na mnie zależy.'),
(308, '11-03', '3 listopada', 'Bez względu na to, co się dzieje\r\n', NULL, '„Wcześniej czy później będziemy musieli stanąć na własnych nogach i skonfrontować się z realnym życiem, dlaczego więc nie zrobić tego na samym początku.”  \r\n\r\n~Tekst Podstawowy   \r\n\r\nNiektórzy z nas uważają, że powinniśmy chronić nowoprzybyłych, mówiąc im, że wcześniej wszystko było okropne, a teraz w zdrowieniu wszystko jest cudowne. Wydaje nam się, że prawdopodobnie odstraszylibyśmy ich, opowiadając im o bólu i trudnościach, o rozwiedzionych małżeństwach, o włamaniu do naszego mieszkania i podobnych rzeczach. Ze szczerej chęci niesienia posłania mamy tendencję, by opowiadać z entuzjazmem tylko o tym, co nam w życiu układa się dobrze. Jednak większość nowoprzybyłych domyśla się prawdy, nawet, jeśli są oni czyści zaledwie od kilku dni. Prawdopodobnie realia życiowe, które przeżywa przeciętny nowoprzybyły niosą o wiele więcej stresów niż te, z którymi na co dzień styka się przeciętny weteran. Jeżeli jednak uda nam się przekonać nowoprzybyłego, że w zdrowieniu wszystko jest różowe, to lepiej byśmy byli pewni, że będziemy mogli wspierać tego nowoprzybyłego, jeśli w jego lub jej życiu będzie działo się coś złego. Być może powinniśmy po prostu dzielić się tym, jak wykorzystujemy środki NA do tego, aby zaakceptować realne życie, bez względu na to, jakie ono stawia nam warunki w danym dniu. Zdrowienie i samo życie zawierają w sobie ból i radość w jednakowych proporcjach. Powinniśmy dzielić się jednym i drugim, żeby nowoprzybyli wiedzieli, że pozostajemy czyści bez względu na to, co by się nie działo.', 'Będę uczciwy wobec nowoprzybyłych, z którymi się dzielę i powiem im, że nie muszę brać narkotyków bez względu na to, co niesie życie.'),
(309, '11-04', '4 listopada', 'Kochać i być kochanym\r\n', NULL, '„…dajemy miłość, ponieważ została ona nam tak hojnie darowana. Gdy uczymy się kochać, otwierają się przed nami nowe przestworza. Miłość może być strumieniem energii życiowej płynącym od jednego człowieka do drugiego.„  \r\n\r\n~Tekst Podstawowy  \r\n\r\nDawanie miłości i otrzymywanie miłości stanowi esencję życia. Miłość jest wspólnym dla wszystkich mianownikiem, który łączy nas z innymi ludźmi. Uzależnienie pozbawiło nas tej relacji i uwięziło w samych sobie. Miłość, którą odnajdujemy w programie NA, ponownie otwiera przed nami świat. To ona otwiera klatkę uzależnienia, w której jesteśmy uwięzieni. Poprzez miłość, którą dają nam inni członkowie NA, dowiadujemy się, być może po raz pierwszy, czym jest miłość i czego może ona dokonać. Słyszymy, jak inni członkowie NA mówią o dzieleniu się miłością i czujemy, jaką wartość nadaje to ich życiu. Zaczynamy przypuszczać, że skoro dawanie i otrzymywanie miłości ma tak wielkie znaczenie dla innych, może nada to również sens naszemu życiu. Czujemy, że stoimy u progu wielkiego odkrycia, jednak czujemy również, że nie będziemy w stanie w pełni pojąć znaczenia miłości, póki sami nie zaczniemy jej dawać innym. Próbujemy tego i odkrywamy brakującą więź między nami i światem. Dziś, uświadamiamy sobie, że to, co oni mówili było prawdą: „Możemy zachować to, co mamy, jedynie poprzez dzielenie się tym z innymi.”', 'Życie jest dla mnie nową przestrzenią, a środkiem do jej zbadania jest miłość. Będę hojnie rozdawać miłość, którą otrzymałem.'),
(310, '11-05', '5 listopada', 'Boże przewodnictwo\r\n', NULL, '„Nasza Siła Wyższa jest dla nas dostępna przez cały czas. Gdy prosimy o objawienie woli Boga wobec nas, otrzymujemy przewodnictwo.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPodjęcie słusznej decyzji nie zawsze jest łatwe. Zwłaszcza dla uzależnionych, którzy po raz pierwszy uczą się żyć duchowymi zasadami Programu. W uzależnieniu rozwinęliśmy autodestrukcyjne i antyspołeczne odruchy. W sytuacjach konfliktowych kierowaliśmy się tymi negatywnymi odruchami. Nasza choroba nie przygotowała nas do podejmowania rozsądnych decyzji. Dzisiaj prosimy Siłę Wyższą o wskazanie nam właściwej drogi. Zatrzymujemy się, modlimy się i w ciszy wsłuchujemy się w głos przewodnictwa, który jest wewnątrz nas. Uwierzyliśmy, ze możemy polegać na Sile większej od nas samych. Ta Siła jest dla nas dostępna, kiedy tylko jej potrzebujemy. Jedyna rzeczą, jaką musimy zrobić, jest modlitwa o poznanie Bożej woli wobec nas oraz o siłę do jej spełnienia. Za każdym razem, gdy to robimy, znajdujemy właściwą drogę pośród naszego chaosu i nasza wiara wzrasta. Im bardziej polegamy na Sile Wyższej, tym łatwiej jest pytać o przewodnictwo. Znaleźliśmy Siłę, którą straciliśmy w naszym uzależnieniu, Siłę, która jest dla nas zawsze dostępna. Chcąc znaleźć wskazówki, niezbędne nam do tego, by żyć pełnią życia i wzrastać duchowo, musimy tylko utrzymywać kontakt z Bogiem, jakkolwiek go pojmujemy.', 'Moja Siła Wyższa jest moim wewnętrznym źródłem duchowego przewodnictwa, z którego zawsze mogę czerpać. Jeśli dziś zgubię kierunek, poproszę o poznanie woli mojej Siły Wyższej.'),
(311, '11-06', '6 listopada', 'Rozumienie pokory\r\n', NULL, '„Pokora jest wynikiem uczciwości wobec siebie\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPokora była dla większości z nas pojęciem na tyle obcym, że ignorowaliśmy ją tak długo, jak tylko było to możliwe. Gdy po raz pierwszy zobaczyliśmy w Kroku Siódmym słowo \"pokornie\", podejrzewaliśmy, że oznacza to czekające nas upokorzenie. Być może sprawdziliśmy to słowo w słowniku, lecz definicja jeszcze bardziej zbiła nas z tropu. Nie rozumieliśmy co skromność i służba mogą mieć wspólnego ze zdrowieniem. Bycie pokornym nie oznacza wcale, że jesteśmy najniższą formą życia. Wręcz przeciwnie - stanie się pokornym oznacza zdobycie realnej oceny samego siebie i swojego miejsca w świecie. Dorastamy do świadomości opartej na akceptacji wszystkich aspektów naszego życia. Nie zaprzeczamy naszym zaletom i nie przerysowujemy naszych wad. Uczciwie akceptujemy siebie takimi, jakimi jesteśmy. Nikt z nas nie osiągnie nigdy stanu doskonałej pokory. Natomiast, możemy oczywiście dążyć do tego, by uczciwie przyznać się do naszych niedoskonałości, zaakceptować nasze zalety i polegać na naszej Sile Wyższej, jako źródle mocy. Pokora nie oznacza wcale, że mamy czołgać się po naszej drodze życia na czworakach, oznacza ona jedynie, że musimy przyznać, że nie jesteśmy w stanie zdrowieć o własnych siłach. Potrzebujemy się nawzajem, a ponad wszystko potrzebujemy mocy kochającego Boga. ', 'Aby być pokornym, uczciwie zaakceptuję całą prawdę o sobie, dostrzegając moje faktyczne miejsce w świecie. By starczyło mi sił, potrzebnych do zajęcia tego miejsca, będę polegać na Bogu, jakkolwiek go pojmuję.'),
(312, '11-07', '7 listopada', 'Czując wolę Boga\r\n', NULL, '„Szczerze wierzę, że Siła Wyższa może przywrócić mi zdrowie duchowe, i że mogę zaprzestać prób dochodzenia woli bożej, przyjmując po prostu rzeczy takimi, jakie one są i będąc za nie wdzięcznym.\"  \r\n\r\n~Tekst Podstawowy ( Historie Osobiste)  \r\n\r\nIm dłużej jesteśmy czyści, tym mniej jesteśmy pewni naszej „wiedzy” na temat tego, jakie są wobec nas plany naszej Siły Wyższej i tym mniej ważne się to staje. Rozpoznawanie woli Siły Wyższej staje się mniej „wiedzą”, a bardziej „odczuciem.” Wciąż sumiennie praktykujemy Krok Jedenasty. Zamiast jednak wypatrywać znaków od naszej Siły Wyższej, zaczynamy polegać na naszej intuicji i zawierzać naszym uczuciom dotyczącym tego, co przyniesie nam więcej korzyści. Po kilku latach czystości prawdopodobnie wiemy już kiedy postępujemy wbrew woli bożej. Kiedy działamy wbrew woli Boga, przychodzi to nieprzyjemne uczucie w brzuchu. Ten dyskomfort przestrzega nas, że jeśli pójdziemy dalej w tym kierunku, będzie nas czekało wiele bezsennych nocy. Musimy być uważni wobec tych odczuć, ponieważ są one znakiem tego, że nasze działanie jest sprzeczne z wolą Siły Wyższej wobec nas. Nasz Krok Jedenasty mówi jednoznacznie, o co faktycznie chodzi w modlitwie i medytacji. Chodzi o pogłębianie naszego świadomego kontaktu z Bogiem, jakkolwiek go pojmujemy, tak, abyśmy lepiej rozpoznawali jego wolę wobec nas i dostali siłę do jej spełnienia. Wolę Boga rozpoznajemy najlepiej nie poprzez „znaki” lub słowa, lecz poprzez odczucia - a to, co czujemy, jest prawdziwe.', 'Będę się modlić o to, aby poznać wolę mojej Siły Wyższej wobec mnie oraz o siłę do jej spełnienia. Będę zwracać uwagę na swoje uczucia i działać wtedy, gdy poczuję, że są one prawdziwe.');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(313, '11-08', '8 listopada', 'Uwolnieni od szaleństwa\r\n', NULL, '„Czy zdaję sobie sprawę z tego, że szaleństwem byłoby podejść do kogoś i powiedzieć: „Czy mógłby pan sprawić, abym dostał zawału serca lub uległ śmiertelnemu wypadkowi?”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJest takie powiedzenie, że jeżeli nie byliśmy zakochani, to nie możemy pamiętać czym jest miłość. To samo można powiedzieć o szaleństwie: gdy już raz zostaniemy od niego uwolnieni, możemy zapomnieć jak bardzo dziwne mogą być nasze szalone myśli. Aby jednak odczuwać wdzięczność za ten poziom równowagi wewnętrznej, który został nam przywrócony w NA, powinniśmy pamiętać, jak bardzo byliśmy szaleni. Dzisiaj może nam sprawić trudność wyobrażenie sobie kogoś, kto mówi coś podobnie absurdalnego jak: „Czy mógłby pan sprawić, abym dostał zawału serca lub uległ śmiertelnemu wypadkowi?” Nikt normalny nie poprosiłby o coś takiego. I o to właśnie chodzi. Gdy byliśmy czynnie uzależnieni, nie byliśmy normalni. Każdego dnia, gdy braliśmy, igraliśmy ze śmiertelną chorobą, ulegaliśmy degradacji, wyniszczeniu i wykorzystywaniu, mogliśmy zostać wtrąceni do więzienia lub ponieść śmierć na skutek przemocy lub nawet w wyniku zwykłej głupoty. W tym kontekście poproszenie kogoś o spowodowanie zawału serca bądź śmiertelnego wypadku nie brzmi aż tak dziwnie. Właśnie tacy szaleni byliśmy. Program, wspólnota i nasza Siła Wyższa, wzięte razem, dokonują cudu. Drugi Krok nie jest próżną nadzieją - jest prawdą. Będąc świadomi poziomu szaleństwa, jakiego doświadczyliśmy, możemy w większym stopniu docenić tę cudowną Siłę, która przywróciła nam równowagę wewnętrzną. Jesteśmy jej za to naprawdę wdzięczni.', 'Poświęcę trochę czasu na przypomnienie sobie, jak bardzo byłem szalony, gdy brałem narkotyki. Następnie podziękuję mojej Sile Wyższej za przywróconą mi równowagę wewnętrzną.'),
(314, '11-09', '9 listopada', 'Świetnie ułożone plany\r\n', NULL, '„Ważne są nasze działania. Efekty tych działań pozostawiamy naszej Sile Wyższej.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzasem, na mityngach słyszymy takie stare powiedzenie: „Jeżeli chcesz rozśmieszyć Boga, opowiedz mu o swoich planach”. Słysząc to,  zazwyczaj śmiejemy się, ale często jest to śmiech podszyty złością. Zastanawiamy się, czy wszystkie nasze misternie ułożone plany są z góry skazane na porażkę. Gdy planujemy duże wydarzenia - np. ślub, powrót do szkoły, zmianę pracy - zaczynamy zastanawiać się, czy nasze plany są zgodne z planami naszej Siły Wyższej. Czasem zdarza się, że szukając odpowiedzi na to pytanie, zadręczamy się do takiego stopnia, że w ogóle rezygnujemy z planowania. Faktem jednak jest, że tak naprawdę nie wiemy, czy plany naszej Siły Wyższej dotyczące naszego życia są wyryte w kamieniu czy też nie. Większość z nas ma wyrobione zdanie na temat losu i przeznaczenia, ale bez względu na to, czy wierzymy w te teorie, czy nie, wciąż jesteśmy odpowiedzialni za nasze życie i za robienie planów na przyszłość. Jeżeli nie przyjmiemy odpowiedzialności za swoje życie, nadal będziemy robić plany - plany na płytką i nudną egzystencję. W zdrowieniu zajmujemy się planami, a nie rezultatami. Nigdy nie będziemy wiedzieć czy małżeństwo, wykształcenie lub nowa praca będą dla nas dobre, dopóki nie spróbujemy tego zrealizować. Po prostu kierujemy się zdrowym rozsądkiem, weryfikujemy swoje pomysły ze sponsorem, modlimy się, korzystamy z wszelkich dostępnych informacji i doświadczeń, które mamy i robimy najbardziej rozsądne plany, jakie potrafimy zrobić. Co do reszty, to ufamy opiece kochającego Boga, jakkolwiek Go pojmujemy, wierząc, że postąpiliśmy odpowiedzialnie.', 'Będę robić plany, ale nie będę planował rezultatów. Zaufam opiece mojej kochającej Siły Wyższej.'),
(315, '11-10', '10 listopada', 'Lęk czy wiara?', NULL, '„Jak daleko byśmy nie próbowali uciec, lęk zawsze nam towarzyszył.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPrzed przybyciem do wspólnoty Anonimowych Narkomanów dla wielu z nas lęk był wiernym towarzyszem życia. Braliśmy, ponieważ baliśmy się emocjonalnego lub fizycznego bólu. Strach przed ludźmi i sytuacjami był dla nas wygodną wymówką w braniu narkotyków. Niektórzy spośród nas tak bardzo się bali wszystkiego, że nie byli nawet w stanie wyjść z domu, jeżeli czegoś wcześniej nie zażyli. Gdy pozostajemy czyści, zastępujemy nasz lęk zaufaniem do wspólnoty, kroków i Siły Wyższej. W miarę wzrostu tego zaufania, nasza wiara w cud zdrowienia zaczyna dotykać wszystkich aspektów naszego życia. Zaczynamy postrzegać siebie w inny sposób. Uświadamiamy sobie, że jesteśmy istotami duchowymi i staramy się żyć w zgodzie z duchowymi zasadami. Zastosowanie zasad duchowych pomaga w wyeliminowaniu lęku z naszego życia. Gdy powstrzymujemy się od wyrządzenia innym ludziom krzywdy, nie musimy bać się tego, jak zostaniemy przez nich potraktowani. Gdy w relacjach z innymi kierujemy się miłością, współczuciem, zrozumieniem i cierpliwością, w zamian jesteśmy traktowani z szacunkiem i uwagą. Uświadamiamy sobie, że te pozytywne zmiany wynikają z tego, że pozwalamy naszej Sile Wyższej działać przez nas. Zaczynamy wierzyć - nie rozumieć, lecz wierzyć - że nasza Siła Wyższa chce naszego dobra. Odkrywamy, że bez względu na okoliczności możemy iść przez życie z wiarą zamiast z lękiem.', 'Już nie muszę pędzić ze strachem, lecz mogę kroczyć z wiarą w to, że moja Siła Wyższa ma dla mnie przygotowane tylko to, co najlepsze. '),
(316, '11-11', '11 listopada', 'Od poddania się do akceptacji\r\n', NULL, '„Spokojnie poddajemy się i pozwalamy Bogu, jakkolwiek go pojmujemy, zaopiekować się nami”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPoddanie się i akceptacja są jak zauroczenie i miłość. Zauroczenie zaczyna się wtedy, gdy spotykamy kogoś wyjątkowego. Zauroczenie nie wymaga niczego poza uznaniem obiektu naszego zauroczenia. Jednak trzeba włożyć sporo wysiłku, aby zauroczenie przeistoczyło się w miłość. Przeistoczenie się nowej znajomości w trwałą więź wymaga czasu i cierpliwości. To samo dotyczy poddania się i akceptacji. Poddajemy się, gdy uznajemy naszą bezsilność. Powoli zaczynamy wierzyć, że Siła większa od nas samych może otoczyć nas opieką, której potrzebujemy. Poddanie się przeistacza się w akceptację, gdy pozwalamy tej Sile działać w naszym życiu. Badamy samych siebie i pozwalamy, aby nasz Bóg widział nas takimi, jakimi jesteśmy. Pozwalając Bogu, jakkolwiek Go pojmujemy, przeniknąć w głąb nas, przyjmujemy więcej Jego opieki. Prosimy tę Siłę, aby uwolniła nas od naszych wad charakteru i pomogła nam zadośćuczynić osobom, które skrzywdziliśmy. Potem podążamy nową drogą życia, pogłębiając świadomy kontakt z naszą Siłą Wyższą i akceptując Jej ciągłą opiekę, przewodnictwo i siłę. Poddanie się, tak jak zauroczenie, może być początkiem związku na całe życie. Jednak, aby poddanie się przeistoczyło się w akceptację musimy pozwolić Bogu, jakkolwiek Go pojmujemy, opiekować się nami każdego dnia. ', 'Moje zdrowienie jest czymś więcej niż tylko zauroczeniem. Poddałem się. Dzisiaj będę pogłębiał świadomy kontakt z moją Siłą Wyższą i zaakceptuję Jej nieustającą opiekę nade mną.'),
(317, '11-12', '12 listopada', 'Nasza osobista historia\r\n', NULL, 'Kiedy uczciwie opowiadamy naszą historię, ktoś inny może się z nami utożsamić.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas słyszało fascynujących mówców na zlotach NA. Przypominamy sobie jak słuchacze oscylowali pomiędzy łzami identyfikacji a łzami radosnej pogody ducha. Być może myśleliśmy: „Pewnego dnia ja również zabiorę głos na głównym mityngu w czasie zlotu”. Dla wielu z nas ten dzień jeszcze nie nadszedł. Od czasu do czasu jesteśmy proszeni o wypowiedź na mityngu odbywającym się w naszej okolicy. Być może również zabieramy głos na warsztatach w czasie małych zlotów. Jednak wciąż jeszcze nie jesteśmy „gwiazdami zlotów NA” - i to jest OK. Nauczyliśmy się, że my również możemy się podzielić specjalnym posłaniem, nawet jeżeli jest to zwykły mityng, w którym uczestniczy piętnastu lub dwudziestu uzależnionych. Każdy ma do opowiedzenia tylko własną historię - nic więcej. Nie możemy opowiadać historii innych. Bardzo często, gdy wstajemy, by przemówić, stwierdzamy, że wyparowały nam z głowy wszystkie błyskotliwe kwestie i wesołe historie. Mamy jednak coś do zaoferowania. Niesiemy posłanie nadziei o tym, że możemy zdrowieć i faktycznie zdrowiejemy z naszego uzależnienia. I to wystarczy. ', 'Będę pamiętać, że to, co mogę zrobić najlepszego, to podzielić się uczciwie moją historią z innymi. Na obecną chwilę to wystarczy.'),
(318, '11-13', '13 listopada', 'Niedoskonali', NULL, '„Nie dążymy do doskonałości. Gdybyśmy byli doskonali, nie bylibyśmy ludźmi.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKażdy z nas miał jakieś oczekiwania wobec życia w zdrowieniu. Niektórzy z nas myśleli, że zdrowiejąc, od razu staniemy się ludźmi użytecznymi lub zdolnymi do robienia wszystkiego, czego tylko zapragniemy. A może wyobrażaliśmy sobie, że szybko zyskamy łatwość w kontaktach z innymi ludźmi. Jeśli przez chwilę spokojnie pomyślimy, to uświadomimy sobie, że oczekiwaliśmy od zdrowienia, iż uczyni ono nas ludźmi doskonałymi. Nie spodziewaliśmy się, że w dalszym ciągu będziemy popełniać błędy. Jednak wciąż je popełniamy. I nie jest to przejawem naszego uzależnienia, lecz naszego człowieczeństwa. W NA dążymy do zdrowienia, a nie do doskonałości. Jedyną obietnicą jest wolność od czynnego uzależnienia. Doskonałość jest stanem niedostępnym dla istot ludzkich; jest celem niemożliwym do osiągnięcia. W doskonałości najczęściej szukamy wolności od popełniania błędów i związanego z tym dyskomfortu. W zamian za tę wolność od dyskomfortu jesteśmy w stanie oddać naszą ciekawość, elastyczność i nasze pole do wzrostu. Możemy rozważyć następujący wybór: czy chcemy przeżyć resztę naszego życia w naszym małym, zorganizowanym światku, bezpieczni, lecz prawdopodobnie zdławieni? Czy tez może chcemy podjąć się podróży w nieznane, podjąć ryzyko i sięgnąć po wszystko, co życie ma do zaoferowania?', 'Chcę wszystkiego, co życie ma mi do zaoferowania i wszystkiego, co może dać zdrowienie. Dzisiaj, podejmę ryzyko, spróbuję czegoś nowego i wzrosnę.'),
(319, '11-14', '14 listopada', 'Nie tylko przetrwać\r\n', NULL, '„Kiedy braliśmy, nasze życie było szkołą przetrwania. Teraz, nasze działania ukierunkowane są bardziej na życie niż na przetrwanie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\n„Lepiej byłoby, gdybym umarł!” – to zdanie czynni uzależnieni powtarzają często nie bez powodu. Od przyszłości mogliśmy się spodziewać jedynie kontynuacji naszej marnej egzystencji. Wola życia była w nas bardzo słaba. Wciąż towarzyszył nam stan emocjonalnego rozkładu, duchowego upadku i przytłaczającej świadomości tego, że już nigdy nic się nie zmieni. Pozostało nam trochę nadziei i żadnego pomysłu na życie, które bezpowrotnie traciliśmy. Na wskrzeszenie naszych uczuć, duszy i zdrowia fizycznego trzeba czasu. Im więcej zdobywamy życiowego doświadczenia, zamiast jedynie egzystować, tym bardziej rozumiemy, jak drogocenne i wspaniałe może być życie. Podróżowanie, zabawy z małym dzieckiem, przeżywanie miłości, poszerzanie naszego duchowego horyzontu i budowanie relacji - to wszystko należy do niezliczonych rodzajów aktywności, które mówią, że: „ja żyję.” Odkrywamy tak wiele rzeczy, które cenimy całym sercem i jesteśmy wdzięczni za to, że dostaliśmy drugą szansę. Gdybyśmy umarli w czynnym uzależnieniu, bylibyśmy okrutnie ograbieni z tak wielu radości życia. Każdego dnia dziękujemy Sile większej od nas samych za kolejny czysty dzień i za kolejny dzień życia.', 'Jestem wdzięczny za to, że żyję. Dzisiaj zrobię coś, żeby to uczcić.'),
(320, '11-15', '15 listopada', 'Odpuścić sobie\r\n', NULL, '„Weź moją wolę i moje życie. Prowadź mnie w moim zdrowieniu. Pokaż mi jak żyć.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJak zaczynamy proces pozwalania naszej Sile Wyższej, aby kierowała naszym życiem? Gdy szukamy rady w sytuacjach, które przysparzają nam problemów, często stwierdzamy, że nasza Siła Wyższa działa przez innych. Akceptując fakt, że nie na wszystko mamy odpowiedź, otwieramy się na nowe możliwości. Gotowość do odpuszczenia sobie naszych utartych przekonań i opinii pozwala duchowemu przewodnictwu oświetlić naszą drogę. Czasami musimy dojść do całkowitej destrukcji, nim staniemy się gotowi, aby trudne sytuacje powierzać naszej Sile Wyższej. Frasobliwe knowania, walka, planowanie, martwienie się - to za mało. Natomiast, możemy być pewni, że jeżeli powierzymy nasze problemy Sile Wyższej, otrzymamy odpowiedź w wypowiedziach osób dzielących się swoim doświadczeniem lub w ciszy medytacji. Nie ma sensu żyć na skraju szaleństwa. Pędzenie przez życie, jakby się paliło, wyczerpuje nas i prowadzi do nikąd. Ostatecznie, sytuacja nie zmienia się, bez względu na to, jak bardzo staramy się manipulować. Jeśli odpuścimy sobie i pozwolimy na kontakt z Siłą Wyższą, odkryjemy najlepszą drogę postępowania. Możemy być pewni, że odpowiedzi, które mają duchową podstawę, są lepsze od jakichkolwiek odpowiedzi, które moglibyśmy wymyślić sami.', 'Odpuszczę sobie i pozwolę mojej Sile Wyższej kierować moim życiem.'),
(321, '11-16', '16 listopada', 'Nigdy więcej samotny\r\n', NULL, '„Stopniowo i ostrożnie wyciągamy siebie z izolacji i samotności uzależnienia i wciągamy się w główny nurt życia.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas podczas brania spędzało sporo czasu w samotności, za wszelką cenę unikając innych ludzi, szczególnie tych, którzy nie brali. Po latach izolacji nie zawsze jest łatwo znaleźć swoje miejsce w hałaśliwej, pełnej zgiełku wspólnocie. Być może dalej czujemy się samotni, koncentrując się na różnicach zamiast na podobieństwach. Przytłaczające uczucia, które często pojawiają się na początku zdrowienia - uczucie strachu, złości i braku zaufania - mogą nas izolować jeszcze bardziej. Być może czujemy się obco, ale musimy  pamiętać, że ta obcość pochodzi z nas, a nie od NA. W NA otrzymujemy niezwykłą okazję do nawiązywania przyjaźni. Spotykamy się z ludźmi, którzy rozumieją nas bardziej niż ktokolwiek inny. Jesteśmy zachęcani do tego, aby dzielić z tymi ludźmi nasze uczucia, problemy, triumfy i porażki. Powoli, uznanie i identyfikacja, którą znajdujemy w NA, budują mosty nad samotną przepaścią alienacji w naszym sercu. I tak jak słyszeliśmy, można powiedzieć, że program działa, jeżeli mu na to pozwolimy.', 'Przyjaźń z innymi członkami wspólnoty jest prezentem na całe życie. Przyjmę przyjaźń, którą oferuje mi NA i zaakceptuję ją.'),
(322, '11-17', '17 listopada', 'Przechodząc przez ból', NULL, '„Nie musimy już nigdy brać narkotyków, bez względu na to, jakbyśmy się nie czuli. Wszystkie uczucia, prędzej czy później, miną.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nBoli, jak nigdy dotąd. Wstajesz z łóżka po bezsennej nocy, rozmawiasz z Bogiem, jednak ciągle nie czujesz się lepiej. „To minie\" - mówi ci jakiś cichy głos. „Kiedy?\" - zastanawiasz się, idąc dalej, i, mamrocząc coś, kontynuujesz swój dzień. Popłakujesz w samochodzie i podkręcasz radio tak, by nie słyszeć własnych myśli. Jednak jedziesz prosto do pracy i nawet nie pomyślisz o tym, żeby wziąć narkotyki. Wydaje ci się, że wewnątrz ciebie wszystko płonie. A kiedy ból staje się nie do wytrzymania, wpadasz w odrętwienie i milkniesz. Idziesz na mityng i chciałbyś być tak szczęśliwy, jak szczęśliwi wydają się być inni. Ale nie wracasz do narkotyków. Płaczesz jeszcze bardziej i dzwonisz do swojego sponsora. Jedziesz do przyjaciela i nawet nie zauważasz, jakie piękno cię otacza, ponieważ wewnątrz ciebie jest tak ponuro. Prawdopodobnie po wizycie u przyjaciela nie czujesz się dużo lepiej, ale przynajmniej nie byłeś u swojego dealera. Słuchasz czyjegoś Piątego Kroku. Dzielisz się na mityngu. Spoglądasz w kalendarz i stwierdzasz, że przeżyłeś kolejny czysty dzień. Potem, któregoś dnia, budzisz się i stwierdzasz, że dzień jest piękny. Słońce świeci. Niebo jest błękitne. Oddychasz głęboko, uśmiechasz się znowu i wiesz, że to naprawdę minęło.', 'Bez względu na to, jak się dzisiaj czuję, będę kroczył dalej w moim zdrowieniu.'),
(323, '11-18', '18 listopada', 'Odkrywanie samego siebie\r\n', NULL, '„Dziesiąty Krok może pomóc nam w rozwiązaniu naszych życiowych problemów i zapobiec ich powtarzaniu się.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNasza tożsamość, czyli sposób w jaki myślimy i czujemy, ukształtowała się pod wpływem naszych doświadczeń. Niektóre spośród tych doświadczeń uczyniły z nas lepszych ludzi, inne zaś wywołują w nas wstyd i zakłopotanie, a całość wpłynęła na to, kim jesteśmy dzisiaj. Możemy skorzystać z wiedzy zdobytej w trakcie analizy naszych błędów i kierować się tą mądrością przy podejmowaniu dzisiejszych decyzji. Akceptacja siebie oznacza akceptowanie wszystkich aspektów nas samych - naszych zalet, naszych wad, naszych sukcesów i porażek. Poczucie wstydu i winy, pozostawione samym sobie, mogą nas sparaliżować i przeszkodzić naszemu rozwojowi. Jednym z najbardziej sensownych sposobów naprawienia popełnionych przez nas w przeszłości błędów może być po prostu to, że dzisiaj będziemy postępować w inny sposób. Dążymy do poprawy i mierzymy nasz sukces, porównując to, kim byliśmy w przeszłości, z tym, kim jesteśmy dzisiaj. Będąc ludźmi, będziemy nadal popełniać błędy; jednakże nie musimy popełniać wciąż tych samych błędów. Przyglądając się naszej przeszłości i zdając sobie sprawę z tego, że zmieniliśmy się i dorośliśmy, odnajdziemy nadzieję na przyszłość. Najlepsze jeszcze nadejdzie.', 'To, co mam dziś do zrobienia, zrobię najlepiej jak potrafię. Codziennie będę uczył się czegoś nowego, co pomoże mi w dniu jutrzejszym.'),
(324, '11-19', '19 listopada', 'Język empatii', NULL, '„... uzależniony odnajdzie tyle identyfikacji, ile mu potrzeba, aby przekonać się, że może pozostać czysty dzięki przykładowi innych, zdrowiejących od wielu lat.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas na naszym pierwszym mityngu, gdy nie byliśmy jeszcze do końca przekonani, że NA jest dla nas, znalazło sobie wiele rzeczy do skrytykowania. Wydawało nam się, że albo nikt nigdy nie cierpiał tak jak my, albo że my sami doświadczyliśmy za mało cierpienia. Jednak w miarę słuchania wypowiedzi innych, usłyszeliśmy nowy dla naszego ucha język, zrozumiały bez słów, sięgający swymi korzeniami uznania, zaufania i wiary - język empatii. Pragnąc przynależeć do tej społeczności,słuchaliśmy. Jeśli nauczymy się rozumieć i mówić językiem empatii, odnajdziemy potrzebną nam identyfikację. Aby zrozumieć ten specyficzny język, słuchamy sercem. Język empatii nie używa wielu słów; dociera do nas bardziej przez serce niż przez słuch. Nie jest to język kazań lub wykładów - jest to język serca. Może on dotrzeć do uzależnionego i poruszyć go bez jednego wypowiedzianego słowa. Umiejętność posługiwania się językiem empatii przychodzi do nas wraz z praktyką. Im bardziej posługujemy się nim w relacjach z drugim uzależnionym i Siłą Wyższą, tym bardziej go rozumiemy. Dzięki niemu wciąż wracamy na mityngi.', 'Będę słuchał sercem. Z każdym dniem będę poznawał coraz lepiej język empatii.'),
(325, '11-20', '20 listopada', 'Odnajdując spełnienie\r\n', NULL, '„Nie dążyliśmy ku spełnieniu; w naszym życiu dominowały przede wszystkim pustka i bezwartościowość.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy braliśmy, prawdopodobnie setki razy chcieliśmy być kimś innym. Być może pragnęliśmy zamienić się z kimś, kto miał ładniejszy samochód, większy dom, lepszą pracę lub atrakcyjniejszego partnera, czyli wszystko, czego nie mieliśmy my. Nasza frustracja była tak głęboka, że trudno nam sobie było wyobrazić kogoś, kto byłby w gorszej od nas sytuacji. W zdrowieniu, możemy zauważyć, że doświadczamy różnego rodzaju zawiści. Być może nadal porównujemy się z innymi i mamy uczucie, że wciąż jeszcze czegoś nam brakuje. Być może wydaje nam się, że każda z wypowiedzi innych uczestników mityngu, począwszy od nowoprzybyłego aż do osoby o najdłuższym stażu zdrowienia, brzmi lepiej od naszej. Być może myślimy, że wszyscy pracują nad jakimś lepszym programem, ponieważ mają lepsze samochody, większe domy, więcej pieniędzy itd. Proces zdrowienia, którego doświadczamy dzięki naszym Dwunastu Krokom, zaprowadzi nas od postawy zawiści i niskiego poczucia wartości do stanu duchowego spełnienia i głębokiego docenienia tego, co mamy. Stwierdzamy, że nigdy nie zamienilibyśmy się z innymi, ponieważ to, co odkryliśmy wewnątrz siebie, jest bezcenne.', 'W moim życiu jest wiele rzeczy, za które mogę być wdzięczny. Docenię duchowe spełnienie, które odnalazłem w zdrowieniu.'),
(326, '11-21', '21 listopada', 'Pozwolić naszym wadom odejść\r\n', NULL, '„Gdyby nasze wady charakteru przyczyniały się pozytywnie do naszego zdrowienia i szczęścia, nie mielibyśmy aż tak głębokich stanów depresyjnych”.  \r\n\r\n~Tekst podstawowy  \r\n\r\nRozpoczęcie Kroku Szóstego i Siódmego nie jest wcale łatwe. Może nam się wydawać, że z powodu tak wielu posiadanych przez nas wad jesteśmy jedną wielką chodzącą wadą. Być może czujemy się tak, jakbyśmy byli przywaleni wielkim kamieniem. Pod żadnym pozorem nie chcemy, by nasi przyjaciele ze wspólnoty zobaczyli jak bardzo jesteśmy wybrakowani. Prawdopodobnie przejdziemy przez okres, w którym będziemy kontrolować każde nasze słowo i wszystko, co robimy, po to, by zidentyfikować daną wadę charakteru i upewnić się czy udało się nam ją poskromić. Być może będziemy czuć ogromne zażenowanie i wstyd z powodu czegoś, co w przeszłości, w jakimś konkretnym dniu, powiedzieliśmy. Byliśmy zdeterminowani, by za wszelką cenę uwolnić się od tej okropnej cechy. Lecz nigdzie, ani w Kroku Szóstym, ani w Kroku Siódmym, nie jest powiedziane, że możemy nauczyć się kontrolowanie naszych wad charakteru. Faktem natomiast jest, że im więcej poświęcamy im uwagi, tym mocniej zakorzeniają się one w naszym życiu. Uznanie tego, że nie możemy kontrolować naszych wad charakteru, podobnie jak nie możemy kontrolować naszego uzależnienia, wymaga pokory. Nie jesteśmy w stanie usunąć naszych własnych wad charakteru, możemy jedynie prosić kochającego Boga, by je usunął. Pozbywanie się czegoś, co przynosi nam cierpienie, może być równie trudne, jak rezygnacja z czegoś, co sprawia nam przyjemność. Spójrzmy jednak prawdzie w oczy - trzymanie się tych wad wymaga ogromnego wysiłku. Kiedy jednak w pełni zdamy sobie sprawę z tego, czego tak na prawdę się trzymamy, to zrozumiemy, że ten wysiłek nie jest wart zachodu. Już czas pożegnać się ze swoimi wadami charakteru i poprosić Boga, by je usunął. ', 'Jestem gotów, by moje wady charakteru zostały usunięte. Pożegnam się z nimi i pozwolę kochającej Sile Wyższej zaopiekować się mną.'),
(327, '11-22', '22 listopada', 'Najpierw fundamenty \r\n', NULL, '„Gdy zaczynamy funkcjonować w społeczeństwie, wolność i wynikająca z niej otwartość umysłu pomagają nam w uporządkowaniu priorytetów i zadbaniu o sprawy najważniejsze.”  \r\n\r\n~Tekst Podstawowy \r\n\r\nNiektórzy z nas, mając zaledwie krótki okres czystości, zaczynają przedkładać różne rzeczy ponad zdrowienie. Kariera, rodzina, związki - wszystko to jest częścią życia, które za jakiś czas odnajdziemy, położywszy fundamenty pod nasze zdrowienie. Nie możemy jednak zbudować stabilnego życia, zanim nie dokonamy ciężkiej, podstawowej pracy kładzenia fundamentów pod nasze zdrowienie. Takie życie, podobnie jak dom zbudowany na piasku, w najlepszym przypadku będzie chwiejne. Zanim zaczniemy skupiać całą naszą uwagę na odbudowywaniu szczegółowej konstrukcji naszego życia, musimy najpierw położyć fundamenty. W pierwszej kolejności przyznajemy, że nie mamy jeszcze tych fundamentów i że uzależnienie uczyniło nasze życie zupełnie niemożliwym do opanowania. A wtedy, z pomocą naszego sponsora i naszej grupy domowej odnajdujemy wiarę w Siłę, która jest wystarczająco mocna, by przygotować podstawę naszego nowego życia. Sprzątamy gruzy z miejsca, w którym zbudujemy nasze nowe życie. Następnie, rozwijamy w sobie głęboką i praktyczną znajomość zasad, które będziemy praktykować we wszystkich sferach naszego życia: uczciwa samoocena, zaufanie przewodnictwu i mocy naszej Siły Wyższej oraz służba innym ludziom. Dopiero wtedy, gdy przygotujemy fundament, możemy z całą siłą zacząć odbudowywać nasze życie. Najpierw jednak musimy upewnić się, że nasze fundamenty są solidne, w przeciwnym razie, cokolwiek na nich wybudujemy nie będzie stało długo. ', 'Zadbam o to, aby położyć solidne fundamenty pod moje zdrowienie. Na takich fundamentach mogę budować życie w zdrowieniu.'),
(328, '11-23', '23 listopada', 'Wola Boża', NULL, '„Ulga, którą czujemy, pozwalając Bogu kierować nami, pomaga nam budować życie, które jest warte przeżycia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy braliśmy, baliśmy się, co się stanie, jeśli przestaniemy kontrolować otoczenie. Wielu z nas używało jakichś wymyślnych kłamstw, aby tylko ustrzec nasz nałóg przed czyjąś ingerencją. Wielu z nas manipulowało otaczającymi nas ludźmi, rozpaczliwie próbując wydobyć od nich coś, co pomogłoby nam zdobyć więcej narkotyków. Niektórzy byli gotowi na wszystko, byle tylko nie dopuścić do rozmowy dwóch osób, w której mogłoby wyjść na jaw jakieś nasze oszustwo. Wkładaliśmy całą swoją energię w to, aby podtrzymać iluzję kontroli naszego uzależnienia. Pochłonięci tymi wysiłkami nie byliśmy w stanie zaznać spokoju, który przychodzi wraz z kapitulację i poddaniem się woli Siły Wyższej. W zdrowieniu ważne jest, abyśmy pozbyli się iluzji kontroli i poddali Sile Wyższej, której wola jest lepsza od naszych pomysłów i manipulacji. Jeśli zauważymy, że próbujemy mieć kontrolę nad efektami naszych działań i czujemy lęk przed przyszłością, to możemy zrobić coś, co pomoże nam zmienić nasze myśli i uczucia. Powracamy do Kroku Drugiego i Trzeciego i przyglądamy się temu, do jakiego doszliśmy pojmowania Siły Wyższej. Czy rzeczywiście wierzymy, że ta Siła troszczy się o nas i może przywrócić nam rozsądek. Jeśli tak jest, to będziemy mogli przeżyć wszystkie życiowe upadki i wzloty - rozczarowania, smutki, rzeczy cudowne i radosne. ', 'Poddam się i pozwolę zaistnieć Sile Wyższej w moim życiu. Przyjmę w darze pokój ducha, który przychodzi wraz z poddaniem się.'),
(329, '11-24', '24 listopada', 'Zdrowiejąc z wdzięcznością\r\n', NULL, '„Czasem nachodzą nas myśli, że pozostawanie w czystości nie ma sensu, a stary sposób myślenia wpędza nas w użalanie się nad sobą, wywołując urazy i gniew.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nBywają takie dni, gdy niektórzy z nas pogrążają się w użalaniu się nad sobą. Być może mamy jakieś oczekiwania względem tego, jak powinno wyglądać nasze życie w zdrowieniu, które jednak nie zawsze się spełniają. Może próbujemy bezskutecznie kogoś kontrolować, lub uważamy, że nasze życie powinno wyglądać inaczej. Być może zaczęliśmy porównywać się z innymi zdrowiejącymi i doszliśmy do wniosku, że szczęście nas omija. Im bardziej chcemy dostosować nasze życie do naszych wyobrażeń, tym bardziej odczuwamy dyskomfort. Użalanie się może wynikać z tego, że wciąż żyjemy oczekiwaniami, zamiast żyć życiem takim, jakie ono jest. Gdy świat nie pasuje do naszych oczekiwań, często okazuje się, że to nasze oczekiwania wymagają zmiany, a nie świat. Możemy porównać obecne nasze życie z życiem, które mieliśmy przedtem i wzbudzić w sobie wdzięczność za zdrowienie. Możemy poszerzyć to praktykowanie wdzięczności poprzez podsumowywanie tego, co spotyka nas w życiu dobrego i wzbudzanie w sobie wdzięczności za to, że świat nie dostosowuje się do naszych oczekiwań, lecz przewyższa je. A jeśli kontynuujemy pracę nad Dwunastoma Krokami, nadal pielęgnując w sobie wdzięczność i akceptację, to możemy liczyć na to, że w przyszłości będziemy coraz bardziej się rozwijać, doznawać coraz więcej szczęścia i mieć w sobie coraz więcej pogody ducha. W zdrowieniu dostajemy wiele, a pozostawanie w czystości warte jest włożonego wysiłku. Akceptując nasze życie, właśnie dzisiaj, uwalniamy się od użalania się nad sobą.', 'Będę z wdzięcznością przyjmował życie takim, jakie ono jest.'),
(330, '11-25', '25 listopada', 'Medytacja', NULL, '„Wyciszenie umysłu poprzez medytację przynosi wewnętrzny spokój, który z kolei prowadzi nas do wewnętrznej relacji z Bogiem.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJeśli robimy postępy w zdrowieniu, często zastanawiamy się, co w pierwszej kolejności było powodem naszego przyjścia do wspólnoty Anonimowych Narkomanów i oceniamy jak bardzo polepszyła się od tego czasu jakoś naszego życia. Już nie musimy bać się własnych myśli. Im więcej czasu poświęcamy modlitwie i medytacji, tym lepiej się czujemy i doznajemy więcej spokoju. Wyciszenie i spokój, spływające na nas w czasie medytacji, są dowodem tego, że nasze najważniejsze potrzeby duchowe zostają zaspokojone. W trakcie medytacji jesteśmy zdolni do współodczuwania wraz z innymi uzależnionymi i równocześnie wzmacniamy swoje sumienie. Uczymy się nie osądzać innych i doświadczamy wolności bycia sobą. W trakcie tych duchowych rozważań odkrywamy „Boga wewnątrz siebie” i zauważamy, że jesteśmy w harmonii z Siłą większą od nas samych.', 'Będę rozmyślał o darze zdrowienia i spokojnie wsłuchiwał się w głos mojej Siły Wyższej.'),
(331, '11-26', '26 listopada', 'Odpowiedzialność\r\n', NULL, '„W ciągu jednego dnia zdarza się wiele rzeczy, zarówno negatywnych jak i pozytywnych. Jeżeli nie damy sobie czasu, aby docenić jedne i drugie, być może przegapimy coś, co pomogłoby nam we wzrastaniu.”  \r\n\r\n~IP nr8  \r\n\r\nOdpowiedzialność, odpowiedzialność - odpowiedzialność w życiu jest wszędzie. „Powinniśmy” zapiąć pas bezpieczeństwa. „Powinniśmy” posprzątać mieszkanie. „Powinniśmy” zrobić określone rzeczy względem naszych partnerów, naszych dzieci, osób, którym sponsorujemy. Na szczycie tego wszystkiego, co „powinniśmy” jest chodzenie na mityngi i praktykowanie naszego programu najlepiej jak potrafimy. Nic w tym dziwnego, że czasami chcemy uciec od tego wszystkiego na odległą wyspę, gdzie nie będziemy mieć żadnych obowiązków! W chwilach, gdy czujemy się przytłoczeni naszą odpowiedzialnością, zapominamy, że ona wcale nie musi być ciężarem. Wtedy, gdy najchętniej ucieklibyśmy przed naszą odpowiedzialnością, musimy zwolnić tempo, przypomnieć sobie, dlaczego ją wybraliśmy i zwrócić uwagę na profity, które ona ze sobą niesie. Czy jest to praca, którą normalnie uważamy za interesującą i stanowiącą wyzwanie, czy partner, którego osobowością zazwyczaj się zachwycamy, czy też dziecko, z którym w sposób naturalny chętnie się bawimy, i o które chętnie się troszczymy - w każdym rodzaju odpowiedzialności możemy odnaleźć radość.', 'Każda chwila jest wyjątkowa. Zwrócę uwagę na to, aby być wdzięcznym za moją odpowiedzialność i za tę szczególną radość, którą niesie ona ze sobą.'),
(332, '11-27', '27 listopada', 'Szukanie pomocy Bożej', NULL, '„Z czasem, w zdrowieniu, decyzja o tym, by prosić Boga o pomoc jest najważniejszym źródłem siły i odwagi.”\r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy robimy Krok Trzeci, decydujemy się pozwolić kochającej Sile Wyższej, by nas prowadziła i troszczyła się o nas na co dzień. Podejmujemy tę decyzję, aby pozwolić temu przewodnictwu i opiece wejść do naszego życia. Niektórzy z nas wierzą, że gdy tylko podejmiemy decyzję Kroku Trzeciego, to Bóg będzie nas prowadził; od tej chwili będziemy musieli tylko zwracać swoją uwagę na to dokąd jesteśmy prowadzeni. Decyzja Kroku trzeciego jest aktem wiary, a proszenie Boga o pomoc jest odnawianiem tego aktu wiary. Praktykowanie wiary w codziennym życiu daje potrzebną nam siłę i odwagę, ponieważ wiemy, że mamy pomoc kochającej Siły Wyższej. Ufamy, że nasze potrzeby będą zaspokojone. Możemy przejawiać tę wiarę i zaufanie po prostu poprzez proszenie o nie. ', 'Będę sam sobie przypominać o tym, że nie jestem samotny, prosząc moją Siłę Wyższą o pomoc na każdym kroku.'),
(333, '11-28', '28 listopada', 'Być sobą\r\n', NULL, '„Bycie prawdziwie pokornym oznacza akceptację samego siebie i podejmowanie uczciwych prób bycia sobą.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPokora jest dość zagadkowym pojęciem. Wiemy wiele o upokorzeniu, lecz pokora jest dla nas nowym pojęciem. Słowo to brzmi podejrzanie, niczym czołganie się, bicie pokłonów lub płaszczenie się. Ale nie o to w ogóle chodzi. Prawdziwa pokora oznacza jedynie akceptację siebie takimi, jakimi jesteśmy. Zanim dojdziemy do kroku, w którym użyte jest słowo „pokora\", jesteśmy już w trakcie praktykowania zasady pokory w naszym życiu. Czwarty Krok daje nam możliwość sprawdzenia kim naprawdę jesteśmy, a Krok Piąty pomaga nam zaakceptować tę wiedzę. Do praktykowania pokory należy akceptowanie naszej prawdziwej  natury i uczciwe bycie sobą. Nie musimy płaszczyć się, ani upokarzać się, nie musimy próbować uchodzić za mądrzejszych, bogatszych lub szczęśliwszych, niż jesteśmy w rzeczywistości. Pokora oznacza po prostu, że odrzucamy wszystkie nasze pretensje i żyjemy tak uczciwie, jak tylko potrafimy.', 'Pozwolę, by znajomość mojej prawdziwej natury przewodziła moim działaniom. Dzisiaj skonfrontuję się ze światem, będąc sobą.'),
(334, '11-29', '29 listopada', 'Opieka naszej Siły Wyższej\r\n', NULL, '„Wierzymy, że nasza Siła Wyższa zaopiekuje się nami\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNasz program opiera się na idei, że stosowanie prostych zasad może mieć głęboki wpływ na nasze życie. Jedną z tych zasad jest to, że nasza Siła Wyższa zatroszczy się o nas, jeśli ją o to poprosimy. Ponieważ ta zasada jest tak prosta, możemy czuć pokusę, by ją ignorować. Jeżeli nie nauczymy się świadomie stosować tej zasady, możemy przegapić coś, co dla naszego zdrowienia jest tak ważne, jak oddychanie dla życia. Co się dzieje, gdy stwierdzamy, że jesteśmy zestresowani lub spanikowani? Jeżeli staraliśmy się wytrwale pogłębiać naszą relację z Siłą Wyższą, nie będziemy mieć z tym żadnego problemu. Zamiast działać w pośpiechu, zatrzymamy się na chwilę, aby przypomnieć sobie sytuacje z przeszłości, w których nasza Siła Wyższa troszczyła się o nas. To daje nam pewność, że nasza Siła Wyższa ciągle sprawuje pieczę nad naszym życiem. Wtedy będziemy szukać przewodnictwa i siły w obecnej sytuacji i będziemy spokojnie podążać dalej, pewni, że nasze życie jest w rękach Boga. „Nasz program, to zestaw zasad\", mówi nam nasza Biała Książeczka. Im bardziej konsekwentnie będziemy starali się udoskonalać nasze świadome uznawanie tych zasad, tym łatwiej będzie nam je stosować.', 'Będę starać się ulepszyć mój świadomy kontakt z Siłą Wyższą, która troszczy się o mnie. Wiem, że będę zdolny zaufać tej opiece, jeśli nadejdzie taka potrzeba.'),
(335, '11-30', '30 listopada', 'Dzielić się prawdziwym sobą\r\n', NULL, '„Dzielenie się z innymi chroni nas przed uczuciem izolacji i osamotnienia.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nIntymność oznacza dzielenie się z inną istotą ludzką swoimi najgłębszymi myślami i uczuciami. Wielu z nas tęskni za ciepłem i przyjaźnią, które niesie ze sobą intymność, lecz te rzeczy nie przychodzą bez wysiłku. W naszym uzależnieniu nauczyliśmy się odgradzać od innych, żeby nie zagrażali naszemu zażywaniu narkotyków. Aby poczuć bliskość, którą niesie ze sobą intymność, musimy pozwolić innym zbliżyć się do nas - do nas prawdziwych. Jeżeli chcemy dzielić z innymi nasze najbardziej intymne sprawy, musimy najpierw mieć pojęcie o tym, czym właściwie są te nasze najbardziej intymne sprawy. Regularnie analizujemy nasze życie, aby dowiedzieć się kim naprawdę jesteśmy, czego naprawdę chcemy i co naprawdę czujemy. Następnie, bazując na naszych regularnych autoanalizach, musimy być całkowicie i konsekwentnie uczciwi z naszymi przyjaciółmi, na tyle, na ile potrafimy. Intymność jest częścią życia, a przez to również częścią życia w czystości - i intymność, tak jak wszystko w zdrowieniu, ma swoją cenę. Sumienna autoanaliza, której wymaga intymność, może okazać się ciężką pracą. Całkowita uczciwość w intymnych relacjach często niesie ze sobą różne komplikacje. Jednak wolność od izolacji i osamotnienia, którą niesie ze sobą intymność, jest naprawdę warta tego wysiłku.', 'Szukam wolności od izolacji i osamotnienia, która przynosi ze sobą intymność. Dzisiaj poznam „prawdziwego siebie\" poprzez autoanalizę i będę praktykował bycie całkowicie uczciwym z drugą osobą.'),
(336, '12-01', '1 grudnia', 'Nagrody życia', NULL, '„Zaczynamy modlić się jedynie o poznanie woli Boga wobec nas. Dzięki temu dostajemy tylko to, z czym jesteśmy w stanie sobie poradzić.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWyobraź sobie jakby to było, gdyby Bóg dał nam wszystko, czego chcemy. Wspaniały nowy samochód, najlepsze oceny w nauce, potrójną pensję – i wszystko to dostalibyśmy bez żadnego wysiłku z naszej strony, tylko dlatego, że o to poprosiliśmy. A teraz wyobraź sobie problemy, które przyszłyby razem z niezarobionymi bogactwami, nowymi luksusowymi samochodami i bezprawnie noszonymi tytułami akademickimi. Co byśmy zrobili z bezpodstawnie przyznaną nam ogromną podwyżką zarobków? Jak byśmy obeszli się z naszą nową finansową odpowiedzialnością? I jak byśmy żyli z taką podwyżką? Czy kiedykolwiek moglibyśmy jakkolwiek uwiarygodnić to, że zasłużyliśmy na taką płacę, skoro wiemy, że nie zasłużyliśmy? Nowy fantastyczny samochód? Większość takich samochodów wymaga wysokiego ubezpieczenia i wysokich kosztów utrzymania. Czy jesteśmy przygotowani, aby dbać o to, o co prosimy? Wyróżnienia akademickie? Czy potrafilibyśmy wykonać tę samą pracę, którą wykonują najlepsi studenci, jeśli dostalibyśmy świetne oceny, na które nie zapracowaliśmy? Co byśmy zrobili, jeżeli zostalibyśmy uznani za oszustów? Gdy rozmawiamy z Bogiem, musimy pamiętać o tym, że żyjemy w realnym świecie. Sami zarabiamy na swoje wynagrodzenie i uczymy się nim rozporządzać. Jeśli ograniczymy nasze modlitwy do próśb o poznanie woli Boga wobec nas, o siłę do jej spełnienia i umiejętność życia z wynikającymi z tego konsekwencjami, możemy być pewni, że nie dostaniemy więcej, niż jesteśmy w stanie udźwignąć. ', 'Będę się modlić jedynie o poznanie woli Boga wobec mnie oraz o siłę do jej spełnienia w realnym świecie.'),
(337, '12-02', '2 grudnia', 'Zdrowienie naszym najważniejszym priorytetem\r\n', NULL, '„Musimy stawiać zdrowienie na pierwszym miejscu i utrzymywać nasze priorytety we właściwej kolejności.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nPrzed przyjściem do NA używaliśmy wielu wymówek, aby usprawiedliwić swoje zażywanie: „on na mnie nakrzyczał\", „ona powiedziała to i tamto\", „mój partner odszedł\", „zostałem zwolniony z pracy\". Tych samych wymówek używaliśmy, aby nie szukać pomocy w rozwiązaniu naszego problemu z narkotykami. W końcu zdaliśmy sobie sprawę z tego, że to wszystko wciąż się dzieje, ponieważ wciąż bierzemy narkotyki . Dopiero wtedy, gdy postawimy zdrowienie na pierwszym miejscu sytuacje te zaczynają się zmieniać. Być może dziś ulegamy tej samej tendencji używania wymówek, by nie chodzić na mityngi i nie pełnić służb. Nasze obecne wymówki mogą być trochę inne: „nie mogę zostawić dzieci\", „mam teraz wakacje”, „muszę skończyć ten projekt, żeby zrobić wrażenie na moim szefie\" itp. itd. Jeśli jednak nie uczynimy zdrowienia naszym najważniejszym priorytetem, niedługo nie będziemy już musieli martwić się o żadną z tych rzeczy. Dzieci, urlop i praca prawdopodobnie znikną z naszego życia, gdy znów zaczniemy zażywać. Nasze zdrowienie musi być na pierwszym miejscu. Czy mamy pracę, czy jej nie mamy, czy jesteśmy w związku, czy w nim nie jesteśmy, musimy chodzić na mityngi, pracować nad krokami, dzwonić do naszego sponsora, pełnić służbę wobec Boga i innych ludzi. Dzięki tym prostym działaniom możemy mieć wakacje, rodziny i szefów, wszystko to, o co możemy się martwić. Zdrowienie jest fundamentem naszego życia, który czyni możliwym wszystko inne.', 'Będę utrzymywać moje priorytety we właściwej kolejności. Numerem Jeden na tej liście jest moje zdrowienie.'),
(338, '12-03', '3 grudnia', 'Wizja bez ograniczeń\r\n', NULL, '„Być może po raz pierwszy w życiu mamy jakieś wyobrażenia o naszym przyszłym życiu.\"  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy braliśmy, nasz świat był bardzo ograniczony. Codziennie przechodziliśmy przez tę samą rutynę: kupowanie narkotyków, zażywanie i zdobywanie środków, aby mieć ich więcej. I było to wszystko, czego według wszelkiego prawdopodobieństwa mogliśmy się spodziewać do końca naszego życia. Nasz potencjał był ograniczony. Dzisiaj nasze perspektywy na przyszłość zmieniły się. Zdrowienie dało nam nowe spojrzenie na nas samych i na nasze życie. Nie musimy już tkwić uwięzieni w nieskończenie szarej rutynie uzależnienia. Uzyskaliśmy wolność do tego, by próbować nowych dróg, nowych poglądów i nowych działań. Dzięki temu zaczynamy widzieć siebie w nowym świetle. Nasz potencjał ograniczony jest jedynie mocą naszej Siły Wyższej, która się o nas troszczy - a ta moc nie zna żadnych granic. Gdy zdrowiejemy, życie i wszystko, co ono w sobie zawiera stoi przed nami otworem. Prowadzeni przez nasze duchowe zasady i napędzani siłą, którą daje nam Bóg, jakkolwiek go pojmujemy, mamy przed sobą nieograniczone horyzonty.', 'Otworzę oczy na możliwości, które stoją przede mną. Mój potencjał jest tak bezgraniczny i silny, jak Bóg, jakkolwiek go pojmuję. Dzisiaj będę czerpać z tego potencjału.'),
(339, '12-04', '4 grudnia', 'Wola Boga, a nie nasza\r\n', NULL, '„Wiemy, że jeżeli modlimy się o wolę Boga, otrzymamy to, co jest dla nas najlepsze, bez względu na to, co o tym myślimy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nGdy przyszliśmy do NA, nasz głos wewnętrzny był autodestrukcyjny i nie mogliśmy na nim polegać. Uzależnienie ograbiło nas z naszych pasji, zainteresowań i poczucia tego, co jest dla nas najlepsze. Dlatego w zdrowieniu tak ważnym jest rozwijanie naszej wiary w Siłę większą od nas samych, w coś, co zapewni nam przewodnictwo bardziej zrównoważone i niezawodne, niż nasze własne. Rozpoczęliśmy naukę polegania na opiece tej Siły i ufania wewnętrznemu przewodnictwu, które ona nam zapewnia. Tak, jak to jest ze wszystkimi procesami nauki, tak i „modlenie się jedynie o poznanie woli Bożej wobec nas oraz o siłę do jej spełnienia” wymaga od nas praktyki. Samolubne, kierowane przez ego postawy, które rozwinęliśmy w trakcie naszego uzależnienia, nie znikną z dnia na dzień. Mogą one mieć wpływ na nasze modlitwy. Możemy nawet spostrzec, że modlimy się następująco: „Uwolnij mnie od tej wady charakteru, żebym mógł robić lepsze wrażenie”. Im bardziej szczerze przyjrzymy się naszym własnym poglądom i pragnieniom, tym łatwiej będzie nam odróżnić naszą własną wolę od woli Boga. Możemy się modlić następująco: „Tylko do twojej wiedzy, Boże, w tej sytuacji chciałbym tego i tego. Pomimo to, proszę cię, niech się dzieje Twoja wola, a nie moja.” Jeśli tak postępujemy, to jesteśmy przygotowani do tego, by rozpoznać i zaakceptować przewodnictwo naszej Siły Wyższej.', 'Siło Wyższa, nauczyłem się ufać twojemu przewodnictwu, chociaż ciągle mam swoje pomysły dotyczące mojego życia. Pozwól mi podzielić się z tobą moimi pomysłami, a potem jasno zrozumieć jaka jest twoja wola wobec mnie. I niech się dzieje twoja wola, a nie moja.'),
(340, '12-05', '5 grudnia', 'Ci, którzy chcą zdrowieć\r\n', NULL, '„Widzieliśmy, że program działa na każdego uzależnionego, który uczciwie i szczerze chce przestać brać.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJak się możemy dowiedzieć, czy ktoś chce uczciwie i szczerze przestać brać narkotyki? Prawda jest taka, że nie możemy być tego pewni! A ponieważ nie możemy czytać cudzych myśli, ani nie znamy cudzych motywów i pragnień, pozostaje nam tylko mieć nadzieję, że taką chęć dana osoba ma. Może się nam wydawać w czasie rozmowy z nowoprzybyłym, że już go nigdy nie zobaczymy, a potem po kilku latach spotkamy go na jego ścieżce zdrowienia. Możemy mieć tendencję, aby poddawać się wobec osoby, która ciągle ma wpadki lub od razu nie zachowuje czystości, ale nie wolno nam tego robić. Bez względu na niechęć, jaką może ktoś w nas wywoływać, faktem po prostu jest to, że ta uzależniona osoba jest na mityngu. Być może nigdy nie poznamy rezultatów naszej pracy nad Dwunastym Krokiem; nie do nas należy ocenianie dobrej woli nowoprzybyłego. Posłanie, które niesiemy, jest częścią nas. Niesiemy je wszędzie i dzielimy się nim dobrowolnie, pozostawiając rezultaty Sile większej od nas samych.', 'Będę się dzielić moim zdrowieniem z każdym uzależnionym, bez względu na czas, miejsce i okoliczności. Rezultaty pozostawię mojej Sile Wyższej.'),
(341, '12-06', '6 grudnia', 'Związki miłosne a zdrowienie\r\n', NULL, '„Związki z innymi ludźmi mogą być niezwykle bolesnym obszarem naszego życia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nDla niektórych z nas miłość jest jak eliksir. Podniecenie nowym kochankiem, zaintrygowanie zgłębianiem tajników intymności, poczucie ulgi, którego doznajemy pozwalając sobie na odsłonięcie się - to potężne emocje. Nie możemy jednak zapomnieć, że mamy tylko jednodniowe odroczenie od naszego uzależnienia. Trzymanie się tego jednodniowego odroczenia musi być najwyższym priorytetem w życiu każdego uzależnionego. Możemy zbyt mocno zaangażować się w jakiś związek. W trakcie trwania takiego związku możemy zlekceważyć starych przyjaciół i naszego sponsora. A gdy pojawiają się trudności, często czujemy, że nie możemy już nawiązać kontaktu z tymi, którzy pomagali nam przed naszym zauroczeniem. Taki sposób myślenia może stać się podłożem do nawrotu i wpadki. Pracując konsekwentnie nad programem i przychodząc na mityngi, jesteśmy pewni, że mamy stały kontakt ze zdrowieniem, nawet wtedy, gdy głęboko tkwimy w jakimś związku miłosnym. Potrzeba zaangażowania się w taki związek jest dla nas rzeczą naturalną. Nie powinniśmy jednak zapominać, że bez programu nawet najzdrowszy związek nie zabezpieczy nas przed siłą naszego uzależnienia.', 'Pragnąc związku miłosnego, nie zignoruję mojego zdrowienia.'),
(342, '12-07', '7 grudnia', 'Przetrwać swoje emocje\r\n', NULL, 'Używamy wszelkich dostępnych narzędzi i rozwijamy w sobie umiejętność życia z naszymi emocjami.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\n„Przetrwać swoje emocje?” - powiedzą niektórzy z nas - „Chyba żartujesz!” Gdy braliśmy, nigdy nie dawaliśmy sobie szansy, by się tego nauczyć. Nie da się przetrwać swoich uczuć - myśleliśmy - można je zaćpać. Problem polegał na tym, że lekarstwo na nasze nie dające się przetrwać emocje zabijało nas. Gdy przyszliśmy do NA, zaczęliśmy pracować nad Dwunastoma Krokami i w rezultacie zaczęliśmy dojrzewać emocjonalnie. Wielu z nas zaczęło odczuwać emocjonalną ulgę od samego początku. Byliśmy zmęczeni udawaniem, że nasze uzależnienie i nasze życie jest pod kontrolą; poczuliśmy się dobrze, przyznając ostatecznie, że nie kontrolowaliśmy ani jednego, ani drugiego. Po podzieleniu się z naszym sponsorem naszym obrachunkiem moralnym, zaczynamy czuć, że nie musimy już, chcąc być akceptowanymi, zaprzeczać temu, kim jesteśmy, ani temu, co czujemy. Kiedy kończymy nasze zadośćuczynienie, wiemy, że nie musimy cierpieć z powodu poczucia winy; możemy po prostu przyznać się do winy i to nas nie zabije. Im intensywniej pracujemy nad programem, tym lepiej czujemy się z życiem takim, jakie otrzymujemy. Program działa dzisiaj tak samo dobrze, jak dotąd. Robiąc podsumowanie dnia, uczciwie przyznając się do swojego w nim udziału i uznając bezsilność wobec rzeczywistości, możemy przetrwać uczucia, które życie stawia przed nami na naszej drodze. Używając dostępnych nam narzędzi, rozwijamy umiejętność przetrwania naszych emocji.', 'Nie będę zaprzeczać moim uczuciom. Będę praktykować uczciwość i bezsilność wobec życia, takiego, jakie ono jest. Będę używać narzędzi tego programu, aby przetrwać moje emocje.'),
(343, '12-08', '8 grudnia', 'Nazywanie wady wadą\r\n', NULL, '„Gdy widzimy, w jaki sposób nasze wady funkcjonują w naszym życiu i akceptujemy je, jesteśmy gotowi, aby pozwolić im odejść i kontynuować nasze nowe życie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzasami, nasza gotowość do pozbycia się pewnych wad charakteru zależy od tego, jak je nazywamy. Jeżeli ich złe nazywanie powoduje, że wydają się być mniej „wadliwe”, możemy nie być zdolni do zobaczenia szkód, które one powodują. A jeżeli wydaje się nam, że nie powodują one żadnych krzywd, to dlaczego mielibyśmy kiedykolwiek prosić Siłę Wyższą o ich usunięcie z naszego życia? Weźmy na przykład „zadawalanie ludzi”. Nie brzmi to przecież tak źle? To po prostu oznacza, że jesteśmy mili dla ludzi, prawda? Niezupełnie. Mówiąc szczerze, oznacza to, że jesteśmy nieuczciwi i manipulujemy. Kłamiemy odnośnie naszych uczuć, przekonań i potrzeb, chcąc spowodować, żeby inni ludzie spełniali nasze życzenia. Być może wydaje się nam, że jesteśmy „na luzie.” Czy jednak „bycie na luzie” oznacza ignorowanie naszych obowiązków domowych, unikanie konfrontacji i mieszkanie w komfortowym bałaganie? Lepszą nazwą na to byłoby „lenistwo”, „unikanie” lub „strach”. Wielu z nas ma problemy z identyfikacją naszych wad charakteru. Jeżeli tak jest, możemy porozmawiać z naszym sponsorem lub przyjaciółmi z NA. Jasno i uczciwie opisujemy im nasze zachowania i prosimy o pomoc w identyfikacji naszych wad charakteru. Z czasem, mamy coraz lepszą umiejętność identyfikacji naszych wad charakteru, nazywając je po imieniu.', 'Będę nazywać moje wady po imieniu. Jeżeli będę mieć z tym trudności, poproszę mojego sponsora o pomoc.');
INSERT INTO `meditations_pl` (`id`, `date`, `med_day`, `med_title`, `med_page`, `meditation`, `today_note`) VALUES
(344, '12-09', '9 grudnia', 'Słuchanie', NULL, '„Umiejętność słuchania jest darem, który wzrasta w miarę naszego wzrostu duchowego. Życie nabiera nowego znaczenia, gdy otwieramy się na ten dar.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzy kiedykolwiek obserwowałeś rozmowę dwójki dzieci? Podczas, gdy jedno mówi o fioletowym latawcu, drugie martwi się o piasek, który mu przeszkadza w butach. My czasami napotykamy podobne problemy, gdy uczymy się słuchać innych. W czasie mityngów możemy usilnie starać się słuchać kogoś, kto się dzieli, podczas gdy nasze myśli są zajęte tym, co powiemy, gdy nadejdzie nasza kolej. W jakiejś rozmowie możemy nagle uświadomić sobie, że nasze odpowiedzi nie mają nic wspólnego z pytaniami, które nam zadano. Są one przedmową słów, które przygotowaliśmy, owładnięci obsesją na własnym punkcie. Nauka słuchania, prawdziwego słuchania, może być trudnym zadaniem, lecz nie jest zadaniem nieosiągalnym. Możemy zacząć od upewniania się czy nasze odpowiedzi dotyczą tego, o czym mówi nasz rozmówca. Możemy spytać osobę, która dzieli się z nami swoim problemem czy możemy jej jakoś pomóc. Postępując tak, możemy w znacznej mierze uwolnić się od naszej auto-obsesji oraz nawiązać bliższy kontakt z otaczającymi nas ludźmi.', 'Wyciszę moje własne myśli i będę słuchać tego, co mówią inni.'),
(345, '12-10', '10 grudnia', 'Zwycięzcy', NULL, '„Zacząłem naśladować niektóre rzeczy, które robili zwycięzcy. Odnalazłem się w NA. Poczułem się dobrze.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzęsto słyszymy na mityngach, że powinniśmy „trzymać się zwycięzców”. Kim są zwycięzcy w NA? Zwycięzcy są łatwi do zdefiniowania. Zwycięzcy pracują aktywnie nad programem zdrowienia, żyją rozwiązaniami, a nie problemami. Zwycięzcy są zawsze gotowi, aby wyciągnąć rękę do nowoprzybyłych. Zwycięzcy mają sponsorów i pracują z nimi. Zwycięzcy pozostają czyści, właśnie dzisiaj. Zwycięzcy są zdrowiejącymi uzależnionymi, którzy utrzymują pozytywny sposób myślenia. Zwycięzcy mogą przechodzić przez trudne okresy, mogą mieć problemy, ale w tym czasie nie przestają przychodzić na mityngi i dzielić się tym, co się dzieje w ich życiu. Zwycięzcy wiedzą w głębi serca, że z pomocą Siły Wyższej, nic z tego, co ich spotyka, nie będzie nie do pokonania. Zwycięzcy dążą do jedności w służbach, które pełnią. Zwycięzcy praktykują „pierwszeństwo zasad przed osobistymi ambicjami”. Zwycięzcy pamiętają o zasadzie anonimowości, trzymając się jej, bez względu na osobę, której dotyczy dana sytuacja. Zwycięzcy mają poczucie humoru. Zwycięzcy potrafią śmiać się z samych siebie. A kiedy się śmieją, śmieją się z tobą, a nie z ciebie. Kim są zwycięzcy w NA? Każdy z nas może być uznawany za zwycięzcę. Wszyscy z nas wykazują się niektórymi zachowania mi zwycięzcy; czasami jesteśmy bardzo blisko ideału, czasami nie. Jeżeli dzisiaj jesteśmy czyści i pracujemy nad programem najlepiej jak potrafimy, jesteśmy zwycięzcami!', 'Będę dążyć do spełnienia swoich ideałów. Będę zwycięzcą.'),
(346, '12-11', '11 grudnia', 'Nie musimy być nieszczęśliwi\r\n', NULL, '„Nikt nie zmusza nas do rezygnacji z naszego cierpienia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nZabawnie jest przypomnieć sobie czasami, jak bardzo opieraliśmy się przed poddaniem się zdrowieniu. Wydawało się nam, że jako zażywający narkotyki uzależnieni, mieliśmy wspaniałe i udane życie, a zaprzestanie zażywania byłoby gorsze niż odbywanie dożywotniego wyroku ciężkich robót. W rzeczywistości, prawda była zupełnie inna: nasze życie było żałosne, ale baliśmy się zamienić dobrze znane nam cierpienie na pełne niewiadomych zdrowienie. Zdrowiejąc, też możemy czuć się nieszczęśliwi, ale tak być nie musi. Nikt nie będzie nas zmuszać do pracy nad krokami, do chodzenia na mityngi czy do spotkań ze sponsorem. Nie ma policji NA, która będzie nas zmuszać do tego, abyśmy robili rzeczy, które uwolnią nas od bólu. Mamy jednak wybór. Wybraliśmy już rezygnację z cierpienia związanego z czynnym uzależnieniem na rzecz wewnętrznego spokoju, który niesie ze sobą zdrowienie. Teraz, jeżeli jesteśmy gotowi zamienić nasze dzisiejsze cierpienia na jeszcze większy spokój, możemy to po prostu zrobić - jeżeli tego naprawdę chcemy.', 'Nie muszę być nieszczęśliwy, jeśli naprawdę tego chcę. Dziś, wymienię moje cierpienia na korzyści płynące ze zdrowienia.'),
(347, '12-12', '12 grudnia', 'Lęk przed zmianą\r\n', NULL, '„Pracując nad krokami, zaczynamy akceptować wolę Siły Wyższej... Lęk przed nieznanym opuszcza nas. Stajemy się wolni.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nŻycie jest serią zmian - tych wielkich i tych małych. Mimo, iż intelektualnie możemy akceptować ten fakt, emocjonalnie na każdą zmianę prawdopodobnie reagujemy lękiem. Z jakichś przyczyn zakładamy, że każda zmiana sprawi nam ból i przyczyni się do tego, że będziemy nieszczęśliwi. Jeżeli spojrzymy w przeszłość na zmiany, które zaszły w naszym życiu, zobaczymy, że większość z nich wyszła nam na dobre. Z pewnością swego czasu na samą myśl o życiu bez narkotyków ogarniało nas przerażenie - a teraz, jest to najlepsza rzecz, jaka nam się kiedykolwiek przydarzyła. Być może straciliśmy pracę, bez której wydawało nam się, że umrzemy, ale potem odnaleźliśmy większe wyzwania i osobiste spełnienie w nowym zawodzie. Jeśli robimy postępy w zdrowieniu, możemy doświadczać jeszcze wielu innych zmian. Pozbywamy się starych sytuacji i stajemy się gotowi na nowe. Gdy spotykają nas jakieś zmiany, naturalną naszą reakcją jest chwytanie się czegoś, co znamy, czegokolwiek, i próba zatrzymania tego. Ukojenie możemy znaleźć w Sile większej niż nasza własna. Im więcej zmian dopuszczamy pod przewodnictwem Siły Wyższej, tym bardziej ufamy, że te zmiany są dla naszego dobra. Wiara zastępuje lęk, a my w głębi serca wiemy, że wszystko będzie dobrze.', 'Kiedy będę bać się zmiany w moim życiu, uspokoi mnie świadomość, że wola Boga wobec mnie jest dobra.'),
(348, '12-13', '13 grudnia', 'Przynależność', NULL, '„Jedynym warunkiem przynależności jest chęć zaprzestania zażywania.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWszyscy znamy ludzi, którzy mogliby skorzystać z NA. Mnóstwo ludzi, których napotykamy w życiu - nasi krewni, starzy przyjaciele, koledzy z pracy - faktycznie mogliby zastosować program zdrowienie w swoim życiu. Niestety ci, którzy nas potrzebują, nie zawsze odnajdują drogę do naszych grup. Program NA polega na przyciąganiu, a nie na reklamie. Jesteśmy członkami NA tylko wtedy, gdy sami tak twierdzimy. Możemy zabrać ze sobą na mityng naszych przyjaciół lub inne osoby, które kochamy, jeżeli one tego chcą, ale nie możemy ich zmuszać do tego, by przyjęli sposób życia, który nas uwolnił od czynnego uzależnienia. Przynależność do NA jest w dużej mierze osobistą decyzją. Decyzja o byciu członkiem NA zapada w sercu danej osoby uzależnionej. Wymuszone uczestnictwo w mityngach nie zatrzymuje uzależnionych w naszych salach mityngowych na długo. Tylko sam uzależniony, który wciąż jeszcze cierpi, może zdecydować, czy jest bezsilny wobec swojego uzależnienia, jeżeli będzie mu dana taka możliwość. My możemy nieść posłanie, ale nie możemy nieść uzależnionego.', 'Jestem wdzięczny za moją decyzję o zostaniu członkiem NA. '),
(349, '12-14', '14 grudnia', 'Uzależnienie, narkotyki i zdrowienie\r\n', NULL, '„Uzależnienie jest fizyczną, umysłową i duchową chorobą, która ma wpływ na wszystkie obszary naszego życia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nZanim zaczęliśmy brać narkotyki, większość z nas miała jakieś określone wyobrażenie o tym, jak wyglądają uzależnieni. Niektórzy z nas wyobrażali sobie ćpunów, którzy okradają stacje benzynowe, aby zdobyć pieniądze na narkotyki. Inni myśleli o chorych na paranoję odmieńcach, którzy żyją za ciągle zasłoniętymi oknami i zamkniętymi drzwiami, obserwując stamtąd życie. I póki nie pasowaliśmy do żadnego z tych stereotypów, wydawało się nam, że nie jesteśmy uzależnieni. Kiedy nasze zażywanie narkotyków wzmogło się, odrzuciliśmy te błędne wyobrażenia o uzależnieniu po to tylko, aby zamienić je na inne fałszywe wyobrażenie, a mianowicie takie, że w uzależnieniu chodzi wyłącznie o narkotyki. Prawdopodobnie myśleliśmy, że uzależnienie powoduje fizyczną zależność i wierzyliśmy, że narkotyki, które nie powodują fizycznego uzależnienia, nie uzależniają. Lub myśleliśmy, że to rodzaj zażywanych przez nas narkotyków powodował wszystkie nasze problemy. Uważaliśmy, że zdrowie duchowe w naszym życiu zostanie przywrócone, kiedy po prostu przestaniemy zażywać te określone narkotyki. Jedną z najważniejszych lekcji, jaką dostajemy w NA jest to, że uzależnienie to dużo więcej niż tylko narkotyki, które zażywaliśmy. Uzależnienie jest częścią nas samych. Uzależnienie jest chorobą, która ma wpływ na każdy obszar naszego życia, z narkotykami i bez nich. Możemy rozpoznać jej oddziaływanie na nasze uczucia, myśli i zachowania, również po tym, jak przestaliśmy zażywać. Dlatego też potrzebujemy rozwiązania, które może uporządkować wszystkie sfery naszego życia: potrzebujemy Dwunastu Kroków. ', 'Uzależnienie nie jest prostą chorobą, ale ma proste rozwiązanie. Dzisiaj będę żyć tym rozwiązaniem - będę żyć Dwunastoma Krokami zdrowienia.'),
(350, '12-15', '15 grudnia', 'Radość dzielenia się\r\n', NULL, '„Istnieje duchowa zasada przekazywania dalej tego, co zostało nam dane w NA po to, abyśmy mogli to zachować. Pomagając innym w utrzymywaniu czystości, cieszymy się korzyściami płynącymi z bogactwa duchowego, które odnaleźliśmy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielokrotnie w czasie naszego zdrowienia inni ludzie hojnie dzielili się z nami tym, czym kiedyś inni hojnie dzielili z nimi. Być może otrzymaliśmy posłanie Dwunastego Kroku. Może ktoś zabrał nas ze sobą na nasz pierwszy mityng. Być może ktoś zafundował nam obiad, gdy byliśmy nowi. Wszyscy otrzymaliśmy czas, uwagę i miłość innych członków NA. Może pytaliśmy kogoś: „Jak mogę ci się odwdzięczyć?” a odpowiedź, którą otrzymaliśmy była prawdopodobnie sugestią, żebyśmy zrobili to samo w stosunku do innej osoby nowoprzybyłej, jeżeli będziemy mieć taką możliwość. Kiedy utrzymujemy naszą czystość i zdrowienie, możemy stwierdzić, że chcemy zrobić dla innych to samo, co ktoś zrobił dla nas, i że jesteśmy szczęśliwi, mogąc to zrobić. Jeżeli usłyszeliśmy posłanie NA, przebywając w więzieniu lub w szpitalu, możemy przyłączyć się do naszego lokalnego komitetu H&I (Szpitale i Instytucje). Możemy być wolontariuszami w telefonie zaufania NA. Możemy też ofiarować nasz czas, uwagę i miłość nowoprzybyłemu, któremu staramy się pomóc. W naszym zdrowieniu dostaliśmy dużo. Jednym z największych darów jest przywilej dzielenia się z innymi tym, co tak hojnie było nam dane, bez oczekiwania nagrody. Radością jest odkrycie, że mamy coś, co może być użyteczne dla innych, a ta radość wzmaga się, jeżeli dzielimy się tym. Dzisiaj możemy tak zrobić, dobrowolnie i z wdzięczności. ', 'W moim zdrowieniu dostałem bardzo dużo i jestem za to głęboko wdzięczny. Będę się cieszyć z tego, że mogę dzielić się tym z innymi tak hojnie, jak hojnie mnie obdarowano.'),
(351, '12-16', '16 grudnia', 'Nie ma dymu bez ognia...\r\n', NULL, '„Samozadowolenie jest wrogiem wszystkich członków NA z dłuższym okresem czystości. Jeśli zbyt długo pozostajemy w stanie samozadowolenia, proces zdrowienia ustaje.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nRozpoznanie samozadowolenia w naszym zdrowieniu jest jak zobaczenie dymu w pokoju. „Dym” staje się bardziej gęsty, gdy rzadziej chodzimy na mityngi, gdy nasz kontakt z nowoprzybyłymi zanika lub nasza relacja ze sponsorem urywa się. Jeśli nasze samozadowolenie trwa nadal, nie potrafimy już poprzez dym dostrzec wyjścia ewakuacyjnego. Tylko nasza natychmiastowa reakcja może uchronić nas przed piekłem. Musimy nauczyć się rozpoznawać dym samozadowolenia. W NA możemy otrzymać potrzebną do tego pomoc. Musimy spędzać czas z innymi uzależnionymi, ponieważ oni mogą szybciej wykryć nasze samozadowolenie niż my sami. Nowoprzybyli przypomną nam, jak bolesne może być aktywne uzależnienie. Nasz sponsor pomoże nam nie stracić z oczu naszego priorytetu, literatura zdrowienia, którą ciągle mamy w zasięgu ręki, może posłużyć do gaszenia małych ognisk chorobowych, które od czasu do czasu pojawiają się. Regularne uczestnictwo w naszym zdrowieniu z pewnością umożliwi nam wykrycie wszelkich zalążków dymu na długo przed potężnym pożarem.', 'Będę brać udział w całym moim zdrowieniu. Moje zaangażowanie w NA jest dzisiaj tak samo mocne, jak było na początku mojego zdrowienia.'),
(352, '12-17', '17 grudnia', 'Motywy w służbach\r\n', NULL, '„Wszystko, co dzieje się w służbach NA, powinno być motywowane pragnieniem jeszcze efektywniejszego niesienia posłania tym, którzy wciąż jeszcze cierpią.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nMotywy naszego postępowania często są dla nas niespodzianką. W pierwszych dniach naszego zdrowienia prawie zawsze były one niespodzianką! Nauczyliśmy się sprawdzać nasze motywy poprzez modlitwę, medytację, kroki, rozmowy z naszym sponsorem lub innymi uzależnionymi. Kiedy stwierdzamy u siebie jakąś szczególnie mocną potrzebę zrobienia czegoś, ważne jest, byśmy sprawdzili najpierw nasze motywy, aby dowiedzieć się, czego tak naprawdę chcemy. We wczesnym zdrowieniu wielu z nas rzuca się z wielkim zapałem do pełnienia służb, zanim jeszcze nabierzemy nawyku regularnego sprawdzania swoich motywów. Rozpoznanie prawdziwych przyczyn naszego zapału musi chwilę potrwać. Być może chcemy zrobić wrażenie na innych, pokazać nasze umiejętności, uzyskać uznanie lub poczuć się ważnymi. Te potrzeby wcale nie muszą być szkodliwe w innym kontekście, jeśli zostają zaspokojone w inny sposób. Jednak w służbach NA mogą one wyrządzić poważne szkody. Kiedy decydujemy się służyć w NA, podejmujemy decyzję, aby pomagać innym uzależnionym w znalezieniu zdrowienia i w jego utrzymaniu. Musimy uważnie sprawdzać nasze motywy w służbach, pamiętając o tym, że łatwiej jest odstraszyć czynnie uzależnionych, niż ich przekonać do pozostania z nami. Jeśli pokazujemy im obłudę, manipulację i nadętość, prezentujemy nieatrakcyjny wizerunek zdrowienia. Natomiast, wolna od egocentryzmu potrzeba służenia innym tworzy atmosferę przyciągającą uzależnionych, którzy wciąż jeszcze cierpią.', 'Przyjrzę się swoim motywom, aby moja służba miała charakter prawdziwie duchowy.'),
(353, '12-18', '18 grudnia', 'Posłanie naszych mityngów\r\n', NULL, '„Fakt, że my, jako każda poszczególna grupa, koncentrujemy się na przekazywaniu posłania, zapewnia naszą trwałość; uzależnieni mogą na nas liczyć.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nOpowieści o naszych wybrykach z okresu czynnego uzależnienia są być może zabawne. Historie o naszych ekscentrycznych zachowaniach z czasów, gdy braliśmy, mogą być interesujące. Bardziej jednak wnoszą zamieszanie niż niosą posłanie. Filozoficzne wywody o istocie Boga są fascynujące. Omawianie aktualnych wydarzeń również ma swoje miejsce, jednakże nie na mityngu NA. Okresy, w których rośnie nasza niechęć do mityngów, gdy narzekamy, że „oni nie wiedzą, jak należy się dzielić” lub „to była kolejna sesja marudzenia”, są prawdopodobnie oznaką tego, że sami powinniśmy dokładnie przyjrzeć się własnemu sposobowi dzielenia się na mityngach. Dzieląc się tym, jak trafiliśmy do NA i jak tu pozostaliśmy dzięki praktykowaniu Dwunastu Kroków, niesiemy prawdziwe posłanie zdrowienia. To jest to, czego szukamy, gdy idziemy na mityng. Naszym głównym celem jest niesienie posłania tym, którzy wciąż jeszcze cierpią. To, czym dzielimy się na mityngu może się przyczynić do tego wysiłku lub zniweczyć go. Decyzja i odpowiedzialność należą do nas. ', 'Będę się dzielić moim zdrowieniem na mityngu NA.'),
(354, '12-19', '19 grudnia', 'Iść tą drogą, o której mówimy\r\n', NULL, '„Słowa nie wiele znaczą, dopóki nie wprowadzimy ich w czyn.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKrok Dwunasty przypomina nam o „praktykowaniu tych zasad we wszystkich naszych poczynaniach”. W NA widzimy dookoła siebie żywe przykłady tych sugestii. Bardziej doświadczeni członkowie, którzy wydają się być otoczeni aurą spokoju, demonstrują korzyści płynące ze stosowania tej cząstki mądrości w swoim własnym życiu. Aby otrzymać korzyści płynące z Kroku Dwunastego musimy praktykować duchowe zasady naszego programu, nawet wtedy, gdy nikt nie patrzy. Gdy mówimy na mityngu o zdrowieniu, a żyjemy dalej tak, jakbyśmy byli czynnie uzależnieni, nasi przyjaciele ze wspólnoty z pewnością domyślą się, że nie robimy nic innego poza cytowaniem wzniosłych haseł. To co udaje nam się przekazać osobom nowoprzybyłym pochodzi bardziej z tego, jak żyjemy, niż z tego, co mówimy. Jeśli radzimy komuś „powierzyć to”, podczas gdy sami jeszcze nie doświadczyliśmy cudu Kroku Trzeciego, niewielkie są szanse, że takie posłanie trafi do uszu osób nowoprzybyłych, dla których jest przeznaczone. Jednak, gdy postępujemy zgodnie z tym, co mówimy i dzielimy się naszym prawdziwym doświadczeniem w zdrowieniu, nasze posłanie będzie z pewnością dostępne dla wszystkich. ', 'Będę praktykować zasady zdrowienia, nawet wtedy, kiedy jestem jedyną osobą, która o tym wie.'),
(355, '12-20', '20 grudnia', 'Przezwyciężyć auto-obsesję', NULL, '„Żyjąc krokami, zaczynamy uwalniać się od auto obsesji.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nWielu z nas przyszło do programu z przekonaniem, że nasze uczucia, oczekiwania i potrzeby powinny być dla wszystkich najważniejsze. Przez całe życie zachowywaliśmy się samolubnie i egocentrycznie i wierzyliśmy, że jest to jedyny sposób na życie. Egocentryzm ten nie znika sam z siebie, gdy przestajemy brać narkotyki. Być może na naszym pierwszym mityngu NA byliśmy przekonani o tym, że wszyscy nas obserwują, oceniają i potępiają. Może domagamy się od naszego sponsora, by nieustannie był pod telefonem, na każde nasze zawołanie, ale w odpowiedzi na to sponsor może nam delikatnie zasugerować, że świat nie kręci się wokół nas. Im bardziej upieramy się przy tym, aby być pępkiem świata, tym bardziej niezadowoleni jesteśmy z naszych przyjaciół, naszego sponsora i ze wszystkiego wokół. Uwolnić się od auto obsesji możemy poprzez koncentrowanie się bardziej na potrzebach innych ludzi, niż na własnych. Gdy inni mają problemy, możemy zaoferować im pomoc. Gdy nowoprzybyli muszą dojeżdżać na mityng, możemy ich podwieźć. Gdy nasi przyjaciele czują się samotni, możemy spędzić z nimi czas. Gdy czujemy się niekochani i ignorowani, możemy komuś okazać miłość i uwagę, której sami potrzebujemy. Dając, otrzymujemy z powrotem o wiele więcej - i w tę obietnicę możemy wierzyć.', 'Będę dzielić świat z innymi, wiedząc, że oni są tak samo ważni jak ja. Będę żywić mojego ducha, dając siebie innym. '),
(356, '12-21', '21 grudnia', 'Akceptacja i zmiana\r\n', NULL, '„Zdolność do zmiany przychodzi wraz z akceptacją siebie.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nStrach i zaprzeczanie są przeciwieństwem akceptacji. Nikt z nas nie jest doskonały, nawet we własnych oczach. Wszyscy mamy cechy charakteru, które chętnie byśmy zmienili, gdybyśmy mieli taką możliwość. Czasami, zastanawiając się nad tym, jak bardzo daleko jest nam do naszych ideałów, czujemy się przytłoczeni i ogrania nas strach, że nigdy nie uda nam się stać takimi ludźmi, jakimi chcielibyśmy być. W takiej chwili zaczyna działać nasz obronny mechanizm zaprzeczania, który prowadzi nas w stronę drugiej skrajność: wmawiamy sobie, że nic w nas nie potrzebuje zmiany, po co więc mielibyśmy sobie zawracać tym głowę? Żadna z tych dwóch skrajności nie daje nam możliwości, by się zmienić. Bez względu na to, czy jesteśmy w NA długo, czy dopiero zaczynamy zdrowienie, zdolność do zmieniania się zyskujemy poprzez pracę nad Dwunastoma Krokami. Gdy uznajemy, że jesteśmy bezsilni, i że przestaliśmy kierować własnym życiem, przeciwdziałamy kłamstwu, które mówi nam, że nie musimy się wcale zmieniać. Gdy zaczynamy wierzyć, że Siła Większa od nas samych może nam pomóc, pozbywamy się strachu przed tym, że jesteśmy nieodwracalnie uszkodzeni. Zaczynamy wierzyć, że możemy się zmienić. Powierzamy się opiece Boga, jakkolwiek go pojmujemy, i czerpiemy z tego siłę, która jest nam potrzebna do dokonania gruntownego i uczciwego obrachunku. Wyznajemy Bogu i drugiemu człowiekowi to, czego się dowiedzieliśmy z naszego obrachunku moralnego. Akceptujemy to, co jest w nas dobre i złe. Poprzez tę akceptację stajemy się zdolni do zmiany.', 'Będę się zmieniać. Poprzez pracę nad krokami przeciwstawię się mojemu strachowi i zaprzeczaniu i znajdę akceptację potrzebną do zmiany.'),
(357, '12-22', '22 grudnia', 'Nowa droga życia\r\n', NULL, '„Kiedy w końcu zdajemy sobie sprawę z tego, że nie potrafimy już funkcjonować jako istoty ludzkie, zarówno z narkotykami jak i bez nich,  wszyscy stajemy twarzą w twarz przed następującym dylematem: brnąć dalej, aż do gorzkiego końca - więzienia, szpitala i śmierci - lub odnaleźć nową drogę życia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCo było najgorszym aspektem czynnego uzależnienia? Dla wielu z nas wcale nie była to perspektywa rychłej śmierci z powodu naszej choroby. Najgorszą rzeczą była śmierć za życia, którą przeżywaliśmy każdego dnia, ten nigdy nie kończący się bezsens życia. Czuliśmy się jak chodzące upiory, a nie jak pełne życia i miłości istoty tworzące otaczający nas świat. Zdrowiejąc, zaczęliśmy wierzyć, że jesteśmy na świecie po to, aby kochać siebie i kochać innych. Pracując nad Dwunastoma Krokami nauczyliśmy się akceptować samych siebie. A wraz z samoakceptacją zyskaliśmy również szacunek do siebie. Spostrzegliśmy, że wszystko, co robimy, ma wpływ na innych ludzi; jesteśmy częścią życia otaczających nas ludzi, a oni są częścią naszego życia. Zaczęliśmy ufać otaczającym nas ludziom i akceptować naszą odpowiedzialność wobec nich. Zdrowiejąc, powracamy do życia. Podtrzymujemy nasze nowe życie poprzez przyczynianie się do szczęścia innych ludzi i codzienne poszukiwanie możliwości robienia tego lepiej - dzieje się tak wtedy, gdy zaczyna działać Krok Dziesiąty, Jedenasty i Dwunasty. Czasy, gdy żyliśmy jak upiory należą do przeszłości, ale tylko tak długo, jak długo aktywnie staramy się być zdrowymi, kochającymi i współdziałającymi elementami swojego życia i życia otaczających nas ludzi. ', 'Znalazłem nową drogę życia. Dzisiaj postaram się służyć innym z miłością i kochać samego siebie.'),
(358, '12-23', '23 grudnia', 'Nowe poglądy\r\n', NULL, '„Rewidujemy nasze stare poglądy, by móc oswoić się z nowymi poglądami, które prowadzą nas ku nowej drodze życia.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nNauka życia po nowemu może okazać się trudna. Czasami, kiedy staje się to szczególnie ciężkie, pojawia się pokusa, aby pójść po linii najmniejszego oporu i żyć według naszych starych poglądów. Zapominamy wtedy, że te stare poglądy zabijały nas. Aby iść nową drogą życia, musimy otworzyć się na nowe idee. Praca nad krokami, uczestnictwo w mityngach, dzielenie się z innymi, ufność wobec naszego sponsora - te sugestie napotykają na nasz opór, a nawet na bunt. Program NA wymaga wysiłku, jednak każdy krok w programie zbliża nas do tego, abyśmy się stali takimi ludźmi, jakimi naprawdę chcemy być. Chcemy się zmieniać, podążać dalej i stać się lepszymi ludźmi, niż jesteśmy dzisiaj. Żeby to osiągnąć, otwieramy nasze umysły, próbujemy nowych idei, które znaleźliśmy w NA i uczymy się nowej drogi życia.', 'Otworzę się na nowe idee i będę się uczyć nowego sposobu życia. '),
(359, '12-24', '24 grudnia', 'Grupa', NULL, '„Krok Dwunasty naszego osobistego programu mówi również o tym, że niesiemy posłanie tym, którzy wciąż jeszcze cierpią… Grupa, jest najbardziej efektywnym narzędziem, które mamy, do przekazywania tego posłania.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nKiedy zaczynamy chodzić na mityngi NA, spotykamy tam zdrowiejących uzależnionych. Wiemy, że są uzależnieni, ponieważ mówią o tych samych doświadczeniach i uczuciach, które również my mieliśmy. To, że zdrowieją, poznajemy po ich pogodzie ducha - mają coś, czego również i my pragniemy. Kiedy na mityngach NA inni uzależnieni dzielą się z nami swoim zdrowieniem, otrzymujemy nadzieję. Mityngi przyciągają nas swoją atmosferą zdrowienia. Taka atmosfera powstaje, kiedy członkowie grupy angażują się we wspólną pracę. Próbujemy zwiększyć atmosferę zdrowienia poprzez pomaganie w przygotowaniu mityngu, witanie nowoprzybyłych i rozmawianie po mityngu z innymi uzależnionymi. Te przykłady naszego zaangażowanie sprawiają, że nasze mityngi przyciągają i pomagają naszym grupom dzielić się zdrowieniem. Dzielenie się doświadczeniem na mityngach jest sposobem, w jaki sobie nawzajem pomagamy i często jest podstawą naszego poczucia przynależności. Utożsamiamy się z innymi uzależnionymi i dlatego ufamy ich posłaniu nadziei. Wielu z nas nie pozostałoby w NA bez tego poczucia przynależności i bez tej nadziei. Gdy dzielimy się na mityngach, umacniamy nasze zdrowienie, pomagając jednocześnie innym uzależnionym. ', 'Wyciągnę rękę do innego uzależnionego z mojej grupy i podzielę się z nim moim zdrowieniem.'),
(360, '12-25', '25 grudnia', 'Anonimowość i samowola', NULL, '„Pogoń za osobistymi korzyściami… która w przeszłości przyniosła tyle bólu, odchodzi w niepamięć, jeśli będziemy przestrzegać zasady anonimowości”. \r\n\r\n~Tekst podstawowy  \r\n\r\nSamo słowo anonimowość oznacza bezimienność, ale w anonimowości programu NA działa szersza zasada: zasada bezinteresowności. Kiedy przyznajemy się do naszej bezsilności w zarządzaniu własnym życiem, robimy pierwszy krok od własnej woli i pierwszy krok w stronę bezinteresowności. Im mniej staramy się kierować swoim życiem według własnej woli, tym bardziej zauważamy, że w naszym życiu tak bardzo brakuje nam mocy i kierunku. Ale zasada bezinteresowności nie tylko sprawia, że ​​czujemy się lepiej – pomaga nam lepiej żyć. Nasze wyobrażenia o tym, jak powinien działać świat, zaczynają tracić na znaczeniu i przestajemy próbować narzucać naszą wolę wszystkim i wszystkiemu wokół nas. A kiedy porzucimy pretensje do „wiedzenia wszystkiego” i zaczniemy doceniać wartość doświadczenia innych ludzi, zaczniemy traktować ich z szacunkiem. Interesy innych stają się dla nas tak samo ważne jak nasze własne; zaczynamy myśleć o tym, co jest najlepsze dla grupy, a nie tylko o tym, co jest najlepsze dla nas. Zaczynamy żyć życiem większym od nas samych, czymś więcej niż tylko my, nasze imię i my sami – zaczynamy żyć zgodnie z zasadą anonimowości.', 'Boże, proszę uwolnij mnie od samowoly. Pomóż mi zrozumieć zasadę anonimowości; pomóż mi żyć bezinteresownie.'),
(361, '12-26', '26 grudnia', 'Siła, która nigdy nie zawodzi\r\n', NULL, '„Jeśli uczymy się ufać tej Sile, to zaczynamy pozbywać się lęku przed życiem.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJesteśmy ludźmi, którzy nauczyli się stawiać wszystko na jedną kartę. Wielu z nas miało jakiś określony narkotyk, który był naszym ulubionym narkotykiem. Potrzebowaliśmy go, aby wytrzymywać dzień po dniu i aby życie było łatwiejsze do zniesienia. Zaufaliśmy w pełni temu narkotykowi, a dokładnie mówiąc, oddaliśmy się mu bez reszty, bez żadnych zastrzeżeń. Potem jednak nasz narkotyk obrócił się przeciwko nam. Zostaliśmy zdradzeni przez tę jedną jedyną rzecz, na której kiedykolwiek polegaliśmy i ta zdrada zupełnie nas pogrążyła. Teraz, gdy trafiliśmy do grup zdrowienia, możemy mieć pokusę, by zdać się na innych ludzi, którzy mogliby zaspokoić nasze potrzeby. Możemy tego oczekiwać od naszego sponsora, od naszego partnera lub od naszego najlepszego przyjaciela. Poleganie jednak na drugim człowieku może okazać się ryzykiem. Ludzie mogą zawieść, ponieważ nie są doskonali. Mogą być na urlopie, mogą spać lub po prostu być w złym nastroju, kiedy będziemy ich potrzebować. Musimy zdać się na Siłę, która jest większa od nas samych. Siła człowieka nie może nam przywrócić zdrowia duchowego, ani opiekować się naszą wolą i naszym życiem lub być bezwarunkowo dostępną i kochającą zawsze, gdy tylko będziemy jej potrzebować. Pokładamy naszą ufność w Bogu, jakkolwiek go pojmujemy, w jedynej Sile, która nas nigdy nie zawiedzie.', 'Będę pokładał ufność w Sile większej, niż moja własna, w jedynej Sile, która mnie nigdy nie zawiedzie.'),
(362, '12-27', '27 grudnia', 'Bóg może przywrócić nam zdrowie duchowe\r\n', NULL, '„Proces dochodzenia do wiary przywraca nam zdrowie duchowe. Siła do działania pochodzi właśnie z tej wiary.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nTeraz, gdy w końcu przyznaliśmy się do naszego szaleństwa i zobaczyliśmy przykłady wszystkich jego przejawów, możemy obawiać się, że już przez resztę życia jesteśmy skazani na powtarzanie takich zachowań. Podobnie jak kiedyś, gdy uważaliśmy, że nigdy nie zdołamy przestać brać, tak samo teraz może wydawać się nam, że nasze szaleństwo jest nieuleczalne. Jest to błędne myślenie! Wiemy, że naszą wolność od czynnego uzależnienia zawdzięczamy łasce kochającego Boga. Jeżeli Siła Wyższa mogła dokonać cudu uwolnienia nas od obsesji zażywania narkotyków, z pewnością może również uwolnić nas od wszelkich innych przejawów naszego szaleństwa. Gdy ogarniają nas wątpliwości, pomyślmy o przejawach zdrowia duchowego, które uzyskaliśmy do tej pory. Być może zadłużyliśmy się, wyczerpując do dna nasze karty kredytowe, ale gdy przyznaliśmy się do porażki, zdrowie duchowe powróciło i zniszczyliśmy wszystkie te karty. Być może kiedyś poczuliśmy się samotni i chcieliśmy odwiedzić jakiegoś kumpla ze starych ćpuńskich czasów. Jeżeli zamiast tego odwiedziliśmy naszego sponsora, jest to przejawem rozsądku i zdrowia duchowego. Szaleństwo naszego uzależnienia odchodzi w przeszłość, gdy w naszym zdrowieniu zaczynamy doświadczać momentów zdrowia duchowego. Nasza wiara w Siłę większą, niż nasza własna, wzrasta, gdy zaczynamy uświadamiać sobie, że nawet nasz rodzaj szaleństwa jest niczym w obliczu tej Siły.', 'Dziękuję Bogu, jakkolwiek go pojmuję, za każde rozsądne działanie w moim życiu, ponieważ wiem, że jest ono oznaką mojej odnowy i powrotu do zdrowia duchowego. '),
(363, '12-28', '28 grudnia', 'Depresja', NULL, '„Nie walczymy już dłużej ze strachem, złością, poczuciem winy, użalaniem się lub depresją.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nJako uzależnieni, od czasu do czasu mamy depresję. Kiedy jesteśmy przygnębieni, możemy mieć tendencję do izolowania się, a wtedy nasza depresja może zamienić się w rozpacz. Nie możemy sobie pozwolić na to, aby depresja doprowadziła nas do sięgnięcia po narkotyki. Zamiast tego, staramy się postępować zgodnie z rutyną naszego życia. Najwyższy priorytet dajemy mityngom i naszemu sponsorowi. Dzieląc się naszymi uczuciami, możemy zobaczyć, że nie jesteśmy jedynymi, którzy w trakcie zdrowienia cierpią na depresję. Praca z nowoprzybyłymi może dokonać cudów dla naszego stanu ducha. I najważniejsze - modlitwa i medytacja mogą pomóc nam wykorzystać siłę, której potrzebujemy do przetrwania depresji. Praktykujemy akceptację i staramy się pamiętać, że takie uczucia, jak depresja niewątpliwie z czasem przemijają. Zamiast walczyć z naszymi uczuciami, akceptujemy je i prosimy Boga o siłę, aby je przetrwać. ', 'Wiem, że moje stany depresyjne nie będą trwały wiecznie. Porozmawiam otwarcie o moich uczuciach z moim sponsorem lub z inną osobą, która mnie zrozumie.'),
(364, '12-29', '29 grudnia', 'Oczami innych\r\n', NULL, 'Kiedy ktoś wskazuje nam jakiś nasz błąd, prawdopodobnie pierwszą naszą reakcją jest obrona... Jeśli (jednak) naprawdę chcemy być wolni, będziemy z uwagą traktować uwagi naszych przyjaciół ze wspólnot.  \r\n\r\n~Tekst Podstawowy  \r\n\r\nW pewnym momencie naszego zdrowienia stwierdzamy z przykrością, że to, jak widzimy siebie samych, niekoniecznie pokrywa się z tym, jak widzą nas inni. Prawdopodobnie nie jesteśmy ani tacy dobrzy, ani tacy źli, ani tacy piękni, ani tacy brzydcy, jak o sobie myślimy - jesteśmy jednak za blisko samych siebie, aby widzieć siebie wyraźnie. Jest to dobry czas na to, aby nasi przyjaciele z programu zatroszczyli się o nas i powiedzieli nam jak nas postrzegają. Opowiadają nam o naszych zaletach, których być może nie jesteśmy świadomi, ale też mówią nam o naszych uciążliwych cechach, których my sami nie jesteśmy w stanie zobaczyć.  Być może bronimy się przed taką „pomocą” i w niektórych przypadkach jest to uzasadnione. Lecz również złośliwe uwagi o naszych rzekomych wadach mogą oświetlić aspekty naszego zdrowienia, których my sami nigdy byśmy nie dostrzegli. Bez względu na to, od kogo i z jakiej przyczyny są nam oferowane te uwagi, nie możemy sobie pozwolić na to, aby je zignorować.  Nie musimy czekać aż inni sami opowiedzą nam o swoich spostrzeżeniach. Kiedy spędzamy czas z naszym sponsorem lub z przyjaciółmi, którym ufamy, możemy zrobić pierwszy krok i spytać ich, jak postrzegają określone sfery naszego życia, których my sami nie widzimy. Chcemy mieć szersze, niż tylko nasze własne, spojrzenie na nasze życie. A osiągnąć to możemy tylko wtedy, gdy spojrzymy na siebie oczami innych.', 'Spróbuję spojrzeć na siebie takiego, jakim na prawdę jestem. Będę słuchać, gdy inni będą coś o mnie mówić i spojrzę na siebie ich oczami.'),
(365, '12-30', '30 grudnia', 'Działanie i modlitwa\r\n', NULL, '„... wzrastanie nie jest efektem dobrych chęci, lecz działania i modlitwy.”  \r\n\r\n~Tekst Podstawowy  \r\n\r\nCzasami, wydaje się, że nasze zdrowienie postępuje zbyt wolno. Szamoczemy się z krokami, zmagamy się ciągle z tymi samymi problemami, dzień po dniu cierpimy z powodu tych samych nieprzyjemnych uczuć. Chcielibyśmy, aby nasze zdrowienie postępowało nieco szybciej, żebyśmy w końcu mogli znaleźć trochę wytchnienia! Same chęci nie przynoszą rezultatów w zdrowieniu; to nie jest program magii. Gdyby uzależnienie mogło być wyleczone samymi tylko chęciami, wszyscy bylibyśmy już dawno zdrowi. To, co naprawdę przynosi nam ulgę, to działanie i modlitwa. NA jest skuteczne w przypadku tak wielu uzależnionych, ponieważ jest starannie opracowanym programem działania i modlitwy. Czynności, które wykonujemy w każdym z kroków, wnoszą coraz więcej zdrowienia do każdej sfery naszego życia. Modlitwa zaś podtrzymuje nasz związek z Siłą Wyższą. Razem, działanie i modlitwa, zapewniają nam dobrą podstawę naszego zdrowienia.', 'Moje zdrowienie jest zbyt cenne, by ograniczyć się tylko chęciami. Dzisiaj jest dobry dzień na działanie i modlitwę.'),
(366, '12-31', '31 grudnia', 'Służyć', NULL, '„Praca z innymi jest tylko początkiem służby.“  \r\n\r\n~Tekst Podstawowy  \r\n\r\nTeraz, zdrowiejemy. Żyjąc programem, osiągnęliśmy w naszym życiu pewną stabilizację. Nasza wiara w Siłę Wyższą wzrosła, a nasze duchowe przebudzenie postępuje. I co teraz? Czy usiądziemy i w spokoju będziemy się tym rozkoszować? Oczywiście, że nie! Odkrywamy nowe sposoby służenia. Jesteśmy skłonni myśleć o służbie, jako o służeniu w jakimś komitecie lub jako o pozycji na którymś z poziomów w strukturach NA. Jednak służba wychodzi daleko poza takie rozumienie. W rzeczywistości, możemy odkryć możliwości służenia we wszystkich obszarach naszego życia. Nasza praca, bez względu na to, jaki zawód wykonujemy, jest formą służby na rzecz społeczeństwa. Praca, którą wykonujemy w domu, jest służbą wobec naszych rodzin. Być może zajmujemy się też wolontariatem, w którejś z dziedzin życia społecznego. I jakżeż wiele zmian powodują nasze wysiłki w służeniu! Jeśli w to wątpimy, spróbujmy sobie wyobrazić, jaki byłby świat, gdyby nikt nie zadawał sobie trudu służenia innym. Nasza praca służy ludzkości. Posłanie, które niesiemy, wychodzi poza pomieszczenia, w których odbywają się mityngi i dotyczy wszystkiego, co robimy.', 'Będę poszukiwać możliwości służenia we wszystkim, co robię.');
